-- Poems batch 153
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('28cb0f4f-19a3-4575-9c98-bb13f8844c14','山水友餘辭 刺椿','王質','宋','宋诗','song-poetry','','[]','喚春鳥，當春呼，莫錯呼，非茱萸。',50,'全唐诗/poet.song.155000.json','["喚春鳥，當春呼，莫錯呼，非茱萸。", "前林迎榆郎，後林接榆姑。", "刺椿，刺椿，黠禽掐捾餘姑存，土卵蕨鷄無宿根。"]'),
('9dff0123-ad50-4498-9b96-9e361065cdcd','山水友餘辭 金櫻子','王質','宋','宋诗','song-poetry','','[]','薔薇花，榅桲實，多㗘㗱，津浥浥。',52,'全唐诗/poet.song.155000.json','["薔薇花，榅桲實，多㗘㗱，津浥浥。", "椰子亦成酒，縮沙亦成蜜。", "金櫻子，金櫻子，速挽菖蒲出溪水，仍招茯苓并遠志。"]'),
('96aa8238-69e2-4aec-8fdb-a61a8254a5f7','山水友餘辭 甜藤','王質','宋','宋诗','song-poetry','','[]','元姓甘，不姓丁，引春風，含常春。',50,'全唐诗/poet.song.155000.json','["元姓甘，不姓丁，引春風，含常春。", "鷄翁呷甘露，祁婆插金稜。", "甜藤，甜藤，粥香餳白度清明，一片春山快活聲。"]'),
('38fda74c-b92f-45e5-aa61-fd905cc13086','山水友餘辭 苦菜','王質','宋','宋诗','song-poetry','','[]','王瓜後，靡草前，薺却苦，荼却甘。',50,'全唐诗/poet.song.156000.json','["王瓜後，靡草前，薺却苦，荼却甘。", "貝母花哆哆，龍葵葉團團。", "苦菜，苦菜，空山自有閒人愛，竹筯木瓢越甜煞。"]'),
('e1300ced-9f40-4804-a230-e3f98dae0780','山水友餘辭 甜椎','王質','宋','宋诗','song-poetry','','[]','花成穗，子成毬，雅相似，終非儔。',50,'全唐诗/poet.song.156000.json','["花成穗，子成毬，雅相似，終非儔。", "茅栗低坡尾，旋栗高岡頭。", "甜椎，甜椎，秋後秋樹倚斜暉，苦者擲與看牛兒。"]'),
('18103f08-4374-49aa-8f44-b4ccd7a83046','山水友餘辭 蓼米','王質','宋','宋诗','song-poetry','','[]','無馬纏，無蝦鬚，羅裙帯，色色無。',50,'全唐诗/poet.song.156000.json','["無馬纏，無蝦鬚，羅裙帯，色色無。", "願花變流沙，願花變穿珠。", "蓼米，蓼米，秋風易摇入秋水，大平中期難屈指。"]'),
('d0279110-844e-41e6-ad65-38e1613dd913','山水友餘辭 水芋頭','王質','宋','宋诗','song-poetry','','[]','不粵卵，不岷鴟，雖沉波，堪作魁。',55,'全唐诗/poet.song.156000.json','["不粵卵，不岷鴟，雖沉波，堪作魁。", "葧臍葉搓牙，芥{艹粗}苗整齊。", "水芋頭，水芋頭，江湖百年無一愁，南灣北灣皆膳羞。"]'),
('455da4ca-a77c-48d1-9060-e19b6e04bfb8','山水友餘辭 蔞蒿','王質','宋','宋诗','song-poetry','','[]','皤老白，角子烏，爾未萌，我已敷。',50,'全唐诗/poet.song.156000.json','["皤老白，角子烏，爾未萌，我已敷。", "蘆笋茁戢戢，荻笋抽擢擢。", "蔞蒿，蔞蒿，風枝兩葉老蕭蕭，草堂黍氏不得驕。"]'),
('56abf3f2-9d24-46b5-84cc-bba429e32631','山水友餘辭 茭白','王質','宋','宋诗','song-poetry','','[]','春斑犀，秋彫胡，一年計，在江湖。',56,'全唐诗/poet.song.156000.json','["春斑犀，秋彫胡，一年計，在江湖。", "赤脚白脚癯，黄鮮紅鮮杇。", "茭白，茭白，{艹/广/盧}人漁子手拍拍，槳芽櫓臍曉香發。"]'),
('b3e8a1f8-e25e-4cdc-b62b-f62e331c1b1c','山水友餘辭 黄花菜','王質','宋','宋诗','song-poetry','','[]','大金星，小金錢，急嚥淡，緩嚼甜。',52,'全唐诗/poet.song.156000.json','["大金星，小金錢，急嚥淡，緩嚼甜。", "黄花了未了，小兒群爭討。", "黄花菜，黄花菜，大黄小黄甑蓬闓，飯香蔬香直一噫。"]'),
('9c52946f-0b30-456b-8ff4-736465226356','山水友別辭 茯苓酥','王質','宋','宋诗','song-poetry','','[]','且自伏爾菟，毋勞伏我神。',48,'全唐诗/poet.song.156000.json','["且自伏爾菟，毋勞伏我神。", "只圖滋一啜，不圖延千齡。", "酥也酥，總弗如，松風浩蕩相招呼，呼上青冥山亦無。"]'),
('139f0c9e-07e8-48ea-800a-7fff6a8a342e','山水友別辭 地黄糖','王質','宋','宋诗','song-poetry','','[]','風來聞清香，月來見清光。',48,'全唐诗/poet.song.156000.json','["風來聞清香，月來見清光。", "鶗鴂但先鳴，芐芭毋歇芳。", "糖他糖，總弗强，草花樹花爭結房，迎梅送梅陂愈蒼。"]'),
('38299357-0a8b-449d-b105-d5d1a769f30b','山水友別辭 薏苡飯','王質','宋','宋诗','song-poetry','','[]','勾漏升空飛，伏波抱愁死。',48,'全唐诗/poet.song.156000.json','["勾漏升空飛，伏波抱愁死。", "一飽萬事已，古人皆流水。", "飯它飯，總弗換，樹陰相隨鳥聲變，草蟲木蝱自撩亂。"]'),
('850867ef-349b-489c-954c-4f532dae933e','山水友別辭 松粉','王質','宋','宋诗','song-poetry','','[]','奉勸十八公，莫入明光宮。',48,'全唐诗/poet.song.156000.json','["奉勸十八公，莫入明光宮。", "藉爾毬端露，助我屩底風。", "粉它粉，總弗近，總總松毛糞松本，松子松花香愈猛。"]'),
('5cf3602b-9f7c-4331-977e-bfdbe0500ceb','山水友別辭 芭蕉脯','王質','宋','宋诗','song-poetry','','[]','不愁風槭槭，不愁雨蕭蕭。',48,'全唐诗/poet.song.156000.json','["不愁風槭槭，不愁雨蕭蕭。", "爲人張秋本，爲我解春牢。", "脯它脯，總弗許，山鬼且往凭山樹，繁陰相倍享風露。"]'),
('de74284e-99d5-495c-abc7-cd5f9c9ecd01','山水友別辭 薝蔔鮓','王質','宋','宋诗','song-poetry','','[]','天上雪花六，地下梅花六。',48,'全唐诗/poet.song.156000.json','["天上雪花六，地下梅花六。", "彼花花我眼，此花實我腹。", "鮓它鮓，總弗亞，山南招提北蘭若，野僧家風莫相捨。"]'),
('903646cf-ca02-48b6-8711-564776d7bd5d','山水友別辭 榆醤','王質','宋','宋诗','song-poetry','','[]','榆葉瀹可葅，榆皮舂可脯。',48,'全唐诗/poet.song.156000.json','["榆葉瀹可葅，榆皮舂可脯。", "代豆釀爲醤，代麵膠爲糊。", "醤他醤，總莫尚，榆郎榆姑春春旺，林下山間慰所望。"]'),
('d5e8383c-10ed-493f-a1db-6f8da30d781c','山水友別辭 蒼耳酒','王質','宋','宋诗','song-poetry','','[]','山婦耳带璫，山兒耳带枲。',48,'全唐诗/poet.song.156000.json','["山婦耳带璫，山兒耳带枲。", "黄衣醤已佳，碧葉酒尤美。", "酒它酒，總弗右，陂草草深別宇宙，野香薰蒸噴饙餾。"]'),
('647e13fe-66f5-469a-96ac-087d8a841692','避暑烟水亭與王南卿回文聯句一首','王質','宋','宋诗','song-poetry','','[]','顔舒且對清樽酒，晝永方濃翠幄陰。',64,'全唐诗/poet.song.156000.json','["顔舒且對清樽酒，晝永方濃翠幄陰。", "環佩響溪寒浪急，畫圖藏谷繡烟深。", "班生石潤苔紋亂，碧度雲飛鳥影沉。", "閒館邃風來迥野，隔林斜日轉疎林。"]'),
('21be41cf-ef84-46ca-a751-da2972319276','過洞庭','王質','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雲可有無水，風能奔走沙。',48,'全唐诗/poet.song.156000.json','["雲可有無水，風能奔走沙。", "蟠深鳴老䖦，飛倦落長鴉。", "地有湘頭尾，山無楚正斜。", "人間與天上，何處礙浮槎。"]'),
('2c61a9fc-1229-4bce-b998-5b7a16fa4f18','黄香梅','王質','宋','宋诗','song-poetry','','[]','新翻微變壽陽粧，喜色橫斜水一方。',32,'全唐诗/poet.song.156000.json','["新翻微變壽陽粧，喜色橫斜水一方。", "點破冰肌愈清絕，月明無處著清香。"]'),
('21da6f06-ceaa-4e43-8c52-0d4d063d522a','墨梅','王質','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紛紛初疑月掛樹，耿耿獨與參橫昏。',132,'全唐诗/poet.song.156000.json','["紛紛初疑月掛樹，耿耿獨與參橫昏。", "自從東坡老子飛此英，茫茫世界總無人。", "疏影橫斜水清淺，暗香浮動月黄昏。", "自從西湖處士揚此靈，紛紛豪俊半無神。", "贈子一轉語，挑子萬年機。", "嘬蘇詩，嚅林詩，要使蘇詩林詩透心脾。", "槎南枝，挼北枝，直使南枝北枝伏指麾。", "九州四海尋人去，不遇當人不要歸。"]'),
('ae1d0ba2-ede0-40f7-93f8-49bf223d269a','和沈述之與俞舜俞題墨梅','王質','宋','宋诗','song-poetry','','[]','玉京羣帝周大羅，芙蓉倒影旌旗多。',226,'全唐诗/poet.song.156000.json','["玉京羣帝周大羅，芙蓉倒影旌旗多。", "明視仍孫竊姮娥，雙成飛瓊相和歌。", "飛瓊授以無聲詩，下走人間駃莫追。", "梅花狂掃不自持，但見浮動橫斜他不知。", "中書君貴列鐘鼓，喚下真真命歌舞。", "真真呼上復呼下，上屏不言下屏語。", "空郊莽蒼江渺茫，中書頭銳身瘦長。", "玄泓濡首醉淋浪，首所觸者皆生香。", "柳山俞生氣象別，不惟手潔更身潔。", "中書相與有良緣，共看霜天羌筦裂。", "十指五指握妙華，不在山顛即水涯。", "老楊死守梅花樹，攀枝弄葉猶咨嗟。", "眼光落此亦前定，過去垣外觸參井。", "俞生今世伴梅花，若伴他花應不肯。"]'),
('9c481031-6f9e-4dfd-b029-c066494920a7','題龔嘉謀墨梅','王質','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅花一枝復一枝，是邪非邪吾不知。',208,'全唐诗/poet.song.156000.json','["梅花一枝復一枝，是邪非邪吾不知。", "空堂慘淡寒寂寞，安得璀璨生光輝。", "今朝朔雲覆江野，無乃雪花衝屋楣。", "少定徐觀元不爾，壁上橫陳皆不飛。", "摩挲零亂爭欲動，亟避又不來沾衣。", "稍悟寒英著明縞，已信未信猶銜疑。", "雖然是梅不是雪，亦豈人力攘天機。", "伸脚欲下俄復縮，泠泠亦似奔湍溪。", "忽聽簷牙啅林雀，紛紛驚下玉葳蕤。", "鼻端三嗅定何有，蕭騷若有霜風吹。", "乃是瀼溪小龔子，搦筆汎翰生清奇。", "老杜見松被松嚇，王子見梅遭梅欺。", "却憶西湖疏影裏，斷橋流水袖香歸。"]'),
('541f5b70-91fb-4075-8ed2-927c31e3b6f9','題俞舜俞墨梅','王質','宋','宋诗','song-poetry','','[]','楊無咎，透梅肝膽入梅心。',282,'全唐诗/poet.song.156000.json','["楊無咎，透梅肝膽入梅心。", "俞舜俞，刳梅皮骨到梅髓。", "大江之西出二士，長淮以北屈兩指。", "吾嘗菁村山中飽玩玉葳蕤，十里五里無他枝。", "所恨俞子不同載，至今心繫吳江湄。", "吾嘗竹山道上爛看蠟凌亂，三程兩程行不斷。", "所恨俞子不同征，至今夢繞襄山畔。", "百尺卷雪樓，十頃黄龍州。", "此地遇俞子，此時逢孟秋。", "巽二滕六皆未集，廣寒宮中暗竊來相投。", "一枝兩枝雖不多，千林紅紫無若何。", "七尺八尺抑何短，萬里莽蒼亦云滿。", "贈爾一則語，收却萬年功。", "真梅藴在磊塊胸，幻梅流出精明瞳。", "溟濛摸索未有覩，慘淡經營何所從。", "中庸大學松齋繹幾轉，楞嚴圓覺竹几繙數卷。", "他時相逢江路傍，茫茫江月梅花香。", "但見梅花普照眼，不爲梅花空斷腸。"]'),
('db22e529-65fa-4255-938e-01560ba8ba52','題晁子止侍郎小橫軸江路野梅數枝','王質','宋','宋诗','song-poetry','','[]','西樓何自有江聲，安得梅花的皪明。',32,'全唐诗/poet.song.156000.json','["西樓何自有江聲，安得梅花的皪明。", "斗轉參橫無定舍，侍郎行處亦隨行。"]'),
('5bb094c8-14cb-441a-a6f8-82fc09323a90','題李贊可掀篷梅軸二首  其一','王質','宋','宋诗','song-poetry','','[]','低篷掀起湊平沙，略見玲瓏八九花。',32,'全唐诗/poet.song.156000.json','["低篷掀起湊平沙，略見玲瓏八九花。", "自有青天衮明月，靈臺長見影橫斜。"]'),
('b2d90e98-d2ce-4854-b9ad-852821a61f9e','題李贊可掀篷梅軸二首  其二','王質','宋','宋诗','song-poetry','','[]','半腰已自見全身，但要當人著眼明。',32,'全唐诗/poet.song.156000.json','["半腰已自見全身，但要當人著眼明。", "覷到梅花頭上上，十方同是玉爲京。"]'),
('ff8f9ef7-176b-468a-9c87-f0d7734bb38c','再題二首  其一','王質','宋','宋诗','song-poetry','','[]','不見梅稍不見根，參橫咫尺未能捫。',32,'全唐诗/poet.song.156000.json','["不見梅稍不見根，參橫咫尺未能捫。", "掀篷何自掀篷盡，一任江風吹斷魂。"]'),
('6c036e70-8bc4-44f2-8d03-287643878a6b','再題二首  其二','王質','宋','宋诗','song-poetry','','[]','半江鼻觀已前知，恨不身先急櫂飛。',32,'全唐诗/poet.song.156000.json','["半江鼻觀已前知，恨不身先急櫂飛。", "雖則梅花不全見，妙香滿載野航歸。"]'),
('46f362a3-d5e7-4b48-a4a5-ae27bf193a7f','近村','王質','宋','宋诗','song-poetry','','[]','急急殺殘點，沉沉敲遠鐘。',48,'全唐诗/poet.song.156000.json','["急急殺殘點，沉沉敲遠鐘。", "黄深湖霧重，白厚草霜濃。", "慘淡兵交氣，凄涼歲晚容。", "雲山望不極，吾恨亦重重。"]'),
('4b5a2c00-2efd-4535-9d50-c12d626437b0','過隆中村','王質','宋','宋诗','song-poetry','','[]','當日隆中事，它時渭上悲。',48,'全唐诗/poet.song.156000.json','["當日隆中事，它時渭上悲。", "出頭知幾度，彈指不多時。", "有客吟梁甫，何人表出師。", "姓龐名藴者，應笑卧龍兒。"]'),
('fb8578e0-edda-40d0-9369-e35fe870fdd5','聖燈偈','王質','宋','宋诗','song-poetry','','[]','是燈非草爇，亦非以膏滋。',216,'全唐诗/poet.song.156000.json','["是燈非草爇，亦非以膏滋。", "又非似瓶貯，亦非似盤擎。", "自靈府踴出，眼界現光輝。", "隨高下岩谷，以至杳靄外。", "然祈近眉睫，倏出尋丈間。", "亦有本無覩，啟發悲悔心。", "發心不須臾，所見亦如是。", "暫發俄即退，終亦不可得。", "二人或並處，所見各一境。", "以至五六輩，亦復五六種。", "人心如人面，是燈亦如之。", "譬如有目人，皆見當空月。", "目有昏明異，月亦分昏明。", "或有目眚者，隨眚作光相。", "不幸無目者，元未嘗有月。", "大智慧光明，遍滿河沙界。", "何獨不見燈，亦復不見我。", "何獨不見我，總不知所見。"]'),
('ae2dc8f8-99e8-435e-8bf2-9830febf9fec','集少陵佳句題和政堂呈使君','王質','宋','宋诗','song-poetry','','[]','上帝高居絳節朝，使君意氣凌青霄。',192,'全唐诗/poet.song.156000.json','["上帝高居絳節朝，使君意氣凌青霄。", "君臣既與時濟會，一豁明主正鬰陶。", "伯仲之間見伊呂，臨江節士安足數。", "欲傾東海洗乾坤，世人那得知其故。", "諸君何以答昇平，濟世宜引賢俊人。", "鳳臆龍鬐未易識，不與八駿俱先鳴。", "回鞭却走見天子，光芒六合無泥滓。", "後漢今周喜再昌，丹青婉轉麒麟裏。", "天時人事日相催，抑塞磊落之奇才。", "攙搶熒惑不敢動，五雲多處是三台。", "春來準擬開懷久，稍待秋風涼冷後。", "夜騎天駟超天河，南極一星朝北斗。"]'),
('ba2dee7d-4ddc-4f6d-9f4f-3e9bed9d207f','句','王質','宋','宋诗','song-poetry','','[]','真翁自了平生事，不了山陰陸務觀。',16,'全唐诗/poet.song.156000.json','["真翁自了平生事，不了山陰陸務觀。"]'),
('6254c056-c4fd-4c0e-b524-3324c6417829','榮木和陶靖節韻','程洵','宋','宋诗','song-poetry','','[]','我卜我居，游息在茲。',160,'全唐诗/poet.song.156000.json','["我卜我居，游息在茲。", "有榮者木，日封殖之。", "本根既固，發生以時。", "我時傾瞻，中心慨而。", "維人之生，孰本孰根。", "惟皇降衷，天理具存。", "是曰成性，道義之門。", "欽斯承斯，大化以敦。", "嗟彼世人，自安淺陋。", "德不圖新，惡或念舊。", "有干惟祿，有覬惟富。", "孰能毅然，不爲利疚。", "我懷師訓，罔敢失墜。", "匪道曷從，匪義曷畏。", "聖門雖遠，率焉以冀。", "庶幾疲駑，久亦告至。"]'),
('5716141a-2eef-4228-95a2-3839b03dc2f2','張允迪出示方清老詩用韻簡之','程洵','宋','宋诗','song-poetry','','[]','十里五里聊幽尋，遠山近山相對陰。',64,'全唐诗/poet.song.156000.json','["十里五里聊幽尋，遠山近山相對陰。", "煙雲變態晚逾好，竹樹葱蒼秋未深。", "故人見我喜欲舞，倚杖共看鴉投林。", "呼兒秉燭語清夜，烱烱君應識此心。"]'),
('342dbbf8-435b-4fd2-a08c-ef08958bf62c','度黄瓜嶺','程洵','宋','宋诗','song-poetry','','[]','十年來往黄瓜路，冒日衝風凌雨霧。',64,'全唐诗/poet.song.156000.json','["十年來往黄瓜路，冒日衝風凌雨霧。", "今朝短策又披雲，一笑成詩復悽楚。", "我行對鏡并浮鱅，欲攀星斗摩蒼穹。", "黄瓜雖小亦其亞，領略鱗鱗千萬峰。"]'),
('2f6ba92d-e812-426c-bd26-7ffaaa91900d','次方唐卿對月見寄','程洵','宋','宋诗','song-poetry','','[]','芒鞋却走荒山道，始覺在家貧亦好。',96,'全唐诗/poet.song.156000.json','["芒鞋却走荒山道，始覺在家貧亦好。", "歸來對月思故人，寂寞柴門迹如掃。", "故人遺我新詩章，反覆幽懷欲傾倒。", "恍如明月墜我室，烱烱清光滿懷抱。", "祗今秋稼已如雲，飽意可緩憂心擣。", "潑醅酒熟君不來，遠思緜緜滿秋草。"]'),
('75bbc00f-1053-45e5-a3d9-efb7189135a4','張衡山南山瑞芝','程洵','宋','宋诗','song-poetry','','["\u8861\u5c71"]','君不見商山昔有龐眉叟，道德高風聳山斗。',131,'全唐诗/poet.song.156000.json','["君不見商山昔有龐眉叟，道德高風聳山斗。", "茹芝歲久得長年，身與此山俱不朽。", "張公道與此老同，失身偶墜世網中。", "却從神武挂簪紱，林泉歲晚殊從容。", "壽宮誰遣芝生柱，三秀煌煌照庭宇。", "平生心地只天知，天遣芝爲靈府助。", "商山之老長茹芝，公雖不茹亦不疑。", "商山南山兩不朽，公壽定應山與齊。"]'),
('9babaf29-38d2-46d0-a10a-e83d92b8062c','伯羽許見過雨不果','程洵','宋','宋诗','song-poetry','','[]','結廬在溪上，觸目皆可娛。',96,'全唐诗/poet.song.156000.json','["結廬在溪上，觸目皆可娛。", "嗟予亦何爲，悠悠事征途。", "鄉閭駕言歸，計日抵舊廬。", "春風百花老，遶屋桑柘疎。", "念無肯來人，門庭日荒蕪。", "之子獨有期，猶以雨意拘。", "人生感離合，惡懷固難舒。", "寄言我懷人，念我當焉如。"]'),
('d8b3091c-f375-4e36-a7f4-62835d369a29','度鳳凰嶺次董叔重韻','程洵','宋','宋诗','song-poetry','','[]','連山翳寒雲，孤松秀巍嶺。',48,'全唐诗/poet.song.156000.json','["連山翳寒雲，孤松秀巍嶺。", "松吟石潄水，山露髻撐頂。", "我行亦何事，歲晏苦淒冷。", "頻有同心人，哦詩味雋永。"]'),
('e6405be4-2953-4738-97e4-c1d51f43af4c','丫頭巖用前韻','程洵','宋','宋诗','song-poetry','','[]','側看初成峰，橫看復成嶺。',48,'全唐诗/poet.song.156000.json','["側看初成峰，橫看復成嶺。", "何年古仙人，飛步緩絕頂。", "至今兩髻丫，縹緲煙霞冷。", "安步躡荒遐，長嘯清夜永。"]'),
('b53983ee-6c2c-47ec-9f98-01edbcd2670e','用前韻入閩','程洵','宋','宋诗','song-poetry','','[]','風雪武夷溪，乍阿還復嶺。',48,'全唐诗/poet.song.156000.json','["風雪武夷溪，乍阿還復嶺。", "依依鴉共林，片片雲摩頂。", "山中有高士，紙帳梅花冷。", "相期從此翁，晤語冬夜永。"]'),
('481f3401-b064-4063-b69e-238499869ed0','用前韻懷兄晦翁','程洵','宋','宋诗','song-poetry','','[]','人皆樂夷塗，而憚陟崖嶺。',48,'全唐诗/poet.song.156000.json','["人皆樂夷塗，而憚陟崖嶺。", "不折彭澤腰，即摩墨氏頂。", "誰能如此翁，獨卧滄波冷。", "寂寞詩書林，優游歲年永。"]'),
('c26b0637-d1d9-48aa-b061-6dcb252409dd','同正思叔重發潭溪度梅嶺用前韻','程洵','宋','宋诗','song-poetry','','[]','山行已淒迷，而況步脩嶺。',48,'全唐诗/poet.song.156000.json','["山行已淒迷，而況步脩嶺。", "飛仙不可見，誰復撫我頂。", "懷人雲嶠長，倦憩石磴冷。", "樵斧忽丁丁，彌覺清晝永。"]'),
('1b54b02e-e1cb-4a61-90dd-e2c757d1bd52','汪節夫解官東歸賦此贈行','程洵','宋','宋诗','song-poetry','','[]','積潦卷洪落，秋容媚郊坰。',204,'全唐诗/poet.song.156000.json','["積潦卷洪落，秋容媚郊坰。", "登高望長陌，念君將有行。", "君生盛德後，家世多簪纓。", "尚書望最重，當代推名卿。", "幾年卧東山，屬望勞蒼生。", "天亦陰相之，芝蘭滿階庭。", "君子尤可人，少日負俊聲。", "曼倩聊玩世，子真豈求名。", "一官姑自慰，三歲俄終更。", "我從韓溪來，挽袂仍班荆。", "殷勤故舊意，丁寧離別情。", "聖門雖高遠，心地當恢宏。", "篤敬己可克，致知義方精。", "造次勤鑽仰，從容自規繩。", "他時立朝右，風節彌堅貞。", "江湖秋多風，歸途眼增明。", "引首看高舉，毋辭事遐征。"]'),
('0044bf83-484a-4aac-a7f7-2e7515a01db3','初發豫章','程洵','宋','宋诗','song-poetry','','[]','昨日苦暖今日寒，樹頭淅淅風聲乾。',64,'全唐诗/poet.song.156000.json','["昨日苦暖今日寒，樹頭淅淅風聲乾。", "舟師祭罷喜風便，呼兒理楫高挂帆。", "孤舟一葉去如舞，白浪翻空作飛雨。", "爾曹醉膽何大耶，胡不江雲占砲車。"]'),
('7ae81391-d3ef-48d3-9bee-674aa612483d','夜泊華家埠','程洵','宋','宋诗','song-poetry','','[]','江涵寒月明，人掩孤篷卧。',48,'全唐诗/poet.song.156000.json','["江涵寒月明，人掩孤篷卧。", "蕭蕭木末風，驚我幽夢破。", "心閑萬念寂，枕穩千波妥。", "時聞掠水聲，知有魚舠過。"]'),
('ffac84a6-cd77-4944-9608-c45035e2275b','初泛湘江','程洵','宋','宋诗','song-poetry','','[]','昔聞瀟湘好，今作瀟湘遊。',48,'全唐诗/poet.song.156000.json','["昔聞瀟湘好，今作瀟湘遊。", "雨餘萬籟息，夷猶任輕舟。", "黯黯雲幕垂，漂漂浪花浮。", "故人在何許，悵望心悠悠。"]'),
('2f3bf3ae-2bc4-410e-b19a-fda975b99bc1','送楊文父還醴陵','程洵','宋','宋诗','song-poetry','','[]','君家江西我江東，相望雖遠聲氣同。',64,'全唐诗/poet.song.156000.json','["君家江西我江東，相望雖遠聲氣同。", "一行作吏湖湘上，數面成親談笑中。", "君思松竹行色動，我困簿領蜚塵蒙。", "他時登高倘有賦，莫望江頭回鴈峰。"]'),
('1366e17c-431d-417c-85d0-a9a32e40ef29','送陳求仁還永嘉兼寄劉孝移','程洵','宋','宋诗','song-poetry','','[]','往年予□祁山丞，坐上屢聞君姓名。',160,'全唐诗/poet.song.156000.json','["往年予□祁山丞，坐上屢聞君姓名。", "那知流落天一角，一笑共挹湘江清。", "地緜賦急員羞具，黄龔遐軌空馳溯。", "催科撫字兩勤勞，古道羨君今獨步。", "耒陽之水化理濡，耒陽之人何于于。", "疎梧細柳白日浄，唯有聲氣與君俱。", "君今快展摩天翮，會看赤手扶羲御。", "煙波渺渺正愁予，萬里瀟湘未歸去。", "河陽當日桃花紅，主人好客樽不空。", "相逢倘問衡陽簿，爲說年來惟悴容。"]'),
('3738b513-08bb-48b1-ae5c-7c54d7cb50e1','次韻趙祖德送李衡陽有感','程洵','宋','宋诗','song-poetry','','[]','秋日曬古城，秋風來水鄉。',204,'全唐诗/poet.song.156000.json','["秋日曬古城，秋風來水鄉。", "臨流送歸客，離思飛雲揚。", "銀液深蘸甲，金釵儼分行。", "祖行禮雖微，善頌意則良。", "破涕忽成笑，欲語旋復忘。", "若人工涉世，止沸非揚湯。", "俛首是非海，如居清浄坊。", "一朝脫屣去，翩如鴈隨陽。", "三折僅存臂，九回無復腸。", "所欣返全璧，詎復憂焚岡。", "我本山林人，才非錐處囊。", "偶然踏朝市，包以冠與裳。", "誰吹鄒子律，自分冰氏凉。", "餘習但文字，殘星弄微芒。", "來時岸柳綠，倏見秋葉黄。", "何當首歸途，解此名利韁。", "湖山足佳處，與君共徜徉。"]'),
('d5eebab6-059c-4907-8279-691e0a172703','謁杜子美祠','程洵','宋','宋诗','song-poetry','','[]','少年誦公詩，諷詠忘日夕。',240,'全唐诗/poet.song.156000.json','["少年誦公詩，諷詠忘日夕。", "晚爲湖外遊，適有耒陽役。", "仙人梅子真，邀我連轡策。", "蒼山環古城，幽路轉石壁。", "叢祠隠木末，古冢纍道側。", "衣冠尚唐制，金石存古刻。", "緬懷天寶年，綱紀絲棼劇。", "肅代雖中興，安史互攘賊。", "風雲暗宇宙，蛇豕莽區域。", "生靈困魚爛，廊廟鄙肉食。", "崎嶇兵戎閒，公亦屢顛踣。", "時危孰與持，忠憤氣彌激。", "烱烱心懷丹，蕭蕭髮垂白。", "興來謾吟哦，賦罷還歎息。", "區區杞人憂，此意誰復測。", "至今杜陵編，義與風雅敵。", "人亡遺像在，廟古爐香寂。", "庭花日日紅，階草年年碧。", "公身不可見，公心猶可識。", "惟餘耒陽流，與君共無極。"]'),
('ce242c46-ed8b-449e-ac08-655ebc807c0c','潘提刑生日四首用以介眉壽爲韻  其一','程洵','宋','宋诗','song-poetry','','[]','泉以沙故渾，草以風故靡。',48,'全唐诗/poet.song.156000.json','["泉以沙故渾，草以風故靡。", "誰能表獨出，屹若柱立砥。", "先生抱懿德，取喻當奚以。", "孤高衡嶽松，清潤湘江水。"]'),
('3f260830-8c70-4db4-9e11-3a67d95c8129','潘提刑生日四首用以介眉壽爲韻  其二','程洵','宋','宋诗','song-poetry','','[]','華堂敞千楹，居者嫌陋隘。',48,'全唐诗/poet.song.156000.json','["華堂敞千楹，居者嫌陋隘。", "安知圜扉中，蟣蝨生杻械。", "先生慮囚時，矜測逮鮮介。", "此心即天心，不爲門閭大。"]'),
('dae6b320-3f1f-4fd8-9bac-b564c4743238','潘提刑生日四首用以介眉壽爲韻  其三','程洵','宋','宋诗','song-poetry','','[]','天心本廣大，有外寧合之。',48,'全唐诗/poet.song.156000.json','["天心本廣大，有外寧合之。", "咄哉吝驕者，妄自分町畦。", "先生克己學，不起一念私。", "斯道愈光新，渠用夸揚眉。"]'),
('1f3116fa-bb0b-48b8-9047-d5fb31a11e82','潘提刑生日四首用以介眉壽爲韻  其四','程洵','宋','宋诗','song-poetry','','[]','賢者必得貴，仁者必得壽。',48,'全唐诗/poet.song.156000.json','["賢者必得貴，仁者必得壽。", "天人何閒然，如契鑰相受。", "先生邁種德，無覬報自厚。", "應笑昌黎翁，區區說南斗。"]'),
('94c099bb-abea-4733-a2fd-57249505cfd9','遊獅子巖','程洵','宋','宋诗','song-poetry','','[]','南州風氣殊，二月若中夏。',168,'全唐诗/poet.song.156000.json','["南州風氣殊，二月若中夏。", "我從耒江來，無地稅征駕。", "縈紆躡蘚徑，問訊得精舍。", "石崖屹傍起，峭壁儼難跨。", "嵌巖忽中閒，宛宛如覆瓦。", "日光何處來，返照幽以雅。", "獅猊騁其勇，踞坐頤頰哆。", "欲爲河東吼，解使百獸啞。", "應是山靈護，豈容俗人假。", "茲遊真勝絕，欲去重嗟咤。", "老僧勸少留，秉燭語清夜。", "那知巖伏情，眺玩不可舍。", "他年倘復來，陳迹猶可藉。", "巖前有隙地，分我茅一把。"]'),
('629cbc6a-0ead-454e-8bbe-a44b669f03b1','游浯溪用張宛邱韻','程洵','宋','宋诗','song-poetry','','[]','六合塵昏誰汛掃，秦王功業成橫草。',160,'全唐诗/poet.song.156000.json','["六合塵昏誰汛掃，秦王功業成橫草。", "後裔居安不慮危，欲向溫柔鄉裏老。", "漁陽金鼓動地來，羯胡本非劉石才。", "若爲二十四郡守，如振槁葉彈浮埃。", "皇天悔禍見星紀，太白入月胡當死。", "英英李郭爲時生，濟世何須識丁字。", "祅災已去瑞慶來，何人大筆書丹崖。", "南□猶自頌聲作，中天想見氛祲開。", "遺文三復堪悲慨，興廢渾如目前在。", "咄哉誤國高將軍，猶歎兩京作斤賣。"]'),
('9befbadd-ea8a-47f7-878c-0174a52f5eb0','遊東安五峰閣凜然亭','程洵','宋','宋诗','song-poetry','','[]','穹林擁精廬，奇石林端起。',132,'全唐诗/poet.song.156000.json','["穹林擁精廬，奇石林端起。", "玲瓏蛟兔穴，編綴東方齒。", "峩峩倚高寒，落落負壯偉。", "何人昔好事，誅薙發天閟。", "傑閣冠其顛，幽亭踞其趾。", "五峰天際來，縱臾供燕几。", "吾聞零陵郡，地藴清淑氣。", "法當産瑰奇，鍾秀乃在此。", "何當蠟吾屐，盡攬入胸次。", "融成九華詩，寫作菱溪記。", "却笑奇章公，班班刻名字。"]'),
('d5efc4c1-30f1-42f6-bbdb-741b53d3afb0','過愚溪登愚亭拜柳子厚像','程洵','宋','宋诗','song-poetry','','[]','我從耒陽來，已拜杜陵墓。',48,'全唐诗/poet.song.156000.json','["我從耒陽來，已拜杜陵墓。", "今行湘水湄，復識愚溪路。", "茲遊豈無益，登覽屢弔古。", "明日理扁舟，又向浯溪去。"]'),
('0941a1b0-9775-4e09-9db4-5a9ab1539f14','薛使君生日','程洵','宋','宋诗','song-poetry','','[]','春來一雨不終日，處處野田龜兆坼。',128,'全唐诗/poet.song.156000.json','["春來一雨不終日，處處野田龜兆坼。", "使君閔雨雨應期，插水新秧綠如織。", "人言秧好歲定豐，民感使君慈父同。", "生朝共上千歲壽，酒酌流霞花裊紅。", "使君爲德豈但此，念念愛民如愛子。", "陰功無數只天知，報以長年固其理。", "青衫短簿人莫知，索米不充方朔饑。", "香山松鶴舉無有，但采民言成頌詩。"]'),
('4c37944e-4545-42c8-900e-3a66ed8c5633','次韻劉子厚人日立春','程洵','宋','宋诗','song-poetry','','[]','流光馳兔烏，弱質感蒲柳。',108,'全唐诗/poet.song.156000.json','["流光馳兔烏，弱質感蒲柳。", "新年有樂事，菜羹侑甘酒。", "楚俗本自佳，顔巷敢嫌陋。", "陶然爲一醉，闊步無何有。", "畫屏貼綵人，赤牛負土偶。", "誰能效兒童，翦飾較妍醜。", "城南有佳士，避世不回首。", "詩成試問之，如此近道否。", "鈍根君勿嗤，著語不敢苟。"]'),
('ce95ea53-a0b1-455f-a328-5af33390cb9c','劉寺簿所居五詠 墨莊','程洵','宋','宋诗','song-poetry','','[]','先生耕道時，萬卷皆其具。',24,'全唐诗/poet.song.156000.json','["先生耕道時，萬卷皆其具。", "歲晚德已豐，萬卷猶如故。"]'),
('fa986d02-224a-4366-aa37-07b57a8c0407','劉寺簿所居五詠 洌軒','程洵','宋','宋诗','song-poetry','','[]','理甓完新甃，披沙挹舊清。',24,'全唐诗/poet.song.156000.json','["理甓完新甃，披沙挹舊清。", "一瓢遺味在，雋永若爲名。"]'),
('a439f408-bf52-4360-bb5e-8f0ce5f8940e','劉寺簿所居五詠 靜春堂','程洵','宋','宋诗','song-poetry','','[]','氛埃痛掃溉，鄰里謝將迎。',24,'全唐诗/poet.song.156000.json','["氛埃痛掃溉，鄰里謝將迎。", "默坐無餘念，欣欣物自榮。"]'),
('2eb8fd4a-94a6-4e1f-871d-cb0628b7de4b','劉寺簿所居五詠 玩易齋','程洵','宋','宋诗','song-poetry','','[]','萬變本六畫，六畫來何從。',24,'全唐诗/poet.song.156000.json','["萬變本六畫，六畫來何從。", "此理須玩索，明窗露未濃。"]'),
('2cde746a-7434-49f0-a616-2d6e68e70f91','劉寺簿所居五詠 君子亭','程洵','宋','宋诗','song-poetry','','[]','食藕痊沈痾，製荷被吾體。',24,'全唐诗/poet.song.156000.json','["食藕痊沈痾，製荷被吾體。", "未如對芳華，幽貞似君子。"]'),
('fc3d1b7a-d1c6-4244-bec9-639beff0f29a','次韻劉寺簿暇日出郊按視貢院安養院漏澤園南教場飯於花藥寺用韋蘇州韻賦詩','程洵','宋','宋诗','song-poetry','','[]','使君抱孤韻，勝日成獨遊。',96,'全唐诗/poet.song.156000.json','["使君抱孤韻，勝日成獨遊。", "聊循七里郭，一賞千林秋。", "射圃既徘徊，澤宮重咨疇。", "孰生病我療，孰死骨我收。", "遐觀興未窮，小憩山更幽。", "昔人事登覽，不憚道里悠。", "而我縛微官，抗塵苦淹留。", "何當奉杖屨，崇論排田騶。"]'),
('05e06271-d63a-4f80-a852-8f3741247b70','余季行肯堂','程洵','宋','宋诗','song-poetry','','[]','天地有常運，成功須四時。',180,'全唐诗/poet.song.156000.json','["天地有常運，成功須四時。", "斂藏苟不至，生養猶浪施。", "而況結夏屋，豈伊一人爲。", "向非來者賢，俯仰成棄基。", "余氏本望族，舊業祖所貽。", "流光被累葉，衍也復嗣之。", "華堂小荒茀，新築俄翬飛。", "老木傲風煙，脩篁拂雲霓。", "連峰累奇石，一鏡開清池。", "窗閒編簡橫，門外塵鞅希。", "封胡幾男子，晨夕相追隨。", "步趨朱與張，談笑書與詩。", "寧復綺紈習，所期君子歸。", "青桐韓家樹，丹桂竇氏枝。", "它年定儷美，吾言豈君欺。"]'),
('83739ec8-c72c-4d0e-9684-f39544b21198','次韻張順之見寄','程洵','宋','宋诗','song-poetry','','[]','詩翁老去百年灰，皮膚剝落真實在。',240,'全唐诗/poet.song.156000.json','["詩翁老去百年灰，皮膚剝落真實在。", "誅茅築室傍幽林，泉石煙雲動光彩。", "酸寒不作郊島態，尚友淵明向千載。", "但欣妙語筆端生，不管流年暗中改。", "鄰家有景借脩竹，野徑無風馥芳茝。", "人嫌柴門雀可羅，自倚奚囊富成海。", "我聞公名嗟已久，嚮風每恨平生昧。", "袖詩過我豈宜蒙，公才較丕幾十倍。", "要從柳州鬭雅健，未許公羊誇辨裁。", "別來又見秋風高，抵掌論文幾時再。", "尊中綠酒已堪酌，籬下黄花行可戴。", "幸無俗物惱幽人，祇可劇談佳客對。", "方侯況是社中酒，辨舌瀾翻似秦代。", "公來當爲折簡呼，園有佳蔬更同采。", "雅集何須畫作圖，風流自可追前輩。"]'),
('ab5fcc18-c805-4c33-87a2-bec827829de3','贈寫真方處士','程洵','宋','宋诗','song-poetry','','[]','世久無絕藝，斯人妙丹青。',156,'全唐诗/poet.song.156000.json','["世久無絕藝，斯人妙丹青。", "時將好東絹，貌彼神與形。", "悠然意象會，轉轉毛骨生。", "或濯若春柳，或清如壺冰。", "或聳千丈壑，或森武庫兵。", "妍媸有真鑒，抑揚無遁情。", "楚相欲談笑，中郎存典刑。", "斯人胸次奇，不以藝自名。", "逍遥萬物閒，非俗仍非僧。", "游戲於筆端，遂爾造其精。", "殊非學可致，要是天與能。", "待詔集金馬，功臣圖景靈。", "渠當自致此，胡爲老沈冥。"]'),
('dc57130d-1535-4b0c-b74e-6aa2428c6d47','留別處州陳舜卿教授以筆贈之','程洵','宋','宋诗','song-poetry','','[]','中歲探至道，頗欲齊得喪。',144,'全唐诗/poet.song.156000.json','["中歲探至道，頗欲齊得喪。", "偶然遇逆境，又爾起諸妄。", "賢哉陳夫子，胸次甚夷曠。", "警我以微言，恐我猶事障。", "嗟我與夫子，少長異州黨。", "傾蓋逆旅中，談笑便抵掌。", "誰言江浙遠，嗜好無異尚。", "我雖謬涉世，途窮理歸鞅。", "而君方朝天，高論獻忠讜。", "贈君秋兔毫，聊以代盃盎。", "勿云管城子，未有食肉相。", "當知中書君，日侍九天上。"]'),
('92af8597-ec5f-44f2-89f8-6ca1ae373b8a','董銖求詩賦古風二章示之  其一','程洵','宋','宋诗','song-poetry','','[]','森森山上松，濯濯堂前柳。',48,'全唐诗/poet.song.156000.json','["森森山上松，濯濯堂前柳。", "顔色雖不殊，霜餘別妍醜。", "君看射利子，榮悴俯仰中。", "寧知堂前柳，不如山上松。"]'),
('af87b19a-d61f-45f8-8295-04b66f72a2c7','董銖求詩賦古風二章示之  其二','程洵','宋','宋诗','song-poetry','','[]','學海失淵源，詞林少根柢。',48,'全唐诗/poet.song.156000.json','["學海失淵源，詞林少根柢。", "蘇程百世師，遺書滿天地。", "遺書亦言爾，道豈言能傳。", "言外有妙處，萬理常森然。"]'),
('fd4f9d11-05a1-4d7f-92e8-58b6b61cfb41','張衡州南山壽芝','程洵','宋','宋诗','song-poetry','','[]','煌煌慶色金壺重，婉婉高枝兒臂拱。',208,'全唐诗/poet.song.156000.json','["煌煌慶色金壺重，婉婉高枝兒臂拱。", "團團更著綫暈紅，鬰鬰時看祥靄動。", "使君少日抱奇才，可與斯世作楹棟。", "黄堂坐嘯晚方貴，急流引退心殊勇。", "平生陰德只天知，壽骨巉然天所縱。", "靈華更向壽宮出，和氣疑與商山共。", "翻嫌四老太多事，采掇辛勤走巖隴。", "何如邱壑著胸中，靜閲世氛如幻夢。", "朝餐不用閑草木，夜氣自有真鉛汞。", "殊祥坐使神物效，異卉不煩天女供。", "閑中禪悅更尋源，閙裏塵緣徐脫鞚。", "從渠童子尚饒舌，强出松陰談谷董。", "要知無本是性宗，看我當機呈大用。"]'),
('2974e8cd-5615-4e75-96cf-236ac94e4969','過鉛山望鵝湖峰次叔重韻','程洵','宋','宋诗','song-poetry','','[]','好山如高人，堂堂萬夫傑。',84,'全唐诗/poet.song.156000.json','["好山如高人，堂堂萬夫傑。", "嶽立培塿中，千古磨不滅。", "茲山雖未高，濃淡似粧抹。", "樹老樛枝重，石皴靈液洌。", "登臨恨未能，想像心已豁。", "寄言山中客，慎勿厭幽絕。", "君看名利途，黄塵漲日月。"]'),
('086a8ae0-26e7-4a2e-a7b3-e439d5141029','宿野人家追和韋齋韻','程洵','宋','宋诗','song-poetry','','[]','澆愁正頼一蕉葉，萬慮洗空從兀兀。',64,'全唐诗/poet.song.156000.json','["澆愁正頼一蕉葉，萬慮洗空從兀兀。", "投牀便作碖䃂眠，不記來時石頭滑。", "茅家亦復有何好，門外澄江綠如鴨。", "箇中風味吾自知，賦詩歸向兒曹說。"]'),
('eb5e6a1c-9e28-4ee1-818f-19fcc72f34db','游石鼓次柯德初韻','程洵','宋','宋诗','song-poetry','','[]','簿書塵涴人，高士莫肯顧。',288,'全唐诗/poet.song.156000.json','["簿書塵涴人，高士莫肯顧。", "我窮敢言高，餬口隨所遇。", "一遭猿鶴嗔，詎能蟲魚注。", "讀禮尺不盈，披易體忘互。", "案惟朱墨塵，吏執符移付。", "催科本雖拙，勉强亦備數。", "有時迅檄來，又辦走長路。", "名山謾在眼，俗駕不容駐。", "茲遊豈無意，發興亦已屢。", "心知江山奇，遠目當與寓。", "冠裳裹病軀，汲汲忘旦暮。", "今日復何日，從君舉幽步。", "柳深尚藏烏，水淺可立鷺。", "離離網舉魚，隠隠舟橫渡。", "登臨得勝地，一覽萬景聚。", "況遠城市喧，無復塵埃污。", "六籍爛星羅，百氏紛雲布。", "窗虛明照人，几浄寒生霧。", "仰止夫子堂，敬誦昌黎句。", "文章何足言，道義有真趣。", "由來重儒學，所貴通世務。", "恨我拙且迂，浪奉先生屨。", "明朝九衢塵，回道迹已故。", "重來定何時，詩就髮如素。"]'),
('b618dced-74be-4f3b-8e0c-95748a3eeeab','次韻劉寺簿與客酌酃泉','程洵','宋','宋诗','song-poetry','','[]','庭無聚訟喧，門有佳客至。',48,'全唐诗/poet.song.156000.json','["庭無聚訟喧，門有佳客至。", "登高一以眺，天末鴈橫字。", "公心本無著，佳處偶會意。", "意會旋已忘，陶然不妨醉。"]'),
('084a9d82-e1ad-4c3f-b701-efd7282aa1ec','幽閨','程洵','宋','宋诗','song-poetry','','[]','幽閨有美人，終宵抱長歎。',48,'全唐诗/poet.song.156000.json','["幽閨有美人，終宵抱長歎。", "念彼遠征客，風露如許寒。", "耿耿不成寐，悵然理哀彈。", "離鸞韻纖指，曲終淚闌桿。"]'),
('c1b6d617-b383-4db6-a680-365ae1830482','秋風','程洵','宋','宋诗','song-poetry','','[]','秋風來幾日，草木殊未知。',48,'全唐诗/poet.song.156000.json','["秋風來幾日，草木殊未知。", "寒蟲獨何者，若與秋有期。", "露竹動寒彩，雲松弄幽姿。", "夢尋溪頭路，意行當何時。"]'),
('7075aef3-4d37-4eb1-a00f-5ad989cf24a1','次韻胡國器游歷崌','程洵','宋','宋诗','song-poetry','','[]','枯筇挂倒星斗傍，意行屈曲忘陵岡。',96,'全唐诗/poet.song.156000.json','["枯筇挂倒星斗傍，意行屈曲忘陵岡。", "忽逢蕭寺倚巖腹，門前水影涵山光。", "憑虛飄欲上霄漢，覽遠浩如浮大滄。", "嗟子失身墜世網，恨不與子同翺翔。", "白蓮共結清浄社，紅裙絕意溫柔鄉。", "何當脫屣聲利場，從渠萬態爭炎涼。"]'),
('6742db65-fe7e-44ad-95f1-84bce8b89ba8','次韻答唐卿歎梅','程洵','宋','宋诗','song-poetry','','[]','玄冥玄冥如有辭，大鈞播物初無私。',64,'全唐诗/poet.song.156000.json','["玄冥玄冥如有辭，大鈞播物初無私。", "春蘭秋菊亦有爾，梅獨强分南北枝。", "南枝北枝自有時，人言冷暖浪自欺。", "天公與人不相似，時來看取葭灰吹。"]'),
('6cd57477-f23f-44ca-8590-8c290c31d6c1','黄彥周求秀亭詩云其地山水合六秀法故以名亭','程洵','宋','宋诗','song-poetry','','[]','少年銳意功名會，李廣數奇終鷁退。',128,'全唐诗/poet.song.156000.json','["少年銳意功名會，李廣數奇終鷁退。", "晚從林下得幽棲，綠浄翠微動賞對。", "危亭蕭灑八九椽，千巖萬壑相迴環。", "人言山秀水亦秀，偶然得此寧非天。", "身世區區如逆旅，人生要有歸全處。", "天星地卦且置之，陰德從來不知數。", "會當置酒傍清樾，一語壽君君笑發。", "且住人閒五百年，銜盃樂聖山水閒。"]'),
('0bb9bd2a-c9a1-4cde-a01b-6e0b961c11cf','張公成生日','程洵','宋','宋诗','song-poetry','','[]','沒膝春泥未易過，華堂咫尺隔關河。',64,'全唐诗/poet.song.156000.json','["沒膝春泥未易過，華堂咫尺隔關河。", "精神聞說年來健，歲月從渠老去多。", "閙裏漸應排世事，靜中正好養天和。", "祝君壽骨如張果，莫惜頻傾金叵羅。"]'),
('f7c69eb9-d368-499f-b367-7925ff897a48','梅花','程洵','宋','宋诗','song-poetry','','[]','落木蕭蕭歲已深，天教梅蕊獨爭新。',64,'全唐诗/poet.song.156000.json','["落木蕭蕭歲已深，天教梅蕊獨爭新。", "一枝嶺上方傳恨，千樹江頭忽暗春。", "會與霜筠矜節概，不同風柳鬭腰身。", "羅浮當日醉眠起，斗轉參橫誰與鄰。"]'),
('02425416-b10e-4b6e-becf-66c4d057ec5d','贈劉道人兼送何蕃秀才東歸','程洵','宋','宋诗','song-poetry','','[]','道人別我三年久，邱壑胸中趣益真。',64,'全唐诗/poet.song.156000.json','["道人別我三年久，邱壑胸中趣益真。", "更與風流能賦客，來尋憔悴負痾人。", "明窗辨藥分寒燥，清夜吟詩動鬼神。", "促膝方歡又分袂，別愁還與月痕新。"]'),
('0e94d1f6-cc31-48ae-8249-20e6b36a6636','兆察道中','程洵','宋','宋诗','song-poetry','','[]','偶作郊原十里行，蕭蕭入袂晚風清。',32,'全唐诗/poet.song.156000.json','["偶作郊原十里行，蕭蕭入袂晚風清。", "夕陽疎樹無佳處，只有殘鴉自在鳴。"]'),
('aba63484-b6b8-427d-bc93-23d4c145e59b','送張子有彥實舍人之姪','程洵','宋','宋诗','song-poetry','','[]','宴居仙伯已騎鯨，猶子東來尚典刑。',64,'全唐诗/poet.song.156000.json','["宴居仙伯已騎鯨，猶子東來尚典刑。", "才氣逼人春盎盎，交情閲世柏青青。", "昨朝方對聖賢酒，今日又尋長短亭。", "歸路不妨携古錦，萱叢菖葉正芳馨。"]'),
('7d365ee4-9c79-4ecd-b49a-b5dc05baffcd','寄朱德芳','程洵','宋','宋诗','song-poetry','','[]','武林倉卒指歸程，千里脩途偶並行。',64,'全唐诗/poet.song.156000.json','["武林倉卒指歸程，千里脩途偶並行。", "雲散風流當日事，山長水遠此時情。", "棲遲顧我猶藏拙，邂逅煩君尚寄聲。", "尺素聊憑西去鴈，夢魂今夜遶江城。"]'),
('668e5a53-6af9-409c-9b52-ef07e536ac67','久雨初霽示友','程洵','宋','宋诗','song-poetry','','[]','積雨初收四望新，頹雲淡日弄晴陰。',64,'全唐诗/poet.song.156000.json','["積雨初收四望新，頹雲淡日弄晴陰。", "故園百里夢不到，杜宇一聲春又深。", "宿蝶亂紅渾滿地，藏鴉新綠已成林。", "客中情味君休問，莊舄無聊但越吟。"]'),
('33c0951d-fcf3-4fc4-9769-138e5b71ca4b','楊日新闢書室以月壺榜之求詩  其一','程洵','宋','宋诗','song-poetry','','[]','清透虛簷冷侵空，下弦祝罷且從容。',32,'全唐诗/poet.song.156000.json','["清透虛簷冷侵空，下弦祝罷且從容。", "是中自有一天地，何必更登天柱峰。"]'),
('d8c07089-5bd8-451b-b30f-646407cd3d64','楊日新闢書室以月壺榜之求詩  其二','程洵','宋','宋诗','song-poetry','','[]','此郎表裏久融明，胸次悠然冰玉清。',32,'全唐诗/poet.song.156000.json','["此郎表裏久融明，胸次悠然冰玉清。", "虛室如今已生白，不隨晦望有虧盈。"]'),
('ab1a8ab7-46a9-4c91-a8ab-1721ae105391','張巨川爲父慶八十二邀予與坐作詩壽之  其一','程洵','宋','宋诗','song-poetry','','[]','龜形鶴骨舊精神，見了春容幾度新。',32,'全唐诗/poet.song.156000.json','["龜形鶴骨舊精神，見了春容幾度新。", "却笑當年梁祕監，更將多少較前人。"]'),
('36c00b7f-dda7-4dc0-8514-ef77ed2b9af0','張巨川爲父慶八十二邀予與坐作詩壽之  其二','程洵','宋','宋诗','song-poetry','','[]','官爲秦世柱下史，生憶堯時丙子年。',32,'全唐诗/poet.song.156000.json','["官爲秦世柱下史，生憶堯時丙子年。", "家世從前多壽骨，侯封不必羨神仙。"]'),
('d5d98707-50f1-4f7f-8b23-4ea4217f2e7f','示伯羽  其一','程洵','宋','宋诗','song-poetry','','[]','交遊半作摶沙散，不見周郎亦四春。',32,'全唐诗/poet.song.156000.json','["交遊半作摶沙散，不見周郎亦四春。", "邂逅相逢無一事，依然都似舊時貧。"]'),
('c0719a89-82a3-4105-818f-7effe7b4d1ce','示伯羽  其二','程洵','宋','宋诗','song-poetry','','[]','偃蹇我如蛙伏井，飄零君似鵲尋枝。',32,'全唐诗/poet.song.156000.json','["偃蹇我如蛙伏井，飄零君似鵲尋枝。", "回頭十二年前事，一笑那能似彼時。"]'),
('4d9a47e5-8a83-499d-ab24-8f1b04f5bf34','次唐卿九日','程洵','宋','宋诗','song-poetry','','[]','無錢薄酒自難賒，笑解塵衣到酒家。',32,'全唐诗/poet.song.156000.json','["無錢薄酒自難賒，笑解塵衣到酒家。", "只欠道人殷七七，鶴林重發杜鵑花。"]'),
('543b8ed0-43a1-4c1a-baff-6222c9e9e3b3','祈山九日','程洵','宋','宋诗','song-poetry','','[]','客思到秋如亂麻，每逢佳節倍思家。',64,'全唐诗/poet.song.156000.json','["客思到秋如亂麻，每逢佳節倍思家。", "黄花只作去年好，綠鬢自嫌今歲華。", "千里有情猶共月，一樽無事且傾霞。", "閑來甘露堂前坐，老柳條條噪暮鴉。"]'),
('4038d73e-3b4d-4705-adec-2ad2951905d4','陪晦庵尊兄山行小憩龍居院','程洵','宋','宋诗','song-poetry','','[]','平生發興在林邱，況復追隨長者遊。',64,'全唐诗/poet.song.156000.json','["平生發興在林邱，況復追隨長者遊。", "路入亂山青未了，秧分野水綠初稠。", "劇談已有親朋樂，小憩仍逢寺宇幽。", "滿座春風與和氣，對公無地可言愁。"]'),
('bae5a08e-10f7-435a-851a-e1fc75adb717','用韻送蔡季通還建安','程洵','宋','宋诗','song-poetry','','[]','騎氣居然兩月留，勝遊不減舞雩遊。',64,'全唐诗/poet.song.156000.json','["騎氣居然兩月留，勝遊不減舞雩遊。", "道同頓覺語易契，意合不知情自稠。", "□□還驚千里遠，著鞭又踏萬山幽。", "恨無力挽天河水，爲我臨歧洗別愁。"]'),
('60fdc698-5886-46db-958b-86b1042e0617','次韻喜雨','程洵','宋','宋诗','song-poetry','','[]','敲窗打葉不勝繁，洗盡黄塵萬里昏。',64,'全唐诗/poet.song.156000.json','["敲窗打葉不勝繁，洗盡黄塵萬里昏。", "便有清風生遠樹，祇牽孤夢遶歸村。", "新秔想見黄堆野，老柳猶能綠映門。", "自笑年來詩事廢，得君强韻縮肩跟。"]'),
('a899bd54-98d1-41cf-b10a-62ca5aeb601f','雨中書事  其一','程洵','宋','宋诗','song-poetry','','[]','門無去馬與來車，終日塵編自展舒。',32,'全唐诗/poet.song.156000.json','["門無去馬與來車，終日塵編自展舒。", "笑撫蒲團時有會，古人於我未全疎。"]'),
('ee881f07-b79a-4b5a-a231-57ae47041665','雨中書事  其二','程洵','宋','宋诗','song-poetry','','[]','經邱久已罷巾車，寄傲南窗意自舒。',32,'全唐诗/poet.song.156000.json','["經邱久已罷巾車，寄傲南窗意自舒。", "一炷妙香清萬慮，芭蕉葉上雨疎疎。"]'),
('09b1821e-94a8-4b83-922b-03ebcbc321d6','予甲戌歲與惠州麥少韓始相會於都下後十九年復會焉今又六年而少韓見予益勤將東歸爲詩四章以別  其一','程洵','宋','宋诗','song-poetry','','[]','邂逅京華憶昔時，匆匆長恨遽暌離。',32,'全唐诗/poet.song.156000.json','["邂逅京華憶昔時，匆匆長恨遽暌離。", "重來只有聲音在，兩鬢蕭蕭各欲絲。"]'),
('930a2c21-4ccb-4259-9186-df267317cf2b','予甲戌歲與惠州麥少韓始相會於都下後十九年復會焉今又六年而少韓見予益勤將東歸爲詩四章以別  其二','程洵','宋','宋诗','song-poetry','','[]','與君南北昧平生，傾蓋論心若弟兄。',32,'全唐诗/poet.song.156000.json','["與君南北昧平生，傾蓋論心若弟兄。", "長笑區區市朝客，白頭重欲定交情。"]'),
('e90ef942-9b42-432e-9844-145fbf64182f','予甲戌歲與惠州麥少韓始相會於都下後十九年復會焉今又六年而少韓見予益勤將東歸爲詩四章以別  其三','程洵','宋','宋诗','song-poetry','','[]','鼻祖功名冠有隋，耳孫筆力近京西。',32,'全唐诗/poet.song.156000.json','["鼻祖功名冠有隋，耳孫筆力近京西。", "鵝城勿作潛深計，鴈塔行看高處題。"]'),
('a9869b8e-7120-4950-a5a9-4082c77a9696','予甲戌歲與惠州麥少韓始相會於都下後十九年復會焉今又六年而少韓見予益勤將東歸爲詩四章以別  其四','程洵','宋','宋诗','song-poetry','','[]','人去空山鎖碧雲，紙窗竹屋尚明深。',32,'全唐诗/poet.song.156000.json','["人去空山鎖碧雲，紙窗竹屋尚明深。", "蒼珉遺刻煩多寄，慰我平生敬慕心。"]'),
('639d3085-ccb8-4a1a-948e-a5e6497aa9f1','次韻張順之春日雜詩  其一','程洵','宋','宋诗','song-poetry','','[]','解事東皇自有期，今年春較去年遲。',32,'全唐诗/poet.song.156000.json','["解事東皇自有期，今年春較去年遲。", "未教紅著桃開臉，先放青還柳作眉。"]'),
('b89b7949-d864-420c-bb59-4a0f06202337','次韻張順之春日雜詩  其二','程洵','宋','宋诗','song-poetry','','[]','春來何物不熙熙，川泳雲飛各自奇。',32,'全唐诗/poet.song.156000.json','["春來何物不熙熙，川泳雲飛各自奇。", "趁隊魚兒如得意，窺人燕子似相欺。"]'),
('90f59147-8ce6-43cd-9851-f4fcd616c49c','次韻張順之春日雜詩  其三','程洵','宋','宋诗','song-poetry','','[]','閑齋人靜日方中，想見先生睡思濃。',32,'全唐诗/poet.song.156000.json','["閑齋人靜日方中，想見先生睡思濃。", "只麽賞情殊有味，趁衙雜沓任黄蜂。"]'),
('64ad1f94-dd0f-425f-aa25-50ec64870ad0','次韻張順之春日雜詩  其四','程洵','宋','宋诗','song-poetry','','[]','烱烱朝曦暖意囘，遲遲午景氣佳哉。',32,'全唐诗/poet.song.156000.json','["烱烱朝曦暖意囘，遲遲午景氣佳哉。", "柳陰纔逐斜陽去，花影還隨皓月來。"]'),
('4464843f-d890-4bb2-b317-593906400977','次韻張順之春日雜詩  其五','程洵','宋','宋诗','song-poetry','','[]','沈水燒殘日未西，舊書讀罷卷重披。',32,'全唐诗/poet.song.156000.json','["沈水燒殘日未西，舊書讀罷卷重披。", "傍人欲識閑中趣，看取先生宴坐時。"]'),
('13493e0a-0557-4552-8ca6-0cbec759bec5','寄張順之','程洵','宋','宋诗','song-poetry','','[]','踏遍危途興已闌，倦飛幽鳥故知還。',64,'全唐诗/poet.song.156000.json','["踏遍危途興已闌，倦飛幽鳥故知還。", "手開高士蓬蒿徑，坐對先生苜蓿盤。", "□□揶揄遭點鬼，却羞矍鑠據征鞍。", "侯封到底輸千首，圓美當□似彈丸。"]'),
('ebd9eac1-6b7b-40b2-ac4e-b9a10bf9dcc4','次韻順之見寄','程洵','宋','宋诗','song-poetry','','[]','梅子垂垂雨復晴，田歌初報罷春耕。',64,'全唐诗/poet.song.156000.json','["梅子垂垂雨復晴，田歌初報罷春耕。", "敲門忽有詩筒至，入手懸知句法精。", "應聘申公何日去，草玄揚子幾時成。", "知君不樂盃中物，事業端期身後名。"]'),
('b95cfd5d-0d2e-4656-84d2-e8ed26f7ed57','中秋夜久方見月','程洵','宋','宋诗','song-poetry','','[]','此夕清光本自多，不勞玉斧更礲磨。',64,'全唐诗/poet.song.156000.json','["此夕清光本自多，不勞玉斧更礲磨。", "祇應雲物偶如此，未愜詩情可奈何。", "喜見一輪還舊觀，遥知千斛費明河。", "先生賞罷渾無事，古井依然湛不波。"]'),
('4d8c7cd8-a2c0-486c-9438-10f40cb20500','次韻楊日新出郊尋桂乃有送者','程洵','宋','宋诗','song-poetry','','[]','月窟移來幾換星，幽人何處得繁英。',64,'全唐诗/poet.song.156000.json','["月窟移來幾換星，幽人何處得繁英。", "行尋十里不知遠，歸傍一窗相對清。", "未與□兄較標格，且邀松友定交情。", "歲寒正爾團霜露，尚有蒼蒼照眼明。"]'),
('b15cf8b7-5267-4fe1-aa60-653e1c280514','次韻日新九日書事','程洵','宋','宋诗','song-poetry','','[]','登高不惜躡凌兢，樂此佳辰古所名。',64,'全唐诗/poet.song.156000.json','["登高不惜躡凌兢，樂此佳辰古所名。", "白墮從今無遠寄，黄花依舊弄秋榮。", "霜凋萬木天地肅，水落百川波浪平。", "更喜晚來風力軟，戀頭破帽亦多情。"]'),
('a9baad08-aa78-41a8-807e-a5a3541a78ab','崇安道中','程洵','宋','宋诗','song-poetry','','[]','田如累級登高堂，石如金華卧羣羊。',64,'全唐诗/poet.song.156000.json','["田如累級登高堂，石如金華卧羣羊。", "上梅下梅山路惡，大將小將溪流長。", "振衣欲度分水嶺，回首尚憶楊家莊。", "折花恨不逢驛使，爲寄一枝還紫陽。"]'),
('9e9b4a62-4811-43e5-9e62-ab9fe842376b','過分水嶺','程洵','宋','宋诗','song-poetry','','[]','相與振衣千仞岡，浩歌莫惜邱徜徉。',64,'全唐诗/poet.song.156000.json','["相與振衣千仞岡，浩歌莫惜邱徜徉。", "風來閩徼不知遠，山接吳天如許長。", "裘敝且將雲作氅，囊羞猶可墨如莊。", "眼明更向西南望，依約家林傍夕陽。"]'),
('560a006a-6174-4e50-be45-e7299a7e1617','道傍人家瓶梅正思命賦詩','程洵','宋','宋诗','song-poetry','','[]','茅舍疎籬古道傍，一枝的皪爲誰芳。',32,'全唐诗/poet.song.156000.json','["茅舍疎籬古道傍，一枝的皪爲誰芳。", "壺中春色從來別，冷落全勝白玉堂。"]'),
('89923e94-f579-4119-9674-82bc78c685be','鉛山道中次叔重韻','程洵','宋','宋诗','song-poetry','','[]','煙翠空濛撲遠林，氛埃那復犯靈襟。',32,'全唐诗/poet.song.156000.json','["煙翠空濛撲遠林，氛埃那復犯靈襟。", "歸程不恨風霜惡，自有梅花識此心。"]'),
('e0b22509-300e-4e04-b865-15da09dab5a4','瀏口山巖','程洵','宋','宋诗','song-poetry','','[]','牛羊久已下，行李尚匆匆。',48,'全唐诗/poet.song.156000.json','["牛羊久已下，行李尚匆匆。", "天挂新蟾白，山連野燒紅。", "問途愁店遠，沽酒歎囊空。", "猶喜家山近，籃輿曉又東。"]'),
('c9b409f1-a2db-4a33-bc16-3f6e319138dc','和正思贈別','程洵','宋','宋诗','song-poetry','','[]','同途欣得友，欲別惜分襟。',48,'全唐诗/poet.song.156000.json','["同途欣得友，欲別惜分襟。", "去路無多遠，離觴不厭深。", "遊鱗尋舊壑，倦翼带歸音。", "有底淒涼甚，風霜攪客心。"]'),
('cdd161ab-d422-41df-a04a-35d593d01b3a','次董叔重贈別','程洵','宋','宋诗','song-poetry','','[]','波光草色照人明，別意幽懷酒一傾。',64,'全唐诗/poet.song.156000.json','["波光草色照人明，別意幽懷酒一傾。", "飄泊君方驚旅夢，淹留我遂識人情。", "穿沙碧幹娟娟浄，带雨幽葩豔豔榮。", "何日相從溪上路，臨流倚策話平生。"]'),
('d9e293b2-7a22-46d3-86d7-afff92645571','次韻祖德九日','程洵','宋','宋诗','song-poetry','','[]','黄花歲歲與秋期，又見登高落帽時。',64,'全唐诗/poet.song.156000.json','["黄花歲歲與秋期，又見登高落帽時。", "雲水光中孤賞翫，簿書叢裏足棲遲。", "大篇且對玉連瑣，小酌何須金屈卮。", "只恐頹簷并敗屋，不禁巽二恣狂吹。"]'),
('445f4117-6ff4-40f2-97f9-6feaa2f80688','曉行湘岸竹閒有懷家山','程洵','宋','宋诗','song-poetry','','[]','琅玕萬箇倚江湘，中有人家類辟疆。',64,'全唐诗/poet.song.156000.json','["琅玕萬箇倚江湘，中有人家類辟疆。", "地迥自應塵不到，天開初見日舒光。", "此身汩汩五斗役，舊隠遥遥三徑荒。", "想見韓溪溪上路，煙稍雨葉拂雲長。"]'),
('b1d333ba-0430-429e-9668-8bd7914c5b2d','湘岸道中','程洵','宋','宋诗','song-poetry','','[]','按行又復到江干，近水遥山照眼寒。',32,'全唐诗/poet.song.156000.json','["按行又復到江干，近水遥山照眼寒。", "從此瀟湘在胸次，不須更向畫圖看。"]'),
('75379d3f-5ed7-4ed4-9355-913f65903323','渡湘江','程洵','宋','宋诗','song-poetry','','[]','萬頃澄瀾碧玉寬，笑乘一葉自輕安。',32,'全唐诗/poet.song.156000.json','["萬頃澄瀾碧玉寬，笑乘一葉自輕安。", "綠蓑從此關心事，待向煙林乞釣竿。"]'),
('9d7c49b6-d894-4abe-a623-6c2fda3ab7d0','白竹橋','程洵','宋','宋诗','song-poetry','','[]','向來過此日流金，今日重來雪滿林。',32,'全唐诗/poet.song.156000.json','["向來過此日流金，今日重來雪滿林。", "輕棄簞瓢貪斗粟，區區奔走愧初心。"]'),
('bdb4a3be-7b55-469f-9d41-afbaa080e2e3','寒溪','程洵','宋','宋诗','song-poetry','','[]','溪名偶與故鄉同，恍覺家山在眼中。',32,'全唐诗/poet.song.156000.json','["溪名偶與故鄉同，恍覺家山在眼中。", "定自今宵更愁絕，又飛清夢過江東。"]'),
('19792557-7fd8-40ef-8bdd-9cc7bdf14b2b','過沙木橋懷趙公南','程洵','宋','宋诗','song-poetry','','[]','沙木橋頭野老家，又來㢮檐酌流霞。',32,'全唐诗/poet.song.156000.json','["沙木橋頭野老家，又來㢮檐酌流霞。", "坐中只欠當時客，欲寄南枝一兩花。"]'),
('21dd1cd3-137d-4d06-ac1a-2b90735f1913','道傍見牛舐犢有感','程洵','宋','宋诗','song-poetry','','[]','人物本來同一原，於何却作兩般看。',32,'全唐诗/poet.song.156000.json','["人物本來同一原，於何却作兩般看。", "祇應氣質生時異，差別從茲有萬端。"]'),
('f93b48ba-5cad-450f-8a93-bc54067d4385','泊高安市上夜雪','程洵','宋','宋诗','song-poetry','','[]','柏山高卧有餘清，我坐高安似凍蠅。',32,'全唐诗/poet.song.156000.json','["柏山高卧有餘清，我坐高安似凍蠅。", "却喜明朝添偉觀，峩峩千里踏層冰。"]'),
('f7cd5454-7838-4308-aacf-410021a044c7','三月九日祁陽舟中聞鵑憶去年此日到衡陽有感','程洵','宋','宋诗','song-poetry','','[]','急槳輕舟下碧瀾，歸心切切隴頭鵑。',32,'全唐诗/poet.song.156000.json','["急槳輕舟下碧瀾，歸心切切隴頭鵑。", "人生石火光中住，又向湖南過一年。"]'),
('b0317cb5-1cb7-42af-8a65-5f4218796232','次韻劉寺簿臨蒸精舍落成','程洵','宋','宋诗','song-poetry','','[]','濂溪當日起南方，千載斯文有耿光。',64,'全唐诗/poet.song.156000.json','["濂溪當日起南方，千載斯文有耿光。", "遺俗至今尊孔孟，後生誰肯學蘇張。", "賢關莫歎吳天遠，精舍今臨楚水長。", "試問坐中誰鼓瑟，舞雩風味想難忘。"]'),
('adaac9d8-648a-4db5-af60-3e970a90395f','再用韻','程洵','宋','宋诗','song-poetry','','[]','斯文從昔患多方，今日因公晦復光。',64,'全唐诗/poet.song.156000.json','["斯文從昔患多方，今日因公晦復光。", "心法祇傳書一卷，文華那用紙千張。", "窗前草色沿階翠，川上波流極目長。", "此意更須公指示，後來□□月無忘。"]'),
('03eff657-a387-40e3-bfe0-ecf54b7cc6ce','用韻題諸葛武侯祠二首  其一','程洵','宋','宋诗','song-poetry','','[]','羣雄逐鹿走迷方，四百炎精不復光。',64,'全唐诗/poet.song.156000.json','["羣雄逐鹿走迷方，四百炎精不復光。", "天啟奇才思蟄奮，人嗔黠虜久鴟張。", "悠悠陳迹青編在，寂寂叢祠碧草長。", "成敗由來難逆覩，祇應大義不容忘。"]'),
('58696225-7e81-4b1c-abf7-9166ce146f92','用韻題諸葛武侯祠二首  其二','程洵','宋','宋诗','song-poetry','','[]','獨明大義曉多方，烱烱精忠貫日光。',64,'全唐诗/poet.song.156000.json','["獨明大義曉多方，烱烱精忠貫日光。", "開拓荆榛資蜀漢，驅除鬼蜮老關張。", "司徒豈足知邪正，著作寧能識短長。", "公論到頭須後世，至今尸祝未能忘。"]'),
('95e7d866-6cdd-437f-94fb-bbbebd216c4d','次韻劉寺簿詣學','程洵','宋','宋诗','song-poetry','','[]','衡湘山水競清雄，閒氣曾生益代翁。',64,'全唐诗/poet.song.156000.json','["衡湘山水競清雄，閒氣曾生益代翁。", "後學誰能明絕學，遺風猶可想高風。", "欲求太極精微藴，可乏羣居講究功。", "飛躍鳶魚元有道，使君心與古人同。"]'),
('4d5bd84b-e09f-453d-9aa0-996c07992b42','次韻劉寺簿鹿鳴宴','程洵','宋','宋诗','song-poetry','','[]','江頭梅蕊小裝春，式宴嘉賓屬守臣。',64,'全唐诗/poet.song.156000.json','["江頭梅蕊小裝春，式宴嘉賓屬守臣。", "京國路雖千里遠，瓊林花又一番新。", "且觀鹿野陳鄉樂，休憶羊裘整釣綸。", "老我豈堪陪盛集，爲公强振簿書塵。"]'),
('5cae7a8c-0c1c-40a2-b259-919889cceb88','再用韻','程洵','宋','宋诗','song-poetry','','[]','聖主如天與物春，四方委質願爲臣。',64,'全唐诗/poet.song.156000.json','["聖主如天與物春，四方委質願爲臣。", "設科取士制雖舊，側席求賢意自新。", "揚子詞高非篆刻，井春學富獨紛綸。", "行行好上江都策，莫厭京華沒馬塵。"]'),
('7410d191-3700-4ab7-ad52-576f98ec93a6','寒食次伯潛韻','程洵','宋','宋诗','song-poetry','','[]','小雨浪憎春日遲，輕寒自與晚花宜。',64,'全唐诗/poet.song.156000.json','["小雨浪憎春日遲，輕寒自與晚花宜。", "節過嶺外憶餳日，人比山陰脩禊時。", "雀舌味長初試水，貓頭意懶任穿籬。", "歸途莫恨石頭滑，山色波光總是詩。"]'),
('77800680-ee49-499a-b2f7-f143d7322f6d','張王臣以諸公驂字韻見貽即席奉次','程洵','宋','宋诗','song-poetry','','[]','圜扉草色碧於衫，晏子何勞更解驂。',64,'全唐诗/poet.song.156000.json','["圜扉草色碧於衫，晏子何勞更解驂。", "賸喜文書清幕府，翻嗟賓客滯湖南。", "遲囘愧我非高士，邂逅因公尚劇談。", "清夜論詩到山谷，棒頭妙旨欲重參。"]'),
('55efac2b-cb65-4c4f-b2c5-6db19b1c2990','再韻呈諸公','程洵','宋','宋诗','song-poetry','','[]','羞將華髮照青衫，直擬涼秋整去驂。',64,'全唐诗/poet.song.156000.json','["羞將華髮照青衫，直擬涼秋整去驂。", "應聘豈能如水北，紬書何事尚周南。", "江澄頗覺客愁破，山好那須世事談。", "猶勝元琳日趨府，强持簪笏逐髯參。"]'),
('f0b3cacc-4698-4655-8a70-c2d9a1aaccd1','再用韻呈王臣兼簡同社諸公','程洵','宋','宋诗','song-poetry','','[]','亭下江波綠樣衫，亭前山勢走驚驂。',64,'全唐诗/poet.song.156000.json','["亭下江波綠樣衫，亭前山勢走驚驂。", "心如胡馬猶思北，夢比飛烏正遶南。", "銀筆新書時有省，金鑾故事不須談。", "經綸從昔須賢哲，洗眼諸公國論參。"]'),
('fbe5a75b-af37-4d17-b2b2-65ed7be1d86c','送劉伯瑞通判還吳興','程洵','宋','宋诗','song-poetry','','[]','土牛方著勸農鞭，畫鷁俄聞疊鼓喧。',64,'全唐诗/poet.song.156000.json','["土牛方著勸農鞭，畫鷁俄聞疊鼓喧。", "別駕但知催理楫，邦人政自欲攀轅。", "黄堆荒徑重尋菊，綠擁高堂更樹諼。", "只恐清朝方急士，未容一室老陳蕃。"]'),
('bf7ff0dc-2751-4915-b993-d8d14f678f03','王駒父袖詩見過次韻贈之','程洵','宋','宋诗','song-poetry','','[]','平生志業在經綸，老去未充觀國賓。',64,'全唐诗/poet.song.156000.json','["平生志業在經綸，老去未充觀國賓。", "□道心□□地鏡，固應文□挂夫紳。", "大兒從昔輕餘子，丞相何時薦此君。", "莫爲窮通移晚節，歲寒方始見天真。"]'),
('8196f9ea-dd09-489a-b5ae-9bd71b57edd4','次韻宋郎中劉寺簿劉監廟燕集王大夫山林','程洵','宋','宋诗','song-poetry','','[]','飛旆翩翩亂晚霞，欣聞勝集俯雲沙。',64,'全唐诗/poet.song.156000.json','["飛旆翩翩亂晚霞，欣聞勝集俯雲沙。", "新詩宛似風行水，和氣想如春在花。", "大隠勿嫌朝市閙，朱幡方映繡衣華。", "塵埃短簿今倉氏，悵望清遊轉覺賒。"]'),
('341df31e-166a-4d75-95a5-5dfeab99b725','季章命賦周益公府雙頭蓮蓋太守所送者','程洵','宋','宋诗','song-poetry','','[]','桃根桃葉競妍華，清遠誰知別有花。',64,'全唐诗/poet.song.156000.json','["桃根桃葉競妍華，清遠誰知別有花。", "天爲蒼生娛一老，地從綠水湧雙葩。", "流傳已入騷人句，走送曾煩刺史家。", "却笑昌黎求玉井，路迷青壁重咨嗟。"]'),
('dbacc350-d868-470f-b1ba-2fea4dff8714','益公得牡丹狀如雙魚者以花嬪目之且賦詩俾予屬和','程洵','宋','宋诗','song-poetry','','[]','粧鏡臺前酒一卮，風流從古說楊妃。',64,'全唐诗/poet.song.156000.json','["粧鏡臺前酒一卮，風流從古說楊妃。", "誰令山鬼欺紅粉，却與花王司御衣。", "比儗莫嫌魚共貫，輕狂猶勝燕爭飛。", "老生無分陪清賞，空想鄒枚他夜歸。"]'),
('1e0f6ece-d30e-43d2-89f8-e6fbe254afca','寄贈歐陽伯威','程洵','宋','宋诗','song-poetry','','[]','窗閒花影夜摇春，窗外誰呼祁孔賓。',64,'全唐诗/poet.song.156000.json','["窗閒花影夜摇春，窗外誰呼祁孔賓。", "不信名山謝逋客，至今陋巷卧遺民。", "日高謾戛生魚釜，門掩應無沒馬塵。", "遥想撚鬚時得句，又書尺紙報平津。"]'),
('168381e2-a6f4-4eb5-b35f-3c4e802758c8','贈別','程洵','宋','宋诗','song-poetry','','[]','搔頭日日數歸程，誰信先生少宦情。',64,'全唐诗/poet.song.156000.json','["搔頭日日數歸程，誰信先生少宦情。", "趣駕不知千里遠，振衣始覺一身輕。", "霜林竹柏元同勁，世路風波底用驚。", "獨我臨分苦悽惻，從今懷抱向誰傾。"]'),
('dbeb7731-4b8f-4b1b-8949-63dea3eb2872','王守仁竹齋  其一','程洵','宋','宋诗','song-poetry','','[]','黄塵車馬去如流，名利勞人死不休。',32,'全唐诗/poet.song.156000.json','["黄塵車馬去如流，名利勞人死不休。", "心遠地偏何處是，小齋叢竹媚深幽。"]'),
('39a1ac62-de12-4b9d-a6ac-dd014d6f3c23','王守仁竹齋  其二','程洵','宋','宋诗','song-poetry','','[]','月度寒光影瘦疎，風傳清籟韻虛徐。',32,'全唐诗/poet.song.156000.json','["月度寒光影瘦疎，風傳清籟韻虛徐。", "幽人宴坐蒲團穩，讀罷儒書讀佛書。"]'),
('8f10f712-277e-495b-afad-415ab6184581','楊日新用所賦月壺韻作詩見寄依韻復之  其一','程洵','宋','宋诗','song-poetry','','[]','霜凋羣木鴈橫空，宴坐茅茨促膝容。',32,'全唐诗/poet.song.156000.json','["霜凋羣木鴈橫空，宴坐茅茨促膝容。", "忽有新詩來眼底，巉臨絕岸倚孤峰。"]'),
('ae427eaa-c2bc-4936-bab2-bb5a1f47d4b4','楊日新用所賦月壺韻作詩見寄依韻復之  其二','程洵','宋','宋诗','song-poetry','','[]','觀心要與月同明，覓句應須水樣清。',32,'全唐诗/poet.song.156000.json','["觀心要與月同明，覓句應須水樣清。", "老去不妨文豹隠，郎君已見角犀盈。"]'),
('1aa1ee4e-688f-4383-8eb6-fa507be1bf03','喜雨用山谷韻呈薛使君','程洵','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','畏日炎風是處同，使君閔閔甚三農。',64,'全唐诗/poet.song.156000.json','["畏日炎風是處同，使君閔閔甚三農。", "新詩仰看奔牛堰，好雨忽迷回鴈峰。", "千里祇今被膏澤，一堂行見會雲龍。", "由來膚寸沾天下，衡嶽英靈等岱宗。"]'),
('33113906-7de9-4b31-a0d5-465541774204','句','趙祖德','宋','宋诗','song-poetry','','[]','終當計勇决，湖山足徜徉。',12,'全唐诗/poet.song.156000.json','["終當計勇决，湖山足徜徉。"]'),
('d047f04b-99fd-4563-8e91-89b40ff7711b','贈相士徐鬼眼','蔡元定','宋','宋诗','song-poetry','','[]','挾術滿天下，誰人解識真。',48,'全唐诗/poet.song.156000.json','["挾術滿天下，誰人解識真。", "不因眼是鬼，那得口如神。", "堅白三寸舌，雌黄一世人。", "操修果無愧，方可問人倫。"]'),
('07a8f3c8-cf7b-43c3-a1dc-94808ddf9f75','挽劉忠肅二首  其一','蔡元定','宋','宋诗','song-poetry','','[]','今代中興佐，如公有幾人。',48,'全唐诗/poet.song.156000.json','["今代中興佐，如公有幾人。", "秉心先許國，臨事輒忘身。", "才略優中外，清忠表縉紳。", "天乎何不淑，遽奪我元臣。"]'),
('626de70f-3c3a-4a3a-b570-e6b9f4b4aabf','挽劉忠肅二首  其二','蔡元定','宋','宋诗','song-poetry','','[]','大節人誰識，孤忠我獨知。',48,'全唐诗/poet.song.156000.json','["大節人誰識，孤忠我獨知。", "文章亦餘事，軒冕竟何爲。", "國耻生期報，臣心死未衰。", "淒涼遺奏稿，千載有餘悲。"]'),
('048254d9-f66f-4748-9790-5f1eaf1de92a','謫舂陵別諸友','蔡元定','宋','宋诗','song-poetry','','[]','天道固溟漠，世路尤險巇。',72,'全唐诗/poet.song.156000.json','["天道固溟漠，世路尤險巇。", "吾生本自浮，與物多瑕疵。", "此去知何事，生死不可期。", "執手笑相別，無爲兒女悲。", "輕醉壯行色，扶摇動征衣。", "斷不負所學，此心天所知。"]'),
('bbbf91f2-eba3-48e4-9498-69d1aeb672c1','麻沙八景詩 岱山夕照','蔡元定','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','望斷高峰眼不花，箇中仿佛認人家。',32,'全唐诗/poet.song.156000.json','["望斷高峰眼不花，箇中仿佛認人家。", "情知一樣青山色，纔有斜陽景更佳。"]'),
('3ea1ed73-8bcc-4a79-ae78-c614ef497ed7','麻沙八景詩 煙村春雨','蔡元定','宋','宋诗','song-poetry','','[]','堆螺疊翠聳奇峰，花柳村村綠間紅。',32,'全唐诗/poet.song.156000.json','["堆螺疊翠聳奇峰，花柳村村綠間紅。", "不有翠微翁說破，誰知春在雨煙中。"]'),
('cfbc2bb4-8cae-4317-88b7-452ee6330ea5','麻沙八景詩 雲巖山色','蔡元定','宋','宋诗','song-poetry','','[]','山染煙光弄晚嵐，幾多碧色映寒潭。',32,'全唐诗/poet.song.156000.json','["山染煙光弄晚嵐，幾多碧色映寒潭。", "篆煙銷盡金爐冷，雲滿巖前月滿庵。"]'),
('7accc30f-c090-4a6b-86df-1b43c107cedd','麻沙八景詩 祇園溪聲','蔡元定','宋','宋诗','song-poetry','','[]','橋枕東流路透西，橋邊梵剎亦幽奇。',32,'全唐诗/poet.song.156000.json','["橋枕東流路透西，橋邊梵剎亦幽奇。", "人來問道不須問，抵聽溪聲悟佛機。"]'),
('34ec45a7-885f-470d-b10a-cadd65abd934','麻沙八景詩 松岡夜濤','蔡元定','宋','宋诗','song-poetry','','[]','萬頃雲濤轟怒雷，更深好夢遽驚回。',32,'全唐诗/poet.song.156000.json','["萬頃雲濤轟怒雷，更深好夢遽驚回。", "老松本是無聲物，恰值風從天上來。"]'),
('68a79e3e-5194-4598-84d7-8cdb4bf42f77','麻沙八景詩 蓮湖晚風','蔡元定','宋','宋诗','song-poetry','','[]','湖面花開映綠波，當年曾聽採蓮歌。',32,'全唐诗/poet.song.156000.json','["湖面花開映綠波，當年曾聽採蓮歌。", "垂楊拂地雲臨水，舉目令人感慨多。"]'),
('f4c46d34-370e-4e8a-8dec-fa4aca96af89','麻沙八景詩 武陵橋月','蔡元定','宋','宋诗','song-poetry','','[]','長虹倒景蘸清溪，掩映銀蟾景絕奇。',32,'全唐诗/poet.song.156000.json','["長虹倒景蘸清溪，掩映銀蟾景絕奇。", "題柱惜無人繼志，覽今思古强吟詩。"]'),
('5bf15eda-e904-4ee4-9637-6634bc2a416e','麻沙八景詩 象巖晴雪','蔡元定','宋','宋诗','song-poetry','','[]','風捲寒雲收曉晴，巖巖白石自天生。',32,'全唐诗/poet.song.156000.json','["風捲寒雲收曉晴，巖巖白石自天生。", "遠看似雪還非雪，有物元來是混成。"]'),
('00fa043c-ad61-4f45-a228-03c0bce22529','自詠','蔡元定','宋','宋诗','song-poetry','','[]','獨抱韋編過客稀，簞瓢不厭屢空時。',32,'全唐诗/poet.song.156000.json','["獨抱韋編過客稀，簞瓢不厭屢空時。", "幽然自與庖羲近，春去人間總不知。"]'),
('9d8a3ea8-2cf3-4475-b278-02f84ccdbf43','贈琴士邵邦傑','蔡元定','宋','宋诗','song-poetry','','[]','五寸管能窺造化，七弦琴解寫人心。',32,'全唐诗/poet.song.156000.json','["五寸管能窺造化，七弦琴解寫人心。", "平生不作麒麟夢，且聽高山流水音。"]'),
('5b3b4ccc-f745-407a-bd08-3a69b040236a','西齋自詠','蔡元定','宋','宋诗','song-poetry','','[]','數椽茅屋環流水，布被藜羹飽煖餘。',64,'全唐诗/poet.song.156000.json','["數椽茅屋環流水，布被藜羹飽煖餘。", "不向利中生計較，肯於名上著工夫。", "窗前野馬閑來往，天霽浮雲自卷舒。", "窮達始知皆有命，不妨隨分老樵漁。"]'),
('a597d8ce-3b4b-4597-8691-ca4adf205fa3','推衍後世休咎','蔡元定','宋','宋诗','song-poetry','','[]','顯慶堂將後世推，子孫紹復承吾書。',64,'全唐诗/poet.song.156000.json','["顯慶堂將後世推，子孫紹復承吾書。", "四傳學業家還在，五世因貪人剷除。", "續纘流風六七代，繼興遺蹟八九渠。", "數終輪奐猶有待，御史尹仁爲吹噓。"]'),
('69ab6604-c2f6-4124-951a-df80391c2202','次晦翁韻','蔡元定','宋','宋诗','song-poetry','','[]','屈指摳衣十七年，自憐鬚鬢已皤然。',64,'全唐诗/poet.song.156000.json','["屈指摳衣十七年，自憐鬚鬢已皤然。", "久知軒冕真無分，但覺溪山若有緣。", "下學工夫慚未到，先天事業敢輕傳。", "祇今已飽煙霞痼，更乞清溪理釣船。"]'),
('c9826b02-c93b-4053-b369-1b3f42e15758','林居','蔡元定','宋','宋诗','song-poetry','','[]','富貴良非願，林泉畢此生。',48,'全唐诗/poet.song.156000.json','["富貴良非願，林泉畢此生。", "酒因隨量飲，詩或偶然成。", "秋水和烟釣，春田带雨耕。", "頑然無縫塔，且不費經營。"]'),
('1dfed089-8fe8-47b7-8161-73045547609e','贈蔡季通','蔡元定鄉人','宋','宋诗','song-poetry','','[]','掘盡人家好丘隴，冤魂欲訴更無由。',32,'全唐诗/poet.song.156000.json','["掘盡人家好丘隴，冤魂欲訴更無由。", "先生若有堯夫術，何不先言去道州。"]'),
('aca620ab-22d2-43e8-b25d-5602c1af507a','挽蔡西山先生','黄瑞節','宋','宋诗','song-poetry','','[]','直所遭之慘兮天意奚屈，忽訃音遽聞兮哀痛不淑。',88,'全唐诗/poet.song.156000.json','["直所遭之慘兮天意奚屈，忽訃音遽聞兮哀痛不淑。", "痛哲人云亡兮邦國殄瘁，感死生永訣兮莫睹其悲。", "傷吾道終窮兮何心於世，相長號以酬兮陰輔吾志。", "惟下觀而化兮風聲遠被，想神之有靈兮馨此銘詩。"]'),
('b9d1825d-ed10-41c7-a2c5-f315b9154f1f','疊綵巖登越亭','朱晞顔','宋','宋诗','song-poetry','','[]','不到越亭久，榴花今已紅。',48,'全唐诗/poet.song.156000.json','["不到越亭久，榴花今已紅。", "江流寒瀉玉，山色翠浮空。", "百粵薰風裏，三湘夕照中。", "行藏仗忠信，六合本同風。"]'),
('b793d8a0-0148-4fe8-8e70-3404ca424b7a','朝陽洞','朱晞顔','宋','宋诗','song-poetry','','[]','湖上初驚八月秋，嶺頭又見桂香浮。',64,'全唐诗/poet.song.156000.json','["湖上初驚八月秋，嶺頭又見桂香浮。", "巾車幾憶陶彭澤，竹馬多慙郭細侯。", "未遣靈泉還舊隠，且同巖壑訪真游。", "一枰勝負人何在，試問樵柯已爛否。"]'),
('2b7364ed-5540-4eb2-850e-b46f8613e741','遊壺天觀泛舟過龍隠洞小酌至月上而歸','朱晞顔','宋','宋诗','song-poetry','','[]','浪道湘南是瘴鄉，玉壺銀闕四時凉。',64,'全唐诗/poet.song.156000.json','["浪道湘南是瘴鄉，玉壺銀闕四時凉。", "卧龍不逐葭灰動，愛日空驚繡縷長。", "浮蟻且同佳節醉，探梅不作少年狂。", "暮歸慙愧山頭月，照我駸駸兩鬢霜。"]'),
('995d76be-6759-407b-95b2-d9384d25017c','伏波巖','朱晞顔','宋','宋诗','song-poetry','','[]','天斲神剜不記年，洞中風景異塵寰。',64,'全唐诗/poet.song.156000.json','["天斲神剜不記年，洞中風景異塵寰。", "江波蕩漾青羅带，崖石虛明碧玉環。", "地接三山真蹟在，天連合浦寶珠還。", "重來恍似乘槎到，慚愧雲門夜不關。"]'),
('ebd3f4b8-c5ce-4a0f-9e13-7d981b6db3cd','彈丸山','朱晞顔','宋','宋诗','song-poetry','','[]','傷弓枉木漫猜嫌，岩石稜稜彈樣圓。',64,'全唐诗/poet.song.156000.json','["傷弓枉木漫猜嫌，岩石稜稜彈樣圓。", "鵰鶚橫空秋凜凜，鳬鷗渡水晚翩翩。", "私心灰冷慵思繳，蹇步塵勞不受鞭。", "挾彈張弓付年少，歸歟趁取菊花天。"]'),
('93c8cb51-7f08-4d7a-8e30-a373acd6b571','洞底石間得枯木一株花葉咸無而枝幹峭拔扣之鏗然有聲因成鄙句刻之岩石間','朱晞顔','宋','宋诗','song-poetry','','[]','天教海若效珍祥，不與千林春競芳。',64,'全唐诗/poet.song.156000.json','["天教海若效珍祥，不與千林春競芳。", "擲地遺音清戛玉，凌雲直幹凜凝霜。", "誰浮鯨海星槎到，猶带蟾宮月桂香。", "冶葉浮花埽除盡，堅高直欲共天長。"]'),
('0a618961-d1f7-47c2-bf5d-457b1fff52b3','假日過龍隠山有以千葉白梅獻者輒成鄙句','朱晞顔','宋','宋诗','song-poetry','','[]','素艷重重疊雪輕，先春不怕雪霜凝。',64,'全唐诗/poet.song.156000.json','["素艷重重疊雪輕，先春不怕雪霜凝。", "人言五嶺地皆熱，誰折一枝寒欲冰。", "似笑踈花太孤瘦，故教密葉擁千層。", "湘南別有新春樣，拚醉花前喚不譍。"]'),
('c18cf06a-bd98-494a-8ab8-a87ab64fa4d8','慶元改元寒食日陪都運寺丞遊白龍洞時牡丹盛開小酌岩下夕陽西度並轡而歸','朱晞顔','宋','宋诗','song-poetry','','[]','小溪潄碧響潺潺，路入龍宮杳靄間。',64,'全唐诗/poet.song.156000.json','["小溪潄碧響潺潺，路入龍宮杳靄間。", "佳節漫添新白髮，故人頼有舊青山。", "花朝幾共湘南醉，萍跡何年嶺北還。", "歸路連鑣紅日晚，多慙龍卧白雲閒。"]'),
('5b5c5df2-7394-4582-a14c-e3260bdf738a','龍隠岩','朱晞顔','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','聖主龍飛已在天，洞中猶有老龍眠。',32,'全唐诗/poet.song.156000.json','["聖主龍飛已在天，洞中猶有老龍眠。", "便須吸盡西江水，霈作商霖大有年。"]'),
('dc362a09-3c0d-4543-938b-328bf3dd493a','韶音洞','朱晞顔','宋','宋诗','song-poetry','','[]','曾按薰絃天一方，埽除民慍變清涼。',32,'全唐诗/poet.song.156000.json','["曾按薰絃天一方，埽除民慍變清涼。", "遺音凜凜猶聞耳，不獨當年味可忘。"]'),
('cc7ec7a3-bad0-4bfd-a363-a65ee3745057','石柏','朱晞顔','宋','宋诗','song-poetry','','[]','海物難窮造化奇，後凋惟有歲寒知。',64,'全唐诗/poet.song.156000.json','["海物難窮造化奇，後凋惟有歲寒知。", "誰將修月黄金斧，斲就凌雲紫玉枝。", "直幹豈容塵點涴，靈根偏與石相宜。", "天然不假栽培力，肯逐春風盛與衰。"]'),
('86c34b13-52c8-4ec2-b6dd-79532452cd1a','題大安壁','朱晞顔','宋','宋诗','song-poetry','','[]','萬里同爲客，秋悲未易禁。',48,'全唐诗/poet.song.156000.json','["萬里同爲客，秋悲未易禁。", "萍蓬鄉國夢，松竹歲寒心。", "霜葉青紅亂，雲山紫翠深。", "何時錦屏下，樽酒話塵襟。"]'),
('9e5e225f-1c81-4f2e-b64f-6f0e576cfcbf','煙波閣','朱晞顔','宋','宋诗','song-poetry','','[]','小立煙波上，江湖興未忘。',48,'全唐诗/poet.song.156000.json','["小立煙波上，江湖興未忘。", "敗梧風舞葉，寒菊露滋香。", "目逐去雲斷，愁隨流水長。", "蓴鱸秋正好，飛棹訪滄浪。"]'),
('d5d26b65-7a62-477a-89a7-d29db85ac356','白嶽寄懷','朱晞顔','宋','宋诗','song-poetry','','[]','林間留我住多時，似與煙霞夙有期。',64,'全唐诗/poet.song.156000.json','["林間留我住多時，似與煙霞夙有期。", "野老烹茶來獻客，巖猨偷果去呼兒。", "靜思世上千年事，不值山中一局棋。", "欲說行藏舒卷意，洞天惟有白雲知。"]'),
('1de2cd37-849e-48d3-9942-4bc519e11510','龍隠洞石壁玉立□門虛明目□江流□貫其中上□□□□如印泥然亦異矣暇日携家泛舟來游','朱晞顔','宋','宋诗','song-poetry','','[]','翠壁崢嶸百仞雄，玉龍飛下水晶宮。',64,'全唐诗/poet.song.156000.json','["翠壁崢嶸百仞雄，玉龍飛下水晶宮。", "禹門激浪縱三級，□□□雲僅一弓。", "銀闕交輝天不夜，全鱗倒影水浮空。", "卷懷霖雨沈潛久，會有驚雷□歲豐。"]'),
('abc47b89-ffdd-4a30-addd-11a9a0ba8321','致爽齋','楊王休','宋','宋诗','song-poetry','','[]','翛然一宅一編書，舉世何人得似渠。',32,'全唐诗/poet.song.156000.json','["翛然一宅一編書，舉世何人得似渠。", "三十六峰峰下路，清溪綠竹繞樓居。"]'),
('ba511c28-c9de-495c-adc5-b91e465be5e0','鑿溫嶺','楊王休','宋','宋诗','song-poetry','','[]','黄山形勢南如窩，四十餘里趨丹河。',192,'全唐诗/poet.song.156000.json','["黄山形勢南如窩，四十餘里趨丹河。", "年年七月八月雨，稻田瀰漲漫風波。", "異時都水使者至，東開鐵場分水勢。", "地綿力短功未成，尺一催歸卒吞志。", "舊畫茫茫如棄井，百年遺恨如灰冷。", "我來弔古更窮源，並水沿流至溫嶺。", "嶺之首尾少低昂，如衡稱物錙銖强。", "外即大海枕平麓，相去往往尋丈長。", "天造地設巧乃爾，胡爲棄此而取彼。", "興廢成否抑有時，不獨今非古皆是。", "此來經營煩令君，便有異議爭云云。", "常情自古憚謀始，豈料疲秦終利秦。"]'),
('87a9b2aa-d3b4-4722-9fd3-efc787e221a6','計偕中途寄家大人','戴機','宋','宋诗','song-poetry','','[]','戚戚復戚戚，辭親遠行遊。',72,'全唐诗/poet.song.156000.json','["戚戚復戚戚，辭親遠行遊。", "江湖浩無際，山巒鬰相稠。", "浮雲奮南征，所歷非故丘。", "離禽鮮好音，羈旅多遠憂。", "古人一日養，不以三牲酬。", "胡爲功名意，盼斷倚門眸。"]'),
('1ad3fe96-fa45-44af-bc1f-5d102e144aa7','和楊廷秀下元日詣會慶節所道場','余端禮','宋','宋诗','song-poetry','','[]','殊庭冠佩儼晨趨，聯轡朝真下馬初。',64,'全唐诗/poet.song.156000.json','["殊庭冠佩儼晨趨，聯轡朝真下馬初。", "簾透晴曦金碎剪，霜彫細柳髮新梳。", "三呼獻瑞聞班列，萬籟收聲入步虛。", "祝聖歸來無一事，時平翻恨酒杯疎。"]'),
('104a01ba-4ae8-4818-9545-b7d0c5a4ccbf','勸農石頭城賦詩','余端禮','宋','宋诗','song-poetry','','[]','去年出郊春欲半，鍾阜林巒青未遍。',160,'全唐诗/poet.song.156000.json','["去年出郊春欲半，鍾阜林巒青未遍。", "今年此日蟄初驚，動地春光滿石城。", "柳如蹙金梅碾玉，川原高下麥苗綠。", "一聲布穀已催人，吳儂莫問春遲速。", "蒼顔老守政無奇，只要我民不苦饑。", "奉詔偕行兩赤令，職在勸耕無擾之。", "鮐背厖眉數十叟，聽取吾言醉此酒。", "但遣兒郎力南畝，不患三錢無米斗。", "米斗三錢大江東，從今更祝八方同。", "同見三登太平日，老守不願萬戶封。"]'),
('0623bd69-ce8d-4b16-87a4-d4243c67df4e','浮遠堂  其一','丘崈','宋','宋诗','song-poetry','','[]','西來江水浮天遠，卧看飛鴻入杳冥。',64,'全唐诗/poet.song.156000.json','["西來江水浮天遠，卧看飛鴻入杳冥。", "雲過有山皆點點，潮迴無地不青青。", "風光浩蕩連淮海，氣象高寒近日星。", "醉裏不禁頻極目，敔峰如黛涕先零。"]'),
('821e0e64-4e2d-417e-b12c-619a4ba6e4c7','浮遠堂  其二','丘崈','宋','宋诗','song-poetry','','[]','已作垂垂雨，相爲澹澹陰。',48,'全唐诗/poet.song.156000.json','["已作垂垂雨，相爲澹澹陰。", "吾徒一笑粲，造物用功深。", "跬步西山勝，終年梁甫吟。", "年來賞心處，徒得與君臨。"]'),
('62c5a1c6-8344-426b-b86e-984e53314224','和張孝伯雪窗詩韻','丘崈','宋','宋诗','song-poetry','','[]','洞門陰陰無俗客，樓觀清雄使君宅。',128,'全唐诗/poet.song.156000.json','["洞門陰陰無俗客，樓觀清雄使君宅。", "晴窗妙墨燦銀鉤，要比粉闈冬夏白。", "秀將嵩少只簷間，恍如積霰觀商顔。", "藍田塞關底足異，城陽郡樓那可攀。", "窗中四時同一念，不作寒溫顛倒見。", "試看炎蒸定有無，始知此景無遷變。", "都城畏日騰朝光，趦趄奔競車馬行。", "靦面內熱者誰子，來此爲卿心骨涼。"]'),
('b28979bf-5097-403f-8302-6e18cbbcb471','和朱子武夷雜咏十首 精舍','丘崈','宋','宋诗','song-poetry','','[]','我讀精舍篇，夢作山中客。',24,'全唐诗/poet.song.156000.json','["我讀精舍篇，夢作山中客。", "從公夜不眠，寒燈歌白石。"]'),
('202c65c1-479a-4035-bb84-26222e41db22','和朱子武夷雜咏十首 仁智堂','丘崈','宋','宋诗','song-poetry','','[]','靜如顔心齋，動若禹行水。',24,'全唐诗/poet.song.156000.json','["靜如顔心齋，動若禹行水。", "迷邦謝陽子，謀國付樗里。"]'),
('0a41a487-1e21-4713-b501-c7acef427b87','和朱子武夷雜咏十首 隠求堂','丘崈','宋','宋诗','song-poetry','','[]','抱膝小窗深，讀書空谷響。',24,'全唐诗/poet.song.156000.json','["抱膝小窗深，讀書空谷響。", "一笑有會心，紛紛自雄長。"]'),
('ee513dde-a559-4237-9e00-ba4cde026def','和朱子武夷雜咏十首 觀善齋','丘崈','宋','宋诗','song-poetry','','[]','言發矢無鄉，機深舍爭席。',24,'全唐诗/poet.song.156000.json','["言發矢無鄉，機深舍爭席。", "聖處倘策勳，珍重相與力。"]'),
('02cfbc5d-aa04-482a-8602-5406aca0b37d','和朱子武夷雜咏十首 寒棲館','丘崈','宋','宋诗','song-poetry','','[]','風急窗自鳴，霜嚴酒無力。',24,'全唐诗/poet.song.156000.json','["風急窗自鳴，霜嚴酒無力。", "歲律方崢嶸，幽人坐堅壁。"]'),
('157ea741-efbc-4d04-a5b4-4b11b9b40a50','和朱子武夷雜咏十首 晚對亭','丘崈','宋','宋诗','song-poetry','','[]','蒼山開秋屏，屹立儼無對。',24,'全唐诗/poet.song.156000.json','["蒼山開秋屏，屹立儼無對。", "下有岸幘人，意氣壓蒼翠。"]'),
('709158fd-77a7-4215-b4de-98d1153b2619','和朱子武夷雜咏十首 鐵笛亭','丘崈','宋','宋诗','song-poetry','','[]','橫笛人何在，山空花自開。',24,'全唐诗/poet.song.156000.json','["橫笛人何在，山空花自開。", "不妨聽晚弄，聲與壯心來。"]'),
('892909bc-3998-45d4-a4ef-6b0c7f023d40','和朱子武夷雜咏十首 釣磯','丘崈','宋','宋诗','song-poetry','','[]','清溪轉回環，石磯俯深碧。',24,'全唐诗/poet.song.156000.json','["清溪轉回環，石磯俯深碧。", "公來坐忘歸，此意白雲識。"]'),
('f31ca42d-d342-4fc0-beb0-38caffae32cf','和朱子武夷雜咏十首 茶竈','丘崈','宋','宋诗','song-poetry','','[]','烹茶人外世，遺竈水中央。',24,'全唐诗/poet.song.156000.json','["烹茶人外世，遺竈水中央。", "千載公仍至，茶成水亦香。"]'),
('09abcf53-943b-4c41-83da-7f1e8da8f7a1','和朱子武夷雜咏十首 漁艇','丘崈','宋','宋诗','song-poetry','','[]','世路風波惡，扁舟去住輕。',24,'全唐诗/poet.song.156000.json','["世路風波惡，扁舟去住輕。", "中流發清唱，千古有遺聲。"]'),
('c1028e4f-77aa-4c58-98ec-00a3ab841046','世途','趙公豫','宋','宋诗','song-poetry','','[]','世途若戈矛，達人自宜淑。',84,'全唐诗/poet.song.156000.json','["世途若戈矛，達人自宜淑。", "春日玩春桃，秋時賞秋菊。", "閒來與客談，興至取書讀。", "渴飲溪頭水，饑餐瓶中粥。", "即此可忘憂，世人奚碌碌。", "黄農不復生，誰爲大化育。", "此身當自珍，毋爲世所辱。"]'),
('142c1231-bc47-48ad-b5bb-9184b24b8d4a','教授祖守中逢清以秋菊佳詠見貽次韻奉答','趙公豫','宋','宋诗','song-poetry','','[]','重九寓淮陰，塵囂忘境寂。',108,'全唐诗/poet.song.156000.json','["重九寓淮陰，塵囂忘境寂。", "金風徧原野，芳華未銷歇。", "結友步林坳，秋容正紛發。", "疎籬隠士居，叢菊堪怡悅。", "淡遠異凡葩，清香戀遊蝶。", "皎如冰作盤，長才無放逸。", "廣文祖先生，雞羣之鶴立。", "揮淚賦新言，羣賢皆侍側。", "一編惠遠人，捧誦幾晨夕。"]'),
('66c33df3-7c46-4f40-b5a3-c57f95e77afd','嚴先生釣臺同范茂明浚賦','趙公豫','宋','宋诗','song-poetry','','[]','漢帝中興握赤符，先生恬澹隠名區。',64,'全唐诗/poet.song.156000.json','["漢帝中興握赤符，先生恬澹隠名區。", "羊裘自是林泉物，龍德原非將相徒。", "不學淮陰遭戮辱，豈同尚父預匡扶。", "高蹤卓絕橫今古，瞻拜桐江感嘆俱。"]'),
('ecaf9fb3-2f78-4e07-85ba-5e18ef20e03b','陳元矩昭度納姬戲贈  其一','趙公豫','宋','宋诗','song-poetry','','[]','半載幽居太寂寥，春風送暖此良宵。',32,'全唐诗/poet.song.156000.json','["半載幽居太寂寥，春風送暖此良宵。", "深情不必旁留戀，好布羅帷籠阿嬌。"]'),
('bcf76d8a-b281-4aaa-89b2-a5c6bbcc1e2a','陳元矩昭度納姬戲贈  其二','趙公豫','宋','宋诗','song-poetry','','[]','賺得姬人下鏡臺，錦衾角枕手親裁。',32,'全唐诗/poet.song.156000.json','["賺得姬人下鏡臺，錦衾角枕手親裁。", "魚魚水水成佳會，懶向書堂事酒杯。"]'),
('27de3524-ef3a-489d-af3b-0fb5e47b1ea8','瑞香','趙公豫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','本屬廬山種，今移到小堂。',48,'全唐诗/poet.song.156000.json','["本屬廬山種，今移到小堂。", "疎枝依淺土，永日吐清香。", "不獨供欣賞，還宜兆吉祥。", "春深花氣減，對此更微茫。"]'),
('229721c8-4221-4f90-a0ac-a5baef801df3','留別□州牧孫德操懋','趙公豫','宋','宋诗','song-poetry','','[]','賢守公餘雅讌開，荷香馥馥入蓬萊。',64,'全唐诗/poet.song.156000.json','["賢守公餘雅讌開，荷香馥馥入蓬萊。", "驊騮與座稱仙吏，樗櫟趨陪愧鈍才。", "緯武經文資妙略，民胞物與廣滋培。", "萍蹤將返琴川棹，鈴閣新吟切溯洄。"]'),
('774132bc-0ae4-44be-8645-111eff4eea0d','遊瑯琊寺','趙公豫','宋','宋诗','song-poetry','','[]','滁陽饒古蹟，山水境幽然。',96,'全唐诗/poet.song.156000.json','["滁陽饒古蹟，山水境幽然。", "名流相接踵，題詠日紛繁。", "我來值長至，欲一嚮山前。", "適逢豪俠友，相約入林淵。", "巉巖如虎伏，蒼松似龍眠。", "少憩聞清磬，徐步覽名泉。", "山僧供茗椀，不爲禮數牽。", "坐卧興夷猶，嘯傲山之巔。"]'),
('1c9cbcd3-d0a2-43ae-a0f4-9dc53b255259','秋日遊焦山寺','趙公豫','宋','宋诗','song-poetry','','[]','舟行依岸曲，積氣一峰孤。',48,'全唐诗/poet.song.156000.json','["舟行依岸曲，積氣一峰孤。", "日烈秋容老，霜寒木葉枯。", "閒雲留佛宇，幽鳥借僧餔。", "何日尋真隠，名山信杖扶。"]'),
('dffb6531-e5a3-4876-be95-34be6a95cfe6','金山','趙公豫','宋','宋诗','song-poetry','','[]','波濤流不息，山勢獨縱橫。',48,'全唐诗/poet.song.156000.json','["波濤流不息，山勢獨縱橫。", "高閣空中現，浮圖雨外晴。", "帆檣歸客穩，鐘鼓卧龍驚。", "是處開生面，風雲別有情。"]'),
('3902d429-3bae-46bb-9cb8-942ff51073fd','鶴林寺','趙公豫','宋','宋诗','song-poetry','','[]','山徑紆徐上，行吟喜自如。',48,'全唐诗/poet.song.156000.json','["山徑紆徐上，行吟喜自如。", "蒼松夾道路，翠竹繞門閭。", "是處無紛擾，到來懷隠居。", "南朝碑尚在，遺事信非虛。"]'),
('d6cc472e-c6d7-41a4-a901-c1c28016207e','北固山','趙公豫','宋','宋诗','song-poetry','','[]','名山推北固，乘興一登臨。',48,'全唐诗/poet.song.156000.json','["名山推北固，乘興一登臨。", "古廟稀人語，虛堂響樹音。", "江濤堪寓目，禽鳥足娛心。", "坐卧言歸晚，前村月滿林。"]'),
('102b4605-7ac3-4966-b47a-65a2382f71d1','甘露寺','趙公豫','宋','宋诗','song-poetry','','[]','名山城北峙，突兀到清虛。',48,'全唐诗/poet.song.156000.json','["名山城北峙，突兀到清虛。", "剎踞飛雲上，僧從絕頂居。", "江濤聲斷續，松柏勢扶疎。", "晤對忘人世，登臨意自如。"]'),
('8695b327-02e8-42d4-8339-07622dc830ea','滕王閣懷古和新會馬持國韻','趙公豫','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6ed5\u738b\u9601"]','扁舟直入南州界，屈曲河流勢澎湃。',208,'全唐诗/poet.song.156000.json','["扁舟直入南州界，屈曲河流勢澎湃。", "浩蕩銀濤氣灝漫，淵源不竭通九派。", "昔年作客豫章城，弗覩高樓恒介介。", "再來勝地續前緣，畫棟雕梁稱絕快。", "子安一賦傳古今，俯視羣言猶草芥。", "西山蒼翠無變更，南浦煙雲幾成敗。", "憑欄睇視爽凡襟，惹起狂情破遊戒。", "敏飲醇醪似蔗漿，細覽詞章如披薤。", "寄身天地原寬閒，我獨伊何逢險隘。", "落霞孤鶩景偏幽，秋水長天恬不怪。", "信知造物有化工，能參妙義方無疥。", "長嘯樓頭逸興豪，得意忘言絕機械。", "匡廬有約次遊遨，務須了却林泉債。"]'),
('4d7353fa-f0dc-41f4-82d1-65cc091b6e0a','金陵懷古','趙公豫','宋','宋诗','song-poetry','','[]','六代金湯固，桑田幾變更。',48,'全唐诗/poet.song.156000.json','["六代金湯固，桑田幾變更。", "梁臺秋月冷，吳苑晚鴻鳴。", "禾黍逢時茂，人心嚮化平。", "江山存勝蹟，我輩得怡情。"]'),
('9b85b95b-e1cf-4d7a-8c5a-df36d31f81ca','廬山','趙公豫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山不可盡，躡屐且相尋。',48,'全唐诗/poet.song.156000.json','["廬山不可盡，躡屐且相尋。", "峭壁懸崖險，幽泉仄澗深。", "苔痕侵竹徑，雲氣結松陰。", "古剎安禪靜，聞鐘砭俗心。"]'),
('62e95c5c-95d1-4caa-829f-42a2feeba627','梅仙祠','趙公豫','宋','宋诗','song-poetry','','[]','漢尉垂綸處，遺風事可傳。',48,'全唐诗/poet.song.156000.json','["漢尉垂綸處，遺風事可傳。", "林深飛鳥入，水隔小橋連。", "道室幽如許，山花晚倍妍。", "到來心志靜，不復有塵緣。"]'),
('28b6e257-f0f5-4ce4-b06d-cbe7f4cdc815','新安江泛棹','趙公豫','宋','宋诗','song-poetry','','[]','秋水何清澈，舟行境不窮。',48,'全唐诗/poet.song.156000.json','["秋水何清澈，舟行境不窮。", "猿啼深谷裏，人泛碧流中。", "雲影連帆影，林紅映日紅。", "灘聲時斷續，高曠羨漁翁。"]'),
('476d3827-961f-4228-b359-e09a009ecca7','訪滕王閣舊址','趙公豫','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王高閣已塵埃，故老猶傳結搆材。',64,'全唐诗/poet.song.156000.json','["滕王高閣已塵埃，故老猶傳結搆材。", "南浦寒潭秋月淺，西山爽氣曉風開。", "韓公碑碣生苔蘚，王子文章沒草萊。", "舉目章江多落寞，蕭蕭雲樹總堪哀。"]'),
('0fdacff7-ccd8-4b3c-8e54-ab1f48b98856','韓侯釣臺','趙公豫','宋','宋诗','song-poetry','','[]','湖水盈盈歷古今，我來憑弔識淮陰。',64,'全唐诗/poet.song.156000.json','["湖水盈盈歷古今，我來憑弔識淮陰。", "王孫自失三齊志，漂母誰憐一飯心。", "封拜不堪仍赤族，交遊未可仗黄金。", "富春亦有垂綸者，獨引高風爽客襟。"]'),
('362b89b8-565e-43a1-8aba-d93324b7e83b','嚴先生釣臺同范茂明賦疊前韻','趙公豫','宋','宋诗','song-poetry','','[]','處士星光耀斗符，漢家幸有此區區。',16,'全唐诗/poet.song.156000.json','["處士星光耀斗符，漢家幸有此區區。"]'),
('106f4d2a-83a4-479b-8dfe-687bc4a8b90c','賦贈許上達','趙公豫','宋','宋诗','song-poetry','','[]','十載驅馳萬里程，雞林自昔飲香名。',64,'全唐诗/poet.song.156000.json','["十載驅馳萬里程，雞林自昔飲香名。", "欣瞻霽月光風度，得慰蒼葭白露情。", "博愛已徵欽古道，贈言端可重生平。", "迴舟再謁吟詩處，錯落珠璣映水明。"]'),
('d70cf115-6a42-4bc8-ad60-31fa20b44a9b','月夜接友人書','趙公豫','宋','宋诗','song-poetry','','[]','湖水春來泛碧波，伊人暌隔悵如何。',64,'全唐诗/poet.song.156000.json','["湖水春來泛碧波，伊人暌隔悵如何。", "梅花著露香還艷，竹葉臨風色自和。", "形影莫親憑夢寐，中情頻寫寄詩歌。", "魚書忽喜今宵到，復值堂前好月過。"]'),
('d40cea64-4ee0-44b4-bb93-cf238a5b1f4c','采石磯懷古','趙公豫','宋','宋诗','song-poetry','','[]','姑孰江頭暫置郵，凉風蕭颯勝三秋。',64,'全唐诗/poet.song.156000.json','["姑孰江頭暫置郵，凉風蕭颯勝三秋。", "燃犀韻事歸何處，披錦詩人跡尚留。", "廣濟剎邊松樹古，峨嵋亭畔晚煙浮。", "六朝霸業成殘壘，惟見茫茫水北流。"]'),
('f2c2d7d7-d2d1-4841-8693-a8965fc0c70a','暮雲亭謁青蓮先生祠','趙公豫','宋','宋诗','song-poetry','','[]','學士風流不可名，暮雲猶著古賢聲。',64,'全唐诗/poet.song.156000.json','["學士風流不可名，暮雲猶著古賢聲。", "衣冠渺渺成黄土，松柏蕭蕭散紫英。", "幾見騎鯨尋皓月，當年披錦酌飛觥。", "遥遥歲序還思敬，祠宇重光俎豆情。"]'),
('6cdd9d22-2430-42e9-83a3-2b8e2ad5d43a','亞夫墓','趙公豫','宋','宋诗','song-poetry','','[]','鴻門不用業成灰，碧血孤忠蓄夜臺。',64,'全唐诗/poet.song.156000.json','["鴻門不用業成灰，碧血孤忠蓄夜臺。", "落日兔狐眠宿土，新秋猿鶴叫餘哀。", "虹光閃爍凌雲漢，鼠竊卑汙沒草萊。", "傳道英靈能顯晦，登臨紀異愧無才。"]'),
('9c5897b4-7ab5-45f8-ae8f-0f4bda74de20','高祖廟','趙公豫','宋','宋诗','song-poetry','','[]','尺土無階起沛豐，大風一曲壓羣雄。',64,'全唐诗/poet.song.156000.json','["尺土無階起沛豐，大風一曲壓羣雄。", "秦關約法成王業，楚國掄材衛帝宮。", "遠引留侯悲鳥兔，矜功韓信困牢籠。", "堪憐戚氏終人彘，智略何曾事事工。"]'),
('c7d183a5-5f14-418f-8cda-60d3bbc49495','送春歌','趙公豫','宋','宋诗','song-poetry','','[]','時光如箭遞相催，三春竟過夏方來。',192,'全唐诗/poet.song.156000.json','["時光如箭遞相催，三春竟過夏方來。", "紅英漸落幽三徑，綠葉初肥映翠苔。", "太息勞生同若夢，四十年華輕斷送。", "譬如朝露最傷情，且趁年光免嘲弄。", "陽和布澤滿丘墟，黄鳥聲啼自卷舒。", "聞聲自可娛清晝，何必嗟噓向敝廬。", "獨念鬚眉驚漸老，事業無成悲潦倒。", "曠志深沉似碧潭，孤情磊落如芳草。", "惜春還作送春遊，片刻風光未易酬。", "妙緒清言成韻會，飛觴舉盞滌離愁。", "良會弗長隨往迹，轉盼須臾即宿昔。", "古人秉燭非清狂，吾輩好把時光惜。"]'),
('1f25ddc2-0b4a-4ab0-bb15-54814fea6f8a','江行漫興','趙公豫','宋','宋诗','song-poetry','','[]','江南二月好風光，杏蕊桃花間綠楊。',64,'全唐诗/poet.song.156000.json','["江南二月好風光，杏蕊桃花間綠楊。", "是處芳隄嘶牧馬，誰家紅粉盼孤航。", "永嘉時過人皆盡，建業潮來波自揚。", "物理靜觀多變幻，長歌差勝奏笙簧。"]'),
('76fc1a48-3bd6-40d8-b195-2eb0ccf7e4fa','小孤山','趙公豫','宋','宋诗','song-poetry','','[]','一柱巍然秀不頑，近鄰彭澤達沙灣。',64,'全唐诗/poet.song.156000.json','["一柱巍然秀不頑，近鄰彭澤達沙灣。", "吳花带雨參差媚，楚柳迎風次第班。", "屈子行吟傷放廢，淵明歸賦愛投閒。", "勞身未赴安恬計，且向名山幾度攀。"]'),
('2c0509e6-95dd-40be-ba2e-d203e3817e9e','琵琶亭','趙公豫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','誰把琵琶清夜彈，香山靜聽譜無難。',64,'全唐诗/poet.song.156000.json','["誰把琵琶清夜彈，香山靜聽譜無難。", "江州自古成佳話，亭上於今美大觀。", "湓浦新流春漲碧，匡廬徐轉朔風寒。", "遊人不乏留題興，孰擅騷情踞坫壇。"]'),
('2d409dd8-8a42-4aac-a982-fc1f2087fa74','新燕','趙公豫','宋','宋诗','song-poetry','','[]','養成羽翼在雕梁，掠水穿花技本長。',32,'全唐诗/poet.song.156000.json','["養成羽翼在雕梁，掠水穿花技本長。", "舌口瀾翻驚午夢，好風吹到竹方牀。"]'),
('2254cbfa-4a64-4db0-b489-f2bd6136fe4f','采蓮曲','趙公豫','宋','宋诗','song-poetry','','[]','瀲灧溪光似輞川，新荷出水更嫣然。',32,'全唐诗/poet.song.156000.json','["瀲灧溪光似輞川，新荷出水更嫣然。", "爲言全盛紅顔女，莫折花枝入畫船。"]'),
('e8859b8d-2e73-4659-9f43-47e111c93d45','隋堤布市','趙公豫','宋','宋诗','song-poetry','','[]','隋皇宮闕已荒丘，剩水殘山發旅愁。',32,'全唐诗/poet.song.156000.json','["隋皇宮闕已荒丘，剩水殘山發旅愁。", "絲竹管絃成往事，空餘梭布市揚州。"]'),
('f744674d-128c-4b04-ab3e-cde31eebb7f5','維摩寺和冷世修韻','趙公豫','宋','宋诗','song-poetry','','[]','放達得真賞，風流多逸才。',48,'全唐诗/poet.song.156000.json','["放達得真賞，風流多逸才。", "春邀仙子佩，夜雨法王臺。", "雲磬杯前落，曇花曲畔來。", "但教元度在，明月不須來。"]'),
('91f08cf4-9d27-4ad4-9800-0feefa15ed98','古梅','趙公豫','宋','宋诗','song-poetry','','[]','古折何如此，吾知本自根。',48,'全唐诗/poet.song.156000.json','["古折何如此，吾知本自根。", "歷年香不改，易世骨猶存。", "祇守芳心淡，寧期俗士捫。", "逢春百卉艷，對此似兒孫。"]'),
('3d5cb4f0-eca6-431b-bb59-d91cea6c4f3b','桃花塢懷古','趙公豫','宋','宋诗','song-poetry','','[]','塢號桃花著歷陽，張公曾作讀書堂。',64,'全唐诗/poet.song.156000.json','["塢號桃花著歷陽，張公曾作讀書堂。", "琅琅文采光前代，奕奕儒風顯盛唐。", "履境懷人誠韻事，居今稽古屬賢良。", "河流不減當年綠，酌水猶餘翰墨香。"]'),
('1428b5f9-79b8-46d5-973e-01394e9a7808','次韻奉答教授祖守中逢清','趙公豫','宋','宋诗','song-poetry','','[]','方今士習嘆卑微，宮牆何者切瞻依。',288,'全唐诗/poet.song.156000.json','["方今士習嘆卑微，宮牆何者切瞻依。", "祖君守中來倡導，羣材就法識趨歸。", "夙昔風標矜獨步，文壇立幟能直樹。", "論文角藝日無虛，雅會名流常脫屨。", "文旌攬勝英風揚，擊鉢吟成冠詞場。", "芙蓉出水成高調，牛斗直射瑩精光。", "一氈暫屈萍藻淥，相契同官洵邁俗。", "賢宰鳴琴逸韻飛，少尹哦松音調續。", "無殊畹芷與湘蘭，齋頭苜蓿共盤桓。", "擷秀臺前開宴會，合芳亭下結新歡。", "倡酬互見珠璣落，起弊扶衰金石藥。", "名篇大半寶豐年，可以療饑兼濟涸。", "自慚樗櫟薄高林，畢生荏苒嘆浮沉。", "登陟名山應拱手，臨流勝水每縈心。", "但遇瑶編稱汗漫，目動神驚骨髓換。", "表揚前哲本愚衷，敢謂博名標月旦。", "蒙公詩贈率天真，猶觀大匠作輿輪。", "法律豈惟超近日，風神抑且過前人。"]'),
('5e6cdde3-b048-483d-93e7-f9013761619e','郊外','趙公豫','宋','宋诗','song-poetry','','[]','秋色全摇落，幽尋興未窮。',48,'全唐诗/poet.song.156000.json','["秋色全摇落，幽尋興未窮。", "閒雲迴遠岫，飛鳥下孤桐。", "人事寒相迫，楓林老益紅。", "勝遊堪自適，何必上崆峒。"]'),
('8e89204d-6987-4f83-b1e9-7a07f12a5358','登燕子磯','趙公豫','宋','宋诗','song-poetry','','[]','巖石著江干，扁舟依岸難。',48,'全唐诗/poet.song.156000.json','["巖石著江干，扁舟依岸難。", "鐘音清晚嶼，日色下寒灘。", "寺古藤蘿碧，霜嚴木葉丹。", "登臨殊快意，趺坐看迴瀾。"]'),
('2fbcbee8-9fb4-4258-b58b-7fa77b681ae5','迷樓','趙公豫','宋','宋诗','song-poetry','','[]','大業繁華地，荒凉一梵宮。',48,'全唐诗/poet.song.156000.json','["大業繁華地，荒凉一梵宮。", "煙雲猶夙昔，粉黛已成空。", "今古興亡事，循環宇宙中。", "知人與論世，端屬在儒衷。"]'),
('1d8dab49-7481-4b86-bb59-70db2294077e','彭澤懷古','趙公豫','宋','宋诗','song-poetry','','[]','青山環小邑，白水繞孤城。',48,'全唐诗/poet.song.156000.json','["青山環小邑，白水繞孤城。", "楚蜀源流遠，衡廬氣脈清。", "雲浮縈客思，日落動波聲。", "堪羨陶彭澤，歸田不問名。"]'),
('8d333248-c78a-4894-9a75-c3c2c7c46c23','西子湖同馬先生賦','趙公豫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖水澄如練，中流好放歌。',48,'全唐诗/poet.song.156000.json','["湖水澄如練，中流好放歌。", "橋梁通小艇，樓閣倚巖阿。", "響屧廊猶在，採香澤不磨。", "武林佳麗地，遊衍樂如何。"]'),
('4711d795-7d42-4258-b187-3f028e5de763','彭祖井','趙公豫','宋','宋诗','song-poetry','','[]','茫茫海甸幾滄桑，井澤猶餘姓氏香。',64,'全唐诗/poet.song.156000.json','["茫茫海甸幾滄桑，井澤猶餘姓氏香。", "道術盡人誇往事，仙蹤何處仰遺芳。", "雲龍山下風霜冷，戲馬臺邊草木黄。", "惟有城隅一掬水，春秋代謝自清凉。"]'),
('c5073046-557c-4484-9446-44ffcfa7807e','留侯廟','趙公豫','宋','宋诗','song-poetry','','[]','微茫祠宇著山中，曲徑懸崖杖履通。',64,'全唐诗/poet.song.156000.json','["微茫祠宇著山中，曲徑懸崖杖履通。", "一調楚歌聲斷續，八千甲士散西東。", "良臣遠識存真隠，赤帝雄心賦大風。", "惟有彭城留皓月，春秋光照尚和同。"]'),
('8acb2063-650d-481a-a2be-8678390eb279','次韻奉和蔣元甫雝瑞蘭詩兼賀誕孫','趙公豫','宋','宋诗','song-poetry','','[]','名花不與衆爲行，特向瑶階獻吉祥。',64,'全唐诗/poet.song.156000.json','["名花不與衆爲行，特向瑶階獻吉祥。", "一幹亭亭標異彩，數枝燦燦發幽香。", "高懷直與同清艷，雅韻猶能並潔芳。", "積厚流光邀美報，蘭孫應瑞慶華堂。"]'),
('707d6b31-a376-4359-a06b-0413f69c5a7a','偕冷世修遊頂山廣福院','趙公豫','宋','宋诗','song-poetry','','[]','山寺寂無僧，空門白雲冷。',24,'全唐诗/poet.song.156000.json','["山寺寂無僧，空門白雲冷。", "惟有寒松枝，悠然照潭影。"]'),
('83633453-4662-4adb-a94b-701eca833dd5','賦贈容州刺史馬鯁臣持國','趙公豫','宋','宋诗','song-poetry','','[]','扶風家學屬淵泉，刺史分符繼起賢。',64,'全唐诗/poet.song.156000.json','["扶風家學屬淵泉，刺史分符繼起賢。", "坐嘯名篇詞典要，十春佳詠語輕圓。", "虞山蒙幸騰飛蓋，琴水邀榮泛畫船。", "今日遠人尋舊好，摳衣鈴閣拜君前。"]'),
('5efa2902-5271-4f87-872e-428f1b3cff6d','崇德縣簿冷世修招飲','趙公豫','宋','宋诗','song-poetry','','[]','早衙已放又清歌，文采風流孰若何。',64,'全唐诗/poet.song.156000.json','["早衙已放又清歌，文采風流孰若何。", "別圃娛情多典冊，疎籬適興雜藤蘿。", "秋容包燦迷鴻雁，園菊英含續芰荷。", "飽德霏霏談論爽，如觀大匠斧高柯。"]'),
('287ae2ef-acf3-40e4-8c43-a8a898ccb295','贈池州倅趙漢卿昂發','趙公豫','宋','宋诗','song-poetry','','[]','池陽別駕號宗工，博雅持衡景岱嵩。',64,'全唐诗/poet.song.156000.json','["池陽別駕號宗工，博雅持衡景岱嵩。", "召杜興歌德並美，龔黄政績頌同功。", "清華獨擅標江左，偉望無雙冠域中。", "何幸旌旄來吳會，得瞻懿範沐仁風。"]'),
('2516e4bb-99d0-445d-9f27-5c391c96a050','賦答錢塘馬先生見貽即次原韻','趙公豫','宋','宋诗','song-poetry','','[]','三秋初屆雨凄凄，序轉重陽風日西。',64,'全唐诗/poet.song.156000.json','["三秋初屆雨凄凄，序轉重陽風日西。", "正苦僧房無快境，貽來新咏自珍携。", "芙蓉带水成真艷，鴻雁凌霜作夜啼。", "擬過高軒聆妙諦，恐勞齋供太常妻。"]'),
('d3b70bc2-2422-448e-bf4e-27ab5957cbcc','和馬先生再疊前韻','趙公豫','宋','宋诗','song-poetry','','[]','連朝襆被冷凄凄，客屐湘江到浙西。',64,'全唐诗/poet.song.156000.json','["連朝襆被冷凄凄，客屐湘江到浙西。", "長嘆故園秋漸老，快逢詩伯句頻携。", "迴廊待月來僧梵，曲徑看花聽鳥啼。", "轉盼雪霜應按候，調琴協瑟念山妻。"]'),
('47331a26-8c83-4424-9896-84319a10bcdb','和馬先生留飲三疊前韻','趙公豫','宋','宋诗','song-poetry','','[]','招飲醇醪破寂凄，夕陽掩映畫樓西。',64,'全唐诗/poet.song.156000.json','["招飲醇醪破寂凄，夕陽掩映畫樓西。", "狂瀾就下偏維挽，峻嶺難登每屐携。", "自有珠光能射照，無嫌馭屈作悲啼。", "連朝擬訂盤餐約，誰主僧庖代故妻。"]'),
('f59b7677-f7aa-48fc-92d5-2fefcffdf982','和馬先生雨中見過四疊前韻','趙公豫','宋','宋诗','song-poetry','','[]','連朝風雨苦凄凄，郵得賢書到浙西。',64,'全唐诗/poet.song.156000.json','["連朝風雨苦凄凄，郵得賢書到浙西。", "带屐衝泥叨飫液，貽來新咏又相携。", "清霜落木初成絳，淺渚依鴻半作啼。", "偶合溫家諧韻事，司農掌印有能妻。"]'),
('aeaac394-ffc9-47c2-944c-33cf102cc74c','夜窗獨飲五疊前韻呈馬先生','趙公豫','宋','宋诗','song-poetry','','[]','雲舒風布景凄凄，秋色繽紛遍浙西。',64,'全唐诗/poet.song.156000.json','["雲舒風布景凄凄，秋色繽紛遍浙西。", "愧我厨荒情未展，蒙公誼篤酒頻携。", "深嘉經緯匡時俗，還羨詩歌當笑啼。", "獨酌亦能消永夜，倡酬殊苦少荆妻。"]'),
('7b9ab683-c614-4ab0-9049-5aa36ff7cdd9','和馬先生曉起六疊前韻','趙公豫','宋','宋诗','song-poetry','','[]','秋英漸落景幽凄，嘆息征衫滯浙西。',64,'全唐诗/poet.song.156000.json','["秋英漸落景幽凄，嘆息征衫滯浙西。", "三竺風光公素覽，兩峰山色我新携。", "禪房境冷逢仙侶，客子心閒愛鳥啼。", "揖別黯然情未已，曰歸難對樂羊妻。"]'),
('c99154e8-ff01-4c7d-a376-42f98fb10c0a','蘭谿范茂明過江來訪和韻見貽七疊前韻奉答','趙公豫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','倡酬已六破荒凄，詞客貽吟又日西。',64,'全唐诗/poet.song.156000.json','["倡酬已六破荒凄，詞客貽吟又日西。", "欲罷未能情寓勝，將歸更喜友相携。", "上天竺外霜華重，西子湖頭烏夜啼。", "此境盤桓差快意，無煩鼓瑟並姬妻。"]'),
('b4539e72-506d-4fe9-91aa-5705e2afe8f7','和馬先生贈別八疊前韻','趙公豫','宋','宋诗','song-poetry','','[]','小酌僧房破冷凄，明朝分手各東西。',64,'全唐诗/poet.song.156000.json','["小酌僧房破冷凄，明朝分手各東西。", "一肩行李帆檣便，尺幅龍蛇什襲携。", "水驛山程勞記憶，天光雲影任歌啼。", "得通音問憑魚素，此際傷情似女妻。"]'),
('8bd9241a-ed31-4c76-9f85-d0cacd012c51','慈教寺同冷世修賦','趙公豫','宋','宋诗','song-poetry','','[]','古剎傍江頭，憑高豁遠眸。',48,'全唐诗/poet.song.156000.json','["古剎傍江頭，憑高豁遠眸。", "雲光時散合，山影半沉浮。", "不語參空界，隨緣作勝遊。", "老僧指點處，心事幾多休。"]'),
('a62088d3-6d77-4be4-9129-e0598e09d5c6','立春日作','趙公豫','宋','宋诗','song-poetry','','[]','春風有脚到柴門，最愛朝曦氣自溫。',64,'全唐诗/poet.song.156000.json','["春風有脚到柴門，最愛朝曦氣自溫。", "養性頗知學是貴，涵情尤識道稱尊。", "土牛應候農功起，木鐸傳音官儆存。", "惟願四方成樂歲，投戈解甲牧雞豚。"]'),
('e027b657-3171-46c7-a494-d942c9779936','書建州刺史鮑祗勸農詩後','趙公豫','宋','宋诗','song-poetry','','[]','使君勸稼泛清溪，纔問高田又及低。',64,'全唐诗/poet.song.156000.json','["使君勸稼泛清溪，纔問高田又及低。", "蛙鼓鳴畦芳草際，鶑梭擲柳畫橋西。", "堪憐南畝波生浪，且喜東莊麥秀齊。", "五首新詩發性府，還從老稚慰呼啼。"]'),
('26bf5771-373c-4e58-9806-d9645fa88eec','主簿陳元矩署中畜鵝','趙公豫','宋','宋诗','song-poetry','','[]','素羽稱修潔，蒼音聽不禁。',48,'全唐诗/poet.song.156000.json','["素羽稱修潔，蒼音聽不禁。", "田間宜養育，官舍莫棲侵。", "博愛儒生量，矜全物性心。", "從今傳韻事，誰謂擅山陰。"]'),
('373223d8-0950-46b3-ba4f-7e06c2be3d8e','納凉','趙公豫','宋','宋诗','song-poetry','','[]','移榻空亭納晚凉，更深露下芰荷香。',32,'全唐诗/poet.song.156000.json','["移榻空亭納晚凉，更深露下芰荷香。", "行雲敏捷如流水，愛有遊螢入畫梁。"]'),
('0c1b0518-b4d3-4d6e-bf6a-2d45133f6383','江寧阻風','趙公豫','宋','宋诗','song-poetry','','[]','籬落雞豚傍水涯，蕭蕭楊柳放新芽。',32,'全唐诗/poet.song.156000.json','["籬落雞豚傍水涯，蕭蕭楊柳放新芽。", "石尤故逞波濤惡，使我行蹤看晚霞。"]'),
('ea3da901-f1f1-4e6b-ad4c-898208da83c1','華佗墓  其一','趙公豫','宋','宋诗','song-poetry','','[]','操技頗稱良，全身苦不早。',24,'全唐诗/poet.song.156000.json','["操技頗稱良，全身苦不早。", "堪嗟魏老瞞，今亦同枯槁。"]'),
('7635a459-0f3a-430c-8b83-614d0ab314a1','華佗墓  其二','趙公豫','宋','宋诗','song-poetry','','[]','古墓尚巍然，蒙茸皆宿草。',24,'全唐诗/poet.song.156000.json','["古墓尚巍然，蒙茸皆宿草。", "經春一發生，士女爭祈禱。"]'),
('c4aababd-ef1c-4d6e-91e8-9ad702b2aeea','漂母祠','趙公豫','宋','宋诗','song-poetry','','[]','英雄未得志，落魄有誰憐。',24,'全唐诗/poet.song.156000.json','["英雄未得志，落魄有誰憐。", "一飯尋常事，千秋頌母賢。"]'),
('0011082a-62cd-4e88-a325-edfafc6eab7a','廿四橋','趙公豫','宋','宋诗','song-poetry','','[]','橋在大業間，今日已傾圮。',24,'全唐诗/poet.song.156000.json','["橋在大業間，今日已傾圮。", "萬古長不磨，雲山並煙水。"]'),
('82c40683-414a-40fe-ae8a-658aafcb6be9','逵弟招飲','趙公豫','宋','宋诗','song-poetry','','[]','天潢家世本同宗，玉質亭亭似岱嵩。',64,'全唐诗/poet.song.156000.json','["天潢家世本同宗，玉質亭亭似岱嵩。", "海國快逢情契合，華堂盛集酒香濃。", "談詩雅以唐爲法，植品端惟漢是從。", "握手雉皋旋別去，暮雲春樹想高蹤。"]'),
('5b5ed95f-c953-4d20-b7ca-ad5a46722077','玻璃泉','趙公豫','宋','宋诗','song-poetry','','[]','都梁環繞盡高山，山下幽泉沁齒甘。',64,'全唐诗/poet.song.156000.json','["都梁環繞盡高山，山下幽泉沁齒甘。", "入境頓忘人事擾，臨流能潤舌喉乾。", "孤亭掩映風雲幻，曲檻迷離煙雨寒。", "泗地年來成澤國，奠安常作救時看。"]'),
('5c518a52-24a7-445d-a4b2-6ff46feb99e1','送漢卿再判池州','趙公豫','宋','宋诗','song-poetry','','[]','閥閲清華自職方，長才重蒞古池陽。',64,'全唐诗/poet.song.156000.json','["閥閲清華自職方，長才重蒞古池陽。", "刑曹借箸邀宸眷，秋浦分符定廟堂。", "熊輅聲聞舒驥足，朱旗色映快龍光。", "公餘寄興耽文字，彩筆仍流翰墨香。"]'),
('6945693d-9693-4d3c-8050-71057ad88f36','喜范茂明至','趙公豫','宋','宋诗','song-poetry','','[]','蘭陵江下富春連，三色桃花色澤鮮。',64,'全唐诗/poet.song.156000.json','["蘭陵江下富春連，三色桃花色澤鮮。", "夜雨忽然添尺漲，曉寒猶可著重綿。", "輕囊括盡煙霞趣，逸興吟成風月篇。", "太息塵氛京雒客，誰能瀟洒得安禪。"]'),
('fe4f2427-3bb6-4066-8504-e0d80ede1ac0','徐孺子祠墓','趙公豫','宋','宋诗','song-poetry','','[]','孺子遺蹤何處尋，進賢門外樹森森。',64,'全唐诗/poet.song.156000.json','["孺子遺蹤何處尋，進賢門外樹森森。", "登堂展拜情維繫，過墓傾心敬自深。", "剩有黄鸝鳴院落，還來雲影覆山陰。", "章江積雨增愁思，此日新晴爽客襟。"]'),
('e13e1ec9-9296-4c1f-9d26-8bb548d22157','呂梁洪','趙公豫','宋','宋诗','song-poetry','','[]','呂梁籬落走雞豚，小泊扁舟日已昏。',64,'全唐诗/poet.song.156000.json','["呂梁籬落走雞豚，小泊扁舟日已昏。", "極目黄流來汴泗，有情明月匝煙村。", "隄長柳密巢歸鳥，水急風高浪打門。", "此去彭城知不遠，憑今弔古我思存。"]'),
('ccca5a48-89de-4569-bcd1-fd90efd81efc','戲馬臺','趙公豫','宋','宋诗','song-poetry','','[]','戲馬臺邊風色寒，黄河晝夜水瀰漫。',64,'全唐诗/poet.song.156000.json','["戲馬臺邊風色寒，黄河晝夜水瀰漫。", "椎心每恨英雄盡，放眼還知天地寬。", "宴設鴻門王氣在，煙銷秦闕霸圖殘。", "知幾亞父身先死，不見陰陵行路難。"]'),
('5575187c-0d6a-4f82-bad2-144122568cc3','同鮑祗登醉翁亭看歐陽公手植梅花','趙公豫','宋','宋诗','song-poetry','','[]','歐亭猶在望，梅萼自芬芳。',48,'全唐诗/poet.song.156000.json','["歐亭猶在望，梅萼自芬芳。", "地以人爲重，花爲植者香。", "山峰皆拱列，石骨盡昂藏。", "文采風流事，參軍獨擅場。"]'),
('817193ed-61aa-4466-80b6-8f74aeca6147','上巳','趙公豫','宋','宋诗','song-poetry','','[]','蕪城逢上巳，散步答年光。',48,'全唐诗/poet.song.156000.json','["蕪城逢上巳，散步答年光。", "北郭垂楊媚，西郊碧草芳。", "人皆趨靡麗，我獨戀春陽。", "更愛雙飛燕，翩翩語畫梁。"]'),
('11e82054-9b37-4459-944b-569f9a15c82f','浮梁舟行','趙公豫','宋','宋诗','song-poetry','','[]','一棹沿溪上，沙明水更清。',48,'全唐诗/poet.song.156000.json','["一棹沿溪上，沙明水更清。", "迷濛細雨濕，起落片帆輕。", "磐石中流出，新篁遠岸生。", "客心無所繫，閒坐聽春鶑。"]'),
('502a832e-0bcb-40f7-9eb8-f7ed5a5e206a','祁門駁','趙公豫','宋','宋诗','song-poetry','','[]','舟小名爲駁，臨河體實輕。',48,'全唐诗/poet.song.156000.json','["舟小名爲駁，臨河體實輕。", "捫灘魚貫上，放溜雁行行。", "雲氣仙山靜，風聲遠樹鳴。", "時和春又暮，曠覽可娛情。"]'),
('176c2b66-8809-4f49-bb38-e7977858cd56','黄岡','趙公豫','宋','宋诗','song-poetry','','[]','黄岡臨古岸，依谷盡人家。',48,'全唐诗/poet.song.156000.json','["黄岡臨古岸，依谷盡人家。", "老稚崇清儉，衣冠鄙俗華。", "花香幽徑僻，鳥噪夕陽斜。", "俯仰情何寄，煙霞自足誇。"]'),
('825a7ed0-fb30-4371-8ba8-5a734735d7c5','滕王閣','趙公豫','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','佳名由帝子，千載尚餘芳。',48,'全唐诗/poet.song.156000.json','["佳名由帝子，千載尚餘芳。", "带水來章貢，羣山擁豫章。", "樓臺誇壯麗，魚鳥煥清光。", "粉壁多詞翰，風流孰擅長。"]'),
('b344c5a3-94e6-4175-bfc2-823c4c00d874','望廬山','趙公豫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山何峻極，一望盡蒼清。',48,'全唐诗/poet.song.156000.json','["廬山何峻極，一望盡蒼清。", "不辨松杉色，誰聞鐘磬聲。", "飛崖懸瀑布，幽谷語春鶑。", "堪羨巖栖士，空餘人世情。"]'),
('20417411-6dd5-4428-b870-d82c5e2c18b4','大孤山','趙公豫','宋','宋诗','song-poetry','','[]','客路將幾月，舟行見大孤。',48,'全唐诗/poet.song.156000.json','["客路將幾月，舟行見大孤。", "時和花爛熳，景淑鳥飛呼。", "徑有煙霞氣，村無市井夫。", "曠觀多樂趣，何事苦嗟吁。"]'),
('33ae69e5-0a53-40d6-90aa-bad61ed70d67','陪錢塘馬先生遊兩峰僧寺','趙公豫','宋','宋诗','song-poetry','','[]','兩峰舟少阻，精舍可橋通。',48,'全唐诗/poet.song.156000.json','["兩峰舟少阻，精舍可橋通。", "竹映階苔綠，桃侵佛幔紅。", "心縈章貢外，情寄笑談中。", "坐久愁煩渴，供茶愛遠公。"]'),
('06c61711-319e-42ad-a11a-5aff429365ca','冷泉亭','趙公豫','宋','宋诗','song-poetry','','[]','泉不因人熱，淵源自古今。',48,'全唐诗/poet.song.156000.json','["泉不因人熱，淵源自古今。", "名流耽韻致，智士悅清音。", "徑有煙霞趣，亭無鳥鼠侵。", "浮生徒碌碌，誰自滌凡心。"]'),
('021a8486-26b7-4f4a-82fd-a77d35b158f3','岑山','趙公豫','宋','宋诗','song-poetry','','[]','山踞浙流頂，波聲聳獨尊。',48,'全唐诗/poet.song.156000.json','["山踞浙流頂，波聲聳獨尊。", "帆檣移野浦，鐘磬出烟村。", "脩竹凉風咽，巨魚暑氣吞。", "層巔一矯首，海面見雲根。"]'),
('c6eef85b-fe2d-4062-a20c-84bebe70aba6','謁伍大夫廟','趙公豫','宋','宋诗','song-poetry','','[]','策馬昭關道，投鞭弔昔賢。',48,'全唐诗/poet.song.156000.json','["策馬昭關道，投鞭弔昔賢。", "荒庭多鼠雀，古屋飽雲烟。", "覆楚勳勞淺，强吳智略全。", "英雄精爽在，瞻拜一凄然。"]'),
('44d39dfc-7735-45dc-9cad-7bcfc462eaf7','邗上聞鶑','趙公豫','宋','宋诗','song-poetry','','[]','邗堤芳草軟如綿，夭桃媚柳何娟娟。',139,'全唐诗/poet.song.156000.json','["邗堤芳草軟如綿，夭桃媚柳何娟娟。", "朱欄繡閣依山巔，萬仞巍巍直接天。", "坐卧其中似畫船，開簾俯視小百川。", "牙檣錦纜泊江邊，紅顔放棹來翩躚。", "歌音繚繞落花前，傾耳聽之清且圓。", "倉庚飛翮羽毛鮮，嬌啼婉轉極清妍。", "高風盛德頌前賢，徘徊勝事堪流連。", "君不見吳歌楚舞變桑田，雄圖霸業沉深淵，黄鸝睍睆迷村烟。"]'),
('a263b250-fd59-45a1-8229-068fecd77254','桃花','趙公豫','宋','宋诗','song-poetry','','[]','亭亭一樹燦窗前，氣暖風和分外妍。',32,'全唐诗/poet.song.156000.json','["亭亭一樹燦窗前，氣暖風和分外妍。", "何必桃源尋異處，此間談笑亦神仙。"]'),
('e4d52140-052c-4b4f-be08-aeef635d40d4','哀呂東萊  其一','徐安國','宋','宋诗','song-poetry','','[]','師友曾亡幾，南軒足舊聞。',48,'全唐诗/poet.song.156000.json','["師友曾亡幾，南軒足舊聞。", "嚴陵忻請益，荆渚黯臨分。", "慟哭情方切，招魂志愈勤。", "幡然均地下，應與共修文。"]'),
('86d979c9-5b28-4798-872e-cc28282cf617','哀呂東萊  其二','徐安國','宋','宋诗','song-poetry','','[]','感涕門闌舊，由來豈苟然。',48,'全唐诗/poet.song.156000.json','["感涕門闌舊，由來豈苟然。", "茶山參活法，婺女拾殘編。", "記錄書猶在，忘言意已傳。", "續燈身後事，先是有同年。"]'),
('64359ae8-3e39-4f0a-8294-21032c16fa56','題洪氏浴室院','徐安國','宋','宋诗','song-poetry','','[]','斗橫宴坐一蒲團，丈室寥寥夢境寒。',64,'全唐诗/poet.song.156000.json','["斗橫宴坐一蒲團，丈室寥寥夢境寒。", "夜炷波涵烟易冷，秋簷冰浸露先漙。", "潭中寂境心灰見，鏡裏虛形面壁觀。", "俛仰清光無盡藏，細分沙界萬塵寬。"]'),
('b32eeb1a-661e-45a5-8582-dead6b16ea7c','登古鉢嶺謁慈感祠下','徐安國','宋','宋诗','song-poetry','','[]','郡嶺中推古鉢尊，山川羅列掌中存。',32,'全唐诗/poet.song.156000.json','["郡嶺中推古鉢尊，山川羅列掌中存。", "亭臺突兀聖婆廟，邱垤逶迤山子村。"]'),
('3a100c45-1d90-4df7-a7ad-8bf41b792650','寶華山','徐安國','宋','宋诗','song-poetry','','[]','秀出城南號寶華，翠微深處衲僧家。',32,'全唐诗/poet.song.156000.json','["秀出城南號寶華，翠微深處衲僧家。", "百年臺殿歸煨燼，一徑蒼苔落晚花。"]'),
('d346d67b-9f5b-4af1-8b1d-25295d4ba66f','橫州龍池','徐安國','宋','宋诗','song-poetry','','[]','爲谷爲陵事已非，靈源匯澤發光輝。',32,'全唐诗/poet.song.156000.json','["爲谷爲陵事已非，靈源匯澤發光輝。", "有時風雨連村暗，夜半龍遊古鉢歸。"]'),
('0c7324a9-42ac-48e5-a2f7-08fad44afe88','橫浦','徐安國','宋','宋诗','song-poetry','','[]','暑風披拂瘴烟收，獨倚危樓豁遠眸。',32,'全唐诗/poet.song.156000.json','["暑風披拂瘴烟收，獨倚危樓豁遠眸。", "萬疊山圍城堞古，一灣江抱海槎浮。"]'),
('e7b4bcca-5653-4cad-be5e-9ae1e7f6f36b','妙庭觀  其一','徐安國','宋','宋诗','song-poetry','','[]','玉笙聲絕瑶池杳，桂殿風生幾度寒。',32,'全唐诗/poet.song.156000.json','["玉笙聲絕瑶池杳，桂殿風生幾度寒。", "空使時人慕雞犬，掃除槃鼎舐遺丹。"]'),
('c73aae6f-5642-4928-9657-08a41645ee08','妙庭觀  其二','徐安國','宋','宋诗','song-poetry','','[]','雲軿不許折鐺追，太白遺詩人亦疑。',32,'全唐诗/poet.song.156000.json','["雲軿不許折鐺追，太白遺詩人亦疑。", "千載何人爲湔拂，謝家春草又生池。"]'),
('da320e83-5b08-4cb1-93fb-d4417a1d491b','妙庭觀  其三','徐安國','宋','宋诗','song-poetry','','[]','槐覆星壇惟舊跡，土埋丹鼎不知時。',32,'全唐诗/poet.song.156000.json','["槐覆星壇惟舊跡，土埋丹鼎不知時。", "刻舟何處長生路，回音海山空賦詩。"]'),
('09df9681-c291-43ef-8876-937e5db37241','大滌洞','徐安國','宋','宋诗','song-poetry','','[]','大滌山藏碧玉函，神龍護穴虎馴巖。',32,'全唐诗/poet.song.156000.json','["大滌山藏碧玉函，神龍護穴虎馴巖。", "華陽邃道通仙處，始見元同骨不凡。"]'),
('9f2c90b0-cc1d-481a-a567-c361d2cecde8','石牀','徐安國','宋','宋诗','song-poetry','','[]','枯藤老大似虬懸，一榻留雲對洞門。',32,'全唐诗/poet.song.156000.json','["枯藤老大似虬懸，一榻留雲對洞門。", "無復高人眠醉石，空留芳草引王孫。"]'),
('fa3024ca-af18-4c30-9bb9-61d1a26e456a','登舟','徐安國','宋','宋诗','song-poetry','','[]','廛市塵埃苦沒頭，霜晴清興動林丘。',64,'全唐诗/poet.song.156000.json','["廛市塵埃苦沒頭，霜晴清興動林丘。", "買舟迤邐窮觀覽，載酒從容作拍浮。", "山遠眼隨飛鳥入，溪清身與戲鱼遊。", "遥觀九曲山如鎖，說與篙人緩放舟。"]'),
('be5724e8-c0a6-48a7-8559-be97e1c1536c','道院','徐安國','宋','宋诗','song-poetry','','[]','齋餘深炷一爐香，宴坐怡神閲寶章。',32,'全唐诗/poet.song.156000.json','["齋餘深炷一爐香，宴坐怡神閲寶章。", "夜靜沉沉天籟息，步虛聲起月回廊。"]'),
('7a4ae39b-22c3-46b3-ad4b-c543a5e2088b','天壇','徐安國','宋','宋诗','song-poetry','','[]','峩峩大滌拄天寒，白鹿來迎上界官。',32,'全唐诗/poet.song.156000.json','["峩峩大滌拄天寒，白鹿來迎上界官。", "挹景太霄千載後，猶思冠珮上天壇。"]'),
('0d5a061c-1838-4d45-99b8-e6390f3047c9','放水澗','徐安國','宋','宋诗','song-poetry','','[]','一澗無人測水源，閘開石面瀉奔湍。',32,'全唐诗/poet.song.156000.json','["一澗無人測水源，閘開石面瀉奔湍。", "建瓴已自驚凡目，機錦那鋪澗底看。"]'),
('dc375cf5-0201-4288-9248-39862349f56c','歸雲洞','徐安國','宋','宋诗','song-poetry','','[]','百里周回□蓋天，迴車盡指後門旋。',32,'全唐诗/poet.song.156000.json','["百里周回□蓋天，迴車盡指後門旋。", "悠然一片雲飛晚，指點歸來沙苑仙。"]'),
('22b33374-65a5-4a28-82c2-69385f27332e','雲根','徐安國','宋','宋诗','song-poetry','','[]','出岫俄生一片陰，拄筇行到水窮尋。',32,'全唐诗/poet.song.156000.json','["出岫俄生一片陰，拄筇行到水窮尋。", "千年留得深根在，盤古埋藏古澗心。"]'),
('ddf55451-59c8-492c-94dc-01579172197d','藥圃','徐安國','宋','宋诗','song-poetry','','[]','滿山綠葉與紅英，瓊圃皆由種植榮。',32,'全唐诗/poet.song.156000.json','["滿山綠葉與紅英，瓊圃皆由種植榮。", "翻笑無人繼真跡，靈芝惟望自天成。"]'),
('e066fa21-8b26-493d-b26c-cd2903a0370e','茶嶺','徐安國','宋','宋诗','song-poetry','','[]','天柱峰頭撥曉雲，靈芽一寸得先春。',32,'全唐诗/poet.song.156000.json','["天柱峰頭撥曉雲，靈芽一寸得先春。", "紫芹綠筍方知貴，雷發鎗旗未足珍。"]'),
('6379ff7d-5119-495c-b5dc-19d69b9da19d','白茅洞','徐安國','宋','宋诗','song-poetry','','[]','鑿石成壺不記年，洞門如井忽昇仙。',32,'全唐诗/poet.song.156000.json','["鑿石成壺不記年，洞門如井忽昇仙。", "軒然笞鳳鞭鸞客，翻作醯雞舞甕天。"]'),
('1d0e183e-4105-4455-99c1-21e6409a3b59','馴虎巖','徐安國','宋','宋诗','song-poetry','','[]','害物無如猛獸雄，懼心不起獸難從。',32,'全唐诗/poet.song.156000.json','["害物無如猛獸雄，懼心不起獸難從。", "能探虎口同兒戲，異類從茲不見蹤。"]'),
('51b49172-a43f-43f1-89dd-6b5862d60f1f','龍洞','徐安國','宋','宋诗','song-poetry','','[]','泉脉潛深貫海湫，陰霾晴雹四時秋。',32,'全唐诗/poet.song.156000.json','["泉脉潛深貫海湫，陰霾晴雹四時秋。", "憑誰爲探驪龍睡，好把靈珠頷下求。"]'),
('aa0a8a46-716c-44a5-8b31-3b78dc6a6b43','鳳洞','徐安國','宋','宋诗','song-poetry','','[]','帝遣持將紫詔來，山前九鎖一時開。',32,'全唐诗/poet.song.156000.json','["帝遣持將紫詔來，山前九鎖一時開。", "洞天絕境勝阿閣，覽德飛翔日幾回。"]'),
('c358eebb-8bf9-4bb2-971e-cd1a22f4342d','無骨箬','徐安國','宋','宋诗','song-poetry','','[]','三足碧蟬巖下見，千年丹鼎地中開。',32,'全唐诗/poet.song.156000.json','["三足碧蟬巖下見，千年丹鼎地中開。", "故令紺箬生無骨，要表真仙蛻骨來。"]'),
('23ca25de-49b5-4dfe-b04b-ba5d3a525d4b','祥光亭','徐安國','宋','宋诗','song-poetry','','[]','地藏金玉自通靈，草木英華發粹精。',32,'全唐诗/poet.song.156000.json','["地藏金玉自通靈，草木英華發粹精。", "朮塢芝畦化瓊圃，祥光終日滿山明。"]'),
('490f6865-1e60-4b1b-8282-37bf6cb4f88c','翠微亭','徐安國','宋','宋诗','song-poetry','','[]','拄上風煙脚力頑，華亭深入翠微寒。',32,'全唐诗/poet.song.156000.json','["拄上風煙脚力頑，華亭深入翠微寒。", "千巖萬壑爭呈秀，獨指中峰一柱香。"]'),
('a145c610-46a5-494b-a175-9d883baad4b0','石室','徐安國','宋','宋诗','song-poetry','','[]','編茅結屋附琳宮，索價何高少室同。',32,'全唐诗/poet.song.156000.json','["編茅結屋附琳宮，索價何高少室同。", "妙黑流傳天上去，一山松竹獨吟風。"]'),
('53db8044-e60b-498f-8a57-20e3761d5e1a','清音亭','徐安國','宋','宋诗','song-poetry','','[]','山川無古亦無今，只在游人得趣深。',32,'全唐诗/poet.song.156000.json','["山川無古亦無今，只在游人得趣深。", "洗耳屏除箏與笛，來賢幾個是知音。"]'),
('7ab87d50-fc7e-463d-81a9-45b7c7d8161f','冷泉亭','徐安國','宋','宋诗','song-poetry','','[]','道人心迹已雙清，更挹寒泉滌俗情。',32,'全唐诗/poet.song.156000.json','["道人心迹已雙清，更挹寒泉滌俗情。", "徙倚虛亭無一事，笑予塵土滿冠纓。"]'),
('06c86566-cf2f-4906-b90b-6892de42d02a','石門','徐安國','宋','宋诗','song-poetry','','[]','神刻鬼鑿石爲門，九鎖回環隠帝閽。',32,'全唐诗/poet.song.156000.json','["神刻鬼鑿石爲門，九鎖回環隠帝閽。", "斸藥採芝尋古路，清泉能漱烏能言。"]'),
('383630d9-8cd3-4ebd-a1f7-f80eee44b350','舞翠閣','徐安國','宋','宋诗','song-poetry','','[]','澗邊蟠木歲時深，更著華亭倚翠陰。',32,'全唐诗/poet.song.156000.json','["澗邊蟠木歲時深，更著華亭倚翠陰。", "風下四山蛟起舞，洞中攪動蟄龍心。"]'),
('0a1c0ef4-18a6-41b0-a1de-5cecc6370cf2','歸雲庵','徐安國','宋','宋诗','song-poetry','','[]','忽舒忽卷豈無期，萬狀來呈變化姿。',32,'全唐诗/poet.song.156000.json','["忽舒忽卷豈無期，萬狀來呈變化姿。", "峰帽石衣羅眼底，蒼然暮色欲來時。"]'),
('de0a7068-7897-4e9f-b211-7c9a7c1adf7f','題洪氏浴室院','徐安國','宋','宋诗','song-poetry','','[]','百念灰寒一性空，森然萬象在其中。',64,'全唐诗/poet.song.156000.json','["百念灰寒一性空，森然萬象在其中。", "靜觀寂照銜沙界，翻笑空華翳化宮。", "金屑未除心境異，尼珠獨耀古今同。", "箇中有見非真見，未掩簾時妙無窮。"]'),
('330c6871-65f8-4684-b303-66e820bd251f','句  其一','徐安國','宋','宋诗','song-poetry','','[]','古辣觴客醉，寶華鎸句清。',12,'全唐诗/poet.song.156000.json','["古辣觴客醉，寶華鎸句清。"]'),
('5ce0e734-a734-46d2-80d5-53bfd24b37e4','句  其二','徐安國','宋','宋诗','song-poetry','','[]','出郭扶筇上翠屏，却從雲隙望莎城。',16,'全唐诗/poet.song.156000.json','["出郭扶筇上翠屏，却從雲隙望莎城。"]'),
('ab7f6cf9-052f-44ce-8c18-bd39d66d530c','次楊咸亨江郊亭新成二十三韻','單夔','宋','宋诗','song-poetry','','[]','瞿塘一門江水傾，羣趨激射隨奔鯨。',368,'全唐诗/poet.song.156000.json','["瞿塘一門江水傾，羣趨激射隨奔鯨。", "舟車冠蓋湊蜀道，孰問張丈聯殷兄。", "相逢來往問地主，太守詎敢忘將迎。", "白崖候館久茅蕝，近即野處披榛荆。", "屏修啟剔作廬舍，夙戒里旅遲留行。", "有如綬館及郊勞，舉國定制誰先鳴。", "錢塘鄙人何所似，抵掌自視鴻毛輕。", "食焉抑畏墮偷懦，汎觀彼己同虛盈。", "山溪水滸肆登賞，靡識傑閣誇崢嶸。", "朋從簪盍得衆雋，麈譚冰釋欣初晴。", "鼎新贊我築斯館，棟宇不貴朱連甍。", "入門便足庇風雨，揭榜却借江郊名。", "時哉蓮幕有嘉客，落筆能令風雨驚。", "聯篇累牘溢我目，粲花麗藻舒我情。", "人生悟合良快意，胡爲四美嗟難并。", "日光天際發豐蔀，此去可並依離明。", "直排閶闔出灧澦，肅肅東首歌宵征。", "循崖履坦竟無阻，爲君留取能詩聲。", "此榜與詩儻不朽，此館想同江水清。", "我來歲月媿銷縮，整纓輯屨圖歸程。", "遺名肯復計身後，謹愿第虞槃水擎。", "始終感慨遇僚友，遂事且喜相須成。", "勉旃功業早期就，發軔自是天衢亨。"]'),
('98ec9f28-eec6-4954-9f6f-2fb87900c8db','挽崔舍人  其一','陳蒼舒','宋','宋诗','song-poetry','','[]','早結淵衷眷，英名擅四方。',48,'全唐诗/poet.song.156000.json','["早結淵衷眷，英名擅四方。", "獻箴誠剴切，屢諫極忠良。", "勸講黄金殿，修辭白玉堂。", "簪紳歆盛美，何事遽云亡。"]'),
('d7c01ee9-f206-40c2-a9a7-65f5b2769109','挽崔舍人  其二','陳蒼舒','宋','宋诗','song-poetry','','[]','昔宰金淵日，獲從二陸遊。',48,'全唐诗/poet.song.156000.json','["昔宰金淵日，獲從二陸遊。", "同朝深自喜，投袂意相稠。", "□□方驚歿，公乎遽若休。", "佳城知有日，老淚灑西州。"]'),
('279f37f6-c2fe-43fb-a614-7b3322c0465c','題店壁','董風子','宋','宋诗','song-poetry','','[]','太乙元君遇虎龍，沉沉三洞鎖青風。',32,'全唐诗/poet.song.156000.json','["太乙元君遇虎龍，沉沉三洞鎖青風。", "自從九九朋分了，白髮黄金黑變紅。"]'),
('e4089e2e-d442-46cb-966d-1ec35059ee5f','石芥','梁安世','宋','宋诗','song-poetry','','[]','擷根山石貯瓶罌，柱後緘題見者頳。',64,'全唐诗/poet.song.156000.json','["擷根山石貯瓶罌，柱後緘題見者頳。", "風味莫嫌無醖藉，盃柈亦解作聰明。", "願言則嚏傳心事，搔首躊躕散宿酲。", "最是徂徠明道地，至今姦膽亦魂驚。"]'),
('731ca505-9543-4150-82d3-32b13b64764c','張相公祠','梁安世','宋','宋诗','song-poetry','','[]','五湖煙浪渺難尋，有像區區欲鑄金。',32,'全唐诗/poet.song.156000.json','["五湖煙浪渺難尋，有像區區欲鑄金。", "試問鐵胎身後事，何如羽扇用時心。"]'),
('9cb4e681-cb75-47f9-a138-dd64438753f5','桂林','梁安世','宋','宋诗','song-poetry','','[]','列城二十五，去國一百舍。',24,'全唐诗/poet.song.156000.json','["列城二十五，去國一百舍。", "西夷蟻穴通，南島鯨波駕。"]'),
('21786259-5527-426e-a680-c187c806061c','贈王錫老','梁安世','宋','宋诗','song-poetry','','[]','審齋先生世稀有，曾是金陵一耆舊。',240,'全唐诗/poet.song.156000.json','["審齋先生世稀有，曾是金陵一耆舊。", "萬卷胸中星斗文，百篇筆下龍蛇走。", "淵源更擅麟史長，碑版肯居鰐文後。", "倚馬常摧鏖戰場，脫腕難供掃愁帚。", "中州文獻儒一門，異縣萍蓬家百口。", "恨極黄楊厄閏年，閒却玉堂揮翰手。", "夜光乾沒世稱屈，遠枳卑栖價低售。", "漂摇何地著此翁，忘憂夜醉長沙酒。", "豈無厚祿故人來，爲辦草堂留野叟。", "嗟余亦是可憐人，慚愧阿戎驚白首。", "一燈續得審齋光，多少達人爲裔胄。", "睠予憔悴五峰下，頻寄篇來復相壽。", "年來事事淋過灰，尚有詩情閒情竇。", "有時信筆不自置，憶起居家呂窠臼。", "審齋樂府似花間，何必老夫疥篇右。"]'),
('c3f95b28-b275-43d1-9c7f-4624f86c5d69','題壺天館','梁安世','宋','宋诗','song-poetry','','[]','宣政喜邊功，隆兌築州縣。',156,'全唐诗/poet.song.156000.json','["宣政喜邊功，隆兌築州縣。", "程公自名巖，刻石記所建。", "得既不償費，中興棄不繕。", "誕謾磨崖辭，當日妄誇衒。", "英英石湖仙，改作壺天觀。", "壁間之大字，莊重如峨弁。", "詩文鸞鶴音，筆勢龍蛇變。", "登高瞰洞戶，灕水澄如練。", "勝槩聳靈臺，遐觀起三歎。", "玲瓏二十四，妙墨鎸題徧。", "我來爲拂塵，端若侍顔面。", "邦人頌遺愛，壽骨癯且健。", "今□□麟堂，安得使之見。"]'),
('307e95b1-cef9-4217-91c1-0082c8831b31','雙溪二首  其一','梁安世','宋','宋诗','song-poetry','','[]','春霖漲合兩溪平，雪浪中浮桑柘青。',32,'全唐诗/poet.song.156000.json','["春霖漲合兩溪平，雪浪中浮桑柘青。", "南市喚船撐未到，一番蓑笠滿津亭。"]'),
('997eac43-1c79-4306-9890-0cc3519e9d35','雙溪二首  其二','梁安世','宋','宋诗','song-poetry','','[]','岸高平步遠汀沙，落木梢頭點亂鴉。',32,'全唐诗/poet.song.156000.json','["岸高平步遠汀沙，落木梢頭點亂鴉。", "舞動雙龍金鎖甲，蘭皋影外晚紅斜。"]'),
('528a4c9c-cc84-4703-b99f-9d5aa4ae4515','秦碑一紙并古詩呈王梅溪太守','梁安世','宋','宋诗','song-poetry','','[]','公生博物好奇古，勸我搜求秦望碑。',384,'全唐诗/poet.song.156000.json','["公生博物好奇古，勸我搜求秦望碑。", "我來稽陰且三載，夢寐絕頂雲俱馳。", "事非近代問父老，鼻祖已來猶不知。", "或云其山多虎狼，囦湫罅井蟠蛟螭。", "魍魎木客忌人到，陰霾賊霧迷羊歧。", "樵夫懸磴懼失勢，一落萬丈誰能支。", "吾意此如鍾乳穴，民昔畏擾相譸欺。", "曩時山東之罘石，磅砰入海無津涯。", "固知秦人遊戲餘，非民之利寧一時。", "暇日登臨雲門寺，僧曰若耶溪上奇。", "山曰何山勢最峻，丹鶴夜宿天孫枝。", "南望天臺西錢唐，下視峰岫如羣兒。", "李斯篆書真刻本，昔人避亂此見之。", "裹糧遂偕墨工往，扳崖貫木如鹿麋。", "舉觴酹酒山之神，千古呵護煩神司。", "銷鑠僅存三尺許，龜趺就鑿山石爲。", "剜苔剔蘚隨手剝，面節背角摧霜皮。", "老龍脫甲蛇解蛻，鋪紙拭墨漫披離。", "收藏入袖恍若失，遐想往昔還嗟咨。", "我聞太古功德盛，鋪寫不盡乾坤儀。", "詩書紙上自不朽，金石還有磨滅期。", "秦皇不慕仁義業，直謂堯舜猶瑕疵。", "焚書欲蓋前代美，寧聞伏生傳有頤。", "後生不廢丞相書，歌頌雖在皆浮辭。"]'),
('a71827e2-bba3-4c32-9f1a-d7b5849532a5','句  其一','梁安世','宋','宋诗','song-poetry','','[]','更說此州異特事，寇公歸後二蘇來。',16,'全唐诗/poet.song.156000.json','["更說此州異特事，寇公歸後二蘇來。"]'),
('fd279a9a-2e9e-4973-9b93-ee24fccb6fd6','句  其二','梁安世','宋','宋诗','song-poetry','','[]','歲次屬金知稔熟，木頭點土驗滂沱。',16,'全唐诗/poet.song.156000.json','["歲次屬金知稔熟，木頭點土驗滂沱。"]'),
('4918e33e-cf1d-43d6-a68a-4387f6df41e7','句  其三','梁安世','宋','宋诗','song-poetry','','[]','蕃馬步銜青苜蓿，羌兒卧唱白銅鞮。',16,'全唐诗/poet.song.156000.json','["蕃馬步銜青苜蓿，羌兒卧唱白銅鞮。"]'),
('cd5a1b3d-459b-4666-a8ef-1e99bd2e7a28','句  其四','梁安世','宋','宋诗','song-poetry','','[]','直令萬乘高凡眼，不道人間例是貪。',16,'全唐诗/poet.song.156000.json','["直令萬乘高凡眼，不道人間例是貪。"]'),
('77e55c0d-10bf-4096-a840-4d4cb95a2d88','無題二首  其一','王千秋','宋','宋诗','song-poetry','','[]','雄姿畫麒麟，朽骨分螻蟻。',48,'全唐诗/poet.song.156000.json','["雄姿畫麒麟，朽骨分螻蟻。", "爭似及生前，常爲鶑花醉。", "雲山靜有情，天地寬無際。", "且放兩眉開，萬事非人意。"]'),
('b4d33b33-25c9-4906-9f60-ae72e2928abf','無題二首  其二','王千秋','宋','宋诗','song-poetry','','[]','功名竹上魚，富貴槐根蟻。',48,'全唐诗/poet.song.156000.json','["功名竹上魚，富貴槐根蟻。", "三萬六千場，排日扶頭醉。", "高懷隘世間，壯氣橫天際。", "常是惜春殘，不會東君意。"]'),
('72dd8bc2-3c02-4caf-b50c-d816624b12b5','一段奇軒','傅伯壽','宋','宋诗','song-poetry','','[]','門外紅塵走利名，庵中白髮任浮生。',64,'全唐诗/poet.song.156000.json','["門外紅塵走利名，庵中白髮任浮生。", "羨師法窟能深入，厭我詩壇已屢盟。", "渺渺水光簾萬疊，離離梅影雪三更。", "何人薦取真消息，試鼓瑶琴一再行。"]'),
('84e674f5-c4e8-4a62-8e6f-d8a2fe6266fc','題姜相峰前祠  其一','傅伯壽','宋','宋诗','song-poetry','','[]','草間荒塚沒麒麟，古寺何人爲寫真。',64,'全唐诗/poet.song.156000.json','["草間荒塚沒麒麟，古寺何人爲寫真。", "華表不歸空怨鶴，長松半落欲生鱗。", "艱難曾藉扶危力，鯁介原非賣直人。", "安得貞元同貞觀，懷思忠憤一霑巾。"]'),
('841f431c-0db6-46a5-86c4-b83f81c318e6','題姜相峰前祠  其二','傅伯壽','宋','宋诗','song-poetry','','[]','早歲聲名起日南，暮年病骨卧煙嵐。',32,'全唐诗/poet.song.156000.json','["早歲聲名起日南，暮年病骨卧煙嵐。", "死生有地皆天命，不用人間更疾讒。"]'),
('c4b94917-1fef-4c3c-b0d5-1cc087918a6b','一眺石','傅伯壽','宋','宋诗','song-poetry','','[]','一眺人間萬事非，海鷗山鳥便忘機。',32,'全唐诗/poet.song.156000.json','["一眺人間萬事非，海鷗山鳥便忘機。", "林端髣髴見帆影，知有扁舟天際歸。"]'),
('2e257fc7-da06-4971-96f3-7fd13cb14269','碧玉峽','傅伯壽','宋','宋诗','song-poetry','','[]','野迥方知天廣大，身高更覺石岧嶢。',32,'全唐诗/poet.song.156000.json','["野迥方知天廣大，身高更覺石岧嶢。", "泉人試爲平章看，勝絕何如透碧霄。"]'),
('c8b8008a-2921-4227-87e7-514a6a217c53','釣臺','傅伯壽','宋','宋诗','song-poetry','','[]','倚空絕壁勢雄豪，招引山風接海濤。',32,'全唐诗/poet.song.156000.json','["倚空絕壁勢雄豪，招引山風接海濤。", "不假他人立名字，嚴臺何似此臺高。"]'),
('b0ce1a99-aab0-42f3-b434-4a78c4d8cc2a','和泉守王龜齡','傅伯壽','宋','宋诗','song-poetry','','[]','名節士所重，當如護睛腦。',24,'全唐诗/poet.song.156000.json','["名節士所重，當如護睛腦。", "立朝與行己，本末要可考。"]'),
('d891de92-d8a4-4afd-80a5-d6086908de2b','送行詩','陳琦','宋','宋诗','song-poetry','','[]','太白休愁橫閣暝，少陵剩賦浣花春。',32,'全唐诗/poet.song.156000.json','["太白休愁橫閣暝，少陵剩賦浣花春。", "金沙銀鑠巴中路，綠水紅蓮幕下賓。"]'),
('38cb846f-9f4d-4529-a588-2690cedd80d9','讀書臺','陳琦','宋','宋诗','song-poetry','','[]','水色山光面面開，乾坤牢落此孤臺。',64,'全唐诗/poet.song.156000.json','["水色山光面面開，乾坤牢落此孤臺。", "寒煙老屋巢沙燕，春雨殘碑卧石苔。", "千載英風今可想，八州奇夢舊傳來。", "輶車弔古增惆悵，重爲先生闢草萊。"]'),
('03808014-1b7c-4376-9344-dffb16322e2b','寄遠辭','羅願','宋','宋诗','song-poetry','','[]','過黎陽而遂西兮，煩嘉友之臨餞。',368,'全唐诗/poet.song.156000.json','["過黎陽而遂西兮，煩嘉友之臨餞。", "道躊躇而屢顧兮，忽背馳而不可挽。", "幸介弟之勤我兮，守權輿其益堅。", "人情豈其惡逸兮，慮我脩塗之易倦。", "粲高原與平隰兮，冰雪凜其同踐。", "山負石以當逕兮，泥飛屐以相濺。", "喜招招以卬涉兮，又風濤之交戰。", "幾四載之皆乘兮，初不悟其巳遠。", "亦既降乎廬阜兮，縣尹告以舟辦。", "謀不主於雲夢兮，果若大江之爲限。", "分渚陸之異遵兮，弟亦曰予將返。", "試往閲於千帆兮，前車近其當鑒。", "挾忠信以臨深兮，猶一覘而色變。", "愛我者於是而委去兮，吾然後知所恃之惟天。", "寧戒懼之遂忘兮，託命於南公之雞犬。", "捨親戚與墳墓兮，初豈以易芻豢。", "抑甚珍其所懷兮，每欲棄置而未忍。", "行四方以經營兮，膂力猶幸其可勉。", "荆又用武之國兮，庶幾少施乎吾辯。", "至天性之燥濕兮，蓋終身陋巷而不厭。", "非將老無聞之爲病兮，且安往而不樂其貧賤。", "獨夫人之信此兮，跂予望之而不之見。", "秋蘭何時其可致兮，聊以報乎足繭。"]'),
('ca987551-ca95-4a36-993a-edf19b482f8c','送新安守陳郎中赴闕','羅願','宋','宋诗','song-poetry','','[]','浙水带天邑，於今如澗瀍。',192,'全唐诗/poet.song.156000.json','["浙水带天邑，於今如澗瀍。", "言從發源處，直到行闕前。", "使君儀曹郎，省闈早周旋。", "一行領輔郡，奏課十郡先。", "是時新雨餘，縱纜驚號蟬。", "長河無六月，解带風中眠。", "烏羽動林莽，馬門納雲烟。", "村村老農出，寒女一笑嫣。", "共談兩歲樂，米糧不論錢。", "今日見使君，使君正當年。", "還能持節來，莫作長棄捐。", "再拜不可留，鼓聲催發船。", "嗟我寄枌社，弟兄辱知憐。", "宦遊適四方，從公倘非難。", "農人寔懷土，欲見無由緣。", "唯因足襦袴，長說使君賢。"]'),
('c24d387e-c60b-45af-8b42-958c99fb0a5a','題賢女鋪','羅願','宋','宋诗','song-poetry','','[]','許嫁女始字，昔人良所欽。',108,'全唐诗/poet.song.156000.json','["許嫁女始字，昔人良所欽。", "此身有所屬，安得强委禽。", "嗟哉乃翁愚，棄盟欲重尋。", "死生還復合，世謂遂初心。", "誰知彼寒女，義烈動芳襟。", "頃來已一慚，厚愧方在今。", "正性不負物，臨流殞千金。", "我來弔叢祠，目眩寒潭深。", "淒涼一川上，行客聞知音。"]'),
('62625be0-1a69-4ae3-a622-5bf6ab8f4d31','梁寺丞見示過嶺新作','羅願','宋','宋诗','song-poetry','','[]','凌晨登鬰孤，南走韶陽道。',180,'全唐诗/poet.song.156000.json','["凌晨登鬰孤，南走韶陽道。", "封疆有申畫，山川本懷抱。", "公行度塞嶺，殘雪故未掃。", "高情無南北，反謂茲山小。", "頃來我嘗游，亦覺山媚好。", "前賢困遠謫，我輩得幽討。", "兩崖瞻欲眩，數樹攀且繞。", "想公哦新詩，千騎轉林杪。", "衙冠候顔色，約束軍聲悄。", "韶陽古名郡，四十專城早。", "重華已千歲，蒼石在雲表。", "魚龍舞幽壑，遺韻蓋可攷。", "以茲供撫玩，或可薦壽考。", "公餘亦時飲，未用絕芳醥。", "行行布恩惠，正直神所保。"]'),
('10d17123-93be-4829-9fb8-0f46c4593058','送贛州守施司諫奉祠歸吳興','羅願','宋','宋诗','song-poetry','','[]','去國二千里，叱馭良已勤。',252,'全唐诗/poet.song.156000.json','["去國二千里，叱馭良已勤。", "到官一百日，啜菽念所欣。", "使君豈常流，早歲承華勳。", "螭首有故步，天香带餘熏。", "時清省諫紙，符竹亦再分。", "屬者寇雖除，遺民尚驚塵。", "公來鈐江右，喜氣感三軍。", "下擔見施設，果蘇彫瘵群。", "天姿夙已高，况復勇所聞。", "屬縣但期約，訟庭無放紛。", "村團不識吏，處處飽羹芹。", "生女戒勿怒，減輸勸其耘。", "惠術頗次第，歸心已鄉枌。", "小子謬從師，頗嘗侍朝曛。", "從容進逢掖，慘淡立紅裙。", "中坐要娛客，所陳金石文。", "行裝遂如此，何以充棟棼。", "人事與天意，嗟予豈須云。", "來携諫坡雨，去開崆山雲。", "多公能摧剛，聖慮已策勳。", "行藏吾有命，所願不忘君。"]'),
('3179104c-c71a-4169-99e6-ee0e84d7989c','送辛殿撰自江西提刑移京西漕','羅願','宋','宋诗','song-poetry','','[]','峨峨鬰孤臺，下有十萬家。',288,'全唐诗/poet.song.156000.json','["峨峨鬰孤臺，下有十萬家。", "喧呼隘城闕，戀此明使車。", "憶公初來時，狂狡嘯以譁。", "主將失節度，玉音爲咨嗟。", "一朝出明郎，繡衣對高牙。", "持斧自天下，荒山走矛叉。", "光騰將星魄，枉矢失驚蛇。", "氛霧果盡廓，十州再桑麻。", "恩令撰中祕，天筆有褒嘉。", "辛氏世多賢，一姓古所誇。", "太史善箴闕，伊川知辭華。", "誰歟立軍門，杖節來要遮。", "亦有救折檻，叩頭當殿衙。", "英風雜文武，公獨可肩差。", "佩玦善斷割，揮毫絕紛葩。", "時時有縱舍，惠利亦已遐。", "京西故畿甸，傍塞聞悲笳。", "明時資餽餫，豈減漢褒斜。", "勿云易使耳，重地探荆巴。", "三節萃一握，眷心良有加。", "古來居此人，愛國肯雄誇。", "羊祜保至信，陶公戒其奢。", "安邊有成略，此道未全賒。", "公今有才氣，功名安可涯。"]'),
('f066541c-e40c-4d00-9796-d24cdfb4b410','和汪伯虞求酒','羅願','宋','宋诗','song-poetry','','[]','君不見菊潭之水飲可仙，酒旗五星空在天。',131,'全唐诗/poet.song.156000.json','["君不見菊潭之水飲可仙，酒旗五星空在天。", "此江縠紋更奇絕，投以麴米清如泉。", "分甘正擬供低唱，要築糟臺須大匠。", "詩人便欲醉千日，歡伯僅堪陪一餉。", "曰予此樂未知之，獨愛爲瓶居井湄。", "因君飲興亦浩蕩，夢隨驂駕觴瑶池。", "昔賢酒盡孤長吸，大似竹枯還欲瀝。", "明朝秀句傳滿城，笑指空樽卧牆壁。"]'),
('8915bc52-c48a-4d11-9bc6-1b3969791c93','鹿鳴燕禮成貽解元諸友并呈通判寺簿兄及衆同官五首  其一','羅願','宋','宋诗','song-poetry','','[]','天意欲爲雨，川雲出相望。',96,'全唐诗/poet.song.156000.json','["天意欲爲雨，川雲出相望。", "明時攬俊乂，所立固無方。", "少小諷二南，美此江漢鄉。", "猥當興能職，首闢較藝場。", "群儒悅寬簡，浩蕩出文章。", "方觀縱壑魚，忽作摶風翔。", "此去升禮闈，旋當對殿廊。", "忠言動明主，家國有輝光。"]'),
('88d2f5af-04ca-4c99-ae48-7923ab9e2263','鹿鳴燕禮成貽解元諸友并呈通判寺簿兄及衆同官五首  其二','羅願','宋','宋诗','song-poetry','','[]','鹿鳴首宵雅，義取好賢深。',96,'全唐诗/poet.song.156000.json','["鹿鳴首宵雅，義取好賢深。", "寥寥疑莫續，工席有遺音。", "詩言君臣間，不以位相臨。", "如禽食苹水，有酒方共斟。", "從容陳所好，亦復有鳴琴。", "庶使峨冠者，洋洋動其心。", "願言解子褐，結綬貫華簪。", "真心有相感，千載豈殊今。"]'),
('d0612c8e-f7ba-4207-8c79-dd8396b5a680','鹿鳴燕禮成貽解元諸友并呈通判寺簿兄及衆同官五首  其三','羅願','宋','宋诗','song-poetry','','[]','昔在馮當世，起家冠倫魁。',96,'全唐诗/poet.song.156000.json','["昔在馮當世，起家冠倫魁。", "天衢躍群龍，轉見絕足才。", "馳譽塞四海，致身近三台。", "淒涼城東宅，歲晚就蒿萊。", "古來用武地，編簡委塵埃。", "每見儒冠喜，況逢賢路開。", "祝君如馮公，決科亦崔嵬。", "終身可師法，正復在軻回。"]'),
('b8fff308-1098-48ac-a7ea-660995579a22','鹿鳴燕禮成貽解元諸友并呈通判寺簿兄及衆同官五首  其四','羅願','宋','宋诗','song-poetry','','[]','任子衆所許，一鳴居上頭。',96,'全唐诗/poet.song.156000.json','["任子衆所許，一鳴居上頭。", "王高兩縣來，選拔皆其尤。", "里行張可貴，月書蘇屢優。", "向來丁與虞，頗從別駕游。", "嗟我愛群才，不間薪與槱。", "既爲得者喜，豈忘欲旁搜。", "鼓篋五百家，要皆儒者流。", "相期作鄒魯，過是我何求。"]'),
('2f8122ac-bac0-48d8-a28a-d144c98353d3','鹿鳴燕禮成貽解元諸友并呈通判寺簿兄及衆同官五首  其五','羅願','宋','宋诗','song-poetry','','[]','士有未就駕，郡守身勸之。',108,'全唐诗/poet.song.156000.json','["士有未就駕，郡守身勸之。", "君觀漢詔中，有此勤懇詞。", "由來賢俊人，出處每委蛇。", "譬彼未嫁女，深閨秀容姿。", "施衿有所適，婉孌終自持。", "漢俗尚如此，前世當可知。", "勉哉策名者，不但好爵縻。", "君臣有明義，行矣方自茲。", "惟當秉高節，長副此心期。"]'),
('834ed341-9e77-41b8-a3ba-ce47377aa880','酬任察推惠石耳之作','羅願','宋','宋诗','song-poetry','','[]','班嗣不借書，劉棻真好事。',84,'全唐诗/poet.song.156000.json','["班嗣不借書，劉棻真好事。", "慚君輟漢簡，畀我充口耳。", "胡爲有牽聯，蒼石乃遭刵。", "平生任公子，百犗供釣餌。", "坐令天壤間，厭此江海味。", "君今效清癯，我更覺軟美。", "挾書擬從游，夢到沙頭市。"]'),
('9d82e157-1080-4de8-88bb-c32508b86b6b','酬寺簿勸農追和淵明見貽','羅願','宋','宋诗','song-poetry','','[]','江漢之會，中具五民。',240,'全唐诗/poet.song.156000.json','["江漢之會，中具五民。", "見異而遷，乃喪厥真。", "相彼樊山，我行所因。", "有閒其壤，問彼居人。", "方時清明，家自爲稷。", "其藪其浸，其動其植。", "孰爲使民，有田不穡。", "亦惟蒲魚，恃此鮮食。", "歲運周回，景躔西陸。", "帝籍重開，天顔逾穆。", "耕事將起，毋荒遊逐。", "凡我農官，戒民宜宿。", "戒民伊何，美成在久。", "譬彼射侯，則求其耦。", "驅率慵墮，轉緣南畝。", "數耘疾收，在而心手。", "農亦有書，匪藏金匱。", "盍耕如莘，盍饁如冀。", "桑蔭清好，濁醪日至。", "已勤而食，則無所愧。", "勿謂此州，遠連邊鄙。", "我疆西北，盡其四履。", "風雨順時，日星循軌。", "屢豐作頌，以致歸美。"]'),
('68ebcfd8-3792-430b-b718-533c7425e6fd','鄂州勸農','羅願','宋','宋诗','song-poetry','','[]','國有四民，各分一職。',240,'全唐诗/poet.song.156000.json','["國有四民，各分一職。", "農次於士，蓋尊稼穡。", "日出當作，日入乃息。", "用天分地，以足衣食。", "菖葉初生，於是始耕。", "務限既入，農事轉急。", "禾當播種，乘雨接濕。", "高田大豆，榆莢爲候。", "三月區處，油麻穄黍。", "時當警竊，圖葺牆宇。", "蠶沙麥種，四月收貯。", "開渠決竇，以待暴雨。", "月建在午，秧苗入土。", "女工織作，三伏炎暑。", "七月芟草，燒治荒田。", "大麥小麥，上戊社前。", "禾欲上場，九月塗倉。", "緝績布縷，十月多霜。", "冬至埋穀，預試五種。", "不宜者輕，宜者則重。", "臘月糞地，治碓雕桑。", "脩治農器，向春則忙。", "四時之務，展轉相尋。", "既有常産，當有常心。"]'),
('d5ca6493-9e17-4bc9-8b3a-2e979d798c07','望梅亭','羅願','宋','宋诗','song-poetry','','[]','節物重陽後，風烟庾嶺頭。',48,'全唐诗/poet.song.156000.json','["節物重陽後，風烟庾嶺頭。", "休論梅子雨，纔度菊花秋。", "翠壁堪橫絕，幽亭勸小留。", "謀生兄弟拙，一一傍南州。"]'),
('576e14e0-27dd-4832-ad57-1c1363c630e7','送邕州吳使君','羅願','宋','宋诗','song-poetry','','[]','題輿纔赴日邊程，便擁油幢鎮列城。',64,'全唐诗/poet.song.156000.json','["題輿纔赴日邊程，便擁油幢鎮列城。", "地望素高唐五管，人才今似漢三明。", "時清市駿非無意，歲晏逢花好寄聲。", "太學英名湖海氣，此行持論要平平。"]'),
('595fbfb2-d5a1-43cd-961f-acd033f990af','日涉園次韻五首 虛靜堂','羅願','宋','宋诗','song-poetry','','[]','華堂清曠隔喧卑，戶外春殘綠滿枝。',32,'全唐诗/poet.song.156000.json','["華堂清曠隔喧卑，戶外春殘綠滿枝。", "好鳥窺簷時下啄，有人燕坐獨支頤。"]'),
('aa5e0de4-f14f-410b-b691-03001aa348a3','日涉園次韻五首 息齋','羅願','宋','宋诗','song-poetry','','[]','世間誰號最閒忙，强健收身意自涼。',32,'全唐诗/poet.song.156000.json','["世間誰號最閒忙，强健收身意自涼。", "春去掃花時汲井，客來剪韭旋炊粱。"]'),
('74ecfd0c-e14c-4bc2-b18c-c0b2146ba76f','日涉園次韻五首 丹桂軒','羅願','宋','宋诗','song-poetry','','[]','丹枝近歲出深宮，合向嚴宸伴晚楓。',32,'全唐诗/poet.song.156000.json','["丹枝近歲出深宮，合向嚴宸伴晚楓。", "珍重幽軒無俗物，月中根墢日邊紅。"]'),
('e5a3cb67-4f37-4cad-95df-7548aa85e7d2','日涉園次韻五首 茶巖','羅願','宋','宋诗','song-poetry','','[]','巖下纔經昨夜雷，風爐瓦鼎一時來。',32,'全唐诗/poet.song.156000.json','["巖下纔經昨夜雷，風爐瓦鼎一時來。", "便將槐火煎巖溜，聽作松風萬壑迴。"]'),
('b8f61448-7e81-4f31-9f98-01cd9347fae1','日涉園次韻五首 木瓜塢','羅願','宋','宋诗','song-poetry','','[]','山中果樹略扶疎，炎帝經中未盡書。',32,'全唐诗/poet.song.156000.json','["山中果樹略扶疎，炎帝經中未盡書。", "聞道木瓜紅勝頰，露枝雲葉綴華琚。"]'),
('2b122e9d-85c7-4294-9d68-b2ececebfb10','奉寄交代通守王兄兼簡胡君二首  其一','羅願','宋','宋诗','song-poetry','','[]','籍甚王文度，同儕意自親。',48,'全唐诗/poet.song.156000.json','["籍甚王文度，同儕意自親。", "方舟能送我，別駕苦勞人。", "屬縣應如律，山田向食新。", "荷花開幾許，老子舊凝神。"]'),
('a76b47cf-e14c-4d35-972b-3f5df9136022','奉寄交代通守王兄兼簡胡君二首  其二','羅願','宋','宋诗','song-poetry','','[]','有客纔相識，乖離又許時。',48,'全唐诗/poet.song.156000.json','["有客纔相識，乖離又許時。", "不愁蓬轉遠，獨恨蓋傾遲。", "卑薄江南地，青冥歲晚期。", "宦遊妨意氣，直恐負君詩。"]'),
('edfd82d5-4fe6-47e2-90c5-b626c48c8f14','題汪氏尊己堂','羅願','宋','宋诗','song-poetry','','[]','華屋成來有幾年，名因耆舊里中傳。',64,'全唐诗/poet.song.156000.json','["華屋成來有幾年，名因耆舊里中傳。", "未容極口論臧否，正欲虛心到聖賢。", "室有圖書人自好，門多車馬地還偏。", "邕州健筆人爭誦，姓字從今到日邊。"]'),
('dd26a38f-72e5-45a4-8ec4-b540918b4490','次韻楚覺先見贈','羅願','宋','宋诗','song-poetry','','[]','奏事何能補帝聰，流年早已付天公。',64,'全唐诗/poet.song.156000.json','["奏事何能補帝聰，流年早已付天公。", "舊聞雙劍淪波底，忽有三刀入夢中。", "首出詩文爲我賀，多慚憂樂與人同。", "如君孝友天應報，飛鶴那應久在籠。"]'),
('285a64f2-4aa3-41e3-b95b-138635239bac','聞寺簿燕客因以酒蟹送似有詩見及次韻二首  其一','羅願','宋','宋诗','song-poetry','','[]','冠蓋追隨寂寞濱，絕甘寬我未閒身。',32,'全唐诗/poet.song.156000.json','["冠蓋追隨寂寞濱，絕甘寬我未閒身。", "古來把酒持螯者，便作風流一世人。"]'),
('a699b533-a6da-4531-aba7-a10da38d7340','聞寺簿燕客因以酒蟹送似有詩見及次韻二首  其二','羅願','宋','宋诗','song-poetry','','[]','此物湖鄉價不論，带糟聊遣薦芳樽。',32,'全唐诗/poet.song.156000.json','["此物湖鄉價不論，带糟聊遣薦芳樽。", "夢魂忽去浮清霅，喚撥漁舟傍馬門。"]'),
('a8d5b554-e67a-4d6c-93a3-1c904b206f06','酬寺簿錄示胡康侯戒明仲治郡遺訓','羅願','宋','宋诗','song-poetry','','[]','別駕游心到古初，時將前輩警公餘。',32,'全唐诗/poet.song.156000.json','["別駕游心到古初，時將前輩警公餘。", "異時治行傳青史，名字牽聯倘得書。"]'),
('221f9254-667f-4a92-9fb0-ced797695e44','奉酬李叔勤知縣覓抹莉花栽長句','羅願','宋','宋诗','song-poetry','','[]','郫令風流太史家，早知抹莉有奇葩。',64,'全唐诗/poet.song.156000.json','["郫令風流太史家，早知抹莉有奇葩。", "生嫌衆色空塵滓，遍閲餘香見等差。", "多謝珠璣來坐右，好將根墢到天涯。", "蜀江紅紫紛披後，初看東南第一花。"]'),
('2f3149eb-4f2e-465e-bb44-046ca4f0c32b','次韻酬通判劉兄岳陽樓見懷二首  其一','羅願','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','蓄納深無際，憑臨勢易高。',48,'全唐诗/poet.song.156000.json','["蓄納深無際，憑臨勢易高。", "青春關氣象，白日散風濤。", "有野張軒樂，何人續楚騷。", "古來川浸在，閒却漢陰槹。"]'),
('ad1ba6f1-3882-4f2f-860a-df5c74c9e39c','次韻酬通判劉兄岳陽樓見懷二首  其二','羅願','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','魚龍掀舞後，渺莽記空庭。',48,'全唐诗/poet.song.156000.json','["魚龍掀舞後，渺莽記空庭。", "地带三苗闊，山傳二女靈。", "客懷光水月，詩筆妙丹青。", "少作揚雄悔，惟思草一經。"]'),
('cfd7790b-5f9e-4ef0-9cb3-7bc2f4944af2','次韻和子澄春祠先聖律詩','羅願','宋','宋诗','song-poetry','','[]','質明帨洗動輕漪，禮殿巍巍百世師。',64,'全唐诗/poet.song.156000.json','["質明帨洗動輕漪，禮殿巍巍百世師。", "伏几親瞻古人象，陪祠頗雜漢官儀。", "詩書自可謀元帥，俎豆何妨示小兒。", "春服詠歸千古意，只今童冠可無詩。"]'),
('ae7ab90e-feb7-4f9f-9c7f-59d22af715fc','春社禮成借用寺簿釋奠詩韻呈諸同官','羅願','宋','宋诗','song-poetry','','[]','素餐深覺愧漣漪，后稷勾龍實吏師。',64,'全唐诗/poet.song.156000.json','["素餐深覺愧漣漪，后稷勾龍實吏師。", "平土至今猶有頼，配天在昔蓋多儀。", "操豚底用勤巫祝，餉黍行看媚婦兒。", "海內和平頌聲作，登歌還有載芟詩。"]'),
('19b9387f-3181-4bff-ba7a-1322a31cc5e3','福州趙侍郎開城西古湖以溉田既成冀得致政丞相福公一臨於是有唱和之篇二首  其一','羅願','宋','宋诗','song-poetry','','[]','湖邊飛蓋欲誰同，治行人思舊弱翁。',64,'全唐诗/poet.song.156000.json','["湖邊飛蓋欲誰同，治行人思舊弱翁。", "行樂未饒溱水女，詠歸應有舞雩童。", "閩山影浸烟雲動，滄海潮連浦溆空。", "欲識元侯疏鑿意，君王勤儉正卑宮。"]'),
('8c66d015-fc2e-4e1d-9099-0e5f9f29881d','福州趙侍郎開城西古湖以溉田既成冀得致政丞相福公一臨於是有唱和之篇二首  其二','羅願','宋','宋诗','song-poetry','','[]','南方春早凍先融，荷臿趨時小異同。',64,'全唐诗/poet.song.156000.json','["南方春早凍先融，荷臿趨時小異同。", "要使齊民知水利，亦如前哲變文風。", "四時鏡浄登臨美，萬頃雲垂灌溉通。", "嗟我一麾江漢上，慨然歆嘆似南豐。"]'),
('d3c01ab1-e226-4fe8-b255-395617ddda82','宴留尚書致語口號','羅願','宋','宋诗','song-poetry','','[]','坐對崆峒帥府開，尚書元是濟川材。',64,'全唐诗/poet.song.156000.json','["坐對崆峒帥府開，尚書元是濟川材。", "纔看劍履從天下，倏見旌旗照海來。", "兵衛半年虛抱戟，公堂今日共銜杯。", "文昌暫照東南地，已覺光輝近上臺。"]'),
('d74119e5-7099-4429-8afe-498c9282b0ce','題木犀','羅願','宋','宋诗','song-poetry','','[]','老照軒前翠已空，却驚嘉樹巧玲瓏。',64,'全唐诗/poet.song.156000.json','["老照軒前翠已空，却驚嘉樹巧玲瓏。", "幽芬自出禪枝外，圓相長標法窟中。", "過客莫辭三宿戀，道人已費十年工。", "要須共結團欒坐，賞盡清秋面面風。"]'),
('31a3426c-8dd0-43f6-a122-650d94e835b0','續八詠 雙溪占勝地','唐仲友','宋','宋诗','song-poetry','','[]','占勝地，勝地難摹寫。',268,'全唐诗/poet.song.156000.json','["占勝地，勝地難摹寫。", "二水護城闉，千山带林野。", "山林鬰蒼蒼，千里遥相望。", "括蒼轉曉色，九峰含夕陽。", "危欄壓雉堞，嘉名寄文章。", "陰晴閲變態，晝夜無故常。", "郊平漲潦渺滄溟，渚迴澄波縈素練。", "霽後遥岑歷歷分，霧中疊嶂濛濛見。", "增遠目兮雙明，含清輝兮四面。", "奉分星之肸蠁，切宸居之眩轉。", "邦人來此意以恭，客子臨之遊欲倦。", "神莫睹，敬先通。", "言有盡，興無窮。", "烟籠野以浮碧，浪射霞而湧紅。", "連赤松之佳氣，過三洞之罡風。", "仰層閣而跂翼，俯浮梁而卧虹。", "數征帆而引興，瞻倦翼而省躬。", "接絃歌之盈耳，震鼓角之凌空。", "洪鐘發天半，清磬入雲中。", "英靈降神異，膏腴生物豐。", "清絕茲樓景，佳哉冠江東。"]'),
('ba13cc21-1455-42c0-ad07-65f3a6726553','續八詠 八詠掞英詞','唐仲友','宋','宋诗','song-poetry','','[]','掞英詞，英詞有微意。',290,'全唐诗/poet.song.156000.json','["掞英詞，英詞有微意。", "懷章戀雙闕，吟情深六義。", "秋月清可依，春風惠無私。", "草桐感霜露，鴻鶴傷羽儀。", "解玉佩，去朝會，駕朱旛，張皂蓋。", "張蓋非不榮，解佩難爲情。", "青緺矯濁侈，錦帳懷休明。", "邦衣未容褫，況值佳山水。", "時來一登臨，清曠豁千里。", "既爲茲土愁，復云茲土美。", "揖林壑，俯清淪，摛錦繡，歌陽春。", "天球鳴兮朱絃奏，朱絃奏兮玉律新。", "靈均淵源，建安風度。", "參衆體於柏梁，接遺聲於楚賦。", "值重光，歎盈缺。", "曳長裾，懷散聚。", "想西園兮不復游，典南尉兮未能去。", "薄淮陽之見疎，幸浮邱而來顧。", "非流落以爲患，諒熱中而怨慕。", "景入詠以增輝，詩因樓而得趣。", "嗟暗投於拙目，指微瑕於寶璐。", "高文一何寥，絕境亦難遇。", "子期久云亡，蚍蜉祇撼樹。"]'),
('aa4f6484-dedd-4b32-b0ed-f557757db34a','續八詠 千年增舊觀','唐仲友','宋','宋诗','song-poetry','','[]','增舊觀，舊觀已云美。',286,'全唐诗/poet.song.156000.json','["增舊觀，舊觀已云美。", "棟宇未翬飛，賢侯爲興起。", "昔時兮清賞，昔日兮清文。", "揮絃兮歸雁，隠几兮浮雲。", "八篇合綺麗，萬古垂芳芬。", "鶴歸城郭幸未改，人去典型猶得聞。", "風流兮代變，城隅兮勢逼。", "故蹟兮溪山，靈祠兮門閾。", "湊香火於庶繁，局宇宙於褊側。", "惜經度於無地，厭往來於如織。", "重舊貫於改作，付流年於未極。", "負吟咏之高名，起登眺之太息。", "侯至懷古賢，民樂值豐年。", "謀始規模壯，競辰旌旆遷。", "落成駴不日，面勢快瞻前。", "昔人應有待，神交臭蘭茝。", "淚碑忽已新，革带儼如在。", "當時屈望郎，此意屬真宰。", "樓高兮山遠，野曠兮水長。", "冥冥兮鴻翼，渺渺兮鷗行。", "客至有永日，詩成無短章。", "見聞靡不逮，名實非自彰。", "隆昌七百載，作者永相望。"]'),
('122e43b3-91fa-41e1-83cd-9a01b1e6bd7b','續八詠 萬象出新奇','唐仲友','宋','宋诗','song-poetry','','[]','出新奇，新奇震吳越。',262,'全唐诗/poet.song.156000.json','["出新奇，新奇震吳越。", "經營得要領，呈露入軒闥。", "迢迢括蒼山，虬龍南北環。", "中含七邑壤，下注溪流灣。", "昔樓已據勝，今樓與名稱。", "東西倍軒豁，高下增比興。", "極目送朝宗，目窮波未窮。", "萬里出寸碧，千里來雄風。", "地迥月偏蚤，草綿心易忡。", "窗影射朝白，簷牙留晚紅。", "村村辨迴互，樹樹分玲瓏。", "長烟低抹岸，遠水浄涵空。", "雲間無迅翼，天末識歸篷。", "輪奐覩新作，邦人胡不樂。", "憧憧絕紛擾，寂寂宜淡泊。", "溪響答棋聲，雲影入杯酌。", "守澄心自知，客至意亦宜。", "哦詩句易得，憑檻坐忘疲。", "垂名千古地，一朝風景異。", "楹桷壓閭閻，邱壑輸胸次。", "清游未渠央，吾民那可忘。", "詞章賁高閣，前後兩甘棠。"]'),
('0df4e8c1-efeb-4096-a521-5705fb1df181','續八詠 遲日春偏麗','唐仲友','宋','宋诗','song-poetry','','[]','春偏麗，偏麗兩溪湄。',244,'全唐诗/poet.song.156000.json','["春偏麗，偏麗兩溪湄。", "三農喜趨事，萬物欣逢時。", "伊吾土之洵樂，勤𤱶畝之東作。", "彌隴麥之曠望，遍水田之疏瀹。", "抽新綠之桑麻，換柔青之林薄。", "林薄初遷鶑，郊原膏澤晴。", "園花張錦爛，隄柳弄絲輕。", "落梅吹香盡，芳草連天生。", "遊人自適意，客子偏傷情。", "韶華忽云暮，簷楹亂飛絮。", "南浦綠波瀾，秀野深烟霧。", "魚肥隠釣舟，沙煖多翹鷺。", "紅殘少踏青，日落喧競渡。", "翩翩來去燕，芳洲啣泥便。", "弱羽度高城，斜拂微和扇。", "物態皆光輝，憑高自忘歸。", "輕雷送夜雨，江色含朝暉。", "俗厚異觀洧，服成思浴沂。", "所幸癘不作，但願年無饑。", "寬書已屢下，宣布關深機。"]'),
('dbb24482-91fc-46c8-a140-1a4355281c4d','續八詠 薰風夏更宜','唐仲友','宋','宋诗','song-poetry','','[]','夏更宜，更宜倚欄客。',268,'全唐诗/poet.song.156000.json','["夏更宜，更宜倚欄客。", "扇化養之清微，布豐美之澗澤。", "空翠幄之桑柘，漲黄雲之麰麥。", "掃園囿之落紅，溢𤱶澮之疎白。", "亙東西之入望，固高下之無擇。", "響繅車於林野，度牧笛於阡陌。", "消永晝於尊罍，散輕暑於絺綌。", "嘉賓可以娛，塵襟可以釋。", "俯檻草芊芊，懷人情脉脉。", "黄梅熟兮大霔，洪濤漲兮古渡。", "前渚長兮長已沒，浮梁斷兮斷無路。", "駐征客之行舟，失遠村之芳樹。", "望青林之濟溺，慮黄帕之爲蠹。", "浪洶湧而未息，雲冥濛而猶固。", "幸學海不爲遠，忽安流已如故。", "赤日照奇峰，絕壑召神龍。", "奔雷過車響，急雨跳珠容。", "爲霖利已溥，潑墨收無蹤。", "微涼入殿閣，朝爽開心胸。", "高明可居君莫厭，變化莫測吟可供。"]'),
('b3b19bd6-7ca1-47c3-ad2a-2127c4ca4987','續八詠 秋空月皎皎','唐仲友','宋','宋诗','song-poetry','','[]','月皎皎，皎皎飛明鏡。',274,'全唐诗/poet.song.156000.json','["月皎皎，皎皎飛明鏡。", "滌風露以孤高，照溪山而清靜。", "協二氣之金精，肅萬物之西成。", "捲雲衢之點綴，廓天路之澄清。", "掃埃𡏖於玉宇，流沆瀣於金莖。", "汎林光於遠野，轉簷影於高城。", "盪金蛇兮深浪湧，浸玉兔兮長灘平。", "射潛淵兮魚龍動，冷巢棲兮烏鵲驚。", "在冰壺兮心腑快，吸瓊華兮毛骨輕。", "念遠人兮懷塞北，依末光兮思承明。", "顥氣分深淺，素魄有虧盈。", "橋成牛女渡，日沈河漢傾。", "光輝半八月，憂樂殊羣情。", "肅肅漸寒色，遠雁向南征。", "此景皆奇絕，茲地獨崢嶸。", "當午夜之寥閴，带遠烟之蒙冪。", "認遥山於微微，分近樹於歷歷。", "急搗衣之寒砧，引泊舟之橫笛。", "繄賞心之難并，對茲焉真無敵。", "佳人兮懷哉，參已橫兮歸去來。"]'),
('f3c3fdcb-9f26-451b-b20e-86df4bf33041','續八詠 冬野雪垂垂','唐仲友','宋','宋诗','song-poetry','','[]','雪垂垂，迥野望中奇。',250,'全唐诗/poet.song.156000.json','["雪垂垂，迥野望中奇。", "冥迷一色混，琢鏤萬般宜。", "嚴風初作意，愛日爲收曦。", "千山淡若慘，萬壑凍無姿。", "同雲忽沍合，飛絮漸分披。", "漫天歷亂落，灑檻橫斜吹。", "粉浸兩溪浪，瓊削千林枝。", "素虬橋枕渚，冰柱瓦流澌。", "田種皆雍伯，絃絕非子期。", "沙頭雁影滅，城角鳥聲悲。", "烟孤辨村墅，天沈迷酒旗。", "愛登樓之縱目，忘起粟之侵肌。", "忽愁容以暫開，漏朝暉之照矚。", "射積素之峰嶺，認微波之溪谷。", "燦垂簷之明珠，爛開府之羣玉。", "凜暮寒而復凝，灑夜聲而相續。", "靚開闔以多端，玩朝昏而未足。", "孤松氣獨剛，百穀土增沃。", "積陰那可久，見睍深所欲。", "白雪與陽春，願賡郢中曲。"]'),
('d1877b73-6bee-419b-ac78-e9bdeb3debad','游蓋竹山','唐仲友','宋','宋诗','song-poetry','','[]','籃輿東出雨初收，衆山捲霧奔蒼虬。',370,'全唐诗/poet.song.156000.json','["籃輿東出雨初收，衆山捲霧奔蒼虬。", "麥田濛濛連千疇，去年見種今見秋。", "農家椀大即快活，使君不去能無羞。", "春光欲盡誰挽留，千林薿薿新綠柔。", "桐花遠近淡無色，自開自落那關愁。", "洞天爲我暫晴霽，使我蠟屐窮冥搜。", "天門發秀萬馬下，水口離立羣峰稠。", "瀑泉對面瀉絕壁，寶劍却倚丹鳳樓。", "溪聲噴薄雷震動，石色古怪神剜鎪。", "洞門谽谺風颼颼，香爐峰下蛟龍湫。", "中峰特秀小爲貴，左右旌節森戈矛。", "幾時秘奧一日覩，談笑指示君知不。", "精廬但欲占勝處，專事棟宇非良謀。", "飛閣跨水納佳氣，突兀堂殿居上頭。", "軒窗高下有奇致，洗滌肺腑明雙眸。", "我將於此棲羽流，鳳笙鶴駕應來游。", "丹成一舉淩九州，下視濁世如浮漚。", "靈祠款謁路阻修，層巖曲澗邃且幽。", "經營輪奐亦未就，揮金助爾何須求。", "晚雲漠漠鳴雨鳩，僕痡泥滑吾欲休。", "虹橋列炬促歸騎，城鼓已報初更籌。", "追攀別乘聊復爾，乘興何如王子猷。", "習池不爲倒載去，兒童不用拍手攔街謳。"]'),
('4844c71b-3ae2-464a-a1a8-98cca79ca5c6','石洞','唐仲友','宋','宋诗','song-poetry','','[]','流泉在石上，細路在石下。',104,'全唐诗/poet.song.156000.json','["流泉在石上，細路在石下。", "天宇閉復開，竹樹邃而雅。", "我來不值桂壑風，月寒病骨艱迎逢。", "野田午後愛日烘，杖藜扶去穿谾豅。", "霜清水落石正瘦，落葉擁徑行龍鍾。", "決流作瀑飛短虹，小閣踞坐塵慮空。", "蕭然一笑出山去，迴首峻壁紛青紅。"]'),
('325e0d4a-4bf7-43cd-ad20-e0e8311b9ef5','雲峰院','唐仲友','宋','宋诗','song-poetry','','[]','木杪出危閣，軒窗羅翠屏。',24,'全唐诗/poet.song.156000.json','["木杪出危閣，軒窗羅翠屏。", "更須登石望，欲盡遠山青。"]'),
('f8268f70-5bc2-4f31-90cf-ee81ea83c2ca','村舍','唐仲友','宋','宋诗','song-poetry','','[]','草色紅泉井，桐陰白板扉。',24,'全唐诗/poet.song.156000.json','["草色紅泉井，桐陰白板扉。", "徘徊不忍去，坐待白雲歸。"]'),
('c0f0806a-5336-473b-9022-561277f28175','元應善利真人祠  其一','唐仲友','宋','宋诗','song-poetry','','[]','周道昔波蕩，王子生不辰。',48,'全唐诗/poet.song.156000.json','["周道昔波蕩，王子生不辰。", "忠言諫壅川，親意不我親。", "天壤不可支，厭此濁世塵。", "樂師爾何知，吾將去上賓。"]'),
('23f50576-6242-46f3-a6cb-4c9b19659c4d','元應善利真人祠  其二','唐仲友','宋','宋诗','song-poetry','','[]','吹笙洛陽道，邂逅浮邱公。',48,'全唐诗/poet.song.156000.json','["吹笙洛陽道，邂逅浮邱公。", "方瞳一莫逆，精思嵩高峰。", "劍舄我何有，飛馭凌剛風。", "時聞鳳凰鳴，隠隠丹霞中。"]'),
('2f404298-6de8-4e3d-b038-bb78e4355aab','元應善利真人祠  其三','唐仲友','宋','宋诗','song-poetry','','[]','弦月何皎皎，緱山何巍巍。',48,'全唐诗/poet.song.156000.json','["弦月何皎皎，緱山何巍巍。", "上有白鶴駕，聊與時人期。", "後天凋三光，何必千年歸。", "金闕帝有命，吾非丁令威。"]'),
('932aff86-6ad6-4572-9c7a-be00b970df9a','元應善利真人祠  其四','唐仲友','宋','宋诗','song-poetry','','[]','帝念下土民，山川分百靈。',48,'全唐诗/poet.song.156000.json','["帝念下土民，山川分百靈。", "命汝右弼君，秘宇開金庭。", "闔闢陰陽機，五岳趨朝纓。", "暇日帝汝思，時時來玉京。"]'),
('c44314dc-ed50-4c1c-bb82-cf897ccd56d0','元應善利真人祠  其五','唐仲友','宋','宋诗','song-poetry','','[]','桐柏亦何有，清輝照瓊臺。',48,'全唐诗/poet.song.156000.json','["桐柏亦何有，清輝照瓊臺。", "衆泉注金石，萬木羅琳瑰。", "玉室靜窈窕，鶴轡紛徘徊。", "紫雲擁飛蓋，知是真仙來。"]'),
('45ceb570-a2af-46ce-a1f8-908ab772eaf7','元應善利真人祠  其六','唐仲友','宋','宋诗','song-poetry','','[]','丹符列素奏，黄水晞雲漿。',48,'全唐诗/poet.song.156000.json','["丹符列素奏，黄水晞雲漿。", "吾道固欲傳，世人殊可傷。", "授汝紫陽周，語爾茅山楊。", "食之仙人芝，引袂同飛翔。"]'),
('7e5fd089-84d7-4bb7-9f66-3ced4757a3c0','元應善利真人祠  其七','唐仲友','宋','宋诗','song-poetry','','[]','丹邱壤千里，水旱固所司。',48,'全唐诗/poet.song.156000.json','["丹邱壤千里，水旱固所司。", "吾民實可矜，有守孰不祈。", "應汝捷影響，樂歲免阻饑。", "萬民齊叫閽，天子遠亦知。"]'),
('2b6e63de-521e-4e73-aa05-163b3674cfea','元應善利真人祠  其八','唐仲友','宋','宋诗','song-poetry','','[]','天子錫榮號，賁我靈宮祠。',48,'全唐诗/poet.song.156000.json','["天子錫榮號，賁我靈宮祠。", "吾道豈加損，群心自瞻依。", "峩峩芙蓉冠，劍佩明朱衣。", "自周迄於今，千載彌光輝。"]'),
('bd9d77f2-140f-469f-bbae-349e1e6a0bfb','元應善利真人祠  其九','唐仲友','宋','宋诗','song-poetry','','[]','外傳炯遺跡，真誥垂微言。',48,'全唐诗/poet.song.156000.json','["外傳炯遺跡，真誥垂微言。", "子微有妙筆，羅列丹青傳。", "我生後諸子，傾心慕真詮。", "像設儼如在，白雲聊續篇。"]'),
('f2db0040-6e49-4808-9410-b03edc29bd30','行登新現潭  其一','唐仲友','宋','宋诗','song-poetry','','[]','蕎麥花齊晚稻黄，今年此地是仙鄉。',32,'全唐诗/poet.song.156000.json','["蕎麥花齊晚稻黄，今年此地是仙鄉。", "籃輿又作山中去，敬爲神龍一瓣香。"]'),
('8375db8e-3cab-40a9-af90-4cfefbdccffb','行登新現潭  其二','唐仲友','宋','宋诗','song-poetry','','[]','薄雨輕雲掩翠微，豐年何物不熙熙。',32,'全唐诗/poet.song.156000.json','["薄雨輕雲掩翠微，豐年何物不熙熙。", "拒霜也效嫣然笑，白白紅紅出短籬。"]'),
('160eac87-6299-4118-ae02-aa5ae6f49928','辛丑正月上休日謁靈康廟拜滕公祠','唐仲友','宋','宋诗','song-poetry','','[]','蒼山餘雪在雲端，五兩摇風減曉寒。',64,'全唐诗/poet.song.156000.json','["蒼山餘雪在雲端，五兩摇風減曉寒。", "谷應笙簧成兩部，日涵煙水上三竿。", "相逢戲事留仙傳，如在英魂激壯肝。", "分職幽明均報國，願神終賜免空官。"]'),
('4c3ea85d-010c-4827-be81-5cd663c64c16','送錢守歸朝除大農二首  其一','唐仲友','宋','宋诗','song-poetry','','[]','北海廉平守，曾爲漢大農。',48,'全唐诗/poet.song.156000.json','["北海廉平守，曾爲漢大農。", "此邦高治行，今日繼前風。", "饑饉難於政，循良茂厥功。", "好將清靜對，推與四方同。"]'),
('b74dcccc-bab3-4e5e-972a-2701518627c8','送錢守歸朝除大農二首  其二','唐仲友','宋','宋诗','song-poetry','','[]','賤迹歸田里，高懷不世情。',48,'全唐诗/poet.song.156000.json','["賤迹歸田里，高懷不世情。", "細傾憂國酒，頻話及時耕。", "紫橐恩將近，茅茨計未成。", "攀轅無好語，所願達時英。"]'),
('9249d046-b09f-4e7a-844a-0d085bd31402','代家君答聞老詩三首  其一','唐仲友','宋','宋诗','song-poetry','','[]','流水高山舉似誰，我慚善聽匪鍾期。',32,'全唐诗/poet.song.156000.json','["流水高山舉似誰，我慚善聽匪鍾期。", "三詩歷歷皆可語，彷彿當時病可師。"]'),
('6792d23e-2162-4ea7-a3b8-5da38e8f9f58','代家君答聞老詩三首  其二','唐仲友','宋','宋诗','song-poetry','','[]','附熱銜泥不足言，爾來杖錫亦紛然。',32,'全唐诗/poet.song.156000.json','["附熱銜泥不足言，爾來杖錫亦紛然。", "不趨鑪炭趨寒谷，青白於中覺汝賢。"]'),
('112fb70a-ddbf-4a2b-af5b-b7624d1ed717','代家君答聞老詩三首  其三','唐仲友','宋','宋诗','song-poetry','','[]','江山天借使詩昌，太守風流似沈郎。',32,'全唐诗/poet.song.156000.json','["江山天借使詩昌，太守風流似沈郎。", "莫作推敲衝導其，好携佳句過黄堂。"]'),
('360d8af9-1f92-4263-a1d0-8306f5fba21a','讀章嘉甫詩','唐仲友','宋','宋诗','song-poetry','','[]','句法亡來久，詩壇忽有人。',48,'全唐诗/poet.song.156000.json','["句法亡來久，詩壇忽有人。", "看君哦字苦，勝我食芝新。", "國史空遺恨，竿門未識真。", "尚須樽酒細，非效捧心顰。"]'),
('80f3dd89-2cec-4db8-b72d-c9ea59313396','次季弼索楊繼甫詩  其一','唐仲友','宋','宋诗','song-poetry','','[]','詩來得得巧搜尋，清似壺冰洗我心。',64,'全唐诗/poet.song.156000.json','["詩來得得巧搜尋，清似壺冰洗我心。", "白雪陽春皆絕唱，高山流水欠知音。", "秦淮淼淼涵秋影，楚岸迢迢起夕陰。", "此際須君速相就，寒鴉趁侶欲投林。"]'),
('b435aae9-5375-4254-90bc-317b7c55d159','次季弼索楊繼甫詩  其二','唐仲友','宋','宋诗','song-poetry','','[]','愛山欲作杪秋尋，薄宦逢回倦壯心。',64,'全唐诗/poet.song.156000.json','["愛山欲作杪秋尋，薄宦逢回倦壯心。", "排遣牢愁須魯酒，激揚逸氣和春音。", "歸與物色荒山徑，晚矣功名惜寸陰。", "寂寞孤芳聊自守，不殊蘭芷在深林。"]'),
('b326053f-5c04-485f-84b9-1c59d1e59956','繡川湖','唐仲友','宋','宋诗','song-poetry','','[]','衆水匯山麓，平湖天宇寬。',48,'全唐诗/poet.song.156000.json','["衆水匯山麓，平湖天宇寬。", "千家連島嶼，十里带林巒。", "柳長波瀾闊，荷衰風月寒。", "吾將乘一棹，誰與辦綸竿。"]'),
('979a5517-96e8-4cb8-873f-b5623657b1a2','題劉能之書室日靜齋','唐仲友','宋','宋诗','song-poetry','','[]','書齋一明窗，平湖在軒闥。',72,'全唐诗/poet.song.156000.json','["書齋一明窗，平湖在軒闥。", "良朋求我名，題榜子聽說。", "心靜見天地，水靜燭毫髮。", "槁木兼死灰，智動此機栝。", "微風不揚波，方寸皦明月。", "一舉在雲霄，期汝茲奮發。"]'),
('ac163a2c-8d1c-429e-9131-bd0cc4816c62','雨花臺  其一','唐仲友','宋','宋诗','song-poetry','','[]','竟夕飛花一尺圍，今朝晴色荷神禧。',64,'全唐诗/poet.song.156000.json','["竟夕飛花一尺圍，今朝晴色荷神禧。", "共尋蕭寺因乘興，直上高臺是愛奇。", "鳷鵲餘寒通北極，鳳凰斜照落西垂。", "詩成似得江山助，莫遣金陵勝侶知。"]'),
('f6db1798-c051-4a1f-8f86-bb935cdc1e50','雨花臺  其二','唐仲友','宋','宋诗','song-poetry','','[]','促膝紅爐擁肉圍，淺斟竹葉介繁禧。',64,'全唐诗/poet.song.156000.json','["促膝紅爐擁肉圍，淺斟竹葉介繁禧。", "明年雪裏人應健，醉客詩成語益奇。", "戲掬巧爭肌玉瑩，快餐不省鬢絲垂。", "歸來鼻息春雷動，晴日三竿總未知。"]'),
('0c4b72f9-4a84-4e7e-983e-d9eadda8a972','雨花臺  其三','唐仲友','宋','宋诗','song-poetry','','[]','因時興滅易成空，更向層臺覓舊蹤。',64,'全唐诗/poet.song.156000.json','["因時興滅易成空，更向層臺覓舊蹤。", "江渚餘寒棲白鷺，山崗晴色轉青龍。", "風烟暖入千林景，絲管春生萬井容。", "堪笑冷官詩思苦，絕塵高韻以難從。"]'),
('c2340785-15bf-47af-bed6-eaf097c89194','長臺途中','唐仲友','宋','宋诗','song-poetry','','[]','衝曉入山去，行行遵遠途。',48,'全唐诗/poet.song.156000.json','["衝曉入山去，行行遵遠途。", "灘頭橫略彴，林表出浮圖。", "麥飯田家餉，松醪野店酤。", "紅塵自擾擾，心與白雲孤。"]'),
('148f01d6-e7c4-480f-a397-c1c8149510c3','蠟梅十五絕和陳天予韻  其一','唐仲友','宋','宋诗','song-poetry','','[]','此花清絕似幽人，苦耐冰霜不愛春。',32,'全唐诗/poet.song.156000.json','["此花清絕似幽人，苦耐冰霜不愛春。", "蠟蕊輕明香萬斛，黄姑端的是前身。"]'),
('a753bf65-22e2-453d-93c7-68a49ee4bd49','蠟梅十五絕和陳天予韻  其二','唐仲友','宋','宋诗','song-poetry','','[]','點綴何曾待化人，密房瑣瑣暗藏春。',32,'全唐诗/poet.song.156000.json','["點綴何曾待化人，密房瑣瑣暗藏春。", "定應昔與江梅友，惹得清香尚滿身。"]'),
('38a1d5cd-ace0-4b60-a404-998d1e5048a1','蠟梅十五絕和陳天予韻  其三','唐仲友','宋','宋诗','song-poetry','','[]','袂剪黄羅亦可人，君詩剩覓小園春。',32,'全唐诗/poet.song.156000.json','["袂剪黄羅亦可人，君詩剩覓小園春。", "最憐丈室銅瓶裏，獨對維摩似病身。"]'),
('6668352e-e1aa-47c4-b820-307d03597f74','蠟梅十五絕和陳天予韻  其四','唐仲友','宋','宋诗','song-poetry','','[]','黄姑侍女兩三人，散作名家不嫁春。',32,'全唐诗/poet.song.156000.json','["黄姑侍女兩三人，散作名家不嫁春。", "仙桂飄零籬菊盡，香容付與雪中身。"]'),
('7bcd6645-96d4-42f2-8938-691dfa8b963e','蠟梅十五絕和陳天予韻  其五','唐仲友','宋','宋诗','song-poetry','','[]','日暮天寒倚竹人，淡粧別有一般春。',32,'全唐诗/poet.song.156000.json','["日暮天寒倚竹人，淡粧別有一般春。", "紫橐深貯香無限，金縷初裁穩稱身。"]'),
('1d04532e-9f03-4bfc-9b9b-f79ac8d125dd','蠟梅十五絕和陳天予韻  其六','唐仲友','宋','宋诗','song-poetry','','[]','山麝時時暗襲人，薔薇露濕滿枝春。',32,'全唐诗/poet.song.156000.json','["山麝時時暗襲人，薔薇露濕滿枝春。", "若教粉蝶知音耗，應怨韶華枉誤身。"]'),
('abcb0140-0257-491f-af60-4031dd69b8de','蠟梅十五絕和陳天予韻  其七','唐仲友','宋','宋诗','song-poetry','','[]','的皪光明色照人，枝頭已有十分春。',32,'全唐诗/poet.song.156000.json','["的皪光明色照人，枝頭已有十分春。", "我驚喚作菩提樹，爲是如來幻化身。"]'),
('cc1392e1-8cbf-440e-9748-4aff13c8ef87','蠟梅十五絕和陳天予韻  其八','唐仲友','宋','宋诗','song-poetry','','[]','不管江梅妬殺人，壺中日月已先春。',32,'全唐诗/poet.song.156000.json','["不管江梅妬殺人，壺中日月已先春。", "恰如姑射神仙子，野服高閑物外身。"]'),
('4ab0c849-1139-4413-96c7-b467b8bb1e24','蠟梅十五絕和陳天予韻  其九','唐仲友','宋','宋诗','song-poetry','','[]','長伴南枝带雪開，渾無蜂蝶去徘徊。',32,'全唐诗/poet.song.156000.json','["長伴南枝带雪開，渾無蜂蝶去徘徊。", "可能熟識金仙面，只有詩人日日來。"]'),
('8766e428-4722-41c1-b0f9-f7f2a5836ced','蠟梅十五絕和陳天予韻  其一○','唐仲友','宋','宋诗','song-poetry','','[]','只恐幽花取次開，哦詩忍凍幾徘徊。',32,'全唐诗/poet.song.156000.json','["只恐幽花取次開，哦詩忍凍幾徘徊。", "莫猜野服風情淺，解把天香暗裏來。"]'),
('aaa7f7f6-49a6-4722-8729-15f5229c47b4','蠟梅十五絕和陳天予韻  其一一','唐仲友','宋','宋诗','song-poetry','','[]','甚欲陪君酒甕開，寒侵病骨却徘徊。',32,'全唐诗/poet.song.156000.json','["甚欲陪君酒甕開，寒侵病骨却徘徊。", "不辭更琢金仙句，圖得拋磚換玉來。"]'),
('af9aa13e-8097-42bd-90d7-4d767371ca40','蠟梅十五絕和陳天予韻  其一二','唐仲友','宋','宋诗','song-poetry','','[]','爲愛凌晨細細開，誰人伴我獨徘徊。',32,'全唐诗/poet.song.156000.json','["爲愛凌晨細細開，誰人伴我獨徘徊。", "朝陽滿樹無塵滓，寒雀驚窺欲下來。"]'),
('7108e521-b932-46d4-b24b-e50e59ed7b78','蠟梅十五絕和陳天予韻  其一三','唐仲友','宋','宋诗','song-poetry','','[]','一點輕明照雪開，六花驚妬亦徘徊。',32,'全唐诗/poet.song.156000.json','["一點輕明照雪開，六花驚妬亦徘徊。", "清香不在江梅後，底事全無驛使來。"]'),
('38803eb5-7814-46b3-bb2e-6016977de958','蠟梅十五絕和陳天予韻  其一四','唐仲友','宋','宋诗','song-poetry','','[]','幾歲巖扃獨自開，何人立馬爲徘徊。',32,'全唐诗/poet.song.156000.json','["幾歲巖扃獨自開，何人立馬爲徘徊。", "只因坡谷傳佳句，惹得尋春使少來。"]'),
('50248d2f-d83d-4a5b-9bbd-c67e25fba0c5','蠟梅十五絕和陳天予韻  其一五','唐仲友','宋','宋诗','song-poetry','','[]','積雪愁陰久不開，爲憐花冷故徘徊。',32,'全唐诗/poet.song.156000.json','["積雪愁陰久不開，爲憐花冷故徘徊。", "憑君琢句留金蕊，待取霜風送月來。"]'),
('40913165-ad7c-44a5-b248-e52f3c2177c8','蠟梅','唐仲友','宋','宋诗','song-poetry','','[]','凌寒不獨早梅芳，玉艷更爲一樣粧。',64,'全唐诗/poet.song.156000.json','["凌寒不獨早梅芳，玉艷更爲一樣粧。", "懶著霓裳貪野服，自然仙骨有天香。", "輕明最是宜風日，冷淡從來傲雪霜。", "欲識清奇無盡處，中間深佩紫羅囊。"]'),
('18a8e70c-3a56-4378-8629-24a76fe8a4b2','難老堂吳居厚爲祖母作張子昭劉文叔史直翁賦詩','唐仲友','宋','宋诗','song-poetry','','[]','風樹感親壽，忽若冬隕霜。',84,'全唐诗/poet.song.156000.json','["風樹感親壽，忽若冬隕霜。", "以孫養祖母，惴惴駒隙光。", "無孫又繼絕，此意誰激昂。", "吳氏有純孝，業業含飴傍。", "延年寓題榜，戲綵勤奉觴。", "詩成三巨公，令德昭不忘。", "九原邈已遠，遺範悲空堂。"]'),
('0ccbda6b-1687-427d-b3c7-4691753b8f45','題止一堂','唐仲友','宋','宋诗','song-poetry','','[]','艮不獲其身，人無監流水。',24,'全唐诗/poet.song.156000.json','["艮不獲其身，人無監流水。", "畎畝義惓惓，時止非吾止。"]'),
('8fc4fcad-455e-40e7-a48d-b63bf03e9298','賀孫知從改章服','唐仲友','宋','宋诗','song-poetry','','[]','蚤歲蹉蛇晚節全，舉觴猶自吸長川。',64,'全唐诗/poet.song.156000.json','["蚤歲蹉蛇晚節全，舉觴猶自吸長川。", "紫泥優渥逢熙事，朱紱榮華慰暮年。", "强效瓊杯哦慶語，欲將鐵杖壽真仙。", "明堂尚有蒲輪召，未許終閑野水船。"]'),
('157f4cab-b187-4b0f-8e4f-6c5ce263ddb6','句','唐仲友','宋','宋诗','song-poetry','','[]','萬斛出時非擇地，一泓澄處本無心。',16,'全唐诗/poet.song.156000.json','["萬斛出時非擇地，一泓澄處本無心。"]'),
('d6d27ab7-f3a3-40a5-82c5-b0921bf92385','奉題林稚春菊花枕子歌','林亦之','宋','宋诗','song-poetry','','[]','故人所說菊花枕，似把冰丸月下飲。',166,'全唐诗/poet.song.156000.json','["故人所說菊花枕，似把冰丸月下飲。", "秋水一雙明炯炯，數在青囊第一品。", "狂風江上吹蒹葭，此物往往得之嵇康阮籍家。", "閉門誦書二十年，眼睛損盡生空花。", "建陽小作箸頭書，殘更燈火亂蟲魚。", "石渠文字大如斗，場屋歲月又不偶。", "却來南山青草邊，東西四至盡爲菊花田。", "手提長筐向山曲，一下收拾三百斛。", "昨者昏寐才起來，解把簷頭小字讀。", "乃知妙物通羣仙，一切藥裹應棄捐。"]'),
('a8939b3b-5d42-45bd-b757-35773c4f9156','奉酬稚春梅花行','林亦之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','草堂梅花千萬枝，新詩品題何太奇。',160,'全唐诗/poet.song.156000.json','["草堂梅花千萬枝，新詩品題何太奇。", "可憐一枝非凡羣，賞心何人空自珍。", "請與君談別花人，如或見之當俯身。", "西湖一带何蒼茫，娟娟數枝臨水傍。", "上有幽人眉骨橫，終日對花情意生。", "花如秋月照芭蕉，人似春風吹野苗。", "人與花枝自相親，一篇至今吟如新。", "胸中若有一點塵，縱對此花無精神。", "平生不識市沽兒，四更誦書長苦饑。", "摩挲此腹遶疎籬，笑折花枝花自知。"]'),
('a675e941-aaf4-4df8-ac61-0edbb5b8b0d0','戲題稚春杜少陵詩集','林亦之','宋','宋诗','song-poetry','','[]','十年蕭蕭去武林，橐中唯有謫仙吟。',160,'全唐诗/poet.song.156000.json','["十年蕭蕭去武林，橐中唯有謫仙吟。", "君今失意還山窟，少陵詩集如明月。", "自怪平生每相似，窮愁嗜好亦如許。", "飯顆山頭舊相逢，安得娟娟同處所。", "故人語我明年冬，或騎大馬長安中。", "或倚書樓頭如蓬，即見雙劍終然同。", "我聞此語歡且劇，視君狀貌如其筆。", "兩目津津可終遁，此物應藏月魚室。", "月魚文字非時好，已問菟裘吾將老。", "綠煙亭下黄花時，兩手抱取歸柴扉。"]'),
('7ead3089-a3f8-4d8e-915e-c2163608f712','和李監倉欲遊龍卧山以海風大作不果往','林亦之','宋','宋诗','song-poetry','','[]','枉蒙龍卧篇，如睹藤蘿境。',132,'全唐诗/poet.song.156000.json','["枉蒙龍卧篇，如睹藤蘿境。", "十年招隠士，欲到此山頂。", "坐石誦離騷，掬水弄清影。", "無人同荷鋤，長愧林下景。", "昨者逢李侯，一笑便歡領。", "爲言有明月，公事且暫屏。", "騎馿學賈島，捫蝨喚王猛。", "雙鑣雲外來，斜帽不須整。", "夜投招提宿，聽雨寒更永。", "論文到昌黎，說詩笑匡鼎。", "悶人數日風，何時發深省。"]'),
('0ce02568-c4f3-4707-b2d3-4ab3947187cf','丁亥九月十六夜偕李監倉宿龍卧山中聽雨看月同時事也所謂魚與熊掌兼得之賦詩一篇以紀其事','林亦之','宋','宋诗','song-poetry','','[]','相喚此山來，狂風吹我衣。',72,'全唐诗/poet.song.156000.json','["相喚此山來，狂風吹我衣。", "把酒桂花下，山雲片段飛。", "掩門雨初滴，開門月還上。", "倚樹看月明，半山聞雨響。", "人間有佳景，詩句頗發越。", "何曾似今夕，聽雨還看月。"]'),
('cf7b2d49-3678-4aa3-a9c0-8404bbe5b2ff','九月晦日登烽火山','林亦之','宋','宋诗','song-poetry','','[]','興來走上烽火山，著足不定秋風寒。',96,'全唐诗/poet.song.156000.json','["興來走上烽火山，著足不定秋風寒。", "四邊黄茅滑如雨，低頭一看毛髮豎。", "幾年要到紫菜鄉，大練小練并東牆。", "如今一時在眼傍，白雲浮水天茫茫。", "酒闌更欲弔虎屋，無端日脚相催促。", "一奴魋髻一跛足，逐我下山如野鹿。"]'),
('5dc9c8d9-40d3-47e7-8ef8-c082fc94bca6','見獨斯行叔綺子爲赴春試一出江頭送別殊令牽懷聊爲巴闌行一首以道此意云爾','林亦之','宋','宋诗','song-poetry','','[]','巴闌獨還歲月深，相送出門自沉吟。',232,'全唐诗/poet.song.156000.json','["巴闌獨還歲月深，相送出門自沉吟。", "十年交舊總如許，狂歌一曲傷人心。", "今人讀書如過客，壺飧只向市頭索。", "吾曹苦思腸幾穿，安得相逢不索莫。", "念我平生弄典墳，六月北窗長閉門。", "雕肝篆肺得一句，旁人袖手評其文。", "思量至此復一笑，如何躍馬追年少。", "我今聞說有場屋，兩耳如聾怕聽得。", "網山山下月魚亭，就船買魚活煮羹。", "何時挾冊此來歸，議論不到吾縱橫。", "故人年幾今猶未，正好款門問知己。", "時命相遭不用多，或在半言并片紙。", "老人校書紫雲樓，相見或問吾因由，爲言索處海水頭。", "蓬萊方丈不可到，此心日夕徒生憂。"]'),
('9dd9c4f0-2543-4534-8555-dfeb175dffaf','秋夜同章三十九弟次邠宿延慶山中紀遊一首','林亦之','宋','宋诗','song-poetry','','[]','芭蕉月上照窗扉，屋裏老僧眠不知。',64,'全唐诗/poet.song.156000.json','["芭蕉月上照窗扉，屋裏老僧眠不知。", "起來樹根飲一盞，舉頭忽是三更時。", "藤蘿一處一處好，我亦持盃隨處坐。", "山雞忽叫野鐘鳴，滿地西風愁殺我。"]'),
('cf023cf7-2c1b-4b3f-817c-bb888f5fd17f','古意','林亦之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','深夜步秋檐，明月照石階。',72,'全唐诗/poet.song.156000.json','["深夜步秋檐，明月照石階。", "所憶不可見，乃愛徒興懷。", "我欲掛天帆，長江風浪摧。", "我欲跨綠耳，蒼林煙雨回。", "只有坐長想，佳人安在哉。", "何時覿來袂，雙目冏冏開。"]'),
('2a035a72-2d8f-47cb-8542-260f362b734c','邑大夫范丈寵示廣陵餘事泠然誦之歷歷慘惻如在目中輒賦短篇紀所聞也','林亦之','宋','宋诗','song-poetry','','[]','嘗閲淮南圖，蕭蕭草屋少人居。',208,'全唐诗/poet.song.156000.json','["嘗閲淮南圖，蕭蕭草屋少人居。", "及讀廣陵集，惻惻我心欲垂泣。", "吁嗟戀鄉國，生死不肯去。", "邊笳纔一動，殺幾先此土。", "可憐此土人，父子無白頭。", "不死於饑即死戰，性命只在道旁溝。", "更聞維揚有鬼市，銅錢須臾變爲紙。", "都緣白日殺人多，所以冤魂有如是。", "君侯壯思凌雲空，青衫匹馬戎幕中。", "當時轅門眼所見，長歌短歌淚如綫。", "少陵嶇崎夔峽路，一切悲愁託詩句。", "至今太史不足憑，惟有此詩爲可據。", "紹興辛巳淮楚功，紛紛予奪或異同。", "他年石渠訪遺事，爲說東陽有蔚宗。"]'),
('f556d477-42cd-411e-9227-badb23023b38','范宰登瑞峰塔續蒙寵寄古篇輒次來韻','林亦之','宋','宋诗','song-poetry','','[]','平明眺遠目，蒼波吐紅暾。',96,'全唐诗/poet.song.156000.json','["平明眺遠目，蒼波吐紅暾。", "已瞻大鼇網，復矚鸕鷀門。", "宿酲雖已解，衫襟猶酒痕。", "憑陵不可羈，往往天欲捫。", "却憶去年時，舟役勞朝昏。", "幼婦带桎梏，嚼飯不敢吞。", "今年復此役，溪山恣討論。", "爲有陶元亮，心胸如阜坤。"]'),
('161ff1e0-a9b0-4444-b9db-fad7d40a88bd','范宰見寄遊草堂誰謂漁鹽市之什輒同賦一篇不用元白唱酬之法','林亦之','宋','宋诗','song-poetry','','[]','誰謂魚鹽市，乃枉大夫軒。',144,'全唐诗/poet.song.156000.json','["誰謂魚鹽市，乃枉大夫軒。", "既登雲霞觀，更尋薜蘿村。", "松枝何夾道，萱草况當門。", "借問阿誰家，此爲故人園。", "倚竹坐半日，論詩到初根。", "愧無捫蝨姿，敢辱輟鸞言。", "勞勞青衫客，莽莽紅塵奔。", "所至有山水，何曾解討論。", "君侯食肉相，杞菊爲心魂。", "一縣固多事，終朝如山樊。", "行旌遇佳勝，呼賓羅芳尊。", "有此幽寂趣，從容以剸繁。"]'),
('bd7a89b1-bdbd-41f2-8a91-7755f2802dd4','范宰同鄭簿應尉送戰船至海上招野人同遊賦得可月湖一篇奉呈','林亦之','宋','宋诗','song-poetry','','[]','可月湖邊送戰舸，長嘯便欲凌清波。',128,'全唐诗/poet.song.156000.json','["可月湖邊送戰舸，長嘯便欲凌清波。", "好風吹帆如去馬，鼠曹若可雙手把。", "青天無雲水初漲，一山兩山浮水上。", "平生膽意少羈束，叩舷長歌心益壯。", "生平誦書口啾啾，何似一日觀滄流。", "厖眉太史足重繭，盡驅百怪歸筆頭。", "羣公楚楚皆人物，我亦自忘布衣拙。", "恢諧莫續濟川君，可無一詩記明月。"]'),
('1c4e024f-a970-451c-9206-03feb8cd0683','丈人行答通平林簿','林亦之','宋','宋诗','song-poetry','','[]','祖龍一出羣儒怒，滔滔稷下如抽縷。',224,'全唐诗/poet.song.156000.json','["祖龍一出羣儒怒，滔滔稷下如抽縷。", "樂以聲傳非文字，千年闕斷無人補。", "昔有丈人壺山前，紹興甲寅乙卯年。", "定律不待累黍起，瓦缶皆可成宮徵。", "更言吹律隨隆汙，百世不以一聲拘。", "此法漢魏周隋無，紅泉得之延坐隅。", "一時河漢東西奔，姓氏胡爲旅人門。", "我欲栩栩還皇墳，要以六琯爲根原。", "九簫鼓吹百物和，羽衣狼藉漁陽戈。", "須信樂能召太平，非是太平爲樂歌。", "丈人宿草飛毿毿，乾旋坤轉誰更堪。", "忽有尺紙如春蠶，遺音石笋天一南。", "三更把書不成眠，四更起坐霜月懸。", "五更開門欲上馬，至竟此人何山下。"]'),
('b9bd8c0d-3fd5-4183-8551-a9696b97db23','賀江宰生朝','林亦之','宋','宋诗','song-poetry','','[]','清秋八月月未弦，河陽市上謳聲傳。',256,'全唐诗/poet.song.156000.json','["清秋八月月未弦，河陽市上謳聲傳。", "今年百姓杯飯足，敢不祝公長命篇。", "青衫白馬鳴琴初，適逢吁嗟舞羣巫。", "日維對案愁眉紆，退食皇皇雙頰癯。", "家雖貧困仰母慈，村村樂業無逃逋。", "况此一熟十年無，東家西家禾滿車。", "窮儒如儂四壁立，亦有甌窶可讀書。", "縣人安得此豐歲，實以善政吾非諛。", "昨者越上人苦饑，公一主簿何能爲。", "自穿滄海告鄰糴，所視身命半縷絲。", "長風駕浪海波黑，舟人各各面如墨。", "尚據胡床取紙筆，爲文憤怒駡風伯。", "翩翩盛名日以起，四海識公從此始。", "總爲六鼇带歸去，何哉雙鳬更來此。", "陰德由來活人多，龜齡鶴算定爾過。", "况當竹下圍棋日，繽紛百福連山河。"]'),
('dc2d39ba-b8ad-4aff-9b3a-3f6ccd59edc3','奉酬監鎮梁丈所惠臘梅之什','林亦之','宋','宋诗','song-poetry','','[]','臘梅好好花枝閒，官亭楚楚歲事闌。',64,'全唐诗/poet.song.156000.json','["臘梅好好花枝閒，官亭楚楚歲事闌。", "思量窮冬損情思，感激芳意生容顔。", "孤標不是如許骨，野落可能禁此寒。", "誰信魚鹽屈詩客，三更遶樹興未殘。"]'),
('1c550761-c2a9-443f-b027-628b15cb7ac4','答稚春送瘞鶴銘','林亦之','宋','宋诗','song-poetry','','[]','烹魚蒙尺牘，瘞鶴有殘碑。',48,'全唐诗/poet.song.156000.json','["烹魚蒙尺牘，瘞鶴有殘碑。", "老去無他好，朝來愜所思。", "幽懷增感激，妙處自傾欹。", "喜劇還生嘆，如今愛者誰。"]'),
('4c2158ed-ee3f-4532-bd24-af93298edd16','答稚春所寄詩卷','林亦之','宋','宋诗','song-poetry','','[]','不見幾多日，詩篇句句新。',48,'全唐诗/poet.song.156000.json','["不見幾多日，詩篇句句新。", "沉吟堪膾炙，塗抹更精神。", "世俗難知己，文章却解貧。", "竹窗休苦思，思苦轉愁人。"]'),
('e4888aff-1850-4b23-97c6-e90a07be1e46','草堂同爨呈稚春','林亦之','宋','宋诗','song-poetry','','[]','雲錦堂前花作堆，尋幽養靜屬吾儕。',64,'全唐诗/poet.song.156000.json','["雲錦堂前花作堆，尋幽養靜屬吾儕。", "高高下下黄柑樹，曲曲斜斜碧草階。", "數點遠山如越縣，一條寒水似秦淮。", "龐公父子能留客，我亦三年忘客懷。"]'),
('144f3840-d425-471d-8e96-faaa87f8f096','奉酬監倉李丈金橘銀魚之什','林亦之','宋','宋诗','song-poetry','','[]','爲有風流賀季真，道齋從此往來頻。',64,'全唐诗/poet.song.156000.json','["爲有風流賀季真，道齋從此往來頻。", "錦囊牙軸詩千卷，金橘銀魚酒一巡。", "見我每呼蓮社客，看君還是竹林人。", "有時夜話寒更盡，明日相逢語又新。"]'),
('43bbfe56-4d95-432e-873c-6a540a895762','九月登龍卧山','林亦之','宋','宋诗','song-poetry','','[]','復此雲山飲，吁嗟空自勞。',48,'全唐诗/poet.song.156000.json','["復此雲山飲，吁嗟空自勞。", "三迴看杞菊，兩度歎蓬蒿。", "昨者唯傷李，如今更憶曹。", "海陽真俊逸，一等野墳高。"]'),
('a3cc3aa9-4a97-43cb-8fc3-faa96779f1a4','九月遊龍卧山留一夕明日值雨坐超上人房偶題','林亦之','宋','宋诗','song-poetry','','[]','野興更周遭，應遲問大刀。',48,'全唐诗/poet.song.156000.json','["野興更周遭，應遲問大刀。", "山房逢雨好，人意與秋高。", "多謝烹鮮乳，還令厭濁醪。", "重來須累少，款款聽蕭騷。"]'),
('4e9b3ccb-ef61-4b9e-a155-6c18da3c9d9f','歲晚山樓書懷','林亦之','宋','宋诗','song-poetry','','[]','儺鼓逢逢起，江邊歲又除。',48,'全唐诗/poet.song.156000.json','["儺鼓逢逢起，江邊歲又除。", "哦詩猶古木，高枕尚僧居。", "脚垢時忘洗，頭蓬月懶梳。", "自應塵事少，非我故耽書。"]'),
('cf696eec-5ed7-4f5e-9674-3ae74b1e3e47','秋試歸訪綠煙亭','林亦之','宋','宋诗','song-poetry','','[]','竹逕縈紆去，相逢情若何。',48,'全唐诗/poet.song.156000.json','["竹逕縈紆去，相逢情若何。", "江從木杪見，秋向菊邊多。", "謾有風濤想，如今歲月過。", "唯於交舊裏，聽取碧雲歌。"]'),
('e1adae3b-538f-4a2b-88c6-e2a0ebd66a44','陳文煥秀才所宅近市憑樓一望西山宛然墮几案中縣之豪雋唱酬不下數十百篇野人後來承聽許不必次韻故爲之賦一首','林亦之','宋','宋诗','song-poetry','','[]','西山簷外見，何必鹿門行。',48,'全唐诗/poet.song.156000.json','["西山簷外見，何必鹿門行。", "近晚市聲合，疎簾野意生。", "終朝如此好，初月更多情。", "却愧才華鈍，三年句不成。"]'),
('0c43dd04-3eff-4967-9494-4efde942b304','縣學東軒','林亦之','宋','宋诗','song-poetry','','[]','莫道東軒惡，朝來意欲迷。',48,'全唐诗/poet.song.156000.json','["莫道東軒惡，朝來意欲迷。", "平田飛白鳥，高木叫黄鸝。", "林闕孤峰出，簷低遠樹齊。", "雖然有佳趣，那似海門西。"]'),
('3c9f603e-70e8-4fc3-a1c2-9a16af84a8ca','江上','林亦之','宋','宋诗','song-poetry','','[]','敗絮滄江上，柴門落日中。',48,'全唐诗/poet.song.156000.json','["敗絮滄江上，柴門落日中。", "論文誰與共，覓句不須工。", "壯思如秋葉，搔頭似老翁。", "崎嶇村浦路，敢自說豪雄。"]'),
('43ef2613-aae0-46d6-b7a6-02d5877fdf84','陪范明府與諸同官飲新亭是夕以莞爾榜之因賦此詩','林亦之','宋','宋诗','song-poetry','','[]','把燭新亭下，迂疎聊爾歌。',48,'全唐诗/poet.song.156000.json','["把燭新亭下，迂疎聊爾歌。", "酒緣人品勝，官要野情多。", "燕豆客俱好，漁竿人亦過。", "誰知武城笑，深自惜蹉跎。"]'),
('904ee65e-ff93-4a01-ba68-4937e89301f4','瑞峰院夜語奉酬鄭簿','林亦之','宋','宋诗','song-poetry','','[]','百級上層巒，呼鐙同所歡。',48,'全唐诗/poet.song.156000.json','["百級上層巒，呼鐙同所歡。", "甆杯真有道，行李似無官。", "妙語勝熊掌，疎才愧鶡冠。", "古人相見意，不作酒肴看。"]'),
('6f2e10c4-76d1-410d-884f-e304f23b6faf','江樓陪范長官宴自警一篇戲呈鄭主簿','林亦之','宋','宋诗','song-poetry','','[]','幾回過海上，此日暫躊躇。',48,'全唐诗/poet.song.156000.json','["幾回過海上，此日暫躊躇。", "未盡尊前酒，還奔使者車。", "官人無少暇，賤子敢安居。", "一畝芭蕉圃，如今要自鋤。"]'),
('bcfc82ee-52ea-44e6-a3e2-56e33b76e26f','奉送范宰秩滿還東陽','林亦之','宋','宋诗','song-poetry','','[]','語違今幾日，猶更上層巒。',48,'全唐诗/poet.song.156000.json','["語違今幾日，猶更上層巒。", "情自緣君子，吾非送長官。", "衝寒去程遠，惜別賦詩難。", "政拙爲遺愛，留將識者看。"]'),
('d4004993-f8df-4cdd-b531-1e38dec20762','翁丈柔中同姪昭文相訪留兩日既別贈以詩','林亦之','宋','宋诗','song-poetry','','[]','委巷無過客，明燈迎此翁。',48,'全唐诗/poet.song.156000.json','["委巷無過客，明燈迎此翁。", "歡欣屐齒折，羞澀酒缾空。", "燒芋隨家法，論詩到國風。", "胡麻煮清棗，更擬故人同。"]'),
('8e7ac820-8bd1-4e8c-bef0-400791a59f61','網山二首  其一','林亦之','宋','宋诗','song-poetry','','[]','風濤生長處，土地屬東隅。',48,'全唐诗/poet.song.156000.json','["風濤生長處，土地屬東隅。", "樹樹懸魚網，村村吹鷓鴣。", "酒旗孤嶼見，書卷一山無。", "欲趁雞豚社，深慙身業儒。"]'),
('9afde3d1-8be0-4e67-a21a-31daa70f8d5b','網山二首  其二','林亦之','宋','宋诗','song-poetry','','[]','屋舍高低住，比隣活計同。',48,'全唐诗/poet.song.156000.json','["屋舍高低住，比隣活計同。", "笭箵嫌月白，螃蟹要霜紅。", "吠犬隨村落，賣魚成老翁。", "地鹹耕種少，海熟抵年豐。"]'),
('3b8d7dc8-d882-4dc8-8261-3e5c7123373a','續夢中所見兩句','林亦之','宋','宋诗','song-poetry','','[]','長劍歌明月，吳門一夜過。',24,'全唐诗/poet.song.156000.json','["長劍歌明月，吳門一夜過。", "紅樓何處是，爲說馬闌坡。"]'),
('871096c4-f2a6-411d-b82e-d4a76d7144cd','記九月二十五夜夢中作','林亦之','宋','宋诗','song-poetry','','[]','藥圃幽人徑，桃源處士居。',24,'全唐诗/poet.song.156000.json','["藥圃幽人徑，桃源處士居。", "歲時雖屢改，蹤跡尚如初。"]'),
('e8f0f08d-130c-45b8-abbd-10cc260908bb','延慶寫真贊二首  其一','林亦之','宋','宋诗','song-poetry','','[]','住山頭欲白，何爾太邪揄。',24,'全唐诗/poet.song.156000.json','["住山頭欲白，何爾太邪揄。", "却厭舊時面，丹青別換模。"]'),
('2dbc54f7-caa1-4adc-a1e1-7ed7b08125d3','延慶寫真贊二首  其二','林亦之','宋','宋诗','song-poetry','','[]','秋雨秋山夜，縱縱自橫橫。',24,'全唐诗/poet.song.156000.json','["秋雨秋山夜，縱縱自橫橫。", "平生無罪過，不合去爲僧。"]'),
('a756b59b-c442-474c-81ab-7a3a8f724b39','春晚招石門陳居士遊麥斜巖破新茶因讀南華齊物論二首  其一','林亦之','宋','宋诗','song-poetry','','[]','叫破殘花深處眠，麥斜巖下畢逋前。',32,'全唐诗/poet.song.156000.json','["叫破殘花深處眠，麥斜巖下畢逋前。", "更須汲井開茶共，讀盡南華齊物篇。"]'),
('097dabc4-9d92-49d3-bbe6-055053d75e3d','春晚招石門陳居士遊麥斜巖破新茶因讀南華齊物論二首  其二','林亦之','宋','宋诗','song-poetry','','[]','好好輕衫清晝便，短鋤欲乞此來田。',32,'全唐诗/poet.song.156000.json','["好好輕衫清晝便，短鋤欲乞此來田。", "只應荷蕢無青髮，且謾春風二十年。"]'),
('990ac252-c4a8-45f1-a496-54bcad058399','范公彌誕之辰輒述閭巷語爲邑大夫壽且俟採詩者','林亦之','宋','宋诗','song-poetry','','[]','錦樓壽曲未須吹，且聽江邊老婦詞。',32,'全唐诗/poet.song.156000.json','["錦樓壽曲未須吹，且聽江邊老婦詞。", "但願年年好官長，一如官長在官時。"]'),
('6060c4c3-a52a-42a7-8994-b9e2790065bf','同范長官鄭主簿送戰船至鹽嶼江上奉酬應尉','林亦之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','相送長江風浪輕，尉仙真自好心情。',32,'全唐诗/poet.song.156000.json','["相送長江風浪輕，尉仙真自好心情。", "四更明月宿何處，魚骨山前第一程。"]'),
('742cf107-1341-4f52-b799-f93fd93805ea','題長樂縣靈峰寺望日亭','林亦之','宋','宋诗','song-poetry','','[]','雲母江邊有草亭，分明見得日頭生。',32,'全唐诗/poet.song.156000.json','["雲母江邊有草亭，分明見得日頭生。", "一村籬落更何處，此已無天只水聲。"]'),
('dedd6f30-2bf6-4e77-958b-08f722b7985f','題嚴子陵釣臺','林亦之','宋','宋诗','song-poetry','','[]','莫向金門傲冕旒，歸來却要著羊裘。',32,'全唐诗/poet.song.156000.json','["莫向金門傲冕旒，歸來却要著羊裘。", "乾坤不是劉文叔，那得長竿釣白頭。"]'),
('f13372bb-1acc-4419-aa35-bd0960dd5d3e','林井伯母生日口占','林亦之','宋','宋诗','song-poetry','','[]','由來此母如吾母，再拜一巵復一巵。',32,'全唐诗/poet.song.156000.json','["由來此母如吾母，再拜一巵復一巵。", "最好年年作生日，碧蘭黄菊與同時。"]'),
('66b15e4f-7875-4ee0-aa7d-f3118f0cfa8b','淑人生日口占','林亦之','宋','宋诗','song-poetry','','[]','方朔曾爲老侍郎，麻姑來降紫雲香。',32,'全唐诗/poet.song.156000.json','["方朔曾爲老侍郎，麻姑來降紫雲香。", "壽杯今日逢長至，款款長年此日長。"]'),
('05782d81-3e5d-4179-88fa-25ba153ec9f9','重陽次日登城山','林亦之','宋','宋诗','song-poetry','','[]','城山飲罷冷侵衣，湖上重來月滿巵。',32,'全唐诗/poet.song.156000.json','["城山飲罷冷侵衣，湖上重來月滿巵。", "未愛疎籬黄菊日，最憐秋水白雲時。"]'),
('9b1d9349-329d-41b7-b714-e65bc631a61a','重過紅泉','林亦之','宋','宋诗','song-poetry','','[]','憶昔嘈嘈來拜經，秋燈秋雨苦吟聲。',32,'全唐诗/poet.song.156000.json','["憶昔嘈嘈來拜經，秋燈秋雨苦吟聲。", "如今秋雨秋燈夜，大半當年猶未生。"]'),
('b89cd9a6-db0e-43f7-ab52-52513e815921','秋日題','林亦之','宋','宋诗','song-poetry','','[]','漠漠騷騷如卷砂，當門枯木見巢鴉。',32,'全唐诗/poet.song.156000.json','["漠漠騷騷如卷砂，當門枯木見巢鴉。", "秋林最怕風吹盡，一直愁心無樹遮。"]'),
('cb467217-277f-48e5-bdfe-68721c722036','九日下水','林亦之','宋','宋诗','song-poetry','','[]','黄花時候苦思鄉，急水還家一日强。',32,'全唐诗/poet.song.156000.json','["黄花時候苦思鄉，急水還家一日强。", "不道南風打頭上，客船摇櫓作重陽。"]'),
('5c75ef49-882c-4947-a9ce-a42570f39712','草堂老人和仲平頭七十宴客綠煙亭輒賦口號一章以爲草堂之壽','林亦之','宋','宋诗','song-poetry','','[]','今年七十多青裏，莫把仙翁一例看。',32,'全唐诗/poet.song.156000.json','["今年七十多青裏，莫把仙翁一例看。", "再拜尊前爲翁舞，草堂最好是無官。"]'),
('2b75e496-3e3e-46a3-8704-4af2a849037b','辛卯歲應舉過西峽渡','林亦之','宋','宋诗','song-poetry','','[]','白鹿山頭雲欲頹，峽門灘下水如雷。',64,'全唐诗/poet.song.156000.json','["白鹿山頭雲欲頹，峽門灘下水如雷。", "錦囊破裂元無用，席帽嶔崎還更來。", "我自未能逃世俗，人誰便解脫塵埃。", "扁舟且趁牛羊渡，莫問如今第幾迴。"]'),
('04e16f17-25d2-4f3f-b5c4-3cf152c7e693','寄精嚴谷堂老宿二十年欲訪谷堂觀筆法因循去未得偶逢水西客沉吟久之因寄此詩','林亦之','宋','宋诗','song-poetry','','[]','隔浦娟娟古佛廬，幾迴欲去更踟躇。',64,'全唐诗/poet.song.156000.json','["隔浦娟娟古佛廬，幾迴欲去更踟躇。", "欲誇柳氏元和脚，要問隋僧智果書。", "見說交情多雋達，每慙識面尚生疎。", "山頭紅葉知無限，可許閒人暫寓居。"]'),
('dbea0ab9-e417-4958-b3f0-9f71a322b723','寄范都廂','林亦之','宋','宋诗','song-poetry','','[]','南去封題久不聞，北來數數聽寒暄。',64,'全唐诗/poet.song.156000.json','["南去封題久不聞，北來數數聽寒暄。", "聯鑣太白三千首，擊柝長安十二門。", "飛觀凌空天子國，輕帆半日女兒村。", "淵明好趣柴桑近，官職高卑未要論。"]'),
('a53eabc8-a733-45b9-a84f-af174ac4a0f8','奉陪嚴陵史君楊校書囊山夜語一別數月欲再見不可得因寄此詩','林亦之','宋','宋诗','song-poetry','','[]','鄉廛一語竟何曾，却向他州逢李膺。',64,'全唐诗/poet.song.156000.json','["鄉廛一語竟何曾，却向他州逢李膺。", "白馬千山緣矍相，朱幡四海有嚴陵。", "鵝湖猶記通宵雨，虎石還同半夜燈。", "素髮相看纔兩度，不知再見幾時能。"]'),
('be9b27ce-f80d-4b48-8160-49b65a869e52','秋試後再寄林井伯','林亦之','宋','宋诗','song-poetry','','[]','方國三年一合圍，圜門屢戰定高飛。',64,'全唐诗/poet.song.156000.json','["方國三年一合圍，圜門屢戰定高飛。", "人如我友無青眼，天豈斯文厭紫微。", "苦縣老聃終遁去，敬亭小謝未須歸。", "丈夫謀宦非身計，荔子山前有綵衣。"]'),
('9c562b31-4a33-47ea-9aef-1a055a141f40','送井伯赴上庠','林亦之','宋','宋诗','song-poetry','','[]','紫微巷口送征鞍，白社村前荳葉寒。',64,'全唐诗/poet.song.156000.json','["紫微巷口送征鞍，白社村前荳葉寒。", "一賦雕蟲如癸水，千山羸馬上長安。", "短檠已自甘投老，健筆胡爲未得官。", "鳳閣起家緣六館，州人更欲祝東巒。"]'),
('539672c1-3d7f-43e4-80f9-e97b1b15d009','得舍弟行可鹽官病後書','林亦之','宋','宋诗','song-poetry','','[]','荷花開盡蓼花紅，遊子今年秋又窮。',64,'全唐诗/poet.song.156000.json','["荷花開盡蓼花紅，遊子今年秋又窮。", "千里病眠鴻鴈影，一書愁殺月魚翁。", "天寒好處予煨芋，日落何山汝轉蓬。", "名利不成作歸計，先生已老海門東。"]'),
('6852b03d-8a78-45be-8201-559f35e5dacf','舍弟客臨平','林亦之','宋','宋诗','song-poetry','','[]','憑誰爲問鶺鴒原，燈火三更殞淚痕。',64,'全唐诗/poet.song.156000.json','["憑誰爲問鶺鴒原，燈火三更殞淚痕。", "天遠未知萍梗迹，書來說在藕花村。", "年華似汝寧爲未，場屋如吾已懶言。", "壁水故人今北去，短長門戶好同論。"]'),
('f179ab09-416f-41da-a8ee-1f6fb17198c3','借冊井伯','林亦之','宋','宋诗','song-poetry','','[]','吉貝城邊寄此身，故鄉歸少異鄉親。',64,'全唐诗/poet.song.156000.json','["吉貝城邊寄此身，故鄉歸少異鄉親。", "蜀無擔石雄何苦，洛有書船孟不貧。", "綠水孤村何處客，白頭雙闕老門人。", "令狐冒雪成圖畫，還許渠儂續後塵。"]'),
('69095288-f648-496a-974d-69699be9a14a','憶浮家洞','林亦之','宋','宋诗','song-poetry','','[]','萬竹蒼蒼烏鳥啼，一江渺渺薜蘿西。',64,'全唐诗/poet.song.156000.json','["萬竹蒼蒼烏鳥啼，一江渺渺薜蘿西。", "幽懷動處蘭初長，好句來時月已低。", "年歲却從爲客盡，家書長是倩人題。", "疎鐘日落孤村立，秋燕梁空歸思迷。"]'),
('d79eb862-6ad0-464c-aae3-e0921076b0e1','寄表弟章由之爲理曲堆屋廬','林亦之','宋','宋诗','song-poetry','','[]','苦來爲客竟何爲，宅舍荒村誰與治。',64,'全唐诗/poet.song.156000.json','["苦來爲客竟何爲，宅舍荒村誰與治。", "別墅雖無輞川畫，生涯堪入杜陵詩。", "身如燕子年年去，家似漁舟處處移。", "丹井西頭曲堆下，更煩歲晚定疎籬。"]'),
('30425f7e-a70b-43b7-996c-f91f0add0f8b','送林子方祕書赴廣東提舉','林亦之','宋','宋诗','song-poetry','','[]','乘軺嶺外丈人回，奉使天南學士來。',64,'全唐诗/poet.song.156000.json','["乘軺嶺外丈人回，奉使天南學士來。", "萬里家聲蠻子洞，一門旌節越王臺。", "驛辭瀨口初逢菊，界入潮州定折梅。", "莫怪襄陽負韓約，芸香又好賜環催。"]'),
('6d6945d9-b8a6-4025-8e87-48cec7a5ea9a','次韻奉酬致仕通直吳七丈上元所寄之什','林亦之','宋','宋诗','song-poetry','','[]','空齊自合冷如灰，何物龍鍾似不才。',64,'全唐诗/poet.song.156000.json','["空齊自合冷如灰，何物龍鍾似不才。", "日日讀書無處用，年年作客幾時迴。", "君爲諸老先生行，我在當初最後來。", "可忍殘春對耆舊，不携斗酒去相陪。"]'),
('2ad2a2bb-ac85-45e9-b31f-5c7206e5e659','次韻致政吳丈和林縣丞丹桂非時之什','林亦之','宋','宋诗','song-poetry','','[]','青山湖上宅，丹桂月邊枝。',72,'全唐诗/poet.song.156000.json','["青山湖上宅，丹桂月邊枝。", "菊蕊元同日，桐花却並時。", "籠鵝翁不俗，蠟鳳子多奇。", "須信三秋好，先從數月期。", "藍田一廳壁，黄卷五男兕。", "問禮當年事，芹宮未頌僖。"]'),
('32b0915c-291d-45f2-9f3c-71e9b71be2cd','次韻奉酬林仲雨','林亦之','宋','宋诗','song-poetry','','[]','年去又來三月强，詩成未了寸心狂。',64,'全唐诗/poet.song.156000.json','["年去又來三月强，詩成未了寸心狂。", "已無精力能穿鵠，尚有頭顱可牧羊。", "老柏縱教逢歲晚，幽蘭本不爲人香。", "東膠待補猶堪戰，莫道今無識繞梁。"]'),
('59c3b8ce-a026-4968-80a2-0c5e475c39e9','謝林守架艾軒先生祠堂','林亦之','宋','宋诗','song-poetry','','[]','雙闕已嗟秋草邊，兩楹誰作麥堆前。',64,'全唐诗/poet.song.156000.json','["雙闕已嗟秋草邊，兩楹誰作麥堆前。", "幸逢皂蓋行春日，如見紅泉講道年。", "工部先生天下士，莆陽太守大夫賢。", "斯文直待斯人出，千載名聲與共傳。"]'),
('9b5a7890-d3c7-463c-ad66-9b5c26ae4c78','再用前韻和林守','林亦之','宋','宋诗','song-poetry','','[]','清詠重重畫戟邊，芳題短短竹籬前。',64,'全唐诗/poet.song.156000.json','["清詠重重畫戟邊，芳題短短竹籬前。", "政如美稷西河日，詩到黄初正始年。", "滕國已歌慈父愛，韓門更感使君賢。", "銅魚好句關風教，巴嶺賡酬只浪傳。"]'),
('535f638b-453f-4597-a60c-d6017e0c0d84','奉寄雲安安撫寶文少卿林黄中','林亦之','宋','宋诗','song-poetry','','[]','泥封款款下青冥，却許麾幢換使軿。',64,'全唐诗/poet.song.156000.json','["泥封款款下青冥，却許麾幢換使軿。", "夔子城頭開幕府，杜陵詩卷作圖經。", "十年去國未還國，萬里長亭更短亭。", "可信明時好人物，亂猿啼處是州廳。"]'),
('018993fc-67c1-4471-8d9b-3294433f2d1a','滕王閣懷古奉呈撫州別駕兼簡戶曹','林亦之','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','城連帝子閣西頭，水遶南昌故郡流。',64,'全唐诗/poet.song.156000.json','["城連帝子閣西頭，水遶南昌故郡流。", "山短天長鷗鷺小，夜深雲浄月星浮。", "澹臺墓暗竹根古，孺子亭荒荷葉秋。", "漠漠滄江無了日，哦詩莫苦替人愁。"]'),
('6842dfa1-b615-40e0-9e8e-0694584ffb3f','江西試罷還故里八月二十九日過飛猿嶺連日遇雨','林亦之','宋','宋诗','song-poetry','','[]','萬里崎嶇愁不禁，飛猿更聽雨淋淋。',64,'全唐诗/poet.song.156000.json','["萬里崎嶇愁不禁，飛猿更聽雨淋淋。", "剩將暑藥凉無用，未著秋衣寒已深。", "刻鵠雕蟲成底事，牧羊餧鴨負初心。", "還家漸近病漸好，得句自題時自吟。"]'),
('4812b061-287e-4f9f-b193-1c20aa42a2fb','秋試罷重九過滄峽','林亦之','宋','宋诗','song-poetry','','[]','野闊村歸如暮鴉，路沿溪曲似春蛇。',64,'全唐诗/poet.song.156000.json','["野闊村歸如暮鴉，路沿溪曲似春蛇。", "不諳水土愁多病，忽聽鄉談喜近家。", "一带青山將屋繞，數行綠竹倚門斜。", "年年逆旅逢重九，今歲須看籬下花。"]'),
('fe2685c6-33d8-4186-bcfe-ec5368eb3e3b','同安撫趙子直餞朱晦菴於懷安二首得重字  其一','林亦之','宋','宋诗','song-poetry','','[]','祖帳寒梅白未空，已看新葉綠重重。',64,'全唐诗/poet.song.156000.json','["祖帳寒梅白未空，已看新葉綠重重。", "八州斧鉞送行客，十里旌旗遶暮峰。", "北斗獨高韓吏部，南州爭慕郭林宗。", "一時賓主俱豪傑，敢道招要到野農。"]'),
('fa1b07c1-ab7c-43c8-8673-9b95315ea580','同安撫趙子直餞朱晦菴於懷安二首得重字  其二','林亦之','宋','宋诗','song-poetry','','[]','虎夷長想蕙蘭蹤，螺渚幸修桑梓恭。',64,'全唐诗/poet.song.156000.json','["虎夷長想蕙蘭蹤，螺渚幸修桑梓恭。", "詩造本情天下誦，學傳正統世儒宗。", "三山過客日無數，四海聞人此一逢。", "官燭行行送歸路，半村無月海雲重。"]'),
('cd853c26-537d-4201-810a-92b9ca8369aa','別莆陽史君林宗丞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','下筆翩翩如史君，年過五十始朱輪。',64,'全唐诗/poet.song.156000.json','["下筆翩翩如史君，年過五十始朱輪。", "蜀山久託無家客，滕國曾爲負耒人。", "脫印忽聞過我里，攀轅尤更甚州民。", "乍晴乍雨黄梅道，好聽泥封下紫宸。"]'),
('69a10ec1-298d-4bbf-81f1-d5fef8c456ab','別莆陽史君林宗丞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','扶羸十日候行期，瓜葉初生荷滿池。',64,'全唐诗/poet.song.156000.json','["扶羸十日候行期，瓜葉初生荷滿池。", "別袖難禁須進酒，離情未足更題詩。", "飛鸞渡口還家後，老鼠梯前到闕時。", "士論民謠如繳日，甘泉直上豈容遲。"]'),
('89c75bf6-c65b-47c6-9423-688534a0d7a8','別林黄中帥湖南','林亦之','宋','宋诗','song-poetry','','[]','清秋緩轡馬如雲，論定忠邪黑白分。',64,'全唐诗/poet.song.156000.json','["清秋緩轡馬如雲，論定忠邪黑白分。", "湘水傳呼新刺史，霸陵改觀舊將軍。", "平生孤節人難到，自此一番名愈聞。", "定有詔書催入覲，不勞下擔楚江濆。"]'),
('c425aab1-e1c3-4517-9425-e4d81a1d84d9','代上陳給事二首  其一','林亦之','宋','宋诗','song-poetry','','[]','謝安舊宅翠雲環，復見新牆月樣彎。',64,'全唐诗/poet.song.156000.json','["謝安舊宅翠雲環，復見新牆月樣彎。", "市近豈容三島客，樓居須向九仙山。", "去天尚鬰金門步，計日催歸玉筍班。", "好與衣冠添盛事，一門三府照人寰。"]'),
('74eb7f59-6e8e-42a8-9872-9cd45b507090','代上陳給事二首  其二','林亦之','宋','宋诗','song-poetry','','[]','雲錦軒楹蘭玉階，暫從仙仗下蓬萊。',64,'全唐诗/poet.song.156000.json','["雲錦軒楹蘭玉階，暫從仙仗下蓬萊。", "良辰歌館聲聲起，明月粧樓夜夜開。", "天上李藩批敕手，蜀中嚴武總戎才。", "可教問舍悠然去，即下紅泥促召回。"]'),
('184c3c36-13dd-4f9e-98ca-1b7d77485a38','暫還網山井伯以詩送別次韻','林亦之','宋','宋诗','song-poetry','','[]','暫著芒鞋歸故丘，新詩吟罷恍如秋。',64,'全唐诗/poet.song.156000.json','["暫著芒鞋歸故丘，新詩吟罷恍如秋。", "麥堆去後惟君勝，荔子紅時送客愁。", "好句合教吾北面，生年長恨海東頭。", "如今別袂應須惜，一日能留便少留。"]'),
('9ea02a92-3ee6-4938-bb9e-f34ac686af9a','艾軒先生侍郎挽詞四首  其一','林亦之','宋','宋诗','song-poetry','','[]','典刑還似魯人初，四海衣冠歸坐隅。',32,'全唐诗/poet.song.156000.json','["典刑還似魯人初，四海衣冠歸坐隅。", "涕落寒蕪嗟不見，月明蠏井白雲孤。"]'),
('e1328220-e21f-426b-aa17-6bfdee8a4d0f','艾軒先生侍郎挽詞四首  其二','林亦之','宋','宋诗','song-poetry','','[]','菖蒲對客尚從容，明月紅泉夢已空。',32,'全唐诗/poet.song.156000.json','["菖蒲對客尚從容，明月紅泉夢已空。", "縱是千年有豪傑，六經人物只斯翁。"]'),
('625dcbb8-d912-443d-8141-76f795a6319e','艾軒先生侍郎挽詞四首  其三','林亦之','宋','宋诗','song-poetry','','[]','繡衣曾出黄梅嶺，金印還游紅藥階。',32,'全唐诗/poet.song.156000.json','["繡衣曾出黄梅嶺，金印還游紅藥階。", "勳業至今人道說，幽懷長是在空齋。"]'),
('fbe6eb36-91c3-4b6f-92fa-11ee3005c3f4','艾軒先生侍郎挽詞四首  其四','林亦之','宋','宋诗','song-poetry','','[]','黄柑時候曲堆村，長憶籃輿到蓽門。',32,'全唐诗/poet.song.156000.json','["黄柑時候曲堆村，長憶籃輿到蓽門。", "恰是今年去年日，野螢衰草弔寒原。"]'),
('c4f4e301-6a6c-4c98-ad76-e898af8bcfb2','青龍陳君挽詞四首  其一','林亦之','宋','宋诗','song-poetry','','[]','明月青燈合浦村，北人惟此讀書園。',32,'全唐诗/poet.song.156000.json','["明月青燈合浦村，北人惟此讀書園。", "竇家風義人牢落，多少衡門欲斷魂。"]'),
('0ae05ce6-afa4-4e3e-829a-040eeab3d56e','青龍陳君挽詞四首  其二','林亦之','宋','宋诗','song-poetry','','[]','誰解題封忠敬堂，長安白髮紫微郎。',32,'全唐诗/poet.song.156000.json','["誰解題封忠敬堂，長安白髮紫微郎。", "斯名似不緣渠作，却最關渠泪數行。"]'),
('8b6f23c3-7ff0-427b-99f1-940e537bb357','青龍陳君挽詞四首  其三','林亦之','宋','宋诗','song-poetry','','[]','胡爲春渚夢初回，却是行舟恰到來。',32,'全唐诗/poet.song.156000.json','["胡爲春渚夢初回，却是行舟恰到來。", "數盡長亭過閩嶺，夕陽愁殺落花臺。"]'),
('f9c02bb0-3730-4fff-a40b-e222a08ef492','青龍陳君挽詞四首  其四','林亦之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','欲哭芻靈何日時，長江望斷涕沾衣。',32,'全唐诗/poet.song.156000.json','["欲哭芻靈何日時，長江望斷涕沾衣。", "夜香樓下如重到，鶴叫三更人已非。"]'),
('53ebb28a-f34c-4413-919a-f3d36ec86f42','鮑待用挽詞四首  其一','林亦之','宋','宋诗','song-poetry','','[]','一經教子已青裾，况又行年七十餘。',32,'全唐诗/poet.song.156000.json','["一經教子已青裾，况又行年七十餘。", "恰好遭逢身却死，北風門外只長噓。"]'),
('5f85ce3b-f300-4324-bdf5-e4736c86501c','鮑待用挽詞四首  其二','林亦之','宋','宋诗','song-poetry','','[]','去年一笑荔枝園，今歲重來是墓門。',32,'全唐诗/poet.song.156000.json','["去年一笑荔枝園，今歲重來是墓門。", "縱有青青舊時樹，已看斜日照黄昏。"]'),
('d3501bb8-47a2-4f8b-9958-b51934b9c8ac','鮑待用挽詞四首  其三','林亦之','宋','宋诗','song-poetry','','[]','寒村夜雨斷人煙，却有累累哭野田。',32,'全唐诗/poet.song.156000.json','["寒村夜雨斷人煙，却有累累哭野田。", "一飯誰能弔衰草，似君此事至今傳。"]'),
('169a3a0c-6eca-49c5-a2c3-84892ffea6fb','鮑待用挽詞四首  其四','林亦之','宋','宋诗','song-poetry','','[]','讀盡東床一卷書，不妨蹤跡向來疎。',32,'全唐诗/poet.song.156000.json','["讀盡東床一卷書，不妨蹤跡向來疎。", "劍津紅帳爲門戶，想得多多送葬車。"]'),
('3ed3e57f-abaf-4838-8813-e87dd76cb063','光澤朱君挽詞四首  其一','林亦之','宋','宋诗','song-poetry','','[]','諸老蕭蕭似卷塵，不堪再見素旌新。',32,'全唐诗/poet.song.156000.json','["諸老蕭蕭似卷塵，不堪再見素旌新。", "白頭縣尉笭箵浦，夜雨寒窗是舊人。"]'),
('186af977-d6d1-48ff-b3e6-3ebb7de5255b','光澤朱君挽詞四首  其二','林亦之','宋','宋诗','song-poetry','','[]','長記前回過我廬，艱難步履喚兒扶。',32,'全唐诗/poet.song.156000.json','["長記前回過我廬，艱難步履喚兒扶。", "莫將馬箠敲門去，寒水無人野嶼孤。"]'),
('ca59081c-77ca-441b-a37e-71901f59828c','光澤朱君挽詞四首  其三','林亦之','宋','宋诗','song-poetry','','[]','爲官長者得聲名，唯諾公堂如父兄。',32,'全唐诗/poet.song.156000.json','["爲官長者得聲名，唯諾公堂如父兄。", "欲作汝南耆舊傳，不須多語盡平生。"]'),
('2b3b1e32-3d83-4061-a999-1dda1ec75a98','光澤朱君挽詞四首  其四','林亦之','宋','宋诗','song-poetry','','[]','迺翁飛旐過前村，一婦隨車一在門。',32,'全唐诗/poet.song.156000.json','["迺翁飛旐過前村，一婦隨車一在門。", "何處人家有三柩，髑髏山下合銷魂。"]'),
('cf5bc8da-a3fd-4476-ba3d-d56295ebe784','趙路分挽詞三首  其一','林亦之','宋','宋诗','song-poetry','','[]','三月餘干花草春，天遥莫問謫仙墳。',32,'全唐诗/poet.song.156000.json','["三月餘干花草春，天遥莫問謫仙墳。", "長簫不要吹哀些，愁殺江東日暮雲。"]'),
('7546b4ab-a650-4347-bec9-7e7daa329a76','趙路分挽詞三首  其二','林亦之','宋','宋诗','song-poetry','','[]','苦學聲名聞搢紳，傳家况復有麒麟。',32,'全唐诗/poet.song.156000.json','["苦學聲名聞搢紳，傳家况復有麒麟。", "漢廷玉牒先多士，數盡慈恩只一人。"]'),
('16b28f1b-645a-435b-9cd2-cd368cd24625','趙路分挽詞三首  其三','林亦之','宋','宋诗','song-poetry','','[]','每誇愛子對人言，東觀同游有艾軒。',32,'全唐诗/poet.song.156000.json','["每誇愛子對人言，東觀同游有艾軒。", "我向築場聞此語，斂襟西望轉銷魂。"]'),
('d87e8cf8-a12d-4528-b376-8c633725d03f','林校尉紹老挽詞三首  其一','林亦之','宋','宋诗','song-poetry','','[]','落日平田何處村，竹牆繚繞是高門。',32,'全唐诗/poet.song.156000.json','["落日平田何處村，竹牆繚繞是高門。", "莫言雞黍未相識，一聽悲歌自斷魂。"]'),
('b88050f0-6213-47f1-90d0-0a42c0e135de','林校尉紹老挽詞三首  其二','林亦之','宋','宋诗','song-poetry','','[]','白浪漫天眼自驚，吳兒一見欲飛鳴。',32,'全唐诗/poet.song.156000.json','["白浪漫天眼自驚，吳兒一見欲飛鳴。", "何人爲述膠西事，十萬樓船有姓名。"]'),
('3b8988a2-7ef8-4b1a-a627-c39ef817b316','林校尉紹老挽詞三首  其三','林亦之','宋','宋诗','song-poetry','','[]','華屋共言清浄想，長途還作去來緣。',32,'全唐诗/poet.song.156000.json','["華屋共言清浄想，長途還作去來緣。", "念君陰德有如此，何事春風却短年。"]'),
('08af4e18-1e74-4b27-987c-c5036b200afe','林少朋挽詞三首  其一','林亦之','宋','宋诗','song-poetry','','[]','年年二月看花時，野笛小園長短吹。',32,'全唐诗/poet.song.156000.json','["年年二月看花時，野笛小園長短吹。", "誰道今年看花日，鞦韆門外鼓聲悲。"]'),
('0f756f0f-07f1-4eda-8fcd-497dfb50eeac','林少朋挽詞三首  其二','林亦之','宋','宋诗','song-poetry','','[]','聞說當年歌鹿鳴，黄花八月牡丹生。',32,'全唐诗/poet.song.156000.json','["聞說當年歌鹿鳴，黄花八月牡丹生。", "何人爲續夷堅志，好向橋東問姓名。"]'),
('21532028-a402-4944-977b-96690b871c60','林少朋挽詞三首  其三','林亦之','宋','宋诗','song-poetry','','[]','幾回欲去醉花傍，此事如今轉渺茫。',32,'全唐诗/poet.song.156000.json','["幾回欲去醉花傍，此事如今轉渺茫。", "不獨哦詩弔金谷，更令掩袂憶劉郎。"]'),
('cc390572-5454-42e7-803d-bcc334b5b30d','余倅父子挽詞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','廬陵別駕有慈闈，到處官亭見綵衣。',32,'全唐诗/poet.song.156000.json','["廬陵別駕有慈闈，到處官亭見綵衣。", "總爲青山能送老，不知黄壤却同歸。"]'),
('d25bed7f-a481-4e9b-bc65-8a72e86c74b0','余倅父子挽詞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','誰唱雙棺薤曲悲，前聲未斷後聲隨。',32,'全唐诗/poet.song.156000.json','["誰唱雙棺薤曲悲，前聲未斷後聲隨。", "人間父子情何限，可忍長簫逐箇吹。"]'),
('c7c02a3c-8ea1-4d41-9ef4-aa60824ed863','盧氏母挽詞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','爲語歌鈴過野田，不須淚眼更懸懸。',32,'全唐诗/poet.song.156000.json','["爲語歌鈴過野田，不須淚眼更懸懸。", "人間催促如風葉，誰是平頭八十年。"]'),
('a5de2c35-5f24-40c0-bc8e-b79985f94323','盧氏母挽詞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','小徑幽幽竹遶門，閨樓終日總無言。',32,'全唐诗/poet.song.156000.json','["小徑幽幽竹遶門，閨樓終日總無言。", "若教誦得維摩句，應愧平生費討論。"]'),
('60b567e4-53cf-4a1c-a267-e7cc0eb91870','哭故人曹十九秘校叔明海陽四十弟自潮州送歸柩未有哭詩故人於海陽爲甥舅也沉吟感涕因併以弔之二首  其一','林亦之','宋','宋诗','song-poetry','','[]','海陽天外已傷懷，白水牆頭轉自哀。',32,'全唐诗/poet.song.156000.json','["海陽天外已傷懷，白水牆頭轉自哀。", "却是人生難得好，兩年只見哭聲來。"]'),
('8dd18967-db6d-4a7f-a6ff-9818dc945f0a','哭故人曹十九秘校叔明海陽四十弟自潮州送歸柩未有哭詩故人於海陽爲甥舅也沉吟感涕因併以弔之二首  其二','林亦之','宋','宋诗','song-poetry','','[]','泪眼纔乾更哭君，殘陽破寺起愁雲。',32,'全唐诗/poet.song.156000.json','["泪眼纔乾更哭君，殘陽破寺起愁雲。", "故人海上能多少，已見江南有兩墳。"]'),
('69c308f1-eb42-44ae-8572-63053b8ff6a7','小練林承事挽詞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','薤歌纔唱已堪嗟，莫道生平隔海涯。',32,'全唐诗/poet.song.156000.json','["薤歌纔唱已堪嗟，莫道生平隔海涯。", "曾向網山圖上見，蛇門東去是君家。"]'),
('5c108afb-2d01-4a0c-b9b6-d93eda8ad1de','小練林承事挽詞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','生前莫問劉郎浦，死後還看孟母鄰。',32,'全唐诗/poet.song.156000.json','["生前莫問劉郎浦，死後還看孟母鄰。", "遥想芻靈穿海出，浪頭如屋自愁人。"]'),
('68f18bde-f1fa-44f9-9ab9-67255d581c85','曹不占挽詞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','年年除莫即相呼，夜語如君不可無。',32,'全唐诗/poet.song.156000.json','["年年除莫即相呼，夜語如君不可無。", "爲報歲寒同社客，今年不要作柴爐。"]'),
('7b2cf8d6-531f-4613-8390-4484764b72f9','曹不占挽詞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','有時街上斷行人，猶見敲門訪子雲。',32,'全唐诗/poet.song.156000.json','["有時街上斷行人，猶見敲門訪子雲。", "一種傷心向誰語，夜闌燈火只思君。"]'),
('ac4681d7-b7c3-4d83-921b-d45b5d300bff','鄭氏母挽詞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','片片花飛上巳村，誰將雙淚哭寒原。',32,'全唐诗/poet.song.156000.json','["片片花飛上巳村，誰將雙淚哭寒原。", "明朝况是初三日，好把流杯爲續魂。"]'),
('9c245158-7dd9-418f-9dce-f2c662ec302e','鄭氏母挽詞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','畫樓最好綠波前，萱草還看白髮生。',32,'全唐诗/poet.song.156000.json','["畫樓最好綠波前，萱草還看白髮生。", "更說列卿太常老，吁嗟一曲與人傳。"]'),
('1e146eee-9373-452e-a34b-fb2fceb61d48','曹廷輔挽詞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','里巷相聞長者聲，春風更有女蘿情。',32,'全唐诗/poet.song.156000.json','["里巷相聞長者聲，春風更有女蘿情。", "殷勤爲作愁腸曲，白日西頹月又生。"]'),
('87a71f4c-83a9-414a-aacb-d68b261846f8','曹廷輔挽詞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','綠水白鷗三月天，哀簫長短使人憐。',32,'全唐诗/poet.song.156000.json','["綠水白鷗三月天，哀簫長短使人憐。", "草鞋踏雨同歸去，此事如今十五年。"]'),
('3c6a7b93-94b5-4cdb-be21-eba585e1e60b','盧助教質夫挽詞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','山中香火今誰在，那聽殘春薤曲新。',32,'全唐诗/poet.song.156000.json','["山中香火今誰在，那聽殘春薤曲新。", "第一傷心惟此老，父時諸客已無人。"]'),
('80932357-1917-47d8-9875-883859ba5340','盧助教質夫挽詞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','毗耶鈔軸五千卷，浄几焚香心自閒。',32,'全唐诗/poet.song.156000.json','["毗耶鈔軸五千卷，浄几焚香心自閒。", "蠟燭燒殘春夢斷，逢逢哀鼓弔空山。"]'),
('bc82f0e4-f7c9-4e82-b716-373f0da745f7','方提舉公美挽詞','林亦之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','馬上姿容河朔風，吁嗟不見夕陽紅。',32,'全唐诗/poet.song.156000.json','["馬上姿容河朔風，吁嗟不見夕陽紅。", "長江自小爲鄰舍，昨日歸來無此翁。"]'),
('d61d7b77-e57c-464e-88a8-eba507ba984e','橫路林少皋挽詞','林亦之','宋','宋诗','song-poetry','','[]','十年騎馬畫橋歸，長記朱樓傍水湄。',32,'全唐诗/poet.song.156000.json','["十年騎馬畫橋歸，長記朱樓傍水湄。", "今日悲吟想君屋，一如騎馬十年時。"]'),
('bb5cdb05-412f-45fd-83f1-b23d8d3de780','鄭唐仲挽詞','林亦之','宋','宋诗','song-poetry','','[]','三閭未死已招魂，却是狂夫不要論。',32,'全唐诗/poet.song.156000.json','["三閭未死已招魂，却是狂夫不要論。", "誰肯將身緣問道，十年卧病菊花村。"]'),
('4d3ac8af-af3a-4f1b-9008-d178cc7b8644','夏循矩先生挽詞','林亦之','宋','宋诗','song-poetry','','[]','歎惜青燈下，偏旁古字通。',48,'全唐诗/poet.song.156000.json','["歎惜青燈下，偏旁古字通。", "讀殘五車去，贏得一生窮。", "末俗輕前輩，何人念此翁。", "傷心舊時宅，颯颯已如空。"]'),
('5f967a19-3b5e-4918-a5d7-f1fd3a9a0041','林伯謨挽詞','林亦之','宋','宋诗','song-poetry','','[]','幽情千木外，巧思百花前。',48,'全唐诗/poet.song.156000.json','["幽情千木外，巧思百花前。", "好事如吾子，傷心歎蚤年。", "桃蹊親意悅，薤曲里人憐。", "半夜悲笳起，涼天野月懸。"]'),
('d492ea9b-7bee-41d9-b9c8-38e756715419','古龍孺人曹氏挽詞','林亦之','宋','宋诗','song-poetry','','[]','寒原何處哭，下馬欲銷魂。',48,'全唐诗/poet.song.156000.json','["寒原何處哭，下馬欲銷魂。", "白日數行泪，黄柑十里村。", "傳家猶墨綬，聘婦盡朱門。", "似此何多恨，空漚不要論。"]'),
('2b9a3dd0-3e05-4fb1-ba94-f22834942ae3','孺人鄭氏挽詞','林亦之','宋','宋诗','song-poetry','','[]','國子先生宅，相傳此母賢。',48,'全唐诗/poet.song.156000.json','["國子先生宅，相傳此母賢。", "一哀孤嶼下，再拜十年前。", "舐犢貪書卷，飛鸞慰暮年。", "夕陽聊寓曲，終要到新阡。"]'),
('54b97315-8d2b-4b83-8312-b5b4290b1887','丹井陳子白母挽詞二首  其一','林亦之','宋','宋诗','song-poetry','','[]','哀曲梧桐夜，何年苜蓿盤。',48,'全唐诗/poet.song.156000.json','["哀曲梧桐夜，何年苜蓿盤。", "敬夫前輩重，好客婦人難。", "十月明朝盡，孤墳落日寒。", "鹿門催作黍，此意竟長嘆。"]'),
('40456441-1e96-4871-bb40-ad5113f9cd5f','丹井陳子白母挽詞二首  其二','林亦之','宋','宋诗','song-poetry','','[]','嫁娶比鄰近，門庭古木幽。',48,'全唐诗/poet.song.156000.json','["嫁娶比鄰近，門庭古木幽。", "藁砧舊相好，蘭玉久從游。", "雙鶴來何處，孤鸞不到頭。", "通家丘嫂行，愁涕白雲浮。"]'),
('1570551d-7539-4859-bf96-41dc6738cd32','松林林巖叟挽詞','林亦之','宋','宋诗','song-poetry','','[]','誰學陶朱去，梅花古戍旁。',48,'全唐诗/poet.song.156000.json','["誰學陶朱去，梅花古戍旁。", "平生疎几杖，哀曲損肝腸。", "稚子青衿雋，東床綠袖長。", "四更笳鼓動，月白水茫茫。"]'),
('e981e96f-afcb-4588-aebd-dd98b7421b42','楊嚴州母挽詞','林亦之','宋','宋诗','song-poetry','','[]','生長大夫宅，來歸御史門。',48,'全唐诗/poet.song.156000.json','["生長大夫宅，來歸御史門。", "吾兒天下寶，此母里人尊。", "九嶺三江外，孤雲片月村。", "同鄉無見日，他國賦招魂。"]'),
('d1b2fbeb-99c3-4396-ac5b-89605e4c8ca9','宜人姚氏挽詞','林亦之','宋','宋诗','song-poetry','','[]','別駕歸來日，連年哭九原。',48,'全唐诗/poet.song.156000.json','["別駕歸來日，連年哭九原。", "白頭如此母，丹旐只諸孫。", "燈火檳榔市，簫笳梅子村。", "比鄰惱鵝鴨，還阻弔幽魂。"]'),
('e20920fe-97e1-4e5f-9a68-72a9fb3404d5','林義夫母挽詞','林亦之','宋','宋诗','song-poetry','','[]','孟母何曾憾，生前錦軸橫。',48,'全唐诗/poet.song.156000.json','["孟母何曾憾，生前錦軸橫。", "東征鳳毛好，西府玉昆榮。", "貝葉忘言處，金床寫水聲。", "十年堂上客，一曲自悲鳴。"]'),
('e80bd04d-4b48-40a7-820c-236a26ab61d1','方士登母挽詞','林亦之','宋','宋诗','song-poetry','','[]','傷心來訃日，各各爲沾衣。',48,'全唐诗/poet.song.156000.json','["傷心來訃日，各各爲沾衣。", "慈母夜長訣，郎君客未歸。", "短山長笛慘，青草素旗飛。", "料得楚人些，連篇說斷機。"]'),
('63759235-97af-4ca2-b04c-036865f867f4','清遠尉林昭遠挽詞','林亦之','宋','宋诗','song-poetry','','[]','一宦辭南海，蕭然百念枯。',48,'全唐诗/poet.song.156000.json','["一宦辭南海，蕭然百念枯。", "里閭稱長者，門巷似窮儒。", "死日分明去，生年爾汝無。", "傷心哀鼓動，寒月野園孤。"]'),
('05a14369-c572-40eb-89ae-c7ce7c35e3b3','迎仙致政王修職挽詞','林亦之','宋','宋诗','song-poetry','','[]','晦德香泉下，秋風知幾回。',48,'全唐诗/poet.song.156000.json','["晦德香泉下，秋風知幾回。", "襟懷如阮達，門閥自唐來。", "立馬曾交語，寒蛩重一哀。", "生前雙錦軸，亦足慰蒼苔。"]'),
('d359b72b-8ae1-4e7c-be29-c19ab0dc22fb','黄司業挽詞','林亦之','宋','宋诗','song-poetry','','[]','未作鵬飛萬里程，一時英俊已錚錚。',64,'全唐诗/poet.song.156000.json','["未作鵬飛萬里程，一時英俊已錚錚。", "只應傲雪凌雲氣，合得驚天動地名。", "明月酒杯如李白，暮年官職似陽城。", "秋風癸亥古祠下，多少行人淚眼盈。"]'),
('e7000e42-645a-4693-af27-b22f2a622446','戴少美挽詞','林亦之','宋','宋诗','song-poetry','','[]','一聲哀管水邊聞，忽憶秋風留月軒。',64,'全唐诗/poet.song.156000.json','["一聲哀管水邊聞，忽憶秋風留月軒。", "洛下書生來問字，襄陽耆舊亦過門。", "遊梁無限通宵話，訪戴如今何處村。", "縱使鸞封到幽壠，白雲荒草不堪論。"]'),
('638e79f2-457b-4552-af15-2a992d30187b','陳伯順夫婦挽詞','林亦之','宋','宋诗','song-poetry','','[]','晴春相見未多時，忽嘆霜蕪雪屋非。',64,'全唐诗/poet.song.156000.json','["晴春相見未多時，忽嘆霜蕪雪屋非。", "僵瑟樓前方悼往，吹簫臺下竟同歸。", "讀書歷歷向秋樹，織錦悠悠空曉機。", "須信人間伉儷重，生年死日不相違。"]'),
('6d1c0a86-9c13-4aad-915c-23504ff9724b','陳仲罕母挽詞','林亦之','宋','宋诗','song-poetry','','[]','橘林霜後欲寒天，多記陶家作客年。',64,'全唐诗/poet.song.156000.json','["橘林霜後欲寒天，多記陶家作客年。", "碧水青山如昨日，白雲紅旐是新阡。", "鳲鳩七子母恩重，寡鵠孤巢婦德賢。", "最苦哀簫老松下，漫漫瞿麥雪平田。"]'),
('6d8f0e5a-a9df-4987-9cc6-87a1a729d69f','稚春母鄭氏挽詞','林亦之','宋','宋诗','song-poetry','','[]','他誰天外哭聲長，有客歸程何太忙。',64,'全唐诗/poet.song.156000.json','["他誰天外哭聲長，有客歸程何太忙。", "同爨情親如五服，升堂義重比諸郎。", "昔人澆薤蒸梨事，即我浮家泛宅傍。", "嘆息白頭陶母意，中秋三日轉凄涼。"]'),
('8f7405a6-3375-4a91-8f16-0c16805b7614','蔡以之母挽詞','林亦之','宋','宋诗','song-poetry','','[]','鄰母悲歌長短聲，客窗聞此夢魂驚。',64,'全唐诗/poet.song.156000.json','["鄰母悲歌長短聲，客窗聞此夢魂驚。", "新鄉誰共雞豚社，先世由來香火情。", "薤曲縱教如宋玉，里喪終是愧陳平。", "傷心起望秋雲亂，愁斷千山幾日程。"]'),
('d8c5667e-9f3c-4eb7-948f-8eec2d008634','章徽之妻盧氏挽詞','林亦之','宋','宋诗','song-poetry','','[]','蒿里歌，蒿里曲。',44,'全唐诗/poet.song.156000.json','["蒿里歌，蒿里曲。", "長簫悲奈何，短草歎不足。", "少年款款嫁夫婿，今夜屋簷何處宿。", "蒿里歌，蒿里曲。"]'),
('aeb16ebc-4022-49f5-80c6-f32af1d972a2','句','林亦之','宋','宋诗','song-poetry','','[]','講學紅泉不著書，只將心學授生徒。',16,'全唐诗/poet.song.156000.json','["講學紅泉不著書，只將心學授生徒。"]'),
('ca9edf6a-e8a8-48b9-be3f-66a83ad0abc3','句','林仲雨','宋','宋诗','song-poetry','','[]','萬事不成嗟畫虎，一官那得似驅羊。',16,'全唐诗/poet.song.156000.json','["萬事不成嗟畫虎，一官那得似驅羊。"]'),
('b352b923-954a-4b01-b781-bc8d806b25f4','南山寺','舒璘','宋','宋诗','song-poetry','','[]','山谷幽深鎖梵宮，千章灌木鬰蘢葱。',64,'全唐诗/poet.song.156000.json','["山谷幽深鎖梵宮，千章灌木鬰蘢葱。", "香浮古篆半檐霧，茶潄清泉兩腋風。", "鶴伴老僧歸夕照，山留行客駐霜楓。", "前朝閣閣渾秋草，眺望悽然碧嶺中。"]'),
('fa4bec59-135e-48da-be82-f23775bbc325','頌古八首  其一','釋元聰','宋','宋诗','song-poetry','','[]','釋尊拈起枝花，分明勾賊破家。',28,'全唐诗/poet.song.156000.json','["釋尊拈起枝花，分明勾賊破家。", "致令千古之下，兒孫逐惡隨邪。"]'),
('cd797f27-7efc-4143-bde7-272b5edebeed','頌古八首  其二','釋元聰','宋','宋诗','song-poetry','','[]','倒腹傾腸說向伊，不知何故尚遲疑。',32,'全唐诗/poet.song.156000.json','["倒腹傾腸說向伊，不知何故尚遲疑。", "只今便好猛提取，莫待天明失却鷄。"]'),
('cf821a54-63b6-4b40-bd29-db74de63a2e5','頌古八首  其三','釋元聰','宋','宋诗','song-poetry','','[]','一下蘭橈驀口鞭，大洋海底火燒天。',32,'全唐诗/poet.song.156000.json','["一下蘭橈驀口鞭，大洋海底火燒天。", "父南子北家何許，風滿長空月滿船。"]'),
('74aebac2-a663-40b4-b01c-4e50f026e370','頌古八首  其四','釋元聰','宋','宋诗','song-poetry','','[]','鑽頭閙藍遠侍者，刺腦膠盆老趙州。',32,'全唐诗/poet.song.156000.json','["鑽頭閙藍遠侍者，刺腦膠盆老趙州。", "兩箇人前誇好手，面皮三寸不知羞。"]'),
('71520db3-f303-4c17-a0f8-81b5395355a0','頌古八首  其五','釋元聰','宋','宋诗','song-poetry','','[]','明明道不說，此理憑誰識。',24,'全唐诗/poet.song.156000.json','["明明道不說，此理憑誰識。", "春風一陣來，滿徑花狼籍。"]'),
('e8f90518-ffcc-453b-97a2-29c1feae8ac3','頌古八首  其六','釋元聰','宋','宋诗','song-poetry','','[]','只知瞻禮紫金容，不覺腦門遭霹靂。',32,'全唐诗/poet.song.156000.json','["只知瞻禮紫金容，不覺腦門遭霹靂。", "平生心膽向人傾，相識還同不相識。"]'),
('06aeb4e8-33df-44eb-b642-6dc6cc2b51ed','頌古八首  其七','釋元聰','宋','宋诗','song-poetry','','[]','松陰行不盡，疎雨下無時。',24,'全唐诗/poet.song.156000.json','["松陰行不盡，疎雨下無時。", "世事幾興廢，山中人未知。"]'),
('0fbede8c-1566-4c36-b5d5-85c4f7cf7bd7','頌古八首  其八','釋元聰','宋','宋诗','song-poetry','','[]','因我得禮你，莫放屁撒屎。',24,'全唐诗/poet.song.156000.json','["因我得禮你，莫放屁撒屎。", "带累天下人，錯認自家底。"]'),
('42b493cc-b0e3-45bf-b918-bf808e231c27','臨終辭衆偈','釋元聰','宋','宋诗','song-poetry','','[]','來未嘗來，去未嘗去。',20,'全唐诗/poet.song.156000.json','["來未嘗來，去未嘗去。", "七十四年，月印寒渚。"]'),
('a4509392-1d48-4d85-9ac2-3434232655fc','西湖再開呈張經略','劉穎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','持節南來聳百城，就分帥閫握邊兵。',64,'全唐诗/poet.song.156000.json','["持節南來聳百城，就分帥閫握邊兵。", "盡令殊俗窺風采，更許佳山托姓名。", "峴首要須刊偉蹟，習池底事著狂生。", "風流人物今宗主，物物俱蒙不朽榮。"]'),
('a8893cac-b68c-4696-8c10-ff4cc2e84964','九里嶺','楊寅','宋','宋诗','song-poetry','','[]','上下各九里，東西只數家。',48,'全唐诗/poet.song.156000.json','["上下各九里，東西只數家。", "田橫梯齒密，松列雁行斜。", "分鑣爭嶺道，孤往接天涯。", "爲我謝風景，何路不開花。"]'),
('7f144678-8f22-4c87-bcba-3cbfd65314fa','龍雲寺次羅竦韵','楊寅','宋','宋诗','song-poetry','','[]','路轉羊腸望眼舒，籃輿更入道人居。',64,'全唐诗/poet.song.156000.json','["路轉羊腸望眼舒，籃輿更入道人居。", "千林黄葉新霜後，四面青山夕照餘。", "幽夢乍驚魚鼓響，小詩閑向竹窗書。", "爐烟茗碗匆匆話，已覺人間萬象虛。"]'),
('81eff31a-9306-41dc-aa2e-6dd5dc14f4cf','題尉廨壁','呂祖仁','宋','宋诗','song-poetry','','[]','屈指未逾月，沿封十往還。',48,'全唐诗/poet.song.156000.json','["屈指未逾月，沿封十往還。", "路危頻駐馬，力倦怯登山。", "親老難辭祿，時平懶養閑。", "自憐清苦節，誰與達天顔。"]'),
('db0180f5-bbe8-41a5-be0f-d51b982f1fb5','句','聶有','宋','宋诗','song-poetry','','[]','莫愁千古難再得，只有畫圖傳楚國。',16,'全唐诗/poet.song.156000.json','["莫愁千古難再得，只有畫圖傳楚國。"]'),
('e428cd7e-16ee-4530-8756-b69a5d2c0be3','明月滿庭樹招馬道士','朱渙','宋','宋诗','song-poetry','','[]','明月滿庭樹，與子步清影。',96,'全唐诗/poet.song.156000.json','["明月滿庭樹，與子步清影。", "參橫北斗低，共此良夜永。", "一從明月缺，子即與我別。", "兩槳泛西江，摇蕩萬頃雪。", "明月今復圓，子行阿那邊。", "愛而不可見，望望空淒然。", "願子理歸舟，復向長安道。", "快來我庭前，趁此明月好。"]'),
('2f658d34-94db-4f8c-9873-a3ccbb547baf','蟻飲研槽歌','朱渙','宋','宋诗','song-poetry','','[]','晴窗棐几風日舒，呼童汲水供蟾蜍，涓流入研玄穎濡。',168,'全唐诗/poet.song.156000.json','["晴窗棐几風日舒，呼童汲水供蟾蜍，涓流入研玄穎濡。", "一蟻蠢蠢爰來趨，須臾十百與之俱。", "前後有行不亂踰，宛若徙穴舁腐餘。", "想應燥吻脣頰枯，清夢思欲吞江湖。", "摇尾羞作涸轍呼，奮迅恰如東海魚。", "物生天地小大殊，饑食渴飲皆同塗。", "矧爾有靈非至愚，大槐南柯名利區。", "一夢而覺驚幻虛，爾其聽我毋睢盱。", "爾吭既沃腹既腴，歸安其藏勿浪逋。", "階前羣兒政嬉娛，以指劃土縻爾軀。"]'),
('788d781c-c401-47d0-a791-962466762698','入山二首  其一','朱渙','宋','宋诗','song-poetry','','[]','雨足溪漲緣，風高花委紅。',36,'全唐诗/poet.song.156000.json','["雨足溪漲緣，風高花委紅。", "天清氣自佳，獨步來山中。", "見竹不敢穿，生怕傷籜龍。"]'),
('6aa3f9b7-1527-4217-b9c7-26f3d13f997c','入山二首  其二','朱渙','宋','宋诗','song-poetry','','[]','溪頭浴吾鬚，樹底蔭吾影。',36,'全唐诗/poet.song.156000.json','["溪頭浴吾鬚，樹底蔭吾影。", "四顧無人來，獨坐了俄頃。", "欲去更徘徊，夕陽射峰頂。"]'),
('360322d7-cdcc-47d1-bee0-69045ba485db','傾城誤人身寄內翰洪丈','朱渙','宋','宋诗','song-poetry','','[]','傾城誤人身，嗟哉難具陳。',232,'全唐诗/poet.song.156000.json','["傾城誤人身，嗟哉難具陳。", "請君試側耳，聽妾歌其因。", "妾初未筓學新妝，肌理玉雪眉黛長。", "融怡窈裊銷金裳，態濃意遠奪目光。", "當時見者心爲狂，共謂絕代驚非常。", "擬思昭陽奉君王，三千寵愛一身當。", "寧知事大繆，嫁作蕩子婦。", "空閨獨宿度芳華，蓬首亂鬢顔色朽。", "四海十年不相聞，一朝歸來新閒舊。", "新閒舊，妾何有，擯妾不使侍箕箒。", "佳人多命薄，是事君信否。", "傾城誤人身，古來唯有李夫人。", "延年作歌帝所珍，貯之金屋薦華茵。", "寵光雜遝疏弟昆，將死掩面留餘恩。", "千載不復見，言之涕沾巾。", "傾城誤人身，此曲哀怨何可聽。"]'),
('326817a8-0569-474e-a4bf-119cb47f37b2','寒夜曲','朱渙','宋','宋诗','song-poetry','','[]','寒夜夜政長，愁人背燈立。',48,'全唐诗/poet.song.156000.json','["寒夜夜政長，愁人背燈立。", "驚風摇竹樹，棲鳥墮復集。", "山空接響多，室靜虛白入。", "怊悵不成眠，殘鐘曉邊急。"]'),
('733e6856-cf38-4b86-8c88-28123e6b24de','題徐禮部家歸去來圖','朱渙','宋','宋诗','song-poetry','','[]','古木參天叫杜鵑，春愁渾在夕陽邊。',32,'全唐诗/poet.song.156000.json','["古木參天叫杜鵑，春愁渾在夕陽邊。", "看君此畫還三歎，憶得西江上水船。"]'),
('03ac23d0-b2e2-4643-a6f1-166523f2d62b','偈頌四十二首  其一','釋祖先','宋','宋诗','song-poetry','','[]','扶持臨濟正法眼，出手還它勇毅人。',32,'全唐诗/poet.song.156000.json','["扶持臨濟正法眼，出手還它勇毅人。", "利物應機全體用，叢林又見一番新。"]'),
('8212a9c8-8ca7-42cd-9721-6ba5e8f058ce','偈頌四十二首  其二','釋祖先','宋','宋诗','song-poetry','','[]','客從南方來，報我天童老。',50,'全唐诗/poet.song.156000.json','["客從南方來，報我天童老。", "撞破太虛空，全身入荒草。", "而今子細思量，令人哭不成哭笑不成笑，寥寥目斷千峰曉。"]'),
('1773b25a-28d7-4594-892f-96cf4e65d333','偈頌四十二首  其三','釋祖先','宋','宋诗','song-poetry','','[]','山潤石含玉，林秀淵藏珠。',24,'全唐诗/poet.song.156000.json','["山潤石含玉，林秀淵藏珠。", "珠玉兩交輝，情窮意難極。"]'),
('dafda8c6-0da9-4245-a6b0-de5ce99ca0d3','偈頌四十二首  其四','釋祖先','宋','宋诗','song-poetry','','[]','一夏九十日，今朝喜告畢。',24,'全唐诗/poet.song.156000.json','["一夏九十日，今朝喜告畢。", "二千年前事，切忌更尋覓。"]'),
('21909991-1587-40bc-83e7-dac98be83fb0','偈頌四十二首  其五','釋祖先','宋','宋诗','song-poetry','','[]','暑威尚熾，喜見新秋。',46,'全唐诗/poet.song.156000.json','["暑威尚熾，喜見新秋。", "潘閬倒騎馿子，梵志翻著襪頭。", "堪悲堪笑，自唱自酬。", "有時乘好月，特地過滄洲。"]'),
('40cecfa3-adfa-4704-84c3-2de1fd084e16','偈頌四十二首  其六','釋祖先','宋','宋诗','song-poetry','','[]','大家共住喫莖虀，熟煮爛炊。',43,'全唐诗/poet.song.156000.json','["大家共住喫莖虀，熟煮爛炊。", "粗餐易飽，細嚼難饑。", "泠淡沒滋味，從來少人知，此意明明說向誰。"]'),
('5df69484-6bc4-4779-9f07-e278b9dab8cc','偈頌四十二首  其七','釋祖先','宋','宋诗','song-poetry','','[]','今朝又見開爐，浩浩諸方暖熱。',44,'全唐诗/poet.song.156000.json','["今朝又見開爐，浩浩諸方暖熱。", "卧龍冷落門庭，也要人前細說。", "夜靜更闌炭也無，衲衣破處冰侵骨。"]'),
('2106ae45-5773-4a23-b760-0d07a975b0d6','偈頌四十二首  其八','釋祖先','宋','宋诗','song-poetry','','[]','楊岐鬭勝不鬭劣，秀峰鬭劣不鬭勝。',48,'全唐诗/poet.song.156000.json','["楊岐鬭勝不鬭劣，秀峰鬭劣不鬭勝。", "秀峰乍住沒親疎，箇箇盡懷滄海珠。", "滿眼湖山看不足，釋迦彌勒是他奴。"]'),
('a66d0d98-21ac-4922-9156-a83022ed2b85','偈頌四十二首  其九','釋祖先','宋','宋诗','song-poetry','','[]','馬祖陞堂，百丈卷席。',20,'全唐诗/poet.song.156000.json','["馬祖陞堂，百丈卷席。", "正令不行，拗曲作直。"]'),
('78b05953-8a1a-4b3f-915c-cd8db1fbb22b','偈頌四十二首  其一○','釋祖先','宋','宋诗','song-poetry','','[]','首夏初臨，薰風乍扇。',48,'全唐诗/poet.song.156000.json','["首夏初臨，薰風乍扇。", "急景如梭，萬化千變。", "惟有拄杖子，黑輪皴，沒思算。", "解道厨庫揖僧堂，三門朝佛殿。"]'),
('f9d9294f-1a67-4f06-9f1b-7407636677d5','偈頌四十二首  其一一','釋祖先','宋','宋诗','song-poetry','','[]','寒食清明節，韶光映林樾。',55,'全唐诗/poet.song.156000.json','["寒食清明節，韶光映林樾。", "壠上標墳人，眼中流出血。", "生滅本無蹤，時人當自決。", "君不見水潦曾經馬師踏，直至而今笑不徹。"]'),
('5e620726-a1a7-4916-a1a5-0212ca39928e','偈頌四十二首  其一二','釋祖先','宋','宋诗','song-poetry','','[]','今朝五月端午，不用書符呪語。',58,'全唐诗/poet.song.156000.json','["今朝五月端午，不用書符呪語。", "只將者箇拄杖，用作降魔鐵杵。", "楚大夫活捉獰龍，張天師倒騎猛虎。", "觸翻東海鯉魚，直得傾盆下雨。"]'),
('6ab5d59a-4b6d-48f1-88bd-b6acaf32aa08','偈頌四十二首  其一三','釋祖先','宋','宋诗','song-poetry','','[]','一夏九十日，今朝喜圓滿。',62,'全唐诗/poet.song.156000.json','["一夏九十日，今朝喜圓滿。", "拈得鞏縣茶瓶，摵碎饒州瓷碗。", "冷笑布袋，平欺懶瓚。", "天堂不拘，地獄不管。", "空腹高心擔片板，無端瞎却頂門眼。"]'),
('8821667f-4887-46d8-98f3-fce8c4b03ff2','偈頌四十二首  其一四','釋祖先','宋','宋诗','song-poetry','','[]','這僧問處，字義炳然。',32,'全唐诗/poet.song.156000.json','["這僧問處，字義炳然。", "藏主無言，文不加點。", "還它老成人，扶持正法眼。"]'),
('cffd3eeb-2909-4a23-8333-a950ba3994b8','偈頌四十二首  其一五','釋祖先','宋','宋诗','song-poetry','','[]','插一莖草建梵剎，畫出規模何太窄。',58,'全唐诗/poet.song.156000.json','["插一莖草建梵剎，畫出規模何太窄。", "爭似亦庵新建立，容盡十方雲水客。", "鷲嶺風高，少林月白。", "光明寂照遍河沙，萬古流輝有張拙。"]'),
('5086d0cf-42d1-4c55-bb91-3ef0a4bbc2bc','偈頌四十二首  其一六','釋祖先','宋','宋诗','song-poetry','','[]','鷓鴣啼處百花香，日暖風和春晝長。',32,'全唐诗/poet.song.156000.json','["鷓鴣啼處百花香，日暖風和春晝長。", "昨夜虛空開口笑，祥光瑞氣滿華堂。"]'),
('32b51827-a45d-418c-ab5a-fbca281d3ac9','偈頌四十二首  其一七','釋祖先','宋','宋诗','song-poetry','','[]','二千年前公案，今朝重爲提撕。',36,'全唐诗/poet.song.156000.json','["二千年前公案，今朝重爲提撕。", "同住大光明藏，無修無證無爲，腦後依前欠一槌。"]'),
('74fb2e89-fb54-437c-a281-e26773c08249','偈頌四十二首  其一八','釋祖先','宋','宋诗','song-poetry','','[]','今朝五月端午節，千妖百怪盡消滅。',48,'全唐诗/poet.song.156000.json','["今朝五月端午節，千妖百怪盡消滅。", "艾虎桃符相耳語，摇頭不肯向人說。", "無端被者主杖子，對衆一時俱漏洩。"]'),
('202467a3-e852-4c07-97a5-e843245c2d8d','偈頌四十二首  其一九','釋祖先','宋','宋诗','song-poetry','','[]','曉來鵲噪一聲聲，象駕崢嶸喜見臨。',32,'全唐诗/poet.song.156000.json','["曉來鵲噪一聲聲，象駕崢嶸喜見臨。", "款聽琅琅終日語，異苗翻秀映叢林。"]'),
('8a25519e-7a84-4e50-a431-4c5d234dd8c8','偈頌四十二首  其二○','釋祖先','宋','宋诗','song-poetry','','[]','達磨西來事，今人謾度量。',46,'全唐诗/poet.song.156000.json','["達磨西來事，今人謾度量。", "天河爭起浪，月桂不聞香。", "達磨西來事，今人謾度量。", "人貧智短，馬瘦毛長。"]'),
('b4bc1666-d5c6-4f01-8d6d-aa7c08095558','偈頌四十二首  其二一','釋祖先','宋','宋诗','song-poetry','','[]','天氣或晴或雨，白雲乍卷乍舒。',38,'全唐诗/poet.song.156000.json','["天氣或晴或雨，白雲乍卷乍舒。", "行脚漢奔南走北似信不信，老臊胡游梁歷魏似有似無。"]'),
('9fe569b8-e495-444f-8351-b03dad8db806','偈頌四十二首  其二二','釋祖先','宋','宋诗','song-poetry','','[]','辦能開飯店，誰怕肚皮寬，說甚方便不方便。',56,'全唐诗/poet.song.156000.json','["辦能開飯店，誰怕肚皮寬，說甚方便不方便。", "先入南湖門，次入南湖室。", "吞底熱鐵丸，喫底洋銅汁。", "本色人到來，沙糖更澆蜜。"]'),
('4877bd51-2a5e-4dd4-9e16-5f705384f603','偈頌四十二首  其二三','釋祖先','宋','宋诗','song-poetry','','[]','諸法寂滅相，不可以言宣。',24,'全唐诗/poet.song.156000.json','["諸法寂滅相，不可以言宣。", "老來不著便，過犯已彌天。"]'),
('d26ae05a-034a-4c3f-b54d-2454243f24a6','偈頌四十二首  其二四','釋祖先','宋','宋诗','song-poetry','','[]','諸人知處良遂知，良遂知處人不知。',32,'全唐诗/poet.song.156000.json','["諸人知處良遂知，良遂知處人不知。", "王維已死無人畫，留得青山對落暉。"]'),
('f2dfbd43-7f05-4230-a4aa-149cc99b55dc','偈頌四十二首  其二五','釋祖先','宋','宋诗','song-poetry','','[]','堯仁廣被三千界，舜德長敷億萬年。',32,'全唐诗/poet.song.156000.json','["堯仁廣被三千界，舜德長敷億萬年。", "珍重聖恩何以報，只憑一炷海檀煙。"]'),
('e79da3d4-a4b1-4702-a6af-691233dcad29','偈頌四十二首  其二六','釋祖先','宋','宋诗','song-poetry','','[]','有問冬來事，京師出大黄。',24,'全唐诗/poet.song.156000.json','["有問冬來事，京師出大黄。", "漢家勳業在，樊噲與張良。"]'),
('0b81ba58-2a05-494f-a9cf-d08aad1a1dd7','偈頌四十二首  其二七','釋祖先','宋','宋诗','song-poetry','','[]','夤緣於此得安閑，屈指三年一瞬間。',32,'全唐诗/poet.song.156000.json','["夤緣於此得安閑，屈指三年一瞬間。", "好是今朝乘快便，又携藜杖過它山。"]'),
('a4aebdb7-111a-4141-871b-6f4abc78da1b','偈頌四十二首  其二八','釋祖先','宋','宋诗','song-poetry','','[]','常獨行，常獨步。',18,'全唐诗/poet.song.156000.json','["常獨行，常獨步。", "咄，莫來攔我毬門路。"]'),
('1bce4c08-f02e-4d42-b0c4-ef22082ee79b','偈頌四十二首  其二九','釋祖先','宋','宋诗','song-poetry','','[]','百不知，百不會。',26,'全唐诗/poet.song.156000.json','["百不知，百不會。", "似兀如癡，隨羣逐隧，誰云趙璧無瑕纇。"]'),
('e0b14ee6-4ae2-4b8c-8b35-194ef3c440d6','偈頌四十二首  其三○','釋祖先','宋','宋诗','song-poetry','','[]','智慧弓，堅固箭，射破虛空成兩片。',80,'全唐诗/poet.song.156000.json','["智慧弓，堅固箭，射破虛空成兩片。", "海門斜去兩三行，驚起暮天沙上雁。", "牛頭沒，馬頭回，鐵壁銀山一拶開。", "上苑玉池方解凍，湖光瀲灧映崔嵬。", "却笑普通年遠事，不從葱嶺带將來。"]'),
('b1318315-af73-4cb6-9739-cc1ab4afa57e','偈頌四十二首  其三一','釋祖先','宋','宋诗','song-poetry','','[]','大小雪竇，錯下名言。',25,'全唐诗/poet.song.156000.json','["大小雪竇，錯下名言。", "若人知得落著，許他喫著大蟲膽。"]'),
('c7996c46-2c5d-477c-9f71-2c3ea84ddef8','偈頌四十二首  其三二','釋祖先','宋','宋诗','song-poetry','','[]','卧病恰旬餘，氣力無一銖。',74,'全唐诗/poet.song.156000.json','["卧病恰旬餘，氣力無一銖。", "皮穿筋骨露，勉强且支梧。", "無鹽無米，誰爲分疎。", "拄杖子起來，瀉出百斛明珠。", "各請點檢倉庫，畢竟是有是無。", "山僧不免隨後念箇蘇嚕蘇嚕。"]'),
('8134a63b-4025-491d-834e-2b3626d5a8c8','偈頌四十二首  其三三','釋祖先','宋','宋诗','song-poetry','','[]','雪子落紛紛，烏盆變白盆。',24,'全唐诗/poet.song.156000.json','["雪子落紛紛，烏盆變白盆。", "忽然日頭出，依舊是烏盆。"]'),
('45154ff0-32f1-4ee0-81a2-62d8f16e3d6b','偈頌四十二首  其三四','釋祖先','宋','宋诗','song-poetry','','[]','十五日已前明似鏡，十五日已後黑如漆。',40,'全唐诗/poet.song.156000.json','["十五日已前明似鏡，十五日已後黑如漆。", "正當十五日，鶑遷喬木頻頻語，蝶戀芳叢對對飛。"]'),
('16bdf6e7-dac1-4640-8b06-3025133db0b1','偈頌四十二首  其三五','釋祖先','宋','宋诗','song-poetry','','[]','一切數句非數句，與吾靈覺何交涉。',26,'全唐诗/poet.song.156000.json','["一切數句非數句，與吾靈覺何交涉。", "字義炳然，當陽一決。"]'),
('e1b1eee8-a508-4f38-9682-60edf128f180','偈頌四十二首  其三六','釋祖先','宋','宋诗','song-poetry','','[]','心鏡明鑑無礙，豁然瑩徹周沙界。',31,'全唐诗/poet.song.156000.json','["心鏡明鑑無礙，豁然瑩徹周沙界。", "萬象森羅不覆藏，一顆圓光非內外。"]'),
('e4333913-c454-4fbc-8b8f-d6c50550615d','偈頌四十二首  其三七','釋祖先','宋','宋诗','song-poetry','','[]','黄檗山頭喫棒，大愚肋下築拳。',28,'全唐诗/poet.song.156000.json','["黄檗山頭喫棒，大愚肋下築拳。", "佛法的的大意，猶隔十萬八千。"]'),
('49750d74-060a-4b5a-90ef-3fa8c2033ac3','偈頌四十二首  其三八','釋祖先','宋','宋诗','song-poetry','','[]','大人具大見，大智得大用。',24,'全唐诗/poet.song.156000.json','["大人具大見，大智得大用。", "胸中懷六合，掌內握乾坤。"]'),
('6375681c-aaa0-4767-96eb-a2c04282920c','偈頌四十二首  其三九','釋祖先','宋','宋诗','song-poetry','','[]','世出世間希有事，顯發須還過量人。',32,'全唐诗/poet.song.156000.json','["世出世間希有事，顯發須還過量人。", "出沒卷舒驚世夢，蓬萊山色又重新。"]'),
('a5c5d730-7b5c-41cf-9e3b-7e9e429b6f96','偈頌四十二首  其四○','釋祖先','宋','宋诗','song-poetry','','[]','不坐空王殿，不掛本來衣。',24,'全唐诗/poet.song.156000.json','["不坐空王殿，不掛本來衣。", "何須更恁麽，切忌未生時。"]'),
('840badfb-fc2a-43b8-9ab4-57022e0588af','偈頌四十二首  其四一','釋祖先','宋','宋诗','song-poetry','','[]','只箇垂垂白髮僧，一生兩度受皇恩。',32,'全唐诗/poet.song.156000.json','["只箇垂垂白髮僧，一生兩度受皇恩。", "只憑少室無私句，地久天長祝聖君。"]'),
('99fbef6d-ad6c-41a3-bea4-e23ae6ff6bb5','偈頌四十二首  其四二','釋祖先','宋','宋诗','song-poetry','','[]','天上月圓，人間月半。',36,'全唐诗/poet.song.156000.json','["天上月圓，人間月半。", "子細看來，從頭錯算。", "姮娥昨夜失金鍼，撼動玉樓尋不見。"]'),
('bcd91e0a-8efc-4a5e-a975-bfb7487305ef','偈頌四十二首  其四三','釋祖先','宋','宋诗','song-poetry','','[]','不是心，不是佛，不是物。',41,'全唐诗/poet.song.156000.json','["不是心，不是佛，不是物。", "忍俊不禁，爲諸人做個瞥脫。", "流水暗銷溪畔石，勸人除却是非難。"]'),
('7049cf04-0335-4421-a34e-dbd718b635dc','偈頌四十二首  其四四','釋祖先','宋','宋诗','song-poetry','','[]','節屆書雲，陰極陽升。',50,'全唐诗/poet.song.156000.json','["節屆書雲，陰極陽升。", "冰河發焰，枯木抽英。", "惟有拄杖子，依舊黑輪皴。", "不遷不變，無辱無榮。", "笑殺當年面壁人。"]'),
('ceb0ec7b-d553-4644-bf04-22623a1294dd','偈頌四十二首  其四五','釋祖先','宋','宋诗','song-poetry','','[]','興化打克賓，猛虎驀腰騎。',24,'全唐诗/poet.song.156000.json','["興化打克賓，猛虎驀腰騎。", "養子不及父，家門一世衰。"]'),
('9e8de8c8-33fd-482a-9969-69cb1f99cfa8','偈頌四十二首  其四六','釋祖先','宋','宋诗','song-poetry','','[]','種種性相義，我及十方佛。',44,'全唐诗/poet.song.156000.json','["種種性相義，我及十方佛。", "乃能知是事，晝見日，夜見月。", "坐卧經行，曾無間歇，吽吽，有甚交涉。"]'),
('fe41aa25-a2b7-40d4-9ad5-a5090c5dc644','偈頌四十二首  其四七','釋祖先','宋','宋诗','song-poetry','','[]','舊歲夜來去，去從何處去。',40,'全唐诗/poet.song.156000.json','["舊歲夜來去，去從何處去。", "新年今日來，來從何處來。", "既無來，又無去，鐵壁銀山成指注。"]'),
('c376a1c9-0e64-43de-8fdf-bfe237b63c6c','達磨贊','釋祖先','宋','宋诗','song-poetry','','[]','梁皇殿前不能把定，少林山下風波愈盛。',32,'全唐诗/poet.song.156000.json','["梁皇殿前不能把定，少林山下風波愈盛。", "若解謹初護末，不到圖形畫影。"]'),
('21ac9f43-4ffc-4131-bbab-6ce12e6c7c87','六祖贊','釋祖先','宋','宋诗','song-poetry','','[]','颺下採樵斧，直入堆坊舂。',24,'全唐诗/poet.song.156000.json','["颺下採樵斧，直入堆坊舂。", "一脚踏到底，黄梅信息通。"]'),
('1dcf226a-9e18-46a3-9fc7-cf21a87abfc0','臨濟贊','釋祖先','宋','宋诗','song-poetry','','[]','揎拳捋肘，只有一箇。',20,'全唐诗/poet.song.156000.json','["揎拳捋肘，只有一箇。", "電卷星飛，抬頭蹉過。"]'),
('4ab94be1-9af0-4f60-b3f6-6f52217cb2d8','布袋贊','釋祖先','宋','宋诗','song-poetry','','[]','散誕不拘儀軌，街頭走到街尾。',28,'全唐诗/poet.song.156000.json','["散誕不拘儀軌，街頭走到街尾。", "逢人大笑呵呵，那個知渠肚裏。"]'),
('5dae3c9a-a4e8-48f5-9383-9327eb1a5fe4','定光贊','釋祖先','宋','宋诗','song-poetry','','[]','天涯海角俱行徧，鬼面神頭只自謾。',32,'全唐诗/poet.song.156000.json','["天涯海角俱行徧，鬼面神頭只自謾。", "却憶當年舊風月，杖頭挑出與人看。"]'),
('cb84103d-c5fc-4e00-b019-51e40d66d9b0','戢菴居士請贊濟顛','釋祖先','宋','宋诗','song-poetry','','[]','瞎堂之子，附馬之后。',48,'全唐诗/poet.song.156000.json','["瞎堂之子，附馬之后。", "出處行藏，一向漏逗。", "是聖是凡莫測，掣顛掣狂希有。", "一拳拳碎虛空，驚得須彌倒走。"]'),
('7442e5ff-aee6-4f9a-8171-16e419d432da','周正字請贊亡母宜人王氏真','釋祖先','宋','宋诗','song-poetry','','[]','畫得十分，依前不是。',36,'全唐诗/poet.song.156000.json','["畫得十分，依前不是。", "端坐北堂，琅琅仁義。", "文殊罔明把手行，入定出定恣游戲。"]'),
('c1834eee-f5e7-4f97-a39c-2a12304a8e28','戢菴居士持壽像求贊','釋祖先','宋','宋诗','song-poetry','','[]','似僧有髮，似俗無塵。',36,'全唐诗/poet.song.156000.json','["似僧有髮，似俗無塵。", "淡默自處，惟德與鄰。", "曾向鳳池親聖訓，更來鹿苑奪芳春。"]'),
('d53e1ef1-1355-4734-bf2e-8ad1daf11df1','性長老寫師真請贊','釋祖先','宋','宋诗','song-poetry','','[]','頑無所知，說無照對。',46,'全唐诗/poet.song.156000.json','["頑無所知，說無照對。", "弄假像真，遭人笑怪。", "花擘臨濟黄檗，佛法未夢見在。", "在在在，是處清風動天籟。"]'),
('c91d811f-6976-47eb-8ecc-2910c41a7c04','本禪人請贊','釋祖先','宋','宋诗','song-poetry','','[]','學道不根，參禪莽鹵。',56,'全唐诗/poet.song.156000.json','["學道不根，參禪莽鹵。", "似恁趣向乖疎，如何傳燈繼祖。", "本禪畫出人前，轉見和泥合土。", "就中更有些子誵訛，焦尾大蟲元來是虎。"]'),
('fbad5042-1812-4260-9d4b-25e3c28e3561','禪人請贊','釋祖先','宋','宋诗','song-poetry','','[]','錯錯錯，徒名邈。',26,'全唐诗/poet.song.156000.json','["錯錯錯，徒名邈。", "畫得十成，欠蹄少角，一任天下人貶剝。"]'),
('80aef6c8-f0c4-4a69-ab8c-eec6f243d026','寄蔣山如一翁','釋祖先','宋','宋诗','song-poetry','','[]','悠悠世路絕躋攀，卧看白雲空往還。',32,'全唐诗/poet.song.156000.json','["悠悠世路絕躋攀，卧看白雲空往還。", "惟有同參一句子，肯將容易混塵寰。"]'),
('98541323-ee66-4796-a490-128ea237bbb5','寄王承務','釋祖先','宋','宋诗','song-poetry','','[]','經年相別無他囑，莫只波波意裏求。',32,'全唐诗/poet.song.156000.json','["經年相別無他囑，莫只波波意裏求。", "病去藥除消息盡，紅塵堆裏等閒游。"]'),
('53585799-2734-4d71-acfc-76b20744691d','送虎丘首座住菴','釋祖先','宋','宋诗','song-poetry','','[]','劍池拾得豐城劍，凜凜寒光射斗牛。',32,'全唐诗/poet.song.156000.json','["劍池拾得豐城劍，凜凜寒光射斗牛。", "爲報不平平底事，草菴蓬戶也風流。"]'),
('98a9f7df-199e-4707-88d2-151555ee9600','示禪人寫華嚴經','釋祖先','宋','宋诗','song-poetry','','[]','毗盧大經卷，塵識久埋藏。',58,'全唐诗/poet.song.156000.json','["毗盧大經卷，塵識久埋藏。", "上人筆端力，掇出放毫光。", "笑他自城游歷，自倒自起自忙。", "江天月曉，夢破斜陽。", "一印印定，無法商量。"]'),
('0a9be5a8-c4e3-43d5-975d-0d780957e83a','示楞嚴座王','釋祖先','宋','宋诗','song-poetry','','[]','見猶離見非真見，還盡八還無可還。',32,'全唐诗/poet.song.156000.json','["見猶離見非真見，還盡八還無可還。", "木落霜天山骨露，不知誰識老瞿曇。"]'),
('4f622538-a850-47b1-a889-5558dea9a161','示南華行者','釋祖先','宋','宋诗','song-poetry','','[]','黄梅會裏七千指，虎驟龍馳空點胸。',32,'全唐诗/poet.song.156000.json','["黄梅會裏七千指，虎驟龍馳空點胸。", "碓蹯老盧愚且拙，坤維占斷最高峰。"]'),
('65262442-cddd-4c73-bd29-8024a5de1334','自詒','釋祖先','宋','宋诗','song-poetry','','[]','宴坐白雲裏，經行碧嶂中。',24,'全唐诗/poet.song.156000.json','["宴坐白雲裏，經行碧嶂中。", "遊人窮不到，幽鳥自怱怱。"]'),
('2243b9f0-4975-4a91-9331-291aa82f7c42','臨終偈','釋祖先','宋','宋诗','song-poetry','','[]','末後一句，已成忉怛。',20,'全唐诗/poet.song.156000.json','["末後一句，已成忉怛。", "寫出人前，千錯萬錯。"]'),
('7d6790fb-63d8-4167-b1e7-2b9670f21b41','頌古三首  其一','釋祖先','宋','宋诗','song-poetry','','[]','應無所住以生心，大地山河一發沉。',32,'全唐诗/poet.song.156000.json','["應無所住以生心，大地山河一發沉。", "從此別開窮世界，新州柴把貴如金。"]'),
('9b0bb401-cb7b-42d2-9604-323d71378858','頌古三首  其二','釋祖先','宋','宋诗','song-poetry','','[]','師姑元是女人作，百衲禪僧多罔措。',32,'全唐诗/poet.song.156000.json','["師姑元是女人作，百衲禪僧多罔措。", "雁囘沙塞口啣蘆，燕遶紅梁渾不顧。"]'),
('99e51307-7da9-4c0a-8aff-a09dc91dacfa','頌古三首  其三','釋祖先','宋','宋诗','song-poetry','','[]','巖頭一拶，虛空迸裂。',20,'全唐诗/poet.song.156000.json','["巖頭一拶，虛空迸裂。", "父子不傳，神仙妙訣。"]'),
('f278aa61-4d70-42d4-954d-856e0a698af6','送馮圓仲入蜀','章甫','宋','宋诗','song-poetry','','[]','我本山中人，早信雲無心。',120,'全唐诗/poet.song.156000.json','["我本山中人，早信雲無心。", "卷舒隨清風，或作三日霖。", "十年江湖游，復識水之性。", "東西因地形，圓折初無定。", "却來閲世人，惟公多古風。", "用舍不繫懷，略與雲水同。", "還乘明月舟，西泝弄雲水。", "雲水遠送迎，鷗鷺皆知己。", "我今與公別，亦若雲水然。", "相望渺江湖，萬里同青天。"]'),
('44ec1a4b-eae5-4788-8412-5d0cdd2583e2','送張寺丞','章甫','宋','宋诗','song-poetry','','[]','知己不易得，相知貴知心。',168,'全唐诗/poet.song.156000.json','["知己不易得，相知貴知心。", "我行遍四方，公獨知我深。", "公如千丈松，凜凜有直氣。", "我如松下草，亦有傲霜意。", "公分刺史符，朅來淮上州。", "而我倦遊者，振衣從公遊。", "花月醉管弦，江山隨杖履。", "激水湔窮愁，逢人賞佳句。", "政成公入覲，酒盡客語離。", "疊鼓催發船，不顧邦人悲。", "邦人勿深悲，宣室定前席。", "公必念爾民，還陳治安策。", "吾君自神聖，事君公不欺。", "祝公但加餐，慰此邦人思。"]'),
('a29b1734-98a1-422c-93e0-75f01461f0af','送孫文輔尉新城','章甫','宋','宋诗','song-poetry','','[]','我來淮上居，忽忽歲月過。',120,'全唐诗/poet.song.156000.json','["我來淮上居，忽忽歲月過。", "定交誰最久，有唱君必和。", "棋枰角勝負，文字工切磋。", "雲山結伴遊，風雨對牀卧。", "那知世途隘，但喜客愁破。", "出處方乃殊，離別情無那。", "江城失益友，山縣得良佐。", "平生愛圖史，晚歲職警邏。", "枹鼓常不驚，雞犬亦相賀。", "强飯君勉旃，功名看老大。"]'),
('a32d2ec4-f2e8-4316-bae4-5735242f0a7f','隠靜分題得靜字','章甫','宋','宋诗','song-poetry','','[]','平生苦愛閒，多病復便靜。',144,'全唐诗/poet.song.156000.json','["平生苦愛閒，多病復便靜。", "每爲林下遊，忽若醉而醒。", "茲山昔曾登，當暑毛骨冷。", "碧霄環珮聲，古木旌幢影。", "五峰如高人，一一各秀穎。", "俗駕難久留，佇立但俄頃。", "別來三十載，往往夢清境。", "從公得再來，共此春日永。", "憑高愜幽思，即事發深省。", "然燈戰枯棋，臨水瀹新茗。", "興闌下山去，妙處心已領。", "曉雨濕籃輿，衝泥度前嶺。"]'),
('242fe135-1294-43a9-91c0-c8923dd5eee8','古洗','章甫','宋','宋诗','song-poetry','','[]','古人不可見，古物亦無幾。',96,'全唐诗/poet.song.156000.json','["古人不可見，古物亦無幾。", "今朝雙眼明，乃識漢時洗。", "規模簡而質，彷彿古君子。", "年深土銷蝕，薄處僅如紙。", "篆名可意逆，依稀辨雙鯉。", "傳寶今幾代，是閲人多矣。", "我生頗好古，摩挲不能已。", "悠然起遐思，俗物一何鄙。"]'),
('7f548a37-9df6-4fa2-80cc-9fbc360effeb','納凉','章甫','宋','宋诗','song-poetry','','[]','大熱金石流，日色赤可畏。',180,'全唐诗/poet.song.156000.json','["大熱金石流，日色赤可畏。", "鄙夫先多病，喘息僅存氣。", "飲冰不救渴，膚汗那容睡。", "秋風幾時來，不問黑貂敝。", "林梢墮斜陽，凉颸颯然至。", "呼童汲井泉，洒掃庭中地。", "胡牀得露坐，始覺有生意。", "老妻破甘瓜，兒女膝下戲。", "鳴蟬雖强聒，亦足代鼓吹。", "坐久月照人，金波正澄霽。", "惜哉疲薾甚，杯酒未敢置。", "浮生能幾何，荏苒忽中歲。", "四時更代謝，寒暑不可避。", "幻身豈長存，中有不遷義。", "且享今夕涼，百年安用計。"]'),
('b25272f8-8357-4e0c-8439-189acf0d32c0','和仲韓見簡韻','章甫','宋','宋诗','song-poetry','','[]','野人不愛名，中歲益安命。',144,'全唐诗/poet.song.156000.json','["野人不愛名，中歲益安命。", "辛苦營一區，婆娑只三徑。", "那知錢有神，但喜酒能聖。", "翩翩趙公子，時時枉軒乘。", "詩詞既清婉，筆力亦端勁。", "傳家堅素守，從仕傷直性。", "語言生風波，道路足機阱。", "君猶沉下僚，我亦抱多病。", "時偷半日閒，樂此一室靜。", "賞月已失期，登高况當令。", "風物漸凄緊，江山更幽夐。", "何時城南樓，曳杖可乘興。"]'),
('e5039279-5cac-4934-b9f1-751bbc5953ec','和韓丈寄崖簿大雅并見簡韻','章甫','宋','宋诗','song-poetry','','[]','故鄉未可歸，異縣難久留。',192,'全唐诗/poet.song.156000.json','["故鄉未可歸，異縣難久留。", "海深蛟鱷怒，安得乘桴遊。", "貧賤豈天意，自不曲如鈎。", "吾道未全窮，三歲依賢侯。", "小雞隨孔鸞，顧影良可羞。", "所喜臭味同，潔己從清修。", "邇來苦多病，頗厭淮南州。", "援琴操土風，大類南冠囚。", "今辰天氣佳，和風吹敝裘。", "桃李競顔色，誰能分劣優。", "空攪遊予心，浩蕩生春愁。", "新詩忽到手，盛意知難酬。", "材生天地間，小大固不侔。", "詞鋒未易當，如以楚伐鄒。", "玉季更多文，情義還相投。", "他年內集時，尚記野人不。"]'),
('a14abef3-5763-4c46-abf3-304242d5a3b5','雷','章甫','宋','宋诗','song-poetry','','[]','三伏久不雨，今辰忽聞雷。',96,'全唐诗/poet.song.156000.json','["三伏久不雨，今辰忽聞雷。", "殷殷地中出，轟轟空際來。", "電光倏先馳，掩耳恐不及。", "陰雲勢相交，銷鑠畏毒日。", "上天行號令，君子敬天威。", "端坐每深省，整冠仍斂衣。", "蒼生苦炎熱，喘汗不可過。", "寄聲謝豐隆，爲起神龍卧。"]'),
('a4d6f09c-cd6e-4d3d-9bae-6e2bd2539503','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其一','章甫','宋','宋诗','song-poetry','','[]','日月無停輪，歲律今崢嶸。',48,'全唐诗/poet.song.156000.json','["日月無停輪，歲律今崢嶸。", "夜長客無睡，打窗秋雨鳴。", "早寒逼衾裯，兒女聲吚嚶。", "令人愧老龐，團欒話平生。"]'),
('3195ab26-9844-432d-aa4b-db3879946878','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其二','章甫','宋','宋诗','song-poetry','','[]','借屋與僧鄰，局促僅如蝸。',48,'全唐诗/poet.song.156000.json','["借屋與僧鄰，局促僅如蝸。", "悲秋懷抱惡，頭緒如亂麻。", "老來怕讀書，隙風燈影斜。", "感時思弟妹，衰淚落天涯。"]'),
('3346253f-09d2-40af-a819-2fb5eb98e3cb','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其三','章甫','宋','宋诗','song-poetry','','[]','饑寒傍人門，面目自可憎。',48,'全唐诗/poet.song.156000.json','["饑寒傍人門，面目自可憎。", "爲善得長貧，天理疑難憑。", "狂談取富貴，易若階而升。", "吾實畏鬼神，勿謂吾無能。"]'),
('fc01979c-5b42-45d1-8340-f453c02d95cc','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其四','章甫','宋','宋诗','song-poetry','','[]','愁陰錯昏曉，北風振葭葦。',48,'全唐诗/poet.song.156000.json','["愁陰錯昏曉，北風振葭葦。", "關塞來悲鴻，戰場多哭鬼。", "人生真幻戲，歸盡同螻螘。", "貪夫患得失，達者今無幾。"]'),
('439f28ff-79bb-4ff7-974e-f62b4f31c8df','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其五','章甫','宋','宋诗','song-poetry','','[]','逆旅故人少，今秋風雨多。',48,'全唐诗/poet.song.156000.json','["逆旅故人少，今秋風雨多。", "禾頭欲生耳，農夫空悲歌。", "饑腸望一飽，嗷嗷同雁鵝。", "臨風不把酒，奈此菊花何。"]'),
('a1d21e5f-402c-4141-a333-3d1439cda890','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其六','章甫','宋','宋诗','song-poetry','','[]','門庭久沮洳，蚯蚓升吾堂。',48,'全唐诗/poet.song.156000.json','["門庭久沮洳，蚯蚓升吾堂。", "夜寒人閴寥，蟋蟀鳴吾床。", "屋頭兩株樹，葉落滿僧廊。", "騷人不須悲，榮悴理之常。"]'),
('4e3e78fa-0a0e-42e0-8e71-1c460a9672be','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其七','章甫','宋','宋诗','song-poetry','','[]','詩吟不必工，酒實性所愛。',48,'全唐诗/poet.song.156000.json','["詩吟不必工，酒實性所愛。", "少年少拘束，日與尊罍對。", "沉酣相呼和，亦有嵇阮輩。", "會合不可常，故人今好在。"]'),
('514ca802-8a30-47e2-979f-2e555b5d3ca2','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其八','章甫','宋','宋诗','song-poetry','','[]','貧窮束縛人，智慧無所施。',48,'全唐诗/poet.song.156000.json','["貧窮束縛人，智慧無所施。", "文籍紛滿前，不救寒與饑。", "佳哉江上山，歸隠寧無時。", "青山若有言，塵土君自羈。"]'),
('f0c246aa-a12d-4a44-9dc7-c57419068b6e','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其九','章甫','宋','宋诗','song-poetry','','[]','憶買京口船，飄飄適荆楚。',48,'全唐诗/poet.song.156000.json','["憶買京口船，飄飄適荆楚。", "覽古弔興亡，亦有會心侶。", "歲月能幾何，已作幽明阻。", "筋骸幸無恙，未害且逆旅。"]'),
('13a81985-c1ce-4a95-84a2-fb6b8992d973','秋雨未已客懷不佳夜誦少陵遣興詩至生涯能幾何常在羈旅中三復增感每字賦一詩  其一○','章甫','宋','宋诗','song-poetry','','[]','今晨氣候佳，萬里來西風。',48,'全唐诗/poet.song.156000.json','["今晨氣候佳，萬里來西風。", "舉頭看浮雲，已歸天漢東。", "野人還負暄，帝澤流無窮。", "心隨鴻雁飛，不離霄壤中。"]'),
('5414abae-c9e2-4bba-aa79-8746f732448f','簡王漕左司','章甫','宋','宋诗','song-poetry','','[]','人生天壤中，孰不有所求。',168,'全唐诗/poet.song.156000.json','["人生天壤中，孰不有所求。", "小大雖不齊，逐物常同憂。", "士子文字間，亦各從所愛。", "取舍未必同，於道均無害。", "我生才甚下，志與俗子殊。", "思賢惄如饑，覓句聊自娛。", "惟公盛德人，君今乃行古。", "富貴等雲烟，詞翰敏風雨。", "荆湖十五州，玉節何煌煌。", "門庭無雜賓，讀書清晝長。", "摳衣願從遊，自視亦何有。", "未知函丈地，能著野人否。", "公誠一顧之，足以爲我榮。", "淮南有石田，歸趁春雨耕。"]'),
('7b226aba-6162-4cca-a47f-d61ea9ebfdf9','分題得草果飲子','章甫','宋','宋诗','song-poetry','','[]','神農書本草，有美生南州。',180,'全唐诗/poet.song.156000.json','["神農書本草，有美生南州。", "春華穗端垂，彷彿芙蓉秋。", "青囊貯嘉實，璀璨安石榴。", "香味極辛烈，果中第一流。", "磊落入盤飣，和羹充肴脩。", "溫中與下氣，功用亦罕儔。", "苞苴走四海，藥籠必見收。", "吾老苦病暍，淡味空頻投。", "作飲近得此，選擇知獨優。", "碧井沈銀瓶，斟酌得自由。", "蔗漿已覺俗，茗粥良可羞。", "乃知古聖人，收拾靡不周。", "日遇七十毒，縱死夫何憂。", "但吾赤子多，疾苦庶有瘳。", "大或仁者心，當與天地侔。"]'),
('cb246adc-6502-4fdf-8add-20cd6c37bb4a','同張季子遊琅邪','章甫','宋','宋诗','song-poetry','','[]','枯藤久靠壁，雙脚殊蜷跼。',288,'全唐诗/poet.song.156000.json','["枯藤久靠壁，雙脚殊蜷跼。", "日長無往還，午醉睡初熟。", "誰與來剝啄，一馬挾兩僕。", "翩翩張公子，得得訪茅屋。", "別來今十年，高誼驚絕俗。", "功名付兄弟，冠裳畏羈束。", "多君殊不凡，愛我常易足。", "呼兒取酒斟，草草具肴䔩。", "劇談連晝夜，何止伴幽獨。", "結爲山水遊，策蹇相追逐。", "滁陽三日程，山路頗詰曲。", "好風吹雨霽，發軔自幽谷。", "至樂聞金聲，非絲亦非竹。", "沉沉柏子潭，神龍所棲宿。", "旱乾禱輒應，雲雨手翻覆。", "路轉醉翁亭，釀泉漱寒玉。", "堂堂四公像，再拜敢不肅。", "雖云斗大州，盛德繼來辱。", "凜然生氣在，遺澤被草木。", "梵宮最高處，俯視山矗矗。", "境聖人乃凡，野僧才五六。", "碑崖爛文字，驪珠混魚目。", "老眼眩生花，往往難盡讀。", "吾能領其要，正自非匆促。"]'),
('140e3288-736d-49f9-8bf8-5c61f1244e55','題玲瓏','章甫','宋','宋诗','song-poetry','','[]','江月不受塵，風竹儼相倚。',48,'全唐诗/poet.song.156000.json','["江月不受塵，風竹儼相倚。", "窗間讀書人，日用亦如是。", "涇渭豈同流，天地果一指。", "客來問如何，南山有雲起。"]'),
('b79e65c8-de08-45a9-ac65-4902c51a4b51','鹿角','章甫','宋','宋诗','song-poetry','','[]','呦呦鳴鹿羣，適意在林藪。',144,'全唐诗/poet.song.156000.json','["呦呦鳴鹿羣，適意在林藪。", "泉甘草豐茂，多力故能走。", "一朝觸禍機，竟死誰人手。", "割鮮登鼎俎，刺血置杯酒。", "犄角未易棄，煮膠方術有。", "汲江爲浸漬，七日去粗垢。", "大候三伏時，煎熬必甖缶。", "色作琥珀紅，堅重如瓊玖。", "補陽遂强骨，輕健還堪久。", "殺身雖可憐，仁實存身後。", "功能利生人，死且垂不朽。", "悠悠肉食輩，亦愧此鹿否。"]'),
('bd8473b6-2f8c-460c-9276-bb7e3011e32b','慈湖磯','章甫','宋','宋诗','song-poetry','','[]','峭壁激湍流，湍流作洄洑。',96,'全唐诗/poet.song.156000.json','["峭壁激湍流，湍流作洄洑。", "初無一餉風，飽我蒲帆腹。", "長笪寄怪石，招呼爭挽牽。", "艱難僅寸進，何翅如登天。", "及磯日猶高，過磯日曛黑。", "依約見漁村，燈火照初夕。", "舟師告疲勞，夜泊投人家。", "驚犬吠籬落，寒生蘆荻花。"]'),
('e0124342-c806-458f-a816-167b0866eda2','雨中舟出潮牐','章甫','宋','宋诗','song-poetry','','[]','官吏急星火，驅民疏漕河。',48,'全唐诗/poet.song.156000.json','["官吏急星火，驅民疏漕河。", "城中三尺泥，歲晚風雨多。", "雨聲來未已，清滿幽人耳。", "曲肱篷底眠，船隨夜潮起。"]'),
('ea38012e-7d2e-44c0-9623-5921df5362aa','卜宅','章甫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','卜宅定何好，廬山泉石奇。',48,'全唐诗/poet.song.156000.json','["卜宅定何好，廬山泉石奇。", "夜夢五老人，問我歸何時。", "山中有蕨薇，可以療子饑。", "束書早歸來，長歌歌紫芝。"]'),
('2df2b9c9-da98-420a-9cbc-bf3f8d4b1320','次高若虛韻','章甫','宋','宋诗','song-poetry','','[]','時事口慵說，性靈詩可陶。',120,'全唐诗/poet.song.156000.json','["時事口慵說，性靈詩可陶。", "客中三日陰，江頭風浪高。", "六年寄此邦，鷗鷺皆心交。", "烟波迥自如，應笑吾生勞。", "世路轉偪仄，旅鬢空蕭騷。", "既往若電夢，所得真毫毛。", "歲月解欺人，木落江之臯。", "勿謂吾甚衰，得酒猶能豪。", "舊遊固可戀，歸盟那得逃。", "負暄依茆簷，兒輩供爬搔。"]'),
('777d3710-c4ae-4c4f-a94c-1d31a0063cc0','歸自真州道中用前韻簡諸故人','章甫','宋','宋诗','song-poetry','','[]','閒愁生旅懷，薄酒安能陶。',120,'全唐诗/poet.song.156000.json','["閒愁生旅懷，薄酒安能陶。", "籃輿赴歸期，歷歷山路高。", "風雨道旁憩，倏然思故交。", "官閑相聚首，懷我登頓勞。", "辯論雜嘲謔，詩詞兼雅騷。", "人生幾何時，容易生二毛。", "方今天子聖，登用皆夔臯。", "願君各努力，去矣追羣豪。", "我生苦畏事，屏處如逋逃。", "縱復技癢存，敢念麻姑搔。"]'),
('c69859b1-1a70-4998-8977-3498812aa144','俞廣文以詩定交次韻奉答','章甫','宋','宋诗','song-poetry','','[]','懶慢易招咎，貧賤難相知。',180,'全唐诗/poet.song.156000.json','["懶慢易招咎，貧賤難相知。", "客歸二十年，破屋臨江湄。", "遣悶豈無酒，寄懷徒有詩。", "慷慨思古人，恨不生同時。", "去秋君始來，雲霧容一披。", "別去冒朔雪，歸來迎南颸。", "載登君子堂，爽氣生芝眉。", "劇談兩無礙，並駕行通逵。", "省闈冠多士，泮宮聊養頤。", "霄漢自茲始，羽翮隨所之。", "門闌謝俗子，遊戲惟毛錐。", "高吟起我病，意欲相箴規。", "琢句要須工，一字亦有師。", "逢迎君忽倦，追逐吾敢辭。", "人生俱寄耳，况乃多別離。"]'),
('31968438-4d07-42a0-ad33-378cf061c023','曾仲恭侍郎惠酒以偶有名酒無夕不飲爲韻謝之  其一','章甫','宋','宋诗','song-poetry','','[]','窮居少人事，落落仍寡偶。',48,'全唐诗/poet.song.156000.json','["窮居少人事，落落仍寡偶。", "晨曦入茆簷，和氣生戶牖。", "擁褐還負暄，看雲更搔首。", "閒哦陶令詩，饑腸作雷吼。"]'),
('bda9aaee-0c22-443b-8820-782398410818','曾仲恭侍郎惠酒以偶有名酒無夕不飲爲韻謝之  其二','章甫','宋','宋诗','song-poetry','','[]','力耕不逢年，歲暮百無有。',48,'全唐诗/poet.song.156000.json','["力耕不逢年，歲暮百無有。", "小雨肥麥根，何時得餬口。", "百年倏已半，辛勤爲升斗。", "頼古多若人，千載可尚友。"]'),
('4cd803b9-156f-43bd-a167-78ee80c6a1ea','曾仲恭侍郎惠酒以偶有名酒無夕不飲爲韻謝之  其三','章甫','宋','宋诗','song-poetry','','[]','古來稱達人，不願身後名。',48,'全唐诗/poet.song.156000.json','["古來稱達人，不願身後名。", "豈其未忘世，隤然聊遣情。", "我生本衰愞，於時淡無營。", "但得秫可釀，何勞詩有聲。"]'),
('68a9131e-986b-4b95-9a77-885737c452a3','曾仲恭侍郎惠酒以偶有名酒無夕不飲爲韻謝之  其四','章甫','宋','宋诗','song-poetry','','[]','烹魚多素書，問字誰載酒。',48,'全唐诗/poet.song.156000.json','["烹魚多素書，問字誰載酒。", "寂寞淮鄉居，歲月亦已久。", "敢希陋巷樂，但覺貧士醜。", "知音幸有人，此事可不朽。"]'),
('514f18c5-d603-46a7-9156-71047adb897a','曾仲恭侍郎惠酒以偶有名酒無夕不飲爲韻謝之  其五','章甫','宋','宋诗','song-poetry','','[]','丹陽賢使君，高誼今所無。',48,'全唐诗/poet.song.156000.json','["丹陽賢使君，高誼今所無。", "鈴齋有餘閒，遥憶耕田夫。", "滿船送美酒，盛事驚道途。", "客來即留醉，不用倩行酤。"]'),
('51547154-6241-43f5-9d14-33a180aa10c2','曾仲恭侍郎惠酒以偶有名酒無夕不飲爲韻謝之  其六','章甫','宋','宋诗','song-poetry','','[]','一杯復一杯，今夕知何夕。',48,'全唐诗/poet.song.156000.json','["一杯復一杯，今夕知何夕。", "蔀屋發光怪，尊罍盈四壁。", "老盆還舊觀，寒燈起佳色。", "既醉使君酒，亦飽使君德。"]'),
('e08e6884-a3c2-44b8-92ce-a9a74b830b94','曾仲恭侍郎惠酒以偶有名酒無夕不飲爲韻謝之  其七','章甫','宋','宋诗','song-poetry','','[]','逢人說項斯，此道今則不。',48,'全唐诗/poet.song.156000.json','["逢人說項斯，此道今則不。", "使君如古人，薦善惟恐後。", "願君登廊廟，搜羅到巖藪。", "使我擊壤歌，投老安隴畝。"]'),
('e42e0717-027c-4562-97f9-e8489acf5c0d','曾仲恭侍郎惠酒以偶有名酒無夕不飲爲韻謝之  其八','章甫','宋','宋诗','song-poetry','','[]','使君開府來，京口酒可飲。',48,'全唐诗/poet.song.156000.json','["使君開府來，京口酒可飲。", "公才真麴糵，留滯已再稔。", "江山助詩興，草木入題品。", "冰霜寒正嚴，爲國護饔寢。"]'),
('686dac32-bb82-42bf-a628-f69e6507d095','陪韓子雲弔張安國舍人墓','章甫','宋','宋诗','song-poetry','','[]','頃從武昌守，來哭清果墓。',144,'全唐诗/poet.song.156000.json','["頃從武昌守，來哭清果墓。", "老淚濕征衫，傷心不忍去。", "焉知五載後，重到山崔嵬。", "松柏倏已拱，宿草纏餘哀。", "公乘使者車，忠厚神所賚。", "遠懷平生親，斗酒相沃酹。", "曩以門下故，獲登君子堂。", "招呼連屋居，此意詎可忘。", "青春閉佳城，榮華竟消歇。", "空餘千古名，不隨世磨滅。", "蓬萊定何處，神仙知有無。", "徘徊重徘徊，悲風生坐隅。"]'),
('6b8fd41f-cff6-48ab-8207-c27d10e384c9','同張伯子威子季子雉子聞子陸及之時子政家弟輔小子槃過馬清叟摘櫻桃以萬顆勻圓訝許同分賦得許字','章甫','宋','宋诗','song-poetry','','[]','南城有隠居，靜退我所與。',240,'全唐诗/poet.song.156000.json','["南城有隠居，靜退我所與。", "兩窮成邂逅，一笑同出處。", "翛然五畝園，耕種了寒暑。", "朱櫻前日栽，茂密已如許。", "今歲風雨時，高枝墊難舉。", "喜我領客來，柴關不我拒。", "倒衣出逢迎，掃地客燕醑。", "童奴罷守衛，徒馭先含咀。", "肴核既雜陳，少長咸以序。", "堆盤火齊紅，磊落照尊俎。", "眼明愛勻圓，酒興莫能禦。", "吾儔既屬饜，亦欲相就語。", "西鄰老禪伯，携茗復來煮。", "放懷誰主賓，劇論忘爾汝。", "題名污牆壁，分韻索毫楮。", "月出未忍還，不記城闉阻。", "懽呼重攀折，璀璨滿筐筥。", "行歌驚路人，歸遺詫兒女。", "明年更强健，載酒寧無侶。", "但恐座上客，相望各吳楚。"]'),
('66a7f373-e9ed-4592-a7ab-f64dc2dbf373','落葉','章甫','宋','宋诗','song-poetry','','[]','青青池邊樹，歲久獨婆娑。',72,'全唐诗/poet.song.156000.json','["青青池邊樹，歲久獨婆娑。", "鳴蜩炎暑時，愛此清陰多。", "西風一披拂，顔色已非故。", "朝看一葉飛，暮落渾無數。", "葉落畢歸根，明年發陽春。", "人生豈長好，日月如飛輪。"]'),
('a0be86b0-862b-40ed-a7df-f65cbd6d81f0','壽王真州','章甫','宋','宋诗','song-poetry','','[]','陽春耀桃李，松柏不動心。',144,'全唐诗/poet.song.156000.json','["陽春耀桃李，松柏不動心。", "歲暮霜霰寒，松柏猶翠陰。", "物生天地間，均此一氣爾。", "小大有不齊，乘除亦常理。", "使君盛德後，清白由家傳。", "平生功名心，不作世態妍。", "公爲人所難，天念公所獨。", "黄屋結深知，青氈行可復。", "致遠要自近，試公先一州。", "生朝喜載臨，頌聲滿江頭。", "仁者壽固宜，富貴公自有。", "作詩祝東風，爲勸尊中酒。"]'),
('ef712bb4-0bf9-4b8d-a76b-20fa4f3618dc','送陳彌高','章甫','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','憶昨歲云徂，艤舟岳陽樓。',144,'全唐诗/poet.song.156000.json','["憶昨歲云徂，艤舟岳陽樓。", "獲見故人面，使我明雙眸。", "今年風露凉，君亦來荆州。", "笑語倍疇昔，舉杯相勸酬。", "詞鋒一當百，鵰鶚橫高秋。", "春風待變化，勇往不可留。", "看花得意時，豈獨爲身謀。", "伊予坐懶慢，行矣歸林丘。", "世故百念冷，潛魚畏吞鈎。", "出處雖異途，十載契分投。", "肉食與藜羹，未用分劣優。", "出門天地寬，鵬鷃逍遥遊。"]'),
('6a938b7c-ae99-4893-8c93-bd02e823a77c','寄上曾仲恭侍郎借凈香寮詩韻','章甫','宋','宋诗','song-poetry','','[]','官酒味甚薄，客懷愁正濃。',132,'全唐诗/poet.song.156000.json','["官酒味甚薄，客懷愁正濃。", "節物苦催人，水葉鳴西風。", "覓句了無得，寂寞誰與同。", "憑高望京口，佳氣何葱葱。", "中有賢府主，瑩然冰雪容。", "家學傳正派，政聲摩秋空。", "閒哦燕寢詩，香篆縈房櫳。", "別來未兼旬，頻夜夢見公。", "白沙距西津，片帆可即通。", "會當滌場圃，還奉杖履從。", "只恐趨召還，接武夔與龍。"]'),
('c4446390-a952-44ed-95e2-0d1d225b3ffe','題王履方畫漁樵扇','章甫','宋','宋诗','song-poetry','','[]','山深多虎狼，腰斧老無力。',96,'全唐诗/poet.song.156000.json','["山深多虎狼，腰斧老無力。", "豈惟身上衣，渾家口中食。", "水闊蛟龍怒，魚鼈不易求。", "雖無租賦迫，長有風波憂。", "偶來蒼江頭，落日相勞苦。", "斗米今幾錢，粗免寒餓否。", "形役乃如此，人生真可憐。", "五陵美少年，寶馬珊瑚鞭。"]'),
('72f65708-787c-4d34-b218-c497bead5c8f','贈葉伯永','章甫','宋','宋诗','song-poetry','','[]','憶昨辛巳秋，張帆過儀真。',288,'全唐诗/poet.song.156000.json','["憶昨辛巳秋，張帆過儀真。", "別君適荆楚，寤寐懷故人。", "狂寇初敗盟，道路多紛紜。", "思君不可見，疑君墮邊塵。", "寄書無處所，消息何時聞。", "去年我東來，泊船舊江津。", "始遣訪生死，戎馬乃駸駸。", "倉皇徑南渡，憂畏損精神。", "仲冬丹陽館，驚喜忽見君。", "執手兩無語，老淚欲沾巾。", "嗟予漫奔走，萬里長酸辛。", "念君兩鬢白，依然生理貧。", "開口論兵勢，直氣摩青雲。", "長揖動卿相，囊封登帝閽。", "當路頗知己，擬活西江鱗。", "鯨波泛大海，去結山東民。", "誓將三寸舌，成此百世勳。", "艱難得生還，和議已復伸。", "智略無所施，裋褐還逡巡。", "藏名酒肆中，悲歌閲芳辰。", "興闌却顧我，相對南風薰。", "宛宛昔別地，倏然今四春。", "江山不改舊，世事凡幾新。", "是非既未定，涇渭何當分。"]'),
('bbca1c47-3766-4163-9ec5-485134285018','喜晴','章甫','宋','宋诗','song-poetry','','[]','連山春雨來，徑滑不容足。',132,'全唐诗/poet.song.156000.json','["連山春雨來，徑滑不容足。", "行人相攀援，泥濘及馬腹。", "欲往不得前，野店可投宿。", "朝來天宇佳，笑語聞童僕。", "宣城半程耳，山路聽詰曲。", "自別賢主人，三歲如轉燭。", "應煩倒屣迎，喜氣見眉目。", "新堂幾日成，春酒此時熟。", "珠璣傾錦囊，塵埃拂楸局。", "上饒千里遠，策蹇許追逐。", "北歸預可料，詩作牛腰束。"]'),
('cd0519f2-20b6-4f4b-9baf-16605abc3f09','履方携姜坦道詩卷相過爲書其後','章甫','宋','宋诗','song-poetry','','[]','姜侯同鄉井，憶昨初見時。',144,'全唐诗/poet.song.156000.json','["姜侯同鄉井，憶昨初見時。", "春風頭陀菴，快作六字詩。", "一別十五年，漂流各萍轉。", "君携此軸來，如覿故人面。", "淤泥青蓮花，本自不受塵。", "得錢付酒保，往往遭謗嗔。", "眷言方遐思，相從問消息。", "清狂猶曩時，鬚髮幸未白。", "我貧過孟郊，何敢以詩鳴。", "擬辦黄篾舫，去尋白鷗盟。", "懷人暮雲碧，憂國寸心折。", "安得癯仙來，共醉望沙月。"]'),
('b1d7f7a5-a46c-420f-87d3-d668569799a0','代呼延信夫以筍乞貓於韓子雲','章甫','宋','宋诗','song-poetry','','[]','官居城一隅，屋漏如野處。',216,'全唐诗/poet.song.156000.json','["官居城一隅，屋漏如野處。", "辛勤補綠蘿，僅可待風雨。", "移家幸亡恙，所苦多碩鼠。", "齧衣費紉縫，盜肉恣含咀。", "引子動成羣，啾啾疑爾汝。", "晝曾無靦顔，入暮誰能禦。", "窺燈殫膏油，驚夢鬭儔侶。", "主人非昔人，爲態尚如許。", "飽食詎可常，潛蹤豈無所。", "灌穴惡盡殺，具磔難悉舉。", "牆東吏部家，兩貓將十子。", "往往感仁惠，相乳忘彼此。", "花墩夜不眠，衛寢如馴虎。", "願分俊逸姿，庶以鎮衡宇。", "穿魚聘銜蟬，於君諒無取。", "丁寧玉板師，委曲致斯語。", "妻孥仍有言，乞貓宜乞女。", "他時遂生育，鄰里轉相予。"]'),
('136a9a96-a680-4cd2-82d5-abb96f3d7c7b','簡查仲明','章甫','宋','宋诗','song-poetry','','[]','佛法若大海，我生猶蚊虻。',120,'全唐诗/poet.song.156000.json','["佛法若大海，我生猶蚊虻。", "飲少腹已滿，鼓翅作微鳴。", "查侯飽禪學，如說且能行。", "有如遼天鶴，豈受網罟嬰。", "有身未免俗，時時還入城。", "籃輿過茅屋，無異同條生。", "相見非何事，說法俱縱橫。", "妙處固不二，其實無所爭。", "願君更方便，除我疑惑情。", "要如兩圓鏡，相照交光明。"]'),
('ac1953a8-caaa-4ce6-90b4-811fd46eebee','題王朝英歇馿圖','章甫','宋','宋诗','song-poetry','','[]','天寒山路長，年荒蹇馿瘦。',72,'全唐诗/poet.song.156000.json','["天寒山路長，年荒蹇馿瘦。", "風松適相遭，金石方互奏。", "是中有佳趣，捨鞍聊杖藜。", "童奴難與言，得句忘吾饑。", "懷遠空暮雲，憂時當肉食。", "市朝塵涴人，歸歟北山北。"]'),
('ac2e2f1d-ca18-4cdd-a502-f6bb9e9ecdcb','送鄉人宗旨上坐','章甫','宋','宋诗','song-poetry','','[]','久客不忘歸，相逢喜鄉曲。',120,'全唐诗/poet.song.156000.json','["久客不忘歸，相逢喜鄉曲。", "杖藜時過門，軟語伴幽獨。", "翩翩別我去，芒鞋踏清秋。", "二浙富山水，令人懷昔遊。", "我今齒髮衰，聞道不加進。", "羨君方妙齡，六翮宜自振。", "末法日頹弊，叢林魔說多。", "願君擇師友，金玉須琢磨。", "他時重逢迎，洗耳聽高論。", "豈惟慰相思，亦以警老鈍。"]'),
('8d1f0171-6666-471f-a54a-10f7f1afd97b','與常不輕弈棋輸松枝筆一篇','章甫','宋','宋诗','song-poetry','','[]','南山蒼髯翁，閲世幾千秋。',144,'全唐诗/poet.song.156000.json','["南山蒼髯翁，閲世幾千秋。", "終以明自煎，晚爲松滋侯。", "孫枝後來秀，勁直餘風流。", "亦學管城子，來從毛穎遊。", "故人使江南，江北停歸輈。", "持贈比歲寒，厚意豈暗投。", "形貌若黄槁，風度猶清修。", "輕健殊可人，不作繞指柔。", "我貧得長閒，造物因冥搜。", "詩成呼使前，脫帽明窗幽。", "旁無賞音人，頼爾能點頭。", "無論及錢神，政恐爲爾羞。"]'),
('c4bdefc9-e285-4b2a-a6ed-0bba35ba0652','繡觀音','章甫','宋','宋诗','song-poetry','','[]','蜀人多巧思，組繡用功深。',120,'全唐诗/poet.song.156000.json','["蜀人多巧思，組繡用功深。", "生綃三尺餘，成此觀世音。", "慈悲歡喜容，如出旃檀林。", "蓮花隨步武，纓絡縵衣襟。", "手中楊柳枝，時布慈雲陰。", "誓度諸有情，能以音聲尋。", "由茲善幻力，使我生恭欽。", "仰瞻大自在，本以一寸針。", "衆生與諸佛，其實同此心。", "願學聞思修，苦海脫浮沉。"]'),
('2013cfc3-942b-43a1-9c4b-12a68c6764b6','紫蘇','章甫','宋','宋诗','song-poetry','','[]','吾家大江南，生長慣卑濕。',144,'全唐诗/poet.song.156000.json','["吾家大江南，生長慣卑濕。", "早衰坐辛勤，寒氣得相襲。", "每愁春夏交，兩脚難行立。", "貧窮醫藥少，未易辦芝朮。", "人言常食飲，蔬茹不可忽。", "紫蘇品之中，功具神農述。", "爲湯益廣庭，調度宜同橘。", "結子最甘香，要待秋霜實。", "作腐罌粟然，加點須薑蜜。", "由茲頗知殊，每就畦丁乞。", "飄流無定居，借屋少容膝。", "何當廣種藝，歲晚愈吾疾。"]'),
('5f46e1c0-f860-43b7-85e0-653b68324d24','答權幹用命字韻見惠','章甫','宋','宋诗','song-poetry','','[]','峩峩儒衣冠，昕貴知義命。',144,'全唐诗/poet.song.156000.json','["峩峩儒衣冠，昕貴知義命。", "大道若坦途，狂夫蹈邪徑。", "惟君異流俗，學古師往聖。", "窮居飲一瓢，輕視車千乘。", "粹然白玉溫，卓爾青松勁。", "風流入蓮幕，忠恕自天性。", "愛賢易好色，避利如深穽。", "時邀野人語，亦說禪家病。", "不辭王事勞，益知仁者靜。", "兼旬當闊別，强飯遵時令。", "邊城霜露寒，淮鄉道里夐。", "事物多感懷，篇章應寓興。"]'),
('490ac244-ab6b-4c48-8586-43b7b3ce529e','連屋','章甫','宋','宋诗','song-poetry','','[]','十年誦公詩，正自識孫楚。',96,'全唐诗/poet.song.156000.json','["十年誦公詩，正自識孫楚。", "一日從公遊，如入圖書府。", "登門跡已熟，入室心相予。", "及觀連屋處，益知用意苦。", "巖巖中書君，正色元祐年。", "文章照今古，神物護簡編。", "盛德宜有後，諸孫如彼賢。", "韡韡常棣華，相戒南陔篇。"]'),
('8303a0f3-76fe-47f1-b574-7b9df1740ad2','驄馬','章甫','宋','宋诗','song-poetry','','[]','門前驄馬無人騎，北風落日長聲嘶。',64,'全唐诗/poet.song.156000.json','["門前驄馬無人騎，北風落日長聲嘶。", "細看毛骨獨殊衆，或言來自流沙西。", "伏櫪忍遭奴隸辱，立仗難貪五品粟。", "將軍邊塞敢橫行，願同生死俱馳逐。"]'),
('dc967cc3-f6de-4cc9-a8f0-c859c5a55148','次韓中父送行韻','章甫','宋','宋诗','song-poetry','','[]','素琴橫牀巾漉酒，千載斯人吾尚友。',96,'全唐诗/poet.song.156000.json','["素琴橫牀巾漉酒，千載斯人吾尚友。", "祇今與世已相違，再見喜君真耐久。", "笑我生緣良易足，畬田新燒屋新築。", "飯牛政自不須歌，失馬焉知未爲福。", "百里未容君疾驅，朝廷用才當不拘。", "他年得意輦轂下，莫忘詩篇寄田舍。"]'),
('f44f0227-ec89-45a3-bc0f-b30246198d5c','送王純仲','章甫','宋','宋诗','song-poetry','','[]','客裏因依三日語，爽氣津津見眉宇。',96,'全唐诗/poet.song.156000.json','["客裏因依三日語，爽氣津津見眉宇。", "自云縱酒少年場，拋擲黄金如糞土。", "倏焉四十髮斑斑，手板青衫才一官。", "江湖陳迹不復夢，食貧月俸仍酸寒。", "別去不勞重歎息，富貴有時君努力。", "青春難再却堪憐，恨不相逢十載前。"]'),
('a37378ed-ac2a-400b-8f99-e37a9d7b2220','別陸務觀','章甫','宋','宋诗','song-poetry','','[]','江南江北雖一水，欲濟無由若千里。',128,'全唐诗/poet.song.156000.json','["江南江北雖一水，欲濟無由若千里。", "那知奔走避邊塵，邂逅西津見君子。", "一飯山間同野僧，花前把酒看張燈。", "醉吟落紙筆不停，留客夜闌雙眼青。", "才氣如公端有幾，半刺江城聊復爾。", "新年華省用名郎，彙征公合聯翩起。", "人生相知貴知心，道同何必問升沉。", "客袂此時成暫別，詩盟他日會重尋。"]'),
('fa09b948-3957-471d-baab-913da828d14a','采石','章甫','宋','宋诗','song-poetry','','[]','江行十日風打頭，采石江邊還小留。',272,'全唐诗/poet.song.156000.json','["江行十日風打頭，采石江邊還小留。", "龍宮煌煌俯湍流，摳衣再拜祈神庥。", "出門逕作蕭寺遊，危亭縹緲臨金牛。", "江南江北蒼烟收，日落未落雙蛾愁。", "尚書麗句世罕儔，惜哉度曲無歌喉。", "折梅置酒齋堂幽，黄冠不飲空夷猶。", "野僧舉觴橫青眸，更得大斗償香羞。", "興闌山下却登舟，使君愛客方綢繆。", "夜深杖藜弔荒丘，列炬照野經塍溝。", "居人竊視聲吚嚘，好事從來無與侔。", "促坐款語相答酬，傷今懷古風颼飀。", "泊渚高吟聊寫憂，然犀照怪知何求。", "醉狂夜披紫綺裘，騎鯨入海窮冥搜。", "聖賢寂寞江悠悠，人在天地真蜉蝣。", "况我此身如贅疣，從公行善臭味投。", "有酒如川容拍浮，但願早登黄鶴樓。", "痛飲浩歌更勸酬，一弔禰衡鸚鵡洲。"]'),
('6f6a6854-7fab-4669-998f-0aa4a4478fd7','益睡','章甫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','主人頎然腰十圍，一官會計同遊嬉。',208,'全唐诗/poet.song.156000.json','["主人頎然腰十圍，一官會計同遊嬉。", "開軒環坐只圖史，錦囊富有驚人詩。", "邇來萬事不掛口，世情盡付鼻中吼。", "便腹無妨弟子嘲，著鞭未落少陵後。", "紛紛逐臭皆羣兒，我正黑甜曾未知。", "雞蟲得失何足較，是身且卧黄琉璃。", "博山生雲香斷續，當午清風度修竹。", "門前吏立雁鶩行，童奴摇手眠方熟。", "夢中了了欲何鄉，寧復蘧蘧栩栩忙。", "寒泉洗耳石礪齒，主人家住廬山傍。", "他時但取青氈舊，歸作春秋同社友。", "北窗槃礴上羲皇，秫田多種釀壺酒。", "奉太夫人千百年，兄弟對牀聽雨眠。"]'),
('8d2e7370-22ef-48ca-8115-b76f5dc487ac','送楊德雋赴漕司試','章甫','宋','宋诗','song-poetry','','[]','木食草衣吾計決，三釜養親君不闕。',64,'全唐诗/poet.song.156000.json','["木食草衣吾計決，三釜養親君不闕。", "胡爲亦趁槐花忙，不共中秋醉明月。", "君言時世眩虛名，才見頭銜分重輕。", "一笫如君當俯拾，卜鄰他日莫寒盟。"]'),
('cfdb7094-cec7-46e5-90be-9e11e2bb4710','寄題郭侯至喜堂','章甫','宋','宋诗','song-poetry','','[]','岷江西來會衆水，峽束奔湍吁可畏。',224,'全唐诗/poet.song.156000.json','["岷江西來會衆水，峽束奔湍吁可畏。", "長年三老更相賀，舟到夷陵若平地。", "寧知市朝車馬塵，仕路風波尤畏人。", "急流往往捷有神，灩澦瞿唐何足云。", "祇今四海滔滔是，未省幾人知此理。", "君侯不與世沉浮，家有新堂名至喜。", "武昌重鎮居上游，雲屯禁旅皆貔貅。", "君侯智略誰與儔，天子久寬西顧憂。", "令嚴將士無驕色，玉帳晝閒人語寂。", "中齋一榻凈無塵，自炷爐香讀周易。", "有時領客尊酒同，雅歌投壺雙頰紅。", "門前官柳摇春風，想應目送天邊鴻。", "狐兔中原須盡掃，功成身退天之道。", "角巾歸路颺輕舟，童僕懽迎人未老。"]'),
('f675c083-8bfd-4f21-a87c-27796d1e2f98','种基祖蔡仲逸孫祖顯一時宦遊荆州官閒無事五日一宴集使僕持鉢其間念既飽食不可無語','章甫','宋','宋诗','song-poetry','','[]','君不聞薊孝廉，日飯二十家。',122,'全唐诗/poet.song.156000.json','["君不聞薊孝廉，日飯二十家。", "一朝拂袖去京國，追之不可空咨嗟。", "又不聞賓頭盧，應供四天下。", "神通妙用固非難，中有巍然不動者。", "今年有客來荆州，半世生涯一敝裘。", "仙風道骨媿二士，諸公亦許相追遊。", "邇來傳食初無問，醉飽無勞主人勸。", "絕勝詩人杜拾遺，所歷諸家纔一飯。"]'),
('280b427e-32a0-4000-b2e1-2c73a6a46dfc','芍藥呈韓丈','章甫','宋','宋诗','song-poetry','','[]','妖氛深蔽洛陽縣，我生不識姚花面。',96,'全唐诗/poet.song.156000.json','["妖氛深蔽洛陽縣，我生不識姚花面。", "揚州風物舊曾遊，佳種年深亦多變。", "去冬淮上起邊塵，不謂見花當此辰。", "眼明忽憶往時事，世間尤物能移人。", "公詩寄興多高遠，早悟色空香不染。", "飽聞嘗醉洛陽春，試比姚花定褒貶。"]'),
('a26eab02-90bf-445b-af35-90abd1f9af29','韓使君分送芍藥索詩因憶舊遊','章甫','宋','宋诗','song-poetry','','[]','憶向西津櫂酒船，維揚去結看花緣。',96,'全唐诗/poet.song.156000.json','["憶向西津櫂酒船，維揚去結看花緣。", "杖藜到處花輒好，夭紅豔紫相留連。", "散盡黄金携酒友，夜深明月還京口。", "中流擊楫來悲風，天闊參橫移北斗。", "俯仰光陰恰十春，二十四橋經戰塵。", "眼明忽見揚州種，衰病無因賈餘勇。"]'),
('85c1d6dd-2e86-45ad-874c-33a03c5b0f66','寄題極星亭','章甫','宋','宋诗','song-poetry','','[]','杜陵白首尚書郎，三見瀼西春草長。',128,'全唐诗/poet.song.156000.json','["杜陵白首尚書郎，三見瀼西春草長。", "忽思蒼梧叫虞舜，翩然短棹下瞿塘。", "晚泊江亭生暝色，野服出船烏帽側。", "南極一星落江湖，戰塵蔽天兵未息。", "閭閻惡少印纍纍，不夢周孔嗟吾衰。", "機心去盡魚鳥狎，在處詩篇神護持。", "四百年間一彈指，當時松竹今餘幾。", "南望冰魂不可招，波翻落日愁雲起。"]'),
('434ec9b5-604a-4566-98ed-567d48cd2e95','寄趙鄂州','章甫','宋','宋诗','song-poetry','','[]','田家禾黍方登場，枯桑索索天雨霜。',128,'全唐诗/poet.song.156000.json','["田家禾黍方登場，枯桑索索天雨霜。", "黄花籬落尚可醉，今我不樂思武昌。", "武昌使君半年別，前日書來慰愁絕。", "相思爲我作西亭，徙倚闌干只明月。", "大材開府何優游，政聲日隨江水流。", "賜金增秩未爲寵，咫尺丹詔催歸輈。", "燈前春雨同揮翰，南風吹船著淮岸。", "雲間過雁喚愁生，短褐飯牛歌夜半。"]'),
('809f7660-c86e-487f-b2da-08565d97c07e','以王通一所畫小舟橫截春江圖爲韓無咎壽','章甫','宋','宋诗','song-poetry','','[]','江上春風花滿樹，春水才平舊痕處。',96,'全唐诗/poet.song.156000.json','["江上春風花滿樹，春水才平舊痕處。", "何人笑傲一扁舟，橫截千波萬波去。", "王郎有句藏毫端，寫出生綃半幅間。", "明窗供我時展玩，彷彿羅带縈烟鬟。", "緘題請壽黄華使，如公福祿川方至。", "吾君願治正思賢，舟楫期公濟大川。"]'),
('0f9f0a18-8798-4ef9-9886-a1d820af2e93','簡張安國','章甫','宋','宋诗','song-poetry','','[]','南北東西厭問津，西海忘形今幾人。',160,'全唐诗/poet.song.156000.json','["南北東西厭問津，西海忘形今幾人。", "惟公名譽一世重，雖不吾與吾當親。", "氣吞雲夢并餘子，深厚文章六經似。", "昂霄聳壑正當時，發策決科餘事耳。", "上方憂顧大江東，虎踞龍盤氣象雄。", "却袖玉堂揮翰手，來成方面保釐功。", "西風澹日邊雲碧，歲晚軍情猶未得。", "不應矯首送飛鴻，想得攢眉正憂國。", "雅聞一諾值千金，推挽尤多樂善心。", "坐上能容野人否，試聽客裏短長吟。"]'),
('e989b7bc-1909-4153-9c70-51da967fb5b2','張使君以畫屏求題','章甫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖景物天與奇，歲晚春風常探支。',96,'全唐诗/poet.song.156000.json','["西湖景物天與奇，歲晚春風常探支。", "水邊竹外更幽絕，一夜花開南北枝。", "何處飛來兩鸂鶒，影碎晴波蕩春碧。", "荷蓋凋零荇带寒，徘徊如與花相識。", "短屏畫手豈無心，待公歸赴西湖春。", "年年春色花照席，應念揮毫老賓客。"]'),
('a610a412-6851-49d4-91e1-ac66a6b8e1f0','臨江何氏結亭松間名曰彈秋因王通一來乞詩','章甫','宋','宋诗','song-poetry','','[]','萬籟從風俱發聲，唯松得之尤善鳴。',96,'全唐诗/poet.song.156000.json','["萬籟從風俱發聲，唯松得之尤善鳴。", "五聲不亂無虧成，膝橫三尺秋月明。", "君家江南一茆屋，直幹森森伴幽獨。", "人言絲竹不如肉，曲肱聽度無絃曲。", "故山偃蓋未十圍，猿驚鶴怨吾當歸。", "聊憑東風寄君詩，風鳴松鳴吾不知。"]'),
('9485313d-fda8-4078-aff4-8cf8523d5ebc','送李文授還越上','章甫','宋','宋诗','song-poetry','','[]','舊歲見君殊草草，懷抱今來各傾倒。',96,'全唐诗/poet.song.156000.json','["舊歲見君殊草草，懷抱今來各傾倒。", "新來正好數相尋，束裝却向山陰道。", "千巖萬壑秋更奇，候門兒女望君歸。", "扁舟此去來何時，莫待梅花開北枝。", "故人問我憑君說，滿目窮愁生事拙。", "秋禾未得補饑瘡，萬一飛蝗作檀越。"]'),
('d8db46a2-0916-4cf2-bbab-7d213d3b8ab4','簡熊帥景瞻','章甫','宋','宋诗','song-poetry','','[]','槐柳陰中數間屋，麤飯濁醪羹杞菊。',160,'全唐诗/poet.song.156000.json','["槐柳陰中數間屋，麤飯濁醪羹杞菊。", "過門問字久無人，只有圖書伴幽獨。", "剝啄是誰來叩扃，手持札翰趨吾庭。", "風采九州安撫使，得得遣騎相招迎。", "我願識公從宿昔，貴賤殊途那易得。", "親染雲箋賁草廬，驚喜盈懷仍歎息。", "折節下士古所稀，豈意於公今見之。", "况公位貌已崇重，英聲凜凜威羌夷。", "滿堂賓客皆豪傑，從容何止談風月。", "野人自視殊缺然，或可爲詩紀勳業。"]'),
('1aff98de-dac0-4c65-88e0-a093fa01d71f','早凉','章甫','宋','宋诗','song-poetry','','[]','江頭雨過涼風早，落葉紛紛費人掃。',64,'全唐诗/poet.song.156000.json','["江頭雨過涼風早，落葉紛紛費人掃。", "鈎簾日暮無所爲，把酒悠然送歸鳥。", "佳人可望不可親，草根唧唧秋蟲吟。", "家本江南客江北，鬚髮新添數莖白。"]'),
('416ef31b-cfc5-425e-bedc-82e646d07b22','次沈商卿見懷韻','章甫','宋','宋诗','song-poetry','','[]','歌喉宛轉變鳴禽，載酒曾同花下吟。',128,'全唐诗/poet.song.156000.json','["歌喉宛轉變鳴禽，載酒曾同花下吟。", "寒潮不應宿漁浦，挑燈還憶夜深語。", "十載故人誰似君，便擬卜隣桑柘村。", "青錢未辦歸期遠，滿目春山空秀婉。", "有酒何須身後名，高軒未必如徒行。", "朝看桃杏發紅萼，晚來風雨嗟零落。", "尋幽選勝不應遲，百歲光陰能幾時。", "問君何日憩奔走，忍令春色成烏有。"]'),
('10296253-d6a0-4dd5-a8bd-9c4149187dd6','寄淮東總領許叔庸','章甫','宋','宋诗','song-poetry','','[]','太平寺裏留詩別，江北江南幾秋月。',128,'全唐诗/poet.song.156000.json','["太平寺裏留詩別，江北江南幾秋月。", "那知未著侍臣冠，坐總軍儲持使節。", "平生一飯不忘君，蟠胸萬卷皆經綸。", "聞說別來頭更白，憂國祇今能幾人。", "憶昨同傾京口酒，笑我凋零已蒲柳。", "曉驅黄犢破荒烟，留眼看公印如斗。", "短篇自昔蒙品題，老矣無復能新奇。", "樂府流傳妙天下，小胥鈔寄定何時。"]'),
('6605c139-bee3-447d-91a7-bf7400222fb7','移家謝趙再可','章甫','宋','宋诗','song-poetry','','[]','病眼不禁黄土瞇，塵纓屢費滄浪水。',128,'全唐诗/poet.song.156000.json','["病眼不禁黄土瞇，塵纓屢費滄浪水。", "曉窗笑語鏡中人，但可置之巖穴裏。", "縣官有田容我耕，收身已是太遲生。", "醉眠牛背自安穩，山鳥慣聽哦詩聲。", "經營小築幽深處，借車歡喜移家去。", "非公誰寄草堂貲，知我舊諳茆屋趣。", "此心此地俱寬閒，從渠曠野多風寒。", "燈前兒女話團欒，廣厦期公千萬間。"]'),
('37f927fe-eace-4a18-85a8-9a864a05046b','謝張倅惠茶','章甫','宋','宋诗','song-poetry','','[]','病軀倦甚不舉酒，便腹枵然尤愛茶。',128,'全唐诗/poet.song.156000.json','["病軀倦甚不舉酒，便腹枵然尤愛茶。", "淮鄉久住已成俗，客至亦復研芝麻。", "稱重緗匳還入手，知公與我詩情厚。", "靜無俗駕叩柴關，急遣僧房借茶臼。", "易足堂中晝倍長，一杯涼餠補饑腸。", "世間萬事不掛口，齒頰盡日留甘香。", "青奴可憐姑少却，睡魔退舍詩魔作。", "詩成吟罷來清風，秋意拂拂生梧桐。"]'),
('698f54e7-93be-4696-8961-53231ebb5fd2','謝韓無咎寄新茶','章甫','宋','宋诗','song-poetry','','[]','武夷仙翁冰雪顔，建甯府中春晝閒。',96,'全唐诗/poet.song.156000.json','["武夷仙翁冰雪顔，建甯府中春晝閒。", "揮毫醉寫烏絲欄，新茗續煎扶玉山。", "應念窮愁坐空谷，頭白眼眵書懶讀。", "殷勤題裹寄春風，澆我從來藜莧腹。", "別公宛陵今五春，渴心何啻生埃塵。", "平生不識七閩路，夢魂欲往山無數。"]'),
('1b324781-36fa-4035-8801-2c8e32ae43c0','簡李牧之','章甫','宋','宋诗','song-poetry','','[]','落日還家聊面壁，剝啄誰來破幽寂。',96,'全唐诗/poet.song.156000.json','["落日還家聊面壁，剝啄誰來破幽寂。", "語音相似桑梓同，風骨軒然雙頰紅。", "亹亹清談霏玉屑，多說東湖與霜傑。", "江西故老已凋零，聽君論詩猶典型。", "君今久占宣城籍，我是江湖未歸客。", "客愁時事兩蒼茫，一醉邀君君莫惜。"]'),
('02e15c69-8fae-4716-8b93-c1bce765712e','張君明昆仲袖唱和詩見過','章甫','宋','宋诗','song-poetry','','[]','村東主客羣飛鴻，月明霜重聲摩空。',192,'全唐诗/poet.song.156000.json','["村東主客羣飛鴻，月明霜重聲摩空。", "村西老人如瘦馬，伏櫪倦嘶天北風。", "村東村西無百步，杖履相尋還有數。", "兒啼妻病不出門，羞見梅花無好句。", "雪晴日出天無埃，故人躡屣聯翩來。", "明珠白璧滿懷袖，使我一見雙眸開。", "文章雖云一小技，妙處非難亦非易。", "染絲織錦未足工，點鐵成金始爲貴。", "我窮半世坐吟詩，詩成不救寒與饑。", "亦知造物厭嘲弄，有手只堪持酒卮。", "願君少吟詩幾首，請君多辦百壺酒。", "但得新詩勝舊年，爲君醉倒春風前。"]'),
('4d4c0c00-30d1-497a-8dca-01eda2b06abd','元用見過誦詩劇談因成古風以成戲惱兼簡若晦唐卿','章甫','宋','宋诗','song-poetry','','[]','有口只可飲醇酒，世事令人三日嘔。',160,'全唐诗/poet.song.156000.json','["有口只可飲醇酒，世事令人三日嘔。", "有耳只可對詩翁，俗語令人三日聾。", "平生嗜酒耽佳句，此外自知無用處。", "東風吹我墮江邊，歲晚知音罕相遇。", "誅茅蓋頭無少閒，數日不到諸君間。", "塵土瞇眼鬚鬢斑，誰賦淮南大小山。", "怪底晴簷靈鵲噪，籃輿相尋談絕倒。", "恨君無乃酒量窄，愛君豈獨詩格老。", "開尊喚客知何時，坐上可無俞與韋。", "更長不怕杯行遲，願見春風楊柳枝。"]'),
('bf49a872-dbb6-49fb-bce0-7e112da1239b','用前韻贈高持一','章甫','宋','宋诗','song-poetry','','[]','全身當作冥飛鴻，無心要似雲行空。',192,'全唐诗/poet.song.156000.json','["全身當作冥飛鴻，無心要似雲行空。", "逢人未用青白眼，與世不妨牛馬風。", "暇日出門聊散步，雪晴愛此山無數。", "骨寒那得使鬼錢，腸枯漫索驚人句。", "邇來筆研欲生埃，舊雨來人今不來。", "百歲光陰能幾許，一春懷抱未曾開。", "古人元不貴多技，大道由來常簡易。", "隨呵之義復何憂，知我者希方足貴。", "華陽道士亦能詩，不覺餐霞坐忍饑。", "高山流水琴三弄，明月清風酒一卮。", "相思不見頻搔首，幾欲招呼無斗酒。", "從今與子遂忘年，有懷欲語子來前。"]'),
('a31918e2-e297-48af-827d-8001a696af93','次呂伯恭見寄韻','章甫','宋','宋诗','song-poetry','','[]','魯鈍不如錐處囊，嗜好鑿圓投枘方。',184,'全唐诗/poet.song.156000.json','["魯鈍不如錐處囊，嗜好鑿圓投枘方。", "鏡中鬚髮今蒼浪，多病年來疏酒觴。", "山林舊約都茫茫，局促何由心膽張。", "半生恍墮水中央，疾呼四顧無舟航。", "客舍雨餘梅杏黄，憶君著書看屋梁。", "緘題到手伸讀忙，亦知別後遥相望。", "我猶駑馬遭絆韁，君若鷹鸇之老蒼。", "見義勇往柔而剛，君不求名名自彰。", "行須正色肅鵷行，不容燕雀高飛翔。", "辱詩敢忘什襲藏，報章勉率聊寄將。", "廣厦他時客幾房，種成桃李滿江鄉，忍使故人趨道旁。"]'),
('9bef7b05-1cfa-42fa-97a6-7ae6dc60f06f','濡須道中','章甫','宋','宋诗','song-poetry','','[]','今年淮西旱，城市無米糶。',60,'全唐诗/poet.song.156000.json','["今年淮西旱，城市無米糶。", "所至蕭條童僕饑，手持楮幣無人要。", "行不擇日糧不齎，恨身不生太平時。", "還家從頭語兒輩，山中寂寞猶可耐。"]'),
('06c9227f-ab5e-49fa-8c32-5510f97c5ccf','白露行','章甫','宋','宋诗','song-poetry','','[]','今歲淮南雨仍缺，官府祈求已踰月。',96,'全唐诗/poet.song.156000.json','["今歲淮南雨仍缺，官府祈求已踰月。", "城中又復閉南門，移市向北人紛紛。", "州前結壇聚巫覡，頭冠神衣競跳擲。", "縛草爲龍置壇側，童子繞壇呼蜥蜴。", "簫鼓迎神來不來，旱風終日吹黄埃。", "寧知白露只數日，稻苗焦枯恐不及。"]'),
('97ec2a14-4b34-41e2-8ac5-7f968b8b6a65','送王道士','章甫','宋','宋诗','song-poetry','','[]','華陽洞天昔曾遊，華陽道士今相訪。',64,'全唐诗/poet.song.156000.json','["華陽洞天昔曾遊，華陽道士今相訪。", "江頭倦客老更拙，山中故人喜亡恙。", "晴沙喚渡何匆匆，鴻飛冥冥天北風。", "他日希虛如話我，憑君一一謝諸公。"]'),
('62820098-633f-406c-8212-299d394174d3','督祖顯和章','章甫','宋','宋诗','song-poetry','','[]','孫侯二尺短檠前，何啻頌詩三百篇。',160,'全唐诗/poet.song.156000.json','["孫侯二尺短檠前，何啻頌詩三百篇。", "金鑾玉堂未歸去，聊結江湖山水緣。", "官閑不復弄朱墨，勝日過門無惡客。", "春風快馬紫遊韁，花底黄鸝盡相識。", "酒酬談辯翻波瀾，得句全勝得好官。", "我亦從來有詩癖，撚髭一字吟難安。", "不知辛苦竟何益，聞道何妨死今夕。", "他年儻使無知音，盈編不作一錢直。", "日來頗怪詩筒遲，恐君豫辦磨崖詩。", "中原窟穴尚狐兔，未應便草閒居賦。"]'),
('296ec25e-d404-4c7a-9f9e-e25e0ffc87ab','放歌招孫祖訓俞國寶飲','章甫','宋','宋诗','song-poetry','','[]','兒時望春春不來，春衣隔年催翦裁。',296,'全唐诗/poet.song.156000.json','["兒時望春春不來，春衣隔年催翦裁。", "平明出遊薄暮回，惟恐雲氣興風雷。", "豈知樂極還悲哀，十年黄塵涴青鞋。", "管領鶑花已無意，感時念舊時傷懷。", "去年寒食丹徒縣，家寄毗陵不相見。", "今年寒食江陵府，妻子相看淚如雨。", "迂儒憂國更憂家，枉殺清明不見花。", "無端柳絮攪愁思，一徑漫漫春日斜。", "主人知我坐憔悴，故遣斗酒來相慰。", "呼妻安穩置牀頭，箇是貧家一祥瑞。", "牀頭三日未開嘗，耿耿憂心自如醉。", "朝來忽覺體中佳，吻角流涎已難制。", "細君平日但濡唇，瓦盆對酌可無人。", "招朋一飲舒清興，要須脫畧任天真。", "高郵孫夫子，相逢不作鬲上語。", "臨川俞先生，客裏傷春作詩苦。", "二公問學該今古，胸吞雲夢輕阿堵。", "我酒雖不多，酒行詩可歌。", "杖藜乘興速來過，不來吟醉奈春何。"]'),
('733b38b3-88c3-4707-9377-b9966b3bd6a8','聞鵓鴣','章甫','宋','宋诗','song-poetry','','[]','陰雲欲暗江頭樹，屋角先聞鵓鴣語。',64,'全唐诗/poet.song.156000.json','["陰雲欲暗江頭樹，屋角先聞鵓鴣語。", "瀟瀟漸作打窗聲，誰道巢居不知雨。", "雨晴喚婦却同飛，須知此物心無機。", "豈比人間情義變，銜冤誓死不相見。"]'),
('1cd06301-b018-493d-9daa-4a8d5dcbf706','題九歌圖','章甫','宋','宋诗','song-poetry','','[]','大夫放逐沅湘濱，嘗作九歌祠鬼神。',64,'全唐诗/poet.song.156000.json','["大夫放逐沅湘濱，嘗作九歌祠鬼神。", "鬼神幽遠不可見，肴酒芬芳猶福人。", "餐菊佩蘭君不識，從彼讒人爲鬼蜮。", "楚江嗚咽楚雲愁，坐對此圖三歎息。"]'),
('60146c17-cf8d-4a8f-8ffb-8eb521bf53a6','題王無邪九華圖','章甫','宋','宋诗','song-poetry','','[]','雲錦仙翁人不識，多生九華茹芝客。',96,'全唐诗/poet.song.156000.json','["雲錦仙翁人不識，多生九華茹芝客。", "少年登覽妙形容，三十七峯俱改色。", "手捉高士淡墨圖，烟雲到處隨卷舒。", "珠璣衮衮入題詠，縑素往往爭臨摹。", "雪潭四時濺飛雪，歎我幻軀方病渴。", "何由得共山中人，脚踏寒流弄明月。"]'),
('9497cc63-bca1-4f04-bf97-b234f224343f','王夢得捕蝗二首  其一','章甫','宋','宋诗','song-poetry','','[]','相逢每歎俱飄流，尊酒作意同新秋。',64,'全唐诗/poet.song.156000.json','["相逢每歎俱飄流，尊酒作意同新秋。", "蝗蟲日來復滿野，府帖夜下還呼舟。", "江天尚黑客騎馬，草露未晞人牧牛。", "路長遥想兀殘夢，家在風烟蘭杜洲。"]'),
('1dbcd694-4314-4e4b-a68f-4d47fff71b25','王夢得捕蝗二首  其二','章甫','宋','宋诗','song-poetry','','[]','江頭曉日方曈曈，僕夫喘汗天無風。',64,'全唐诗/poet.song.156000.json','["江頭曉日方曈曈，僕夫喘汗天無風。", "茅簷汲井洗塵土，野寺煮餠燒油葱。", "平生憂國寸心赤，在處哦詩雙鬢蓬。", "村民喜識長官面，樹陰可坐毋匆匆。"]'),
('62c44e93-300b-48e8-bbc2-7f4bd595a2ee','分蝗食','章甫','宋','宋诗','song-poetry','','[]','田園政爾無多子，連歲旱荒饑欲死。',96,'全唐诗/poet.song.156000.json','["田園政爾無多子，連歲旱荒饑欲死。", "今年何幸風雨時，豈意蝗蟲乃如此。", "麥秋飛從淮北過，遺子滿野何其多。", "撲滅焚瘞能幾何，羽翼已長如飛蛾。", "天公生爾爲民害，爾如不食焉逃罪。", "老夫寒餓悲惱纏，分而食之天或憐。"]'),
('307a4525-a387-4ff1-9aa9-f0d8f62e9bd4','憫農','章甫','宋','宋诗','song-poetry','','[]','前村後村水車聲，咿咿軋軋終夜鳴。',96,'全唐诗/poet.song.156000.json','["前村後村水車聲，咿咿軋軋終夜鳴。", "皇天不雨四十日，高田何止龜兆出。", "田家眼穿望早禾，早禾不熟奈饑何。", "今年神祠禱不應，沽酒買牛空費多。", "天公高居民父母，有耳應聞下民語。", "乞我滂沱半朝雨，免遭縣吏鞭笞苦。"]'),
('53c53450-9872-46b6-aee2-67bd2f74db09','田家苦','章甫','宋','宋诗','song-poetry','','[]','何處行商因問路，歇肩聽說田家苦。',124,'全唐诗/poet.song.156000.json','["何處行商因問路，歇肩聽說田家苦。", "今年麥熟勝去年，賤價還人如糞土。", "五月將次盡，早秧都未移。", "雨師懶病藏不出，家家灼火鑽烏龜。", "前朝夏至還上廟，著衫奠酒乞杯珓。", "許我曾爲五日期，待得秋成敢忘報。", "陰陽水旱由天工，憂雨憂風愁殺儂。", "農商苦樂元不同，淮南不熟販江東。"]'),
('a164a82d-0780-40fe-b595-545086514e7f','送茶與人','章甫','宋','宋诗','song-poetry','','[]','雲氣昏昏釀秋雨，歲月驚心遽如許。',64,'全唐诗/poet.song.156000.json','["雲氣昏昏釀秋雨，歲月驚心遽如許。", "潮生晚浦足風波，頗憶青燈夜深語。", "贈君江南春露芽，恐君誦詩眼生花。", "一杯靜對沉烟斜，世事從渠如亂麻。"]');
